--==================================================
-- [2] BASIC HELPERS
--==================================================

function HolyCleanText(value)

    local text =
        tostring(value or "")

    text =
        text:gsub(
            "^%s+",
            ""
        )

    text =
        text:gsub(
            "%s+$",
            ""
        )

    return text
end

function HolyGetRequestFunction()

    if type(syn) == "table"
    and type(syn.request) == "function" then

        return syn.request
    end

    if type(http_request) == "function" then
        return http_request
    end

    if type(request) == "function" then
        return request
    end

    if type(fluxus) == "table"
    and type(fluxus.request) == "function" then

        return fluxus.request
    end

    local env =
        type(getgenv) == "function"
        and getgenv()
        or _G

    if type(env) == "table" then

        if type(env.request) == "function" then
            return env.request
        end

        if type(env.http_request) == "function" then
            return env.http_request
        end
    end

    return nil
end

function HolyValidateSource(body)

    if type(body) ~= "string"
    or body == "" then

        return nil,
            "empty response"
    end

    if body:sub(1, 3) == "\239\187\191" then
        body = body:sub(4)
    end

    local preview =
        body:sub(1, 220):lower()

    if preview:find("<!doctype html", 1, true)
    or preview:find("<html", 1, true)
    or preview:find("rate limit", 1, true) then

        return nil,
            "response was HTML/rate-limit page"
    end

    if body:find("\0", 1, true) then

        return nil,
            "response contains binary null bytes"
    end

    return body,
        nil
end

function HolyHttpGet(url)

    url =
        HolyCleanText(url)

    if url == "" then
        return nil, "empty URL"
    end

    local failures =
        {}

    local ok,
        result =
        pcall(function()

            return game:HttpGet(
                url,
                true
            )
        end)

    if ok == true then

        local source,
            sourceError =
            HolyValidateSource(result)

        if source then
            return source, nil
        end

        failures[#failures + 1] =
            "game:HttpGet: "
            .. tostring(sourceError)

    else

        failures[#failures + 1] =
            "game:HttpGet failed: "
            .. tostring(result)
    end

    local requestFunction =
        HolyGetRequestFunction()

    if type(requestFunction) == "function" then

        local requestOk,
            response =
            pcall(function()

                return requestFunction({
                    Url = url,
                    Method = "GET",
                    Headers = {
                        ["Accept"] = "text/plain",
                        ["Accept-Encoding"] = "identity",
                        ["Cache-Control"] = "no-cache",
                    },
                })
            end)

        if requestOk == true then

            local body =
                nil

            if type(response) == "string" then

                body =
                    response

            elseif type(response) == "table" then

                body =
                    response.Body
                    or response.body
                    or response.ResponseBody
                    or response.responseBody
            end

            local source,
                sourceError =
                HolyValidateSource(body)

            if source then
                return source, nil
            end

            failures[#failures + 1] =
                "request: "
                .. tostring(sourceError)

        else

            failures[#failures + 1] =
                "request failed: "
                .. tostring(response)
        end
    end

    return nil,
        table.concat(
            failures,
            " | "
        )
end

function HolyGetCompiler()

    if type(loadstring) == "function" then
        return loadstring
    end

    if type(load) == "function" then
        return load
    end

    local env =
        type(getgenv) == "function"
        and getgenv()
        or _G

    if type(env) == "table" then

        if type(env.loadstring) == "function" then
            return env.loadstring
        end

        if type(env.load) == "function" then
            return env.load
        end
    end

    return nil
end

function HolyLoadUrl(url, name)

    name =
        tostring(name or "remote script")

    local source,
        downloadError =
        HolyHttpGet(url)

    if type(source) ~= "string"
    or source == "" then

        error(
            "[HOLY] Failed to download "
            .. name
            .. ": "
            .. tostring(downloadError),
            0
        )
    end

    local compiler =
        HolyGetCompiler()

    if type(compiler) ~= "function" then

        error(
            "[HOLY] loadstring/load is missing.",
            0
        )
    end

    local compileOk,
        chunk,
        compileError =
        pcall(
            compiler,
            source
        )

    if compileOk ~= true
    or type(chunk) ~= "function" then

        error(
            "[HOLY] Failed to compile "
            .. name
            .. ": "
            .. tostring(compileError or chunk),
            0
        )
    end

    local runOk,
        result =
        pcall(chunk)

    if runOk ~= true then

        error(
            "[HOLY] Failed to run "
            .. name
            .. ": "
            .. tostring(result),
            0
        )
    end

    return result
end

function HolyCanUseFiles()

    return type(writefile) == "function"
        and type(readfile) == "function"
        and type(isfile) == "function"
end

function HolyEnsureFolder()

    if type(makefolder) ~= "function"
    or type(isfolder) ~= "function" then

        return false
    end

    local ok =
        pcall(function()

            if not isfolder(UI_SETTINGS_FOLDER) then

                makefolder(
                    UI_SETTINGS_FOLDER
                )
            end
        end)

    return ok == true
end

function HolySaveUISettings()

    if HolyCanUseFiles() ~= true then
        return false
    end

    HolyEnsureFolder()

    local payload = {
        ShowUIOnLoad =
            HOLY_DEV_UI_STATE.ShowUIOnLoad == true,

        AutoCloseUI =
            HOLY_DEV_UI_STATE.ShowUIOnLoad ~= true,

        DPIScale =
            tonumber(
                HOLY_DEV_UI_STATE.DPIScale
            )
            or 100,

        ThemeName =
            tostring(
                HOLY_DEV_UI_STATE.ThemeName
                or "HOLY Red"
            ),

        InterfaceTransparency =
            math.clamp(
                tonumber(
                    HOLY_DEV_UI_STATE.InterfaceTransparency
                )
                or 0,
                0,
                70
            ),

        InterfaceAnimations =
            HOLY_DEV_UI_STATE.InterfaceAnimations
            ~= false,

        ShowHolyLoadingScreen =
            HOLY_DEV_UI_STATE.ShowHolyLoadingScreen
            ~= false,

        SettingsDashboard =
            tostring(
                HOLY_DEV_UI_STATE.SettingsDashboard
                or "Interface"
            ),

        AutoSkipLoading =
            HOLY_DEV_UI_STATE.AutoSkipLoading == true,

        AntiAfk =
            HOLY_DEV_UI_STATE.AntiAfk == true,

        AutoFarmMiddle =
            HOLY_DEV_UI_STATE.AutoFarmMiddle == true,

        UnloadOtherGardens =
            HOLY_DEV_UI_STATE.UnloadOtherGardens == true,

        UnloadOwnGarden =
            HOLY_DEV_UI_STATE.UnloadOwnGarden == true,

        HideMiddle =
            HOLY_DEV_UI_STATE.HideMiddle == true,
    }

    local encodeOk,
        encoded =
        pcall(function()

            return HttpService:JSONEncode(
                payload
            )
        end)

    if encodeOk ~= true
    or type(encoded) ~= "string" then

        return false
    end

    local writeOk =
        pcall(function()

            writefile(
                UI_SETTINGS_FILE,
                encoded
            )
        end)

    return writeOk == true
end

function HolyLoadUISettings()

    if HolyCanUseFiles() ~= true then
        return false
    end

    local exists =
        false

    pcall(function()

        exists =
            isfile(
                UI_SETTINGS_FILE
            )
    end)

    if exists ~= true then
        return false
    end

    local readOk,
        raw =
        pcall(function()

            return readfile(
                UI_SETTINGS_FILE
            )
        end)

    if readOk ~= true
    or type(raw) ~= "string"
    or raw == "" then

        return false
    end

    local decodeOk,
        data =
        pcall(function()

            return HttpService:JSONDecode(
                raw
            )
        end)

    if decodeOk ~= true
    or type(data) ~= "table" then

        return false
    end

    if type(data.AutoCloseUI) == "boolean" then

        HOLY_DEV_UI_STATE.ShowUIOnLoad =
            data.AutoCloseUI ~= true

    elseif type(data.ShowUIOnLoad) == "boolean" then

        HOLY_DEV_UI_STATE.ShowUIOnLoad =
            data.ShowUIOnLoad
    end

    local scale =
        tonumber(
            data.DPIScale
        )

    if scale then

        HOLY_DEV_UI_STATE.DPIScale =
            math.clamp(
                math.floor(
                    scale + 0.5
                ),
                30,
                110
            )
    end

    local themeName =
        tostring(
            data.ThemeName
            or "HOLY Red"
        )

    if themeName == "Obsidian Red" then

        themeName =
            "HOLY Red"
    end

    HOLY_DEV_UI_STATE.ThemeName =
        themeName

    HOLY_DEV_UI_STATE.InterfaceTransparency =
        math.clamp(
            tonumber(
                data.InterfaceTransparency
            )
            or 0,
            0,
            70
        )

    if type(data.InterfaceAnimations) == "boolean" then

        HOLY_DEV_UI_STATE.InterfaceAnimations =
            data.InterfaceAnimations
    end

    if type(data.ShowHolyLoadingScreen) == "boolean" then

        HOLY_DEV_UI_STATE.ShowHolyLoadingScreen =
            data.ShowHolyLoadingScreen
    end

    local settingsDashboard =
        tostring(
            data.SettingsDashboard
            or "Interface"
        )

    if settingsDashboard ~= "Themes"
    and settingsDashboard ~= "Session"
    and settingsDashboard ~= "Performance" then

        settingsDashboard =
            "Interface"
    end

    HOLY_DEV_UI_STATE.SettingsDashboard =
        settingsDashboard

    if type(data.AutoSkipLoading) == "boolean" then

        HOLY_DEV_UI_STATE.AutoSkipLoading =
