function HolyVisualReadSprinklerESPScale(value)

    local text =
        tostring(value or "")
            :gsub("%%", "")

    local scale =
        tonumber(text)

    if type(scale) ~= "number"
    or scale ~= scale
    or scale == math.huge
    or scale == -math.huge then

        scale =
            80
    end

    return math.max(
        10,
        scale
    )
end

