                or "Below"
            ),

        SellValueThreshold =
            tostring(
                HolySellReadValueThreshold(
                    HOLY_SHOP_STATE.SellValueThreshold
                    or "0"
                )
            ),

        SellAllInterval =
            math.clamp(
                tonumber(HOLY_SHOP_STATE.SellAllInterval)
                or 0.10,
                0,
                5
            ),

        FruitsAtOnce =
            HolySellReadFruitsAtOnce(
                HOLY_SHOP_STATE.FruitsAtOnce
            ),
    }

    local encodeOk,
        encoded =
        pcall(function()

            return HttpService:JSONEncode(
                payload
            )
        end)

    if encodeOk ~= true
    or type(encoded) ~= "string" then
        return false
    end

    local writeOk =
        pcall(function()

            writefile(
                SHOP_SETTINGS_FILE,
                encoded
            )
        end)

    return writeOk == true
end

function HolyLoadShopSettings()

    if HolyCanUseFiles() ~= true then
        return false
    end

    local exists =
        false

    pcall(function()

        exists =
            isfile(
                SHOP_SETTINGS_FILE
            )
    end)

    if exists ~= true then
        return false
    end

    local readOk,
        raw =
        pcall(function()

            return readfile(
                SHOP_SETTINGS_FILE
            )
        end)

    if readOk ~= true
    or type(raw) ~= "string"
    or raw == "" then
        return false
    end

    local decodeOk,
        data =
        pcall(function()

            return HttpService:JSONDecode(
                raw
            )
        end)

    if decodeOk ~= true
    or type(data) ~= "table" then
        return false
    end

    HOLY_SHOP_STATE.Mode =
        data.Mode == "Sell"
        and "Sell"
        or "Buy"

    HOLY_SHOP_STATE.AutoBuySeeds =
        data.AutoBuySeeds == true

    HOLY_SHOP_STATE.AutoBuyGear =
        data.AutoBuyGear == true

    HOLY_SHOP_STATE.AutoBuyProps =
        data.AutoBuyProps == true
        or data.AutoBuyCrates == true

    HOLY_SHOP_STATE.SelectedSeeds =
        HolyShopSelectionArray(
            data.SelectedSeeds
        )

    HOLY_SHOP_STATE.SelectedGear =
        HolyShopSelectionArray(
            data.SelectedGear
        )

    HOLY_SHOP_STATE.SelectedProps =
        HolyShopSelectionArray(
            data.SelectedProps
            or data.SelectedCrates
        )

    HOLY_SHOP_STATE.AutoBuyAuctions =
        data.AutoBuyAuctions == true

    if type(data.AuctionDryRun) == "boolean" then

        HOLY_SHOP_STATE.AuctionDryRun =
            data.AuctionDryRun

    else

        HOLY_SHOP_STATE.AuctionDryRun =
            true
    end

    local loadedWatchlist =
        HolyAuctionNormalizeWatchlist(
            data.AuctionWatchlist
        )

    if type(data.AuctionWatchlist) ~= "table" then

        local legacyMaxPrice =
            HolyAuctionReadMoney(
                data.AuctionMaxPrice
                or "0"
            )

        if legacyMaxPrice > 0 then

            for _, itemName in ipairs(
                HolyShopSelectionArray(
                    data.SelectedAuctions
                )
            ) do

                if HolyAuctionItemKey(itemName) ~= "all" then

                    loadedWatchlist[#loadedWatchlist + 1] = {
                        Name = itemName,
                        MaxPrice = legacyMaxPrice,
                    }
                end
            end
        end
    end

    HOLY_SHOP_STATE.AuctionWatchlist =
        HolyAuctionNormalizeWatchlist(
            loadedWatchlist
        )

    HOLY_SHOP_STATE.AuctionKnownItems =
        HolyShopSelectionArray(
            data.AuctionKnownItems
        )

    if type(data.AuctionBuyUntilSoldOut) == "boolean" then

        HOLY_SHOP_STATE.AuctionBuyUntilSoldOut =
            data.AuctionBuyUntilSoldOut

    else

        HOLY_SHOP_STATE.AuctionBuyUntilSoldOut =
            true
    end

    HOLY_SHOP_STATE.AuctionHudEnabled =
        data.AuctionHudEnabled == true

    HOLY_SHOP_STATE.AuctionHudScale =
        tostring(
            data.AuctionHudScale
            or HOLY_SHOP_STATE.AuctionHudScale
            or "80%"
        )

    HOLY_SHOP_STATE.AuctionHudMinimized =
        data.AuctionHudMinimized == true

    HOLY_SHOP_STATE.AuctionHudPosition =
        type(data.AuctionHudPosition) == "table"
        and data.AuctionHudPosition
        or nil

    HOLY_SHOP_STATE.AutoSellFruits =
        data.AutoSellFruits == true

    HOLY_SHOP_STATE.AutoDoubleOrNothing =
        data.AutoDoubleOrNothing == true

    local doubleTargetWins =
        math.floor(
            tonumber(data.DoubleTargetWins)
            or 1
        )

    if doubleTargetWins < 1 then

        doubleTargetWins =
            1
    end

    HOLY_SHOP_STATE.DoubleTargetWins =
        tostring(
            doubleTargetWins
        )

    HOLY_SHOP_STATE.DoubleBustFavDelay =
        tostring(
            data.DoubleBustFavDelay
            or HOLY_SHOP_STATE.DoubleBustFavDelay
            or "0.10"
        )

    HOLY_SHOP_STATE.DoubleUnfavoriteDelay =
        tostring(
            data.DoubleUnfavoriteDelay
            or HOLY_SHOP_STATE.DoubleUnfavoriteDelay
            or "1.00"
        )

    HOLY_SHOP_STATE.DoubleHudEnabled =
        data.DoubleHudEnabled == true

    HOLY_SHOP_STATE.DoubleHudPosition =
        type(data.DoubleHudPosition) == "table"
        and data.DoubleHudPosition
        or nil

    HOLY_SHOP_STATE.AutoDailyDealAll =
        data.AutoDailyDealAll == true

    HOLY_SHOP_STATE.DailyDealTriggerFruits =
        HolyShopSelectionArray(
            data.DailyDealTriggerFruits
            or data.DailyDealFruits
            or {
                "All",
            }
        )

    if #HOLY_SHOP_STATE.DailyDealTriggerFruits <= 0 then

        HOLY_SHOP_STATE.DailyDealTriggerFruits = {
            "All",
        }
    end

    HOLY_SHOP_STATE.DailyDealMinStockMultiplier =
        tostring(
            data.DailyDealMinStockMultiplier
            or HOLY_SHOP_STATE.DailyDealMinStockMultiplier
            or "2"
        )

    HOLY_SHOP_STATE.DailyDealMinFriendBoost =
        tostring(
            data.DailyDealMinFriendBoost
            or HOLY_SHOP_STATE.DailyDealMinFriendBoost
            or "0"
        )

    HOLY_SHOP_STATE.DailyDealMinInventoryValue =
        tostring(
            data.DailyDealMinInventoryValue
            or HOLY_SHOP_STATE.DailyDealMinInventory
            or HOLY_SHOP_STATE.DailyDealMinInventoryValue
            or "0"
        )

    HOLY_SHOP_STATE.DailyDealMinValue =
        tostring(
            data.DailyDealMinValue
            or HOLY_SHOP_STATE.DailyDealMinValue
            or "0"
        )

    if type(data.DailyDealAutoDisable) == "boolean" then

        HOLY_SHOP_STATE.DailyDealAutoDisable =
            data.DailyDealAutoDisable

    else

        HOLY_SHOP_STATE.DailyDealAutoDisable =
            true
    end

    if type(data.DailyDealRequirePreview) == "boolean" then

        HOLY_SHOP_STATE.DailyDealRequirePreview =
            data.DailyDealRequirePreview

    else

        HOLY_SHOP_STATE.DailyDealRequirePreview =
            true
    end

    HOLY_SHOP_STATE.SellMethod =
        HolySellNormalizeMethod(
            data.SellMethod
            or "Sell All"
        )

    HOLY_SHOP_STATE.UseSellFilters =
        data.UseSellFilters == true

    HOLY_SHOP_STATE.SellFruits =
        HolyShopSelectionArray(
            data.SellFruits
        )

    HOLY_SHOP_STATE.SellRarities =
        HolyShopSelectionArray(
            data.SellRarities
        )

    HOLY_SHOP_STATE.SellMutations =
        HolyShopSelectionArray(
            data.SellMutations
        )

    HOLY_SHOP_STATE.SellVariants =
        HolyShopSelectionArray(
            data.SellVariants
        )

    HOLY_SHOP_STATE.ProtectMutations =
        HolyShopSelectionArray(
            data.ProtectMutations
        )

    HOLY_SHOP_STATE.ProtectVariants =
        HolyShopSelectionArray(
            data.ProtectVariants
        )

    HOLY_SHOP_STATE.MinWeightKg =
        tostring(
            data.MinWeightKg
            or data.WeightKg
            or "0"
        )

    HOLY_SHOP_STATE.MaxWeightKg =
        tostring(
            data.MaxWeightKg
            or "0"
        )

    HOLY_SHOP_STATE.SellValueMode =
        HolySellNormalizeValueMode(
            data.SellValueMode
            or data.ValueMode
            or data.FilteredSellValueMode
            or "Below"
        )

    HOLY_SHOP_STATE.SellValueThreshold =
        tostring(
            HolySellReadValueThreshold(
                data.SellValueThreshold
                or data.ValueThreshold
                or data.FilteredSellValueThreshold
                or data.MinValue
                or data.MaxValue
                or "0"
            )
        )

    HOLY_SHOP_STATE.SellAllInterval =
        math.clamp(
            tonumber(data.SellAllInterval)
            or 0.10,
            0,
            5
        )

    HOLY_SHOP_STATE.FruitsAtOnce =
        HolySellReadFruitsAtOnce(
            data.FruitsAtOnce
            or 25
        )

    return true
end

--==================================================
-- [2.12] FARM / FRUIT COLLECTION CORE
--==================================================

function HolyFarmNormalizeCollectMode(value)

    local text =
        HolyCleanText(
            value
        )

    local lower =
        text:lower()

    if lower == "selected"
    or lower == "select"
    or lower == "selected plants"
    or lower == "only selected" then

        return "Selected"
    end

    return "All"
end

function HolyFarmNormalizeMutationMode(value)

    local text =
        HolyCleanText(
            value
        )

    local lower =
        text:lower()

    if lower:find("only", 1, true)
    and lower:find("mutat", 1, true) then

        return "Only Mutated"
    end

    if lower:find("only", 1, true)
    and lower:find("selected", 1, true) then

        return "Only Selected"
    end

    if lower:find("skip", 1, true)
    or lower:find("exclude", 1, true)
    or lower:find("ignore selected", 1, true) then

        return "Skip Selected"
    end

    return "Off"
end

function HolyFarmNormalizeWeightMode(value)

    local text =
        HolyCleanText(
            value
        )

    local lower =
        text:lower()

    if lower == "above"
    or lower == "over"
    or lower == "bigger"
    or lower == "bigger than"
    or lower == "greater"
    or lower == "greater than" then

        return "Above"
    end

    if lower == "below"
    or lower == "under"
    or lower == "smaller"
    or lower == "smaller than"
    or lower == "less"
    or lower == "less than" then

        return "Below"
    end

    return "Off"
end

function HolyFarmReadWeightThresholdKg(value)

    local number =
        tonumber(
            tostring(value or "0")
                :match("[%d%.]+")
        )

    return math.max(
        0,
        tonumber(number)
        or 0
    )
end

function HolyFarmFindBaseWeight(value, depth, seen)

    if type(value) ~= "table" then
        return nil
    end

    seen =
        type(seen) == "table"
        and seen
        or {}

    if seen[value] == true then
        return nil
    end

    seen[value] =
        true

    depth =
        tonumber(depth)
        or 0

    if depth > 5 then
        return nil
    end

    local direct =
        tonumber(value.BaseWeight)

    if direct ~= nil then
        return direct
    end

    if type(value.GrowData) == "table" then

        local growBase =
            tonumber(value.GrowData.BaseWeight)

        if growBase ~= nil then
            return growBase
        end
    end

    for key, child in pairs(value) do

        if type(child) == "table" then

            local found =
                HolyFarmFindBaseWeight(
                    child,
                    depth + 1,
                    seen
                )

            if found ~= nil then
                return found
            end

        elseif type(child) == "number" then

            local keyText =
                tostring(key or "")
                    :lower()

            if keyText:find("baseweight", 1, true)
            or keyText == "weight" then

                return child
            end
        end
    end

    return nil
end

function HolyFarmRequireGenerationModule(module)

    if typeof(module) ~= "Instance"
    or module:IsA("ModuleScript") ~= true then

        return nil
    end

    local ok,
        result =
        pcall(function()

            return require(
                module
            )
        end)

    if ok == true
    and type(result) == "table" then

        return result
    end

    return nil
end

function HolyFarmLoadBaseKgCache(forceRefresh)

    local runtime =
        HolyFarmEnsureRuntime()

    if forceRefresh ~= true
    and runtime.BaseKgCacheLoaded == true
    and type(runtime.BaseKgCache) == "table" then

        return runtime.BaseKgCache
    end

    local cache = {
        Fruits = {},
        Plants = {},
    }

    local plantGenerationModules =
        ReplicatedStorage:FindFirstChild("PlantGenerationModules")

    local function scanFolder(folder, targetMap)

        if typeof(folder) ~= "Instance" then
            return
        end

        for _, module in ipairs(folder:GetChildren()) do

            if module:IsA("ModuleScript") then

                local value =
                    HolyFarmRequireGenerationModule(
                        module
                    )

                local baseWeight =
                    HolyFarmFindBaseWeight(
                        value,
                        0,
                        {}
                    )

                baseWeight =
                    tonumber(baseWeight)

                if baseWeight ~= nil
                and baseWeight > 0 then

                    targetMap[module.Name] =
                        baseWeight
                end
            end
        end
    end

    scanFolder(
        plantGenerationModules
        and plantGenerationModules:FindFirstChild("Fruits"),
        cache.Fruits
    )

    scanFolder(
        plantGenerationModules
        and plantGenerationModules:FindFirstChild("Plants"),
        cache.Plants
    )

    runtime.BaseKgCache =
        cache

    runtime.BaseKgCacheLoaded =
        true

    return cache
end

function HolyFarmGetBaseKg(plantName, kind)

    plantName =
        HolyCleanText(
            plantName
        )

    if plantName == "" then
        return nil
    end

    local cache =
        HolyFarmLoadBaseKgCache(
            false
        )

    cache =
        type(cache) == "table"
        and cache
        or {}

    local fruits =
        type(cache.Fruits) == "table"
        and cache.Fruits
        or {}

    local plants =
        type(cache.Plants) == "table"
        and cache.Plants
        or {}

    if kind == "PlantHarvest" then

        return tonumber(plants[plantName])
            or tonumber(fruits[plantName])
    end

    return tonumber(fruits[plantName])
        or tonumber(plants[plantName])
end

function HolyFarmReadSizeMultiplier(instance, fallbackToOne)

    if typeof(instance) ~= "Instance" then

        return fallbackToOne == true
            and 1
            or nil
    end

    local size =
        HolyFarmReadNumberAttribute(
            instance,
            {
                "SizeMulti",
                "SizeMultiplier",
                "ScaleMultiplier",
                "ScaleMulti",
                "Scale",
                "SizeScale",
            }
        )

    if size ~= nil
    and size > 0 then

        return size
    end

    if instance:IsA("Model") then

        local ok,
            result =
            pcall(function()

                return instance:GetScale()
            end)

        result =
            tonumber(result)

        if ok == true
        and result ~= nil
        and result > 0 then

            return result
        end
    end

    return fallbackToOne == true
        and 1
        or nil
end

function HolyFarmPredictEntryWeightKg(entry)

    if type(entry) ~= "table" then
        return nil
    end

    local plantName =
        HolyCleanText(
            entry.PlantName
            or ""
        )

    if plantName == "" then

        plantName =
            HolyFarmReadPlantName(
                entry.Plant,
                entry.Fruit
            )
    end

    local baseKg =
        HolyFarmGetBaseKg(
            plantName,
            entry.Kind
        )

    if baseKg == nil then
        return nil
    end

    local sizeMulti =
        nil

    if type(entry.FruitData) == "table" then

        sizeMulti =
            tonumber(
                entry.FruitData.SizeMultiplier
                or entry.FruitData.SizeMulti
                or entry.FruitData.ScaleMultiplier
                or entry.FruitData.Scale
            )
    end

    if sizeMulti == nil
    and entry.Kind == "PlantHarvest"
    and type(entry.PlantData) == "table" then

        sizeMulti =
            tonumber(
                entry.PlantData.SizeMultiplier
                or entry.PlantData.SizeMulti
                or entry.PlantData.ScaleMultiplier
                or entry.PlantData.Scale
            )
    end

    if sizeMulti == nil then

        if entry.Kind == "PlantHarvest" then

            sizeMulti =
                HolyFarmReadSizeMultiplier(
                    entry.Plant,
                    true
                )

        else

            sizeMulti =
                HolyFarmReadSizeMultiplier(
                    entry.Fruit,
                    false
                )
        end
    end

    if sizeMulti == nil then
        return nil
    end

    return baseKg * sizeMulti,
        baseKg,
        sizeMulti
end

function HolyFarmWeightAllowsEntry(entry)

    HolyFarmEnsureState()

    local mode =
        HolyFarmNormalizeWeightMode(
            HOLY_FARM_STATE.WeightMode
            or "Off"
        )

    if mode == "Off" then
        return true
    end

    local threshold =
        HolyFarmReadWeightThresholdKg(
            HOLY_FARM_STATE.WeightThresholdKg
        )

    if threshold <= 0 then
        return true
    end

    local predictedKg =
        HolyFarmPredictEntryWeightKg(
            entry
        )

    predictedKg =
        tonumber(predictedKg)

    if predictedKg == nil then
        return false
    end

    if mode == "Above" then

        return predictedKg >= threshold
    end

    if mode == "Below" then

        return predictedKg <= threshold
    end

    return true
end

function HolyFarmSplitMutationText(value)

    local output =
        {}

    local text =
        HolyCleanText(
            value
        )

    if text == "" then
        return output
    end

    text =
        text:gsub("^%[", "")
            :gsub("%]$", "")
            :gsub("^%{", "")
            :gsub("%}$", "")

    for part in text:gmatch("[^,%|/;]+") do

        part =
            HolyCleanText(
                part
            )

        if part ~= "" then

            table.insert(
                output,
                part
            )
        end
    end

    if #output <= 0 then

        table.insert(
            output,
            text
        )
    end

    return output
end

function HolyFarmReadInstanceMutations(instance)

    local output =
        {}

    local seen =
        {}

    if typeof(instance) ~= "Instance" then
        return output
    end

    for _, attributeName in ipairs({
        "Mutation",
        "Mutations",
    }) do

        local raw =
            HolyFarmReadAttribute(
                instance,
                {
                    attributeName,
                }
            )

        for _, part in ipairs(HolyFarmSplitMutationText(raw)) do

            local mutation =
                HolyFarmNormalizeMutationName(
                    part
                )

            if mutation ~= ""
            and seen[mutation] ~= true then

                seen[mutation] =
                    true

                table.insert(
                    output,
                    mutation
                )
            end
        end
    end

    table.sort(output, function(a, b)

        return tostring(a):lower()
            < tostring(b):lower()
    end)

    return output
end

function HolyFarmReadTableMutations(data)

    local output =
        {}

    local seen =
        {}

    if type(data) ~= "table" then
        return output
    end

    local function addMutation(value)

        value =
            HolyFarmNormalizeMutationName(
                value
            )

        local lower =
            tostring(value or "")
                :lower()

        if value == ""
        or lower == "none"
        or lower == "normal"
        or lower == "off" then

            return
        end

        if seen[value] ~= true then

            seen[value] =
                true

            table.insert(
                output,
                value
            )
        end
    end

    local function readValue(value, depth)

        depth =
            tonumber(depth)
            or 0

        if depth > 3 then
            return
        end

        if type(value) == "string" then

            for _, mutation in ipairs(
                HolyFarmSplitMutationText(
                    value
                )
            ) do

                addMutation(
                    mutation
                )
            end

            return
        end

        if type(value) ~= "table" then
            return
        end

        if type(value.Name) == "string" then

            addMutation(
                value.Name
            )
        end

        if type(value.Mutation) == "string" then

            addMutation(
                value.Mutation
            )
        end

        for key, child in pairs(value) do

            if child == true
            and type(key) == "string" then

                addMutation(
                    key
                )

            elseif type(child) == "string" then

                addMutation(
                    child
                )

            elseif type(child) == "table" then

                readValue(
                    child,
                    depth + 1
                )
            end
        end
    end

    readValue(
        data.Mutations,
        0
    )

    readValue(
        data.Mutation,
        0
    )

    table.sort(output, function(a, b)

        return tostring(a):lower()
            < tostring(b):lower()
    end)

    return output
end

function HolyFarmReadEntryMutations(entry)

    if type(entry) ~= "table" then
        return {}
    end

    if type(entry.FruitData) == "table" then

        local mutations =
            HolyFarmReadTableMutations(
                entry.FruitData
            )

        if #mutations > 0 then
            return mutations
        end
    end

    if type(entry.PlantData) == "table" then

        local mutations =
            HolyFarmReadTableMutations(
                entry.PlantData
            )

        if #mutations > 0 then
            return mutations
        end
    end

    if entry.Kind == "PlantHarvest" then

        return HolyFarmReadInstanceMutations(
            entry.Plant
        )
    end

    return HolyFarmReadInstanceMutations(
        entry.Fruit
    )
end

function HolyFarmReadEntryMutation(entry)

    local mutations =
        HolyFarmReadEntryMutations(
            entry
        )

    return mutations[1]
        or ""
end

function HolyFarmMutationListHasSelected(mutations, selectedMap)

    if type(mutations) ~= "table"
    or type(selectedMap) ~= "table" then

        return false
    end

    for _, mutation in ipairs(mutations) do

        if selectedMap[mutation] == true then
            return true
        end
    end

    return false
end

function HolyFarmMutationAllowsEntry(entry)

    HolyFarmEnsureState()

    local mode =
        HolyFarmNormalizeMutationMode(
            HOLY_FARM_STATE.MutationMode
            or "Off"
        )

    if mode == "Off" then
        return true
    end

    local mutations =
        HolyFarmReadEntryMutations(
            entry
        )

    local hasMutation =
        #mutations > 0

    if mode == "Only Mutated" then

        return hasMutation == true
    end

    local selectedMap =
        HolyFarmSelectedMutationMap()

    local hasSelected =
        false

    for _ in pairs(selectedMap) do

        hasSelected =
            true

        break
    end

    if mode == "Only Selected" then

        if hasSelected ~= true then
            return false
        end

        return hasMutation == true
            and HolyFarmMutationListHasSelected(
                mutations,
                selectedMap
            ) == true
    end

    if mode == "Skip Selected" then

        if hasSelected ~= true then
            return true
        end

        if hasMutation ~= true then
            return true
        end

        return HolyFarmMutationListHasSelected(
            mutations,
            selectedMap
        ) ~= true
    end

    return true
end

function HolyFarmEnsureState()

    HOLY_FARM_STATE =
        type(HOLY_FARM_STATE) == "table"
        and HOLY_FARM_STATE
        or {}

    HOLY_FARM_STATE.CollectMode =
        HolyFarmNormalizeCollectMode(
            HOLY_FARM_STATE.CollectMode
            or "All"
        )

    HOLY_FARM_STATE.SelectedPlants =
        HolyFarmNormalizePlantSelection(
            HOLY_FARM_STATE.SelectedPlants
            or {}
        )

    HOLY_FARM_STATE.MutationMode =
        HolyFarmNormalizeMutationMode(
            HOLY_FARM_STATE.MutationMode
            or "Off"
        )

    HOLY_FARM_STATE.SelectedMutations =
        HolyFarmNormalizeMutationSelection(
            HOLY_FARM_STATE.SelectedMutations
            or {}
        )

    HOLY_FARM_STATE.WeightMode =
        HolyFarmNormalizeWeightMode(
            HOLY_FARM_STATE.WeightMode
            or "Off"
        )

    HOLY_FARM_STATE.WeightThresholdKg =
        tostring(
            HolyFarmReadWeightThresholdKg(
                HOLY_FARM_STATE.WeightThresholdKg
                or "0"
            )
        )

    HOLY_FARM_STATE.AutoCollectFruits =
        HOLY_FARM_STATE.AutoCollectFruits == true

    HOLY_FARM_STATE.ProFruitCollector =
        HOLY_FARM_STATE.ProFruitCollector == true

    HOLY_FARM_STATE.LowGardenDetail =
        HOLY_FARM_STATE.LowGardenDetail == true

    HOLY_FARM_STATE.ProCollectionDelay =
        math.clamp(
            tonumber(
                HOLY_FARM_STATE.ProCollectionDelay
            )
            or 0.05,
            0.035,
            1
        )

    return HOLY_FARM_STATE
end

function HolyFarmEnsureRuntime()

    HOLY_FARM_RUNTIME =
        type(HOLY_FARM_RUNTIME) == "table"
        and HOLY_FARM_RUNTIME
        or {}

    local state =
        HOLY_FARM_RUNTIME

    state.Connections =
        type(state.Connections) == "table"
        and state.Connections
        or {}

    state.PlantConnections =
        type(state.PlantConnections) == "table"
        and state.PlantConnections
        or {}

    state.FruitConnections =
        type(state.FruitConnections) == "table"
        and state.FruitConnections
        or {}

    state.WatchedPlants =
        type(state.WatchedPlants) == "table"
        and state.WatchedPlants
        or {}

    state.WatchedFruits =
        type(state.WatchedFruits) == "table"
        and state.WatchedFruits
        or {}

    state.ReadyQueue =
        type(state.ReadyQueue) == "table"
        and state.ReadyQueue
        or {}

    state.ReadyMap =
        type(state.ReadyMap) == "table"
        and state.ReadyMap
        or {}

    state.Pending =
        type(state.Pending) == "table"
        and state.Pending
        or {}

    state.BaseKgCache =
        type(state.BaseKgCache) == "table"
        and state.BaseKgCache
        or nil

    state.BaseKgCacheLoaded =
        state.BaseKgCacheLoaded == true

    state.PlantNameCache =
        type(state.PlantNameCache) == "table"
        and state.PlantNameCache
        or nil

    state.PlantNameCacheLoaded =
        state.PlantNameCacheLoaded == true

    state.PlantNameCacheAt =
        tonumber(state.PlantNameCacheAt)
        or 0

    state.MutationNameCache =
        type(state.MutationNameCache) == "table"
        and state.MutationNameCache
        or nil

    state.MutationNameCacheLoaded =
        state.MutationNameCacheLoaded == true

    state.MutationNameCacheAt =
        tonumber(state.MutationNameCacheAt)
        or 0

    state.StaticCachesPrimed =
        state.StaticCachesPrimed == true

    state.StaticCachesPrimedAt =
        tonumber(state.StaticCachesPrimedAt)
        or 0

    state.RebuildToken =
        tonumber(state.RebuildToken)
        or 0

    state.RebuildPending =
        state.RebuildPending == true

    state.IndexerInstalled =
        state.IndexerInstalled == true

    state.LastIndexerCheckAt =
        tonumber(state.LastIndexerCheckAt)
        or 0

    return state
end

function HolyFarmDisconnectConnectionList(list)

    if type(list) ~= "table" then
        return
    end

    for _, connection in ipairs(list) do

        if typeof(connection) == "RBXScriptConnection" then

            pcall(function()

                connection:Disconnect()
            end)
        end
    end
end

function HolyFarmDisconnectConnectionMap(map)

    if type(map) ~= "table" then
        return
    end

    for _, value in pairs(map) do

        if typeof(value) == "RBXScriptConnection" then

            pcall(function()

                value:Disconnect()
            end)

        elseif type(value) == "table" then

            HolyFarmDisconnectConnectionList(
                value
            )
        end
    end
end

function HolyFarmClearQueues()

    local runtime =
        HolyFarmEnsureRuntime()

    runtime.ReadyQueue =
        {}

    runtime.ReadyMap =
        {}

    runtime.Pending =
        {}

    return true
end

function HolyFarmDisconnectIndexer()

    local runtime =
        HolyFarmEnsureRuntime()

    HolyFarmDisconnectConnectionMap(
        runtime.Connections
    )

    HolyFarmDisconnectConnectionMap(
        runtime.PlantConnections
    )

    HolyFarmDisconnectConnectionMap(
        runtime.FruitConnections
    )

    runtime.Connections =
        {}

    runtime.PlantConnections =
        {}

    runtime.FruitConnections =
        {}

    runtime.WatchedPlants =
        {}

    runtime.WatchedFruits =
        {}

    runtime.OwnPlot =
        nil

    runtime.PlantsFolder =
        nil

    runtime.IndexerInstalled =
        false

    runtime.LastIndexerCheckAt =
        0

    runtime.RebuildToken =
        (
            tonumber(runtime.RebuildToken)
            or 0
        )
        + 1

    runtime.RebuildPending =
        false

    HolyFarmClearQueues()

    return true
end

function HolySaveFarmSettings()

    if HolyCanUseFiles() ~= true then
        return false
    end

    HolyEnsureFolder()

    HolyFarmEnsureState()

    local payload = {
        AutoCollectFruits =
            HOLY_FARM_STATE.AutoCollectFruits == true,

        ProFruitCollector =
            HOLY_FARM_STATE.ProFruitCollector == true,

        LowGardenDetail =
            HOLY_FARM_STATE.LowGardenDetail == true,

        ProCollectionDelay =
            math.clamp(
                tonumber(
                    HOLY_FARM_STATE.ProCollectionDelay
                )
                or 0.05,
                0.035,
                1
            ),

        CollectMode =
            HolyFarmNormalizeCollectMode(
                HOLY_FARM_STATE.CollectMode
            ),

        SelectedPlants =
            HolyShopSelectionArray(
                HOLY_FARM_STATE.SelectedPlants
            ),

        MutationMode =
            HolyFarmNormalizeMutationMode(
                HOLY_FARM_STATE.MutationMode
            ),

        SelectedMutations =
            HolyShopSelectionArray(
                HOLY_FARM_STATE.SelectedMutations
            ),

        WeightMode =
            HolyFarmNormalizeWeightMode(
                HOLY_FARM_STATE.WeightMode
            ),

        WeightThresholdKg =
            tostring(
                HolyFarmReadWeightThresholdKg(
                    HOLY_FARM_STATE.WeightThresholdKg
                )
            ),

        AutoTrowel =
            type(HolyAutoTrowelGetSettingsData) == "function"
            and HolyAutoTrowelGetSettingsData()
            or nil,
    }

    local encodeOk,
        encoded =
        pcall(function()

            return HttpService:JSONEncode(
                payload
            )
        end)

    if encodeOk ~= true
    or type(encoded) ~= "string" then

        return false
    end

    local writeOk =
        pcall(function()

            writefile(
                FARM_SETTINGS_FILE,
                encoded
            )
        end)

    return writeOk == true
end

function HolyLoadFarmSettings()

    if HolyCanUseFiles() ~= true then
        return false
    end

    local exists =
        false

    pcall(function()

        exists =
            isfile(
                FARM_SETTINGS_FILE
            )
    end)

    if exists ~= true then
        return false
    end

    local readOk,
        raw =
        pcall(function()

            return readfile(
                FARM_SETTINGS_FILE
            )
        end)

    if readOk ~= true
    or type(raw) ~= "string"
    or raw == "" then

        return false
    end

    local decodeOk,
        data =
        pcall(function()

            return HttpService:JSONDecode(
                raw
            )
        end)

    if decodeOk ~= true
    or type(data) ~= "table" then

        return false
    end

    HOLY_FARM_STATE.AutoCollectFruits =
        data.AutoCollectFruits == true

    HOLY_FARM_STATE.ProFruitCollector =
        data.ProFruitCollector == true

    HOLY_FARM_STATE.LowGardenDetail =
        data.LowGardenDetail == true

    HOLY_FARM_STATE.ProCollectionDelay =
        math.clamp(
            tonumber(
                data.ProCollectionDelay
            )
            or 0.05,
            0.035,
            1
        )

    if HOLY_FARM_STATE.ProFruitCollector == true then

        HOLY_FARM_STATE.AutoCollectFruits =
            false
    end

    HOLY_FARM_STATE.CollectMode =
        HolyFarmNormalizeCollectMode(
            data.CollectMode
            or "All"
        )

    HOLY_FARM_STATE.SelectedPlants =
        HolyFarmNormalizePlantSelection(
            data.SelectedPlants
        )

    HOLY_FARM_STATE.MutationMode =
        HolyFarmNormalizeMutationMode(
            data.MutationMode
            or "Off"
        )

    HOLY_FARM_STATE.SelectedMutations =
        HolyFarmNormalizeMutationSelection(
            data.SelectedMutations
            or data.Mutations
            or data.SkipMutations
        )

    HOLY_FARM_STATE.WeightMode =
        HolyFarmNormalizeWeightMode(
            data.WeightMode
            or "Off"
        )

    HOLY_FARM_STATE.WeightThresholdKg =
        tostring(
            HolyFarmReadWeightThresholdKg(
                data.WeightThresholdKg
                or data.WeightKg
                or "0"
            )
        )

    if type(HolyAutoTrowelLoadSettingsData) == "function" then

        HolyAutoTrowelLoadSettingsData(
            data.AutoTrowel
        )
    end

    return true
end

function HolyFarmPlantKey(value)

    return HolyCleanText(
        value
    )
        :lower()
        :gsub("[%s_%-%[%]%(%)%.'\"_/{}]", "")
end

function HolyFarmCleanPlantName(value)

    local text =
        HolyCleanText(
            value
        )

    if text == "" then
        return ""
    end

    if text:match("^%d+$") then
        return ""
    end

    local lower =
        text:lower()

    if lower == "partfruit"
    or lower == "gold"
    or lower == "rainbow"
    or lower == "mega"
    or lower == "huge"
    or lower == "big"
    or lower == "normal"
    or lower == "moon bloom old" then

        return ""
    end

    if lower:find("table:", 1, true) then
        return ""
    end

    if #text > 64 then
        return ""
    end

    return text
end

function HolyFarmPlantCacheAddName(cache, value)

    cache =
        type(cache) == "table"
        and cache
        or {}

    cache.Values =
        type(cache.Values) == "table"
        and cache.Values
        or {}

    cache.Map =
        type(cache.Map) == "table"
        and cache.Map
        or {}

    local plantName =
        HolyFarmCleanPlantName(
            value
        )

    if plantName == "" then
        return false
    end

    local key =
        HolyFarmPlantKey(
            plantName
        )

    if key == "" then
        return false
    end

    if cache.Map[key] ~= nil then
        return false
    end

    cache.Map[key] =
        plantName

    table.insert(
        cache.Values,
        plantName
    )

    return true
end

function HolyFarmPlantCacheSort(cache)

    cache =
        type(cache) == "table"
        and cache
        or {}

    cache.Values =
        type(cache.Values) == "table"
        and cache.Values
        or {}

    table.sort(cache.Values, function(a, b)

        return tostring(a):lower()
            < tostring(b):lower()
    end)

    return cache
end

function HolyFarmAddPlantDropdownName(values, seen, value)

    local plantName =
        HolyFarmCleanPlantName(
            value
        )

    if plantName == "" then
        return false
    end

    local key =
        HolyFarmPlantKey(
            plantName
        )

    if key == ""
    or seen[key] == true then

        return false
    end

    seen[key] =
        true

    table.insert(
        values,
        plantName
    )

    return true
end

function HolyFarmAddPlantDropdownSource(values, seen, root)

    if typeof(root) ~= "Instance" then
        return false
    end

    for _, child in ipairs(root:GetChildren()) do

        HolyFarmAddPlantDropdownName(
            values,
            seen,
            child.Name
        )
    end

    return true
end

function HolyFarmBuildPlantNameCache(forceRefresh)

    local runtime =
        HolyFarmEnsureRuntime()

    if forceRefresh ~= true
    and runtime.PlantNameCacheLoaded == true
    and type(runtime.PlantNameCache) == "table" then

        return runtime.PlantNameCache
    end

    local cache = {
        Values = {},
        Map = {},
    }

    local assets =
        ReplicatedStorage:FindFirstChild(
            "Assets"
        )

    local assetPlants =
        assets
        and assets:FindFirstChild(
            "Plants"
        )
        or nil

    if typeof(assetPlants) == "Instance" then

        for _, child in ipairs(assetPlants:GetChildren()) do

            HolyFarmPlantCacheAddName(
                cache,
                child.Name
            )
        end
    end

    local plantGenerationModules =
        ReplicatedStorage:FindFirstChild(
            "PlantGenerationModules"
        )

    local plantsFolder =
        plantGenerationModules
        and plantGenerationModules:FindFirstChild(
            "Plants"
        )
        or nil

    if typeof(plantsFolder) == "Instance" then

        for _, child in ipairs(plantsFolder:GetChildren()) do

            HolyFarmPlantCacheAddName(
                cache,
                child.Name
            )
        end
    end

    local fruitsFolder =
        plantGenerationModules
        and plantGenerationModules:FindFirstChild(
            "Fruits"
        )
        or nil

    if typeof(fruitsFolder) == "Instance" then

        for _, child in ipairs(fruitsFolder:GetChildren()) do

            HolyFarmPlantCacheAddName(
                cache,
                child.Name
            )
        end
    end

    HolyFarmPlantCacheSort(
        cache
    )

    runtime.PlantNameCache =
        cache

    runtime.PlantNameCacheLoaded =
        true

    runtime.PlantNameCacheAt =
        os.clock()

    return cache
end

function HolyFarmInvalidatePlantNameCache()

    local runtime =
        HolyFarmEnsureRuntime()

    runtime.PlantNameCache =
        nil

    runtime.PlantNameCacheLoaded =
        false

    runtime.PlantNameCacheAt =
        0

    return true
end

function HolyFarmGetPlantDropdownValues()

    local cache =
        HolyFarmBuildPlantNameCache(
            false
        )

    local values =
        {}

    for _, plantName in ipairs(
        type(cache) == "table"
        and type(cache.Values) == "table"
        and cache.Values
        or {}
    ) do

        table.insert(
            values,
            plantName
        )
    end

    return values
end

function HolyFarmGetPlantValueMap()

    local cache =
        HolyFarmBuildPlantNameCache(
            false
        )

    local map =
        {}

    if type(cache) == "table"
    and type(cache.Map) == "table" then

        for _, plantName in pairs(cache.Map) do

            map[plantName] =
                true
        end
    end

    return map
end

function HolyFarmNormalizePlantName(value)

    local text =
        HolyFarmCleanPlantName(
            value
        )

    if text == "" then
        return ""
    end

    local cache =
        HolyFarmBuildPlantNameCache(
            false
        )

    local map =
        type(cache) == "table"
        and type(cache.Map) == "table"
        and cache.Map
        or {}

    local canonical =
        map[
            HolyFarmPlantKey(
                text
            )
        ]

    if canonical ~= nil then
        return canonical
    end

    return text
end

function HolyFarmNormalizePlantSelection(value)

    local raw =
        HolyShopSelectionArray(
            value
        )

    if #raw <= 0 then
        return {}
    end

    local validMap =
        HolyFarmGetPlantValueMap()

    local output =
        {}

    local seen =
        {}

    for _, plantName in ipairs(raw) do

        plantName =
            HolyFarmNormalizePlantName(
                plantName
            )

        if plantName ~= ""
        and plantName ~= "All"
        and validMap[plantName] == true
        and seen[plantName] ~= true then

            seen[plantName] =
                true

            table.insert(
                output,
                plantName
            )
        end
    end

    table.sort(output, function(a, b)

        return tostring(a):lower()
            < tostring(b):lower()
    end)

    return output
end

function HolyFarmMutationKey(value)

    return HolyCleanText(
        value
    )
        :lower()
        :gsub("[%s_%-%[%]%(%)%.'\"_/{}]", "")
end

function HolyFarmCleanMutationName(value)

    local text =
        HolyCleanText(
            value
        )

    if text == "" then
        return ""
    end

    local lower =
        text:lower()

    if lower == "all"
    or lower == "none"
    or lower == "normal"
    or lower == "---"
    or lower == "nil"
    or lower == "false"
    or lower == "true"
    or lower == "0"
    or lower == "{}"
    or lower == "[]"
    or lower == "default" then

        return ""
    end

    if lower:find("kg", 1, true) then
        return ""
    end

    if lower:find("table:", 1, true) then
        return ""
    end

    if text:match("^%d+%.?%d*$") then
        return ""
    end

    if #text > 48 then
        return ""
    end

    return text
end

