function HolyFarmGetGardensRoot()

    local gardens =
        workspace:FindFirstChild(
            "Gardens"
        )

    if typeof(gardens) == "Instance" then
        return gardens
    end

    gardens =
        workspace:FindFirstChild(
            "Gardens",
            true
        )

    if typeof(gardens) == "Instance" then
        return gardens
    end

    return nil
end

function HolyFarmCountOwnPrefixedPlants(plantsFolder)

    if typeof(plantsFolder) ~= "Instance" then
        return 0
    end

    local prefix =
        tostring(
            LocalPlayer
            and LocalPlayer.UserId
            or ""
        )
        .. "_"

    if prefix == "_" then
        return 0
    end

    local count =
        0

    for _, plant in ipairs(plantsFolder:GetChildren()) do

        if tostring(plant.Name):sub(1, #prefix) == prefix then

            count =
                count + 1
        end
    end

    return count
end

function HolyFarmScorePlot(plot)

    if typeof(plot) ~= "Instance" then
        return 0
    end

    local score =
        0

    local localUserId =
        tostring(
            LocalPlayer
            and LocalPlayer.UserId
            or ""
        )

    local localName =
        HolyCleanText(
            LocalPlayer
            and LocalPlayer.Name
            or ""
        )

    local ownerUserId =
        nil

    pcall(function()

        ownerUserId =
            plot:GetAttribute(
                "OwnerUserId"
            )
    end)

    if ownerUserId ~= nil
    and tostring(ownerUserId) == localUserId then

        score =
            score + 1000
    end

    local owner =
        nil

    pcall(function()

        owner =
            plot:GetAttribute(
                "Owner"
            )
    end)

    owner =
        HolyCleanText(
            owner
        )

    if owner ~= ""
    and localName ~= ""
    and owner == localName then

        score =
            score + 900
    end

    local plantsFolder =
        plot:FindFirstChild(
            "Plants"
        )

    local ownPrefixCount =
        HolyFarmCountOwnPrefixedPlants(
            plantsFolder
        )

    if ownPrefixCount > 0 then

        score =
            score + 100 + math.min(
                ownPrefixCount,
                100
            )
    end

    return score
end

function HolyFarmResolveOwnPlot(forceRefresh)

    local runtime =
        HolyFarmEnsureRuntime()

    local gardens =
        HolyFarmGetGardensRoot()

    if typeof(gardens) ~= "Instance" then
        return nil
    end

    if forceRefresh ~= true
    and typeof(runtime.OwnPlot) == "Instance"
    and runtime.OwnPlot.Parent == gardens
    and HolyFarmScorePlot(runtime.OwnPlot) > 0 then

        runtime.PlantsFolder =
            runtime.OwnPlot:FindFirstChild(
                "Plants"
            )

        return runtime.OwnPlot
    end

    local bestPlot =
        nil

    local bestScore =
        0

    for _, plot in ipairs(gardens:GetChildren()) do

        local score =
            HolyFarmScorePlot(
                plot
            )

        if score > bestScore then

            bestScore =
                score

            bestPlot =
                plot
        end
    end

    if typeof(bestPlot) == "Instance"
    and bestScore > 0 then

        runtime.OwnPlot =
            bestPlot

        runtime.PlantsFolder =
            bestPlot:FindFirstChild(
                "Plants"
            )

        return bestPlot
    end

    runtime.OwnPlot =
        nil

    runtime.PlantsFolder =
        nil

    return nil
end

function HolyFarmReadAttribute(instance, names)

    if typeof(instance) ~= "Instance" then
        return ""
    end

    for _, name in ipairs(names or {}) do

        local ok,
            value =
            pcall(function()

                return instance:GetAttribute(
                    name
                )
            end)

        value =
            HolyCleanText(
                ok == true
                and value
                or ""
            )

        if value ~= "" then
            return value
        end
    end

    return ""
end

function HolyFarmReadNumberAttribute(instance, names)

    local raw =
        HolyFarmReadAttribute(
            instance,
            names
        )

    return tonumber(raw)
end

function HolyFarmReadPlantId(plant)

    local fromAttr =
        HolyFarmReadAttribute(
            plant,
            {
                "PlantId",
                "PlantID",
                "PlantUUID",
                "PlantUid",
                "UUID",
                "Uuid",
                "Id",
                "ID",
            }
        )

    if fromAttr ~= "" then
        return fromAttr
    end

    local fromName =
        tostring(
            plant
            and plant.Name
            or ""
        )

    local plantId =
        fromName:match(
            "^%d+_(.+)$"
        )

    if plantId
    and plantId ~= "" then
        return plantId
    end

    local uuid =
        fromName:match(
            "([%w]+%-%w+%-%w+%-%w+%-%w+)$"
        )

    return HolyCleanText(
        uuid
        or fromName
    )
end

function HolyFarmReadFruitId(plant, fruit)

    local fromAttr =
        HolyFarmReadAttribute(
            fruit,
            {
                "FruitId",
                "FruitID",
                "FruitUUID",
                "FruitUid",
                "UUID",
                "Uuid",
                "Id",
                "ID",
            }
        )

    if fromAttr ~= "" then
        return fromAttr
    end

    local fruitName =
        tostring(
            fruit
            and fruit.Name
            or ""
        )

    if typeof(plant) == "Instance" then

        local plantName =
            tostring(
                plant.Name
                or ""
            )

        local prefix =
            plantName
            .. "_"

        if fruitName:sub(1, #prefix) == prefix then

            return HolyCleanText(
                fruitName:sub(
                    #prefix + 1
                )
            )
        end
    end

    local uuid =
        fruitName:match(
            "([%w]+%-%w+%-%w+%-%w+%-%w+)$"
        )

    return HolyCleanText(
        uuid
        or fruitName
    )
end

function HolyFarmReadPlantName(plant, fruit)

    local plantName =
        HolyFarmReadAttribute(
            plant,
            {
                "SeedName",
                "PlantName",
                "CropName",
                "FruitName",
                "DisplayName",
                "ItemName",
                "Name",
            }
        )

    if plantName ~= "" then
        return plantName
    end

    plantName =
        HolyFarmReadAttribute(
            fruit,
            {
                "CorePartName",
                "FruitName",
                "SeedName",
                "PlantName",
                "CropName",
                "DisplayName",
                "ItemName",
                "Name",
            }
        )

    if plantName ~= "" then
        return plantName
    end

    return "Unknown"
end

function HolyFarmFindHarvestPrompt(fruit)

    if typeof(fruit) ~= "Instance" then
        return nil
    end

    local harvestPart =
        fruit:FindFirstChild(
            "HarvestPart"
        )

    if harvestPart then

        local prompt =
            harvestPart:FindFirstChildWhichIsA(
                "ProximityPrompt",
                true
            )

        if prompt then
            return prompt
        end
    end

    return fruit:FindFirstChildWhichIsA(
        "ProximityPrompt",
        true
    )
end

function HolyFarmReadBooleanAttribute(instance, names)

    if typeof(instance) ~= "Instance" then
        return nil
    end

    for _, name in ipairs(names or {}) do

        local ok,
            value =
            pcall(function()

                return instance:GetAttribute(
                    name
                )
            end)

        if ok == true
        and value ~= nil then

            if value == true then
                return true
            end

            if value == false then
                return false
            end

            local text =
                tostring(value)
                    :lower()

            if text == "true"
            or text == "1"
            or text == "yes"
            or text == "ready"
            or text == "harvestable" then

                return true
            end

            if text == "false"
            or text == "0"
            or text == "no" then

                return false
            end
        end
    end

    return nil
end

function HolyFarmPromptUnderFruits(prompt, plant)

    if typeof(prompt) ~= "Instance"
    or typeof(plant) ~= "Instance" then

        return false
    end

    local current =
        prompt.Parent

    while current
    and current ~= plant do

        if current.Name == "Fruits" then
            return true
        end

        current =
            current.Parent
    end

    return false
end

function HolyFarmFindPlantHarvestPrompt(plant)

    if typeof(plant) ~= "Instance" then
        return nil
    end

    local prompt =
        HolyFarmFindHarvestPrompt(
            plant
        )

    if typeof(prompt) == "Instance"
    and prompt:IsA("ProximityPrompt")
    and HolyFarmPromptUnderFruits(
        prompt,
        plant
    ) ~= true then

        return prompt
    end

    return nil
end

function HolyFarmPlantHasFruitsFolder(plant)

    if typeof(plant) ~= "Instance" then
        return false
    end

    local fruitsFolder =
        plant:FindFirstChild(
            "Fruits"
        )

    return typeof(fruitsFolder) == "Instance"
end

function HolyFarmInstanceReady(instance)

    if typeof(instance) ~= "Instance"
    or instance.Parent == nil then

        return false
    end

    local age =
        HolyFarmReadNumberAttribute(
            instance,
            {
                "Age",
                "Growth",
                "GrowAge",
                "CurrentAge",
            }
        )

    local maxAge =
        HolyFarmReadNumberAttribute(
            instance,
            {
                "MaxAge",
                "MaxGrowth",
                "GrowTime",
                "GrowthTime",
                "RequiredAge",
            }
        )

    if age ~= nil
    and maxAge ~= nil then

        return age >= maxAge
    end

    local ready =
        HolyFarmReadBooleanAttribute(
            instance,
            {
                "PlantGrowthReady",
                "Ready",
                "IsReady",
                "Harvestable",
                "CanHarvest",
                "Grown",
                "FullyGrown",
                "Ripe",
            }
        )

    if ready == true then
        return true
    end

    return false
end

function HolyFarmFruitReady(fruit)

    if HolyFarmInstanceReady(
        fruit
    ) == true then

        return true
    end

    local prompt =
        HolyFarmFindHarvestPrompt(
            fruit
        )

    if typeof(prompt) == "Instance"
    and prompt:IsA("ProximityPrompt") then

        return prompt.Enabled == true
    end

    return false
end

function HolyFarmPlantLevelHarvestReady(plant)

    if typeof(plant) ~= "Instance"
    or plant.Parent == nil then

        return false
    end

    if HolyFarmPlantHasFruitsFolder(
        plant
    ) == true then

        return false
    end

    if HolyFarmInstanceReady(
        plant
    ) == true then

        return true
    end

    local prompt =
        HolyFarmFindPlantHarvestPrompt(
            plant
        )

    if typeof(prompt) == "Instance"
    and prompt:IsA("ProximityPrompt") then

        return prompt.Enabled == true
    end

    return false
end

function HolyFarmBuildFruitKey(plantId, fruitId)

    plantId =
        HolyCleanText(
            plantId
        )

    fruitId =
        HolyCleanText(
            fruitId
        )

    if plantId == ""
    or fruitId == "" then

        return ""
    end

    return plantId
        .. ":"
        .. fruitId
end

function HolyFarmBuildPlantHarvestKey(plantId)

    plantId =
        HolyCleanText(
            plantId
        )

    if plantId == "" then
        return ""
    end

    return plantId
        .. ":__PLANT_HARVEST__"
end

function HolyFarmResolveCollectFruitPacket(forceRefresh)

    local runtime =
        HolyFarmEnsureRuntime()

    if forceRefresh ~= true
    and type(runtime.CollectFruitPacket) == "table"
    and type(runtime.CollectFruitPacket.Fire) == "function" then

        return runtime.CollectFruitPacket,
            "cached"
    end

    runtime.CollectFruitPacket =
        nil

    local networking =
        nil

    if type(HolyShopRequireModule) == "function" then

        networking =
            HolyShopRequireModule(
                "SharedModules.Networking"
            )
    end

    if type(networking) ~= "table" then

        local module =
            ReplicatedStorage:FindFirstChild("SharedModules")
            and ReplicatedStorage.SharedModules:FindFirstChild("Networking")

        if typeof(module) == "Instance"
        and module:IsA("ModuleScript") == true then

            local ok,
                result =
                pcall(function()

                    return require(
                        module
                    )
                end)

            if ok == true
            and type(result) == "table" then

                networking =
                    result
            end
        end
    end

    local packet =
        type(networking) == "table"
        and type(networking.Garden) == "table"
        and networking.Garden.CollectFruit
        or nil

    if type(packet) ~= "table"
    or type(packet.Fire) ~= "function" then

        return nil,
            "Networking.Garden.CollectFruit missing"
    end

    runtime.CollectFruitPacket =
        packet

    return packet,
        "ok"
end

function HolyFarmPrimeStaticCaches(forceRefresh)

    local runtime =
        HolyFarmEnsureRuntime()

    if forceRefresh ~= true
    and runtime.StaticCachesPrimed == true then

        return true
    end

    pcall(function()

        HolyFarmBuildPlantNameCache(
            forceRefresh == true
        )
    end)

    pcall(function()

        HolyFarmBuildMutationNameCache(
            forceRefresh == true
        )
    end)

    pcall(function()

        HolyFarmLoadBaseKgCache(
            forceRefresh == true
        )
    end)

    pcall(function()

        HolyFarmResolveCollectFruitPacket(
            forceRefresh == true
        )
    end)

    pcall(function()

        HolyFarmResolveOwnPlot(
            forceRefresh == true
        )
    end)

    runtime.StaticCachesPrimed =
        true

    runtime.StaticCachesPrimedAt =
        os.clock()

    return true
end

function HolyFarmIndexerReady()

    local runtime =
        HolyFarmEnsureRuntime()

    return runtime.IndexerInstalled == true
        and typeof(runtime.OwnPlot) == "Instance"
        and runtime.OwnPlot.Parent ~= nil
        and typeof(runtime.PlantsFolder) == "Instance"
        and runtime.PlantsFolder.Parent ~= nil
end

function HolyFarmQueueFruit(plant, fruit, reason)

    local runtime =
        HolyFarmEnsureRuntime()

    if typeof(plant) ~= "Instance"
    or typeof(fruit) ~= "Instance"
    or fruit.Parent == nil then

        return false
    end

    if HolyFarmFruitReady(fruit) ~= true then
        return false
    end

    local plantName =
        HolyFarmReadPlantName(
            plant,
            fruit
        )

    if HolyFarmSelectionAllowsPlant(plantName) ~= true then
        return false
    end

    local plantId =
        HolyFarmReadPlantId(
            plant
        )

    local fruitId =
        HolyFarmReadFruitId(
            plant,
            fruit
        )

    local key =
        HolyFarmBuildFruitKey(
            plantId,
            fruitId
        )

    if key == "" then
        return false
    end

    local entry = {
        Key =
            key,

        Kind =
            "FruitHarvest",

        Plant =
            plant,

        Fruit =
            fruit,

        PlantName =
            plantName,

        PlantId =
            plantId,

        FruitId =
            fruitId,

        QueuedAt =
            os.clock(),

        Reason =
            tostring(reason or "ready"),
    }

    if HolyFarmMutationAllowsEntry(entry) ~= true then
        return false
    end

    if HolyFarmWeightAllowsEntry(entry) ~= true then
        return false
    end

    if runtime.Pending[key] ~= nil
    or runtime.ReadyMap[key] == true then

        return false
    end

    runtime.ReadyMap[key] =
        true

    table.insert(
        runtime.ReadyQueue,
        entry
    )

    return true
end

function HolyFarmQueuePlantHarvest(plant, reason)

    local runtime =
        HolyFarmEnsureRuntime()

    if typeof(plant) ~= "Instance"
    or plant.Parent == nil then

        return false
    end

    if HolyFarmPlantLevelHarvestReady(
        plant
    ) ~= true then

        return false
    end

    local plantName =
        HolyFarmReadPlantName(
            plant,
            nil
        )

    if HolyFarmSelectionAllowsPlant(
        plantName
    ) ~= true then

        return false
    end

    local plantId =
        HolyFarmReadPlantId(
            plant
        )

    local key =
        HolyFarmBuildPlantHarvestKey(
            plantId
        )

    if key == "" then
        return false
    end

    local entry = {
        Key =
            key,

        Kind =
            "PlantHarvest",

        Plant =
            plant,

        Fruit =
            plant,

        PlantName =
            plantName,

        PlantId =
            plantId,

        FruitId =
            "",

        QueuedAt =
            os.clock(),

        Reason =
            tostring(reason or "plant ready"),
    }

    if HolyFarmMutationAllowsEntry(entry) ~= true then
        return false
    end

    if HolyFarmWeightAllowsEntry(entry) ~= true then
        return false
    end

    if runtime.Pending[key] ~= nil
    or runtime.ReadyMap[key] == true then

        return false
    end

    runtime.ReadyMap[key] =
        true

    table.insert(
        runtime.ReadyQueue,
        entry
    )

    return true
end

function HolyFarmRetryEntry(entry, reason)

    if type(entry) ~= "table" then
        return false
    end

    if entry.Kind == "PlantHarvest" then

        return HolyFarmQueuePlantHarvest(
            entry.Plant,
            reason or "retry plant"
        )
    end

    return HolyFarmQueueFruit(
        entry.Plant,
        entry.Fruit,
        reason or "retry fruit"
    )
end

function HolyFarmUnwatchFruit(fruit)

    local runtime =
        HolyFarmEnsureRuntime()

    local connections =
        runtime.FruitConnections[fruit]

    HolyFarmDisconnectConnectionList(
        connections
    )

    runtime.FruitConnections[fruit] =
        nil

    runtime.WatchedFruits[fruit] =
        nil

    return true
end

function HolyFarmWatchFruit(plant, fruit)

    local runtime =
        HolyFarmEnsureRuntime()

    if typeof(plant) ~= "Instance"
    or typeof(fruit) ~= "Instance" then

        return false
    end

    if runtime.WatchedFruits[fruit] == true then

        HolyFarmQueueFruit(
            plant,
            fruit,
            "refresh"
        )

        return true
    end

    runtime.WatchedFruits[fruit] =
        true

    runtime.FruitConnections[fruit] =
        {}

    local function refreshFruit()

        task.defer(function()

            if HOLY_FARM_STATE.AutoCollectFruits == true then

                HolyFarmQueueFruit(
                    plant,
                    fruit,
                    "changed"
                )
            end
        end)
    end

    for _, attributeName in ipairs({
        "Age",
        "MaxAge",
        "Mutation",
        "Mutations",
        "SizeMulti",
        "SizeMultiplier",
        "ScaleMultiplier",
        "ScaleMulti",
        "Scale",
        "SizeScale",
    }) do

        local ok,
            signal =
            pcall(function()

                return fruit:GetAttributeChangedSignal(
                    attributeName
                )
            end)

        if ok == true
        and signal then

            table.insert(
                runtime.FruitConnections[fruit],
                signal:Connect(
                    refreshFruit
                )
            )
        end
    end

    table.insert(
        runtime.FruitConnections[fruit],
        fruit.AncestryChanged:Connect(function(_, parent)

            if parent == nil then

                local plantId =
                    HolyFarmReadPlantId(
                        plant
                    )

                local fruitId =
                    HolyFarmReadFruitId(
                        plant,
                        fruit
                    )

                local key =
                    HolyFarmBuildFruitKey(
                        plantId,
                        fruitId
                    )

                if key ~= "" then

                    runtime.ReadyMap[key] =
                        nil

                    runtime.Pending[key] =
                        nil
                end

                HolyFarmUnwatchFruit(
                    fruit
                )
            end
        end)
    )

    HolyFarmQueueFruit(
        plant,
        fruit,
        "initial"
    )

    return true
end

function HolyFarmUnwatchPlant(plant)

    local runtime =
        HolyFarmEnsureRuntime()

    if typeof(plant) == "Instance" then

        local plantId =
            HolyFarmReadPlantId(
                plant
            )

        local plantKey =
            HolyFarmBuildPlantHarvestKey(
                plantId
            )

        if plantKey ~= "" then

            runtime.ReadyMap[plantKey] =
                nil

            runtime.Pending[plantKey] =
                nil
        end
    end

    HolyFarmDisconnectConnectionList(
        runtime.PlantConnections[plant]
    )

    runtime.PlantConnections[plant] =
        nil

    runtime.WatchedPlants[plant] =
        nil

    return true
end

function HolyFarmWatchPlant(plant)

    local runtime =
        HolyFarmEnsureRuntime()

    if typeof(plant) ~= "Instance" then
        return false
    end

    if runtime.WatchedPlants[plant] == true then

        HolyFarmQueuePlantHarvest(
            plant,
            "plant refresh"
        )

        return true
    end

    runtime.WatchedPlants[plant] =
        true

    runtime.PlantConnections[plant] =
        {}

    local plantPromptConnected =
        false

    local function refreshPlantHarvest()

        task.defer(function()

            if HOLY_FARM_STATE.AutoCollectFruits == true then

                HolyFarmQueuePlantHarvest(
                    plant,
                    "plant changed"
                )
            end
        end)
    end

    local function connectPlantHarvestPrompt()

        if plantPromptConnected == true then
            return false
        end

        local prompt =
            HolyFarmFindPlantHarvestPrompt(
                plant
            )

        if typeof(prompt) ~= "Instance"
        or prompt:IsA("ProximityPrompt") ~= true then

            return false
        end

        plantPromptConnected =
            true

        table.insert(
            runtime.PlantConnections[plant],
            prompt:GetPropertyChangedSignal("Enabled"):Connect(
                refreshPlantHarvest
            )
        )

        return true
    end

    for _, attributeName in ipairs({
        "Age",
        "MaxAge",
        "Mutation",
        "Mutations",
        "PlantGrowthReady",
        "Ready",
        "IsReady",
        "Harvestable",
        "CanHarvest",
        "Grown",
        "FullyGrown",
        "Ripe",
        "SizeMulti",
        "SizeMultiplier",
        "ScaleMultiplier",
        "ScaleMulti",
        "Scale",
        "SizeScale",
    }) do

        local ok,
            signal =
            pcall(function()

                return plant:GetAttributeChangedSignal(
                    attributeName
                )
            end)

        if ok == true
        and signal then

            table.insert(
                runtime.PlantConnections[plant],
                signal:Connect(
                    refreshPlantHarvest
                )
            )
        end
    end

    local function attachFruitsFolder(fruitsFolder)

        if typeof(fruitsFolder) ~= "Instance" then
            return false
        end

        for _, fruit in ipairs(fruitsFolder:GetChildren()) do

            HolyFarmWatchFruit(
                plant,
                fruit
            )
        end

        table.insert(
            runtime.PlantConnections[plant],
            fruitsFolder.ChildAdded:Connect(function(fruit)

                task.defer(function()

                    HolyFarmWatchFruit(
                        plant,
                        fruit
                    )
                end)
            end)
        )

        table.insert(
            runtime.PlantConnections[plant],
            fruitsFolder.ChildRemoved:Connect(function(fruit)

                local plantId =
                    HolyFarmReadPlantId(
                        plant
                    )

                local fruitId =
                    HolyFarmReadFruitId(
                        plant,
                        fruit
                    )

                local key =
                    HolyFarmBuildFruitKey(
                        plantId,
                        fruitId
                    )

                if key ~= "" then

                    runtime.ReadyMap[key] =
                        nil

                    runtime.Pending[key] =
                        nil
                end

                HolyFarmUnwatchFruit(
                    fruit
                )
            end)
        )

        return true
    end

    attachFruitsFolder(
        plant:FindFirstChild(
            "Fruits"
        )
    )

    connectPlantHarvestPrompt()

    HolyFarmQueuePlantHarvest(
        plant,
        "initial plant"
    )

    table.insert(
        runtime.PlantConnections[plant],
        plant.ChildAdded:Connect(function(child)

            if child.Name == "Fruits" then

                task.defer(function()

                    attachFruitsFolder(
                        child
                    )
                end)

            elseif child.Name == "HarvestPart" then

                task.defer(function()

                    connectPlantHarvestPrompt()

                    refreshPlantHarvest()
                end)
            end
        end)
    )

    table.insert(
        runtime.PlantConnections[plant],
        plant.AncestryChanged:Connect(function(_, parent)

            if parent == nil then

                HolyFarmUnwatchPlant(
                    plant
                )
            end
        end)
    )

    return true
end

function HolyFarmInstallIndexer(forceRefresh)

    local runtime =
        HolyFarmEnsureRuntime()

    local plot =
        HolyFarmResolveOwnPlot(
            forceRefresh == true
        )

    if typeof(plot) ~= "Instance" then
        return false, "own plot missing"
    end

    local plantsFolder =
        plot:FindFirstChild(
            "Plants"
        )

    if typeof(plantsFolder) ~= "Instance" then
        return false, "plants folder missing"
    end

    if forceRefresh ~= true
    and runtime.PlantsFolder == plantsFolder
    and runtime.IndexerInstalled == true then

        return true, "cached"
    end

    HolyFarmDisconnectConnectionMap(
        runtime.Connections
    )

    HolyFarmDisconnectConnectionMap(
        runtime.PlantConnections
    )

    HolyFarmDisconnectConnectionMap(
        runtime.FruitConnections
    )

    runtime.Connections =
        {}

    runtime.PlantConnections =
        {}

    runtime.FruitConnections =
        {}

    runtime.WatchedPlants =
        {}

    runtime.WatchedFruits =
        {}

    runtime.ReadyQueue =
        {}

    runtime.ReadyMap =
        {}

    runtime.Pending =
        {}

    runtime.OwnPlot =
        plot

    runtime.PlantsFolder =
        plantsFolder

    runtime.IndexerInstalled =
        true

    for _, plant in ipairs(plantsFolder:GetChildren()) do

        HolyFarmWatchPlant(
            plant
        )
    end

    table.insert(
        runtime.Connections,
        plantsFolder.ChildAdded:Connect(function(plant)

            task.defer(function()

                HolyFarmWatchPlant(
                    plant
                )
            end)
        end)
    )

    table.insert(
        runtime.Connections,
        plantsFolder.ChildRemoved:Connect(function(plant)

            HolyFarmUnwatchPlant(
                plant
            )
        end)
    )

    return true, "ok"
end

function HolyFarmRebuildReadyQueue(reason)

    local runtime =
        HolyFarmEnsureRuntime()

    runtime.ReadyQueue =
        {}

    runtime.ReadyMap =
        {}

    runtime.Pending =
        {}

    if typeof(runtime.PlantsFolder) ~= "Instance"
    or runtime.PlantsFolder.Parent == nil then

        return false
    end

    for _, plant in ipairs(runtime.PlantsFolder:GetChildren()) do

        HolyFarmWatchPlant(
            plant
        )

        local fruitsFolder =
            plant:FindFirstChild(
                "Fruits"
            )

        if typeof(fruitsFolder) == "Instance" then

            for _, fruit in ipairs(fruitsFolder:GetChildren()) do

                HolyFarmQueueFruit(
                    plant,
                    fruit,
                    reason or "rebuild"
                )
            end

        else

            HolyFarmQueuePlantHarvest(
                plant,
                reason or "rebuild plant"
            )
        end
    end

    return true
end

function HolyFarmCollectEntry(entry)

    local runtime =
        HolyFarmEnsureRuntime()

    if type(entry) ~= "table" then
        return false
    end

    if typeof(entry.Plant) ~= "Instance"
    or entry.Plant.Parent == nil then

        return false
    end

    local key =
        ""

    if entry.Kind == "PlantHarvest" then

        if HolyFarmPlantLevelHarvestReady(
            entry.Plant
        ) ~= true then

            return false
        end

        key =
            HolyFarmBuildPlantHarvestKey(
                entry.PlantId
            )

    else

        if typeof(entry.Fruit) ~= "Instance"
        or entry.Fruit.Parent == nil then

            return false
        end

        if HolyFarmFruitReady(
            entry.Fruit
        ) ~= true then

            return false
        end

        key =
            HolyFarmBuildFruitKey(
                entry.PlantId,
                entry.FruitId
            )
    end

    if HolyFarmSelectionAllowsPlant(entry.PlantName) ~= true then
        return false
    end

    if HolyFarmMutationAllowsEntry(entry) ~= true then
        return false
    end

    if HolyFarmWeightAllowsEntry(entry) ~= true then
        return false
    end

    if key == "" then
        return false
    end

    entry.Key =
        key

    if runtime.Pending[key] ~= nil then
        return false
    end

    local packet,
        packetReason =
        HolyFarmResolveCollectFruitPacket(
            false
        )

    if type(packet) ~= "table" then

        local now =
            os.clock()

        if now - (
            tonumber(runtime.LastPacketWarnAt)
            or 0
        ) > 5 then

            runtime.LastPacketWarnAt =
                now

            if type(HolyNotify) == "function" then

                HolyNotify(
                    "HOLY Farm",
                    tostring(packetReason or "CollectFruit packet missing."),
                    4
                )
            end
        end

        return false
    end

    runtime.Pending[key] = {
        At =
            os.clock(),

        Entry =
            entry,
    }

    local ok,
        result =
        pcall(function()

            if entry.Kind == "PlantHarvest" then

                return packet:Fire(
                    entry.PlantId,
                    ""
                )
            end

            return packet:Fire(
                entry.PlantId,
                entry.FruitId
            )
        end)

    if ok ~= true then

        runtime.Pending[key] =
            nil

        task.delay(0.35, function()

            if HOLY_FARM_STATE.AutoCollectFruits == true then

                HolyFarmRetryEntry(
                    entry,
                    "retry"
                )
            end
        end)

        return false,
            tostring(result)
    end

    return true
end

function HolyFarmPrunePending()

    local runtime =
        HolyFarmEnsureRuntime()

    local now =
        os.clock()

    for key, row in pairs(runtime.Pending) do

        local entry =
            type(row) == "table"
            and row.Entry
            or nil

        local at =
            type(row) == "table"
            and tonumber(row.At)
            or 0

        local missing =
            false

        if type(entry) ~= "table" then

            missing =
                true

        elseif entry.Kind == "PlantHarvest" then

            missing =
                typeof(entry.Plant) ~= "Instance"
                or entry.Plant.Parent == nil

        else

            missing =
                typeof(entry.Fruit) ~= "Instance"
                or entry.Fruit.Parent == nil
        end

        if missing == true then

            runtime.Pending[key] =
                nil

            runtime.ReadyMap[key] =
                nil

        elseif now - at >= 3 then

            runtime.Pending[key] =
                nil

            HolyFarmRetryEntry(
                entry,
                "pending retry"
            )
        end
    end
end

function HolyFarmAutoCollectBlocked()

    if type(HOLY_DEFENSE_RUNTIME) == "table"
    and HOLY_DEFENSE_RUNTIME.Active == true then

        return true
    end

    local sniper =
        type(HOLY_SNIPER_RUNTIME) == "table"
        and HOLY_SNIPER_RUNTIME
        or {}

    if sniper.Buying == true
    or sniper.Returning == true
    or sniper.AutoHopInProgress == true
    or sniper.CurrentTarget ~= nil
    or HolyCleanText(sniper.CurrentTargetKey) ~= "" then

        return true
    end

    return false
end

function HolyFarmRunAutoCollectWorker(token)

    local runtime =
        HolyFarmEnsureRuntime()

    runtime.Running =
        true

    runtime.LastIndexerCheckAt =
        0

    while runtime.Token == token
    and HOLY_FARM_STATE.AutoCollectFruits == true do

        if HolyFarmAutoCollectBlocked() == true then

            task.wait(
                0.20
            )

            continue
        end

        local now =
            os.clock()

        if HolyFarmIndexerReady() ~= true
        or now - (
            tonumber(runtime.LastIndexerCheckAt)
            or 0
        ) >= 5 then

            runtime.LastIndexerCheckAt =
                now

            local installed =
                HolyFarmInstallIndexer(
                    false
                )

            if installed ~= true then

                if now - (
                    tonumber(runtime.LastPlotWarnAt)
                    or 0
                ) > 8 then

                    runtime.LastPlotWarnAt =
                        now

                    print(
                        "[HOLY FARM]",
                        "Waiting for own plot / Plants folder."
                    )
                end

                task.wait(
                    0.75
                )

                continue
            end
        end

        HolyFarmPrunePending()

        local entry =
            table.remove(
                runtime.ReadyQueue,
                1
            )

        if type(entry) == "table" then

            runtime.ReadyMap[entry.Key] =
                nil

            HolyFarmCollectEntry(
                entry
            )

            task.wait(
                0.045
            )

        else

            task.wait(
                0.20
            )
        end
    end

    if runtime.Token == token then

        runtime.Running =
            false
    end
end

function HolyFarmStartAutoCollect(reason)

    HolyFarmEnsureState()

    if HOLY_FARM_STATE.AutoCollectFruits ~= true then
        return false
    end

    local runtime =
        HolyFarmEnsureRuntime()

    if runtime.Running == true then
        return false
    end

    HolyFarmPrimeStaticCaches(
        false
    )

    runtime.Token =
        {}

    local token =
        runtime.Token

    local installed =
        HolyFarmInstallIndexer(
            false
        )

    if installed == true then

        HolyFarmRebuildReadyQueue(
            reason or "start"
        )
    end

    task.spawn(function()

        HolyFarmRunAutoCollectWorker(
            token
        )
    end)

    return true
end

function HolyFarmStopAutoCollect(reason)

    local runtime =
        HolyFarmEnsureRuntime()

    runtime.Token =
        nil

    runtime.Running =
        false

    HolyFarmDisconnectIndexer()

    return true
end

function HolyProFarmEnsureRuntime()

    HOLY_PRO_FARM_RUNTIME =
        type(HOLY_PRO_FARM_RUNTIME) == "table"
        and HOLY_PRO_FARM_RUNTIME
        or {}

    local runtime =
        HOLY_PRO_FARM_RUNTIME

    runtime.Connections =
        type(runtime.Connections) == "table"
        and runtime.Connections
        or {}

    runtime.VisualConnections =
        type(runtime.VisualConnections) == "table"
        and runtime.VisualConnections
        or {}

    runtime.Cache =
        type(runtime.Cache) == "table"
        and runtime.Cache
        or {
            Plants = {},
        }

    runtime.Cache.Plants =
        type(runtime.Cache.Plants) == "table"
        and runtime.Cache.Plants
        or {}

    runtime.Cooldowns =
        type(runtime.Cooldowns) == "table"
        and runtime.Cooldowns
        or {}

    runtime.Pending =
        type(runtime.Pending) == "table"
        and runtime.Pending
        or {}

    runtime.NextSendAt =
        tonumber(runtime.NextSendAt)
        or 0

    runtime.MaxPending =
        math.clamp(
            math.floor(
                tonumber(runtime.MaxPending)
                or 10
            ),
            1,
            25
        )

    runtime.ConfirmationTimeout =
        math.clamp(
            tonumber(runtime.ConfirmationTimeout)
            or 2.5,
            0.5,
            10
        )

    runtime.RetryDelay =
        math.clamp(
            tonumber(runtime.RetryDelay)
            or 0.75,
            0,
            5
        )

    runtime.Status =
        tostring(
            runtime.Status
            or "Disabled"
        )

    return runtime
end

function HolyProFarmDisconnectList(list)

    if type(list) ~= "table" then
        return
    end

    for _, connection in pairs(list) do

        if connection
        and type(connection.Disconnect) == "function" then

            pcall(function()

                connection:Disconnect()
            end)
        end
    end

    table.clear(
        list
    )
end

function HolyProFarmSetStatus(status)

    local runtime =
        HolyProFarmEnsureRuntime()

    runtime.Status =
        tostring(
            status
            or "Ready"
        )

    if type(HolyProFarmRefreshUI) == "function" then

        HolyProFarmRefreshUI()
    end

    return runtime.Status
end

function HolyProFarmCurrentAge(data)

    if type(data) ~= "table" then
        return 0
    end

    local age =
        tonumber(
            data.Age
            or data.CurrentAge
        )
        or 0

    local maxAge =
        tonumber(
            data.MaxAge
        )

    local lastClock =
        tonumber(
            data._HolyLastClock
        )

    local growthRate =
        tonumber(
            data.GrowRate
            or data.GrowthRate
            or data.StableGrowthAmount
        )
        or 0

    if lastClock ~= nil
    and growthRate > 0 then

        age +=
            math.max(
                0,
                os.clock() - lastClock
            )
            * growthRate
    end

    if maxAge ~= nil
    and maxAge > 0 then

        age =
            math.min(
                age,
                maxAge
            )
    end

    return age
end

function HolyProFarmDataReady(data)

    if type(data) ~= "table" then
        return false
    end

    local maxAge =
        tonumber(
            data.MaxAge
        )
        or 0

    if maxAge <= 0 then
        return false
    end

    return HolyProFarmCurrentAge(data)
        >= maxAge - 0.01
end

function HolyProFarmPrepareFruit(fruitData)

    if type(fruitData) ~= "table" then
        return
    end

    fruitData._HolyLastClock =
        os.clock()
end

function HolyProFarmPreparePlant(plantData)

    if type(plantData) ~= "table" then
        return
    end

    plantData._HolyLastClock =
        os.clock()

    plantData.Fruits =
        type(plantData.Fruits) == "table"
        and plantData.Fruits
        or {}

    for _, fruitData in pairs(plantData.Fruits) do

        HolyProFarmPrepareFruit(
            fruitData
        )
    end
end

function HolyProFarmPrepareCache()

    local runtime =
        HolyProFarmEnsureRuntime()

    for _, plantData in pairs(runtime.Cache.Plants) do

        HolyProFarmPreparePlant(
            plantData
        )
    end
end

function HolyProFarmCountCache()

    local runtime =
        HolyProFarmEnsureRuntime()

    local plants =
        0

    local fruits =
        0

    local ready =
        0

    for _, plantData in pairs(runtime.Cache.Plants) do

        if type(plantData) == "table" then

            plants +=
                1

            local fruitCount =
                0

            if type(plantData.Fruits) == "table" then

                for _, fruitData in pairs(plantData.Fruits) do

                    if type(fruitData) == "table" then

                        fruitCount +=
                            1

                        fruits +=
                            1

                        if HolyProFarmDataReady(
                            fruitData
                        ) then

                            ready +=
                                1
                        end
                    end
                end
            end

            if fruitCount == 0
            and (
                tonumber(
                    plantData.MaxFruitSpawnLocations
                )
                or 0
            ) <= 0
            and HolyProFarmDataReady(
                plantData
            ) then

                ready +=
                    1
            end
        end
    end

    return plants,
        fruits,
        ready
end

function HolyProFarmBuildStatusText()

    local runtime =
        HolyProFarmEnsureRuntime()

    local plants,
        fruits,
        ready =
        HolyProFarmCountCache()

    local text =
        "Status: "
        .. tostring(
            runtime.Status
            or "Disabled"
        )

    if runtime.SnapshotReady == true then

        text ..=
            "\n"
            .. tostring(ready)
            .. " ready • "
            .. tostring(fruits)
            .. " fruits • "
            .. tostring(plants)
            .. " plants"
    end

    return text
end

function HolyProFarmRefreshUI()

    HOLY_FARM_UI =
        type(HOLY_FARM_UI) == "table"
        and HOLY_FARM_UI
        or {}

    local label =
        HOLY_FARM_UI.ProStatusLabel

    local text =
        HolyProFarmBuildStatusText()

    if type(HolySniperSetLabel) == "function" then

        HolySniperSetLabel(
            label,
            text
        )

        return true
    end

    if type(label) == "table"
    and type(label.SetText) == "function" then

        pcall(function()

            label:SetText(
                text
            )
        end)

        return true
    end

    return false
end

function HolyProFarmGetNetworking()

    local runtime =
        HolyProFarmEnsureRuntime()

    if type(runtime.Networking) == "table"
    and type(runtime.GardenNetworking) == "table" then

        return runtime.Networking,
            runtime.GardenNetworking
    end

    local networking =
        nil

    if type(HolyShopRequireModule) == "function" then

        networking =
            HolyShopRequireModule(
                "SharedModules.Networking"
            )
    end

    if type(networking) ~= "table" then

        local sharedModules =
            ReplicatedStorage:FindFirstChild(
                "SharedModules"
            )

        local module =
            sharedModules
            and sharedModules:FindFirstChild(
                "Networking"
            )

        if typeof(module) == "Instance"
        and module:IsA("ModuleScript") then

            local ok,
                result =
                pcall(function()

                    return require(
                        module
                    )
                end)

            if ok == true
            and type(result) == "table" then

                networking =
                    result
            end
        end
    end

    local garden =
        type(networking) == "table"
        and type(networking.Garden) == "table"
        and networking.Garden
        or nil

    runtime.Networking =
        networking

    runtime.GardenNetworking =
        garden

    runtime.RequestPacket =
        type(garden) == "table"
        and garden.RequestGardens
        or nil

    runtime.SnapshotPacket =
        type(garden) == "table"
        and garden.SyncAllGardens
        or nil

    runtime.CollectPacket =
        type(garden) == "table"
        and garden.CollectFruit
        or nil

    return networking,
        garden
end

function HolyProFarmOwnerMatches(owner)

    return tostring(owner or "")
        == tostring(
            LocalPlayer.UserId
        )
end

function HolyProFarmConnectPacket(packet, callback)

    local runtime =
        HolyProFarmEnsureRuntime()

    if type(packet) ~= "table"
    or packet.OnClientEvent == nil then

        return false
    end

    local ok,
        connection =
        pcall(function()

            return packet.OnClientEvent:Connect(
                callback
            )
        end)

    if ok == true
    and connection ~= nil then

        table.insert(
            runtime.Connections,
            connection
        )

        return true
    end

    return false
end

function HolyProFarmApplySnapshot(snapshot)

    if type(snapshot) ~= "table" then
        return false
    end

    local userId =
        LocalPlayer.UserId

    local gardenData =
        snapshot[userId]
        or snapshot[tostring(userId)]

    if type(gardenData) ~= "table"
    or type(gardenData.Plants) ~= "table" then

        return false
    end

    local runtime =
        HolyProFarmEnsureRuntime()

    runtime.Cache.Plants =
        gardenData.Plants

    HolyProFarmPrepareCache()

    runtime.SnapshotReady =
        true

    runtime.LastSnapshotAt =
        os.clock()

    runtime.ConsecutiveFailures =
        0

    HolyProFarmSetStatus(
        "Ready"
    )

    return true
end

function HolyProFarmConnectEvents()

    local runtime =
        HolyProFarmEnsureRuntime()

    HolyProFarmDisconnectList(
        runtime.Connections
    )

    local _,
        garden =
        HolyProFarmGetNetworking()

    if type(garden) ~= "table" then
        return false
    end

    HolyProFarmConnectPacket(
        garden.SyncAllGardens,
        function(snapshot)

            HolyProFarmApplySnapshot(
                snapshot
            )
        end
    )

    HolyProFarmConnectPacket(
        garden.PlantAdded,
        function(owner, plantId, plantData)

            if HolyProFarmOwnerMatches(owner) ~= true then
                return
            end

            if type(plantData) ~= "table" then
                return
            end

            plantId =
                tostring(plantId)

            HolyProFarmPreparePlant(
                plantData
            )

            runtime.Cache.Plants[plantId] =
                plantData

            HolyProFarmRefreshUI()
        end
    )

    HolyProFarmConnectPacket(
        garden.PlantRemoved,
        function(owner, plantId)

            if HolyProFarmOwnerMatches(owner) ~= true then
                return
            end

            runtime.Cache.Plants[tostring(plantId)] =
                nil

            HolyProFarmRefreshUI()
        end
    )

    HolyProFarmConnectPacket(
        garden.FruitAdded,
        function(owner, plantId, fruitId, fruitData)

            if HolyProFarmOwnerMatches(owner) ~= true then
                return
            end

            if type(fruitData) ~= "table" then
                return
            end

            plantId =
                tostring(plantId)

            fruitId =
                tostring(fruitId)

            local plantData =
                runtime.Cache.Plants[plantId]

            if type(plantData) ~= "table" then

                plantData = {
                    Fruits = {},
                }

                runtime.Cache.Plants[plantId] =
                    plantData
            end

            plantData.Fruits =
                type(plantData.Fruits) == "table"
                and plantData.Fruits
                or {}

            HolyProFarmPrepareFruit(
                fruitData
            )

            plantData.Fruits[fruitId] =
                fruitData

            HolyProFarmRefreshUI()
        end
    )

    HolyProFarmConnectPacket(
        garden.FruitRemoved,
        function(owner, plantId, fruitId)

            if HolyProFarmOwnerMatches(owner) ~= true then
                return
            end

            local plantData =
                runtime.Cache.Plants[tostring(plantId)]

            if type(plantData) == "table"
            and type(plantData.Fruits) == "table" then

                plantData.Fruits[tostring(fruitId)] =
                    nil
            end

            HolyProFarmRefreshUI()
        end
    )

    HolyProFarmConnectPacket(
        garden.PlantGrowthUpdated,
        function(owner, plantId, currentAge, growthRate)

            if HolyProFarmOwnerMatches(owner) ~= true then
                return
            end

            local plantData =
                runtime.Cache.Plants[tostring(plantId)]

            if type(plantData) == "table" then

                plantData.Age =
                    tonumber(currentAge)
                    or plantData.Age
                    or 0

                plantData.GrowRate =
                    tonumber(growthRate)
                    or plantData.GrowRate
                    or 0

                plantData._HolyLastClock =
                    os.clock()
            end
        end
    )

    HolyProFarmConnectPacket(
        garden.FruitGrowthUpdated,
        function(owner, plantId, fruitId, currentAge, growthRate)

            if HolyProFarmOwnerMatches(owner) ~= true then
                return
            end

            local plantData =
                runtime.Cache.Plants[tostring(plantId)]

            local fruitData =
                type(plantData) == "table"
                and type(plantData.Fruits) == "table"
                and plantData.Fruits[tostring(fruitId)]
                or nil

            if type(fruitData) == "table" then

                fruitData.Age =
                    tonumber(currentAge)
                    or fruitData.Age
                    or 0

                fruitData.GrowRate =
                    tonumber(growthRate)
                    or fruitData.GrowRate
                    or 0

                fruitData._HolyLastClock =
                    os.clock()
            end
        end
    )

    HolyProFarmConnectPacket(
        garden.FruitMutationUpdated,
        function(owner, plantId, fruitId, mutationData)

            if HolyProFarmOwnerMatches(owner) ~= true then
                return
            end

            local plantData =
                runtime.Cache.Plants[tostring(plantId)]

            local fruitData =
                type(plantData) == "table"
                and type(plantData.Fruits) == "table"
                and plantData.Fruits[tostring(fruitId)]
                or nil

            if type(fruitData) == "table" then

                fruitData.Mutation =
                    mutationData
            end
        end
    )

    return true
end

function HolyProFarmRequestSnapshot(reason)

    local runtime =
        HolyProFarmEnsureRuntime()

    local _,
        garden =
        HolyProFarmGetNetworking()

    local packet =
        type(garden) == "table"
        and garden.RequestGardens
        or nil

    if type(packet) ~= "table"
    or type(packet.Fire) ~= "function" then

        HolyProFarmSetStatus(
            "Unavailable"
        )

        return false
    end

    runtime.LastRequestAt =
        os.clock()

    HolyProFarmSetStatus(
        "Refreshing"
    )

    local ok =
        pcall(function()

            packet:Fire()
        end)

    if ok ~= true then

        HolyProFarmSetStatus(
            "Refresh Failed"
        )

        return false
    end

    return true
end

function HolyProFarmIsOwnVisualRoot(instance)

    if typeof(instance) ~= "Instance" then
        return false
    end

    local prefix =
        tostring(
            LocalPlayer.UserId
        )
        .. "_"

    return instance.Name:sub(
        1,
        #prefix
    ) == prefix
end

function HolyProFarmFindPlantFolders()

    local folders =
        {}

    local gardens =
        workspace:FindFirstChild(
            "Gardens"
        )

    if typeof(gardens) ~= "Instance" then
        return folders
    end

    for _, plot in ipairs(gardens:GetChildren()) do

        local plants =
            plot:FindFirstChild(
                "Plants"
            )

        if typeof(plants) == "Instance" then

            table.insert(
                folders,
                plants
            )
        end
    end

    return folders
end

function HolyProFarmRemoveOwnVisuals()

    local runtime =
        HolyProFarmEnsureRuntime()

    local removed =
        0

    for _, folder in ipairs(
        HolyProFarmFindPlantFolders()
    ) do

        for _, child in ipairs(folder:GetChildren()) do

            if HolyProFarmIsOwnVisualRoot(child) then

                removed +=
                    1

                pcall(function()

                    child:Destroy()
                end)
            end
        end
    end

    runtime.HiddenVisualRoots +=
        removed

    return removed
end

function HolyProFarmStopVisualBlocker()

    local runtime =
        HolyProFarmEnsureRuntime()

    runtime.VisualBlockerActive =
        false

    HolyProFarmDisconnectList(
        runtime.VisualConnections
    )

    return true
end

function HolyProFarmStartVisualBlocker()

    local runtime =
        HolyProFarmEnsureRuntime()

    HolyProFarmStopVisualBlocker()

    if HOLY_FARM_STATE.LowGardenDetail ~= true
    or HOLY_FARM_STATE.ProFruitCollector ~= true then

        return false
    end

    runtime.VisualBlockerActive =
        true

    for _, folder in ipairs(
        HolyProFarmFindPlantFolders()
    ) do

        table.insert(
            runtime.VisualConnections,
            folder.ChildAdded:Connect(function(child)

                task.defer(function()

                    if runtime.VisualBlockerActive ~= true
                    or HOLY_FARM_STATE.LowGardenDetail ~= true
                    or HOLY_FARM_STATE.ProFruitCollector ~= true then

                        return
                    end

                    if child.Parent == folder
                    and HolyProFarmIsOwnVisualRoot(child) then

                        runtime.HiddenVisualRoots +=
                            1

                        pcall(function()

                            child:Destroy()
                        end)
                    end
                end)
            end)
        )
    end

    HolyProFarmRemoveOwnVisuals()

    return true
end

function HolyProFarmBuildEntry(
    plantId,
    plantData,
    fruitId,
    fruitData
)

    local isPlantHarvest =
        fruitId == nil
        or tostring(fruitId) == ""

    local entry = {
        Kind =
            isPlantHarvest
            and "PlantHarvest"
            or "FruitHarvest",

        Plant =
            nil,

        Fruit =
            nil,

        PlantData =
            plantData,

        FruitData =
            fruitData,

        PlantId =
            tostring(plantId or ""),

        FruitId =
            isPlantHarvest
            and ""
            or tostring(fruitId),

        PlantName =
            HolyCleanText(
                type(plantData) == "table"
                and (
                    plantData.PlantName
                    or plantData.FruitName
                    or plantData.SeedName
                    or plantData.Name
                )
                or ""
            ),
    }

    entry.Key =
        isPlantHarvest
        and HolyFarmBuildPlantHarvestKey(
            entry.PlantId
        )
        or HolyFarmBuildFruitKey(
            entry.PlantId,
            entry.FruitId
        )

    return entry
end

function HolyProFarmEntryAllowed(entry)

    if type(entry) ~= "table"
    or entry.Key == "" then

        return false
    end

    if HolyFarmSelectionAllowsPlant(
        entry.PlantName
    ) ~= true then

        return false
    end

    if HolyFarmMutationAllowsEntry(
        entry
    ) ~= true then

        return false
    end

    if HolyFarmWeightAllowsEntry(
        entry
    ) ~= true then

        return false
    end

    return true
end

function HolyProFarmFindTarget()

    local runtime =
        HolyProFarmEnsureRuntime()

    local now =
        os.clock()

    local candidates =
        {}

    local pendingPlants =
        {}

    for _, pending in pairs(runtime.Pending) do

        local pendingEntry =
            type(pending) == "table"
            and pending.Entry
            or nil

        if type(pendingEntry) == "table" then

            pendingPlants[
                tostring(
                    pendingEntry.PlantId
                    or ""
                )
            ] =
                true
        end
    end

    for plantId, plantData in pairs(runtime.Cache.Plants) do

        if type(plantData) == "table"
        and pendingPlants[tostring(plantId)] ~= true then

            local fruitCount =
                0

            if type(plantData.Fruits) == "table" then

                for fruitId, fruitData in pairs(plantData.Fruits) do

                    if type(fruitData) == "table" then

                        fruitCount +=
                            1

                        if HolyProFarmDataReady(
                            fruitData
                        ) then

                            local entry =
                                HolyProFarmBuildEntry(
                                    plantId,
                                    plantData,
                                    fruitId,
                                    fruitData
                                )

                            local cooldown =
                                tonumber(
                                    runtime.Cooldowns[entry.Key]
                                )
                                or 0

                            if cooldown <= now
                            and runtime.Pending[entry.Key] == nil
                            and HolyProFarmEntryAllowed(
                                entry
                            ) then

                                table.insert(
                                    candidates,
                                    entry
                                )
                            end
                        end
                    end
                end
            end

            if fruitCount == 0
            and (
                tonumber(
                    plantData.MaxFruitSpawnLocations
                )
                or 0
            ) <= 0
            and HolyProFarmDataReady(
                plantData
            ) then

                local entry =
                    HolyProFarmBuildEntry(
                        plantId,
                        plantData,
                        "",
                        plantData
                    )

                local cooldown =
                    tonumber(
                        runtime.Cooldowns[entry.Key]
                    )
                    or 0

                if cooldown <= now
                and runtime.Pending[entry.Key] == nil
                and HolyProFarmEntryAllowed(
                    entry
                ) then

                    table.insert(
                        candidates,
                        entry
                    )
                end
            end
        end
    end

    if #candidates == 0 then
        return nil
    end

    return candidates[
        math.random(
            1,
            #candidates
        )
    ]
end

function HolyProFarmTargetExists(entry)

    local runtime =
        HolyProFarmEnsureRuntime()

    if type(entry) ~= "table" then
        return false
    end

    local plantData =
        runtime.Cache.Plants[entry.PlantId]

    if entry.Kind == "PlantHarvest" then

        return type(plantData) == "table"
    end

    return type(plantData) == "table"
        and type(plantData.Fruits) == "table"
        and plantData.Fruits[entry.FruitId] ~= nil
end

function HolyProFarmWaitForConfirmation(
    token,
    entry,
    timeout
)

    local runtime =
        HolyProFarmEnsureRuntime()

    local deadline =
        os.clock()
        + (
            tonumber(timeout)
            or 2.5
        )

    while runtime.Token == token
    and HOLY_FARM_STATE.ProFruitCollector == true
    and os.clock() < deadline do

        if HolyProFarmTargetExists(
            entry
        ) ~= true then

            return true
        end

        task.wait(
            0.08
        )
    end

    return HolyProFarmTargetExists(
        entry
    ) ~= true
end

function HolyProFarmFireEntry(token, entry)

    local runtime =
        HolyProFarmEnsureRuntime()

    local packet =
        runtime.CollectPacket

    if type(packet) ~= "table"
    or type(packet.Fire) ~= "function" then

        local _,
            garden =
            HolyProFarmGetNetworking()

        packet =
            type(garden) == "table"
            and garden.CollectFruit
            or nil

        runtime.CollectPacket =
            packet
    end

    if type(packet) ~= "table"
    or type(packet.Fire) ~= "function" then

        return false,
            "Collect packet unavailable"
    end

    HolyProFarmSetStatus(
        "Collecting"
    )

    local ok,
        result =
        pcall(function()

            return packet:Fire(
                entry.PlantId,
                entry.FruitId
            )
        end)

    if ok ~= true then

        return false,
            tostring(result)
    end

    if HolyProFarmWaitForConfirmation(
        token,
        entry,
        2.5
    ) then

        return true,
            "confirmed"
    end

    task.wait(
        0.75
    )

    ok,
        result =
        pcall(function()

            return packet:Fire(
                entry.PlantId,
                entry.FruitId
            )
        end)

    if ok ~= true then

        return false,
            tostring(result)
    end

    if HolyProFarmWaitForConfirmation(
        token,
        entry,
        2.5
    ) then

        return true,
            "confirmed after retry"
    end

    return false,
        "not confirmed"
end

function HolyProFarmReadCollectionDelay(value)

    return math.clamp(
        tonumber(value)
        or 0.05,
        0.035,
        1
    )
end

function HolyProFarmGetPendingCount()

    local runtime =
        HolyProFarmEnsureRuntime()

    local count =
        0

    for _ in pairs(runtime.Pending) do

        count +=
            1
    end

    return count
end

function HolyProFarmGetPipelinePacket()

    local runtime =
        HolyProFarmEnsureRuntime()

    local packet =
        runtime.CollectPacket

    if type(packet) == "table"
    and type(packet.Fire) == "function" then

        return packet
    end

    local _,
        garden =
        HolyProFarmGetNetworking()

    packet =
        type(garden) == "table"
        and garden.CollectFruit
        or nil

    runtime.CollectPacket =
        packet

    if type(packet) ~= "table"
    or type(packet.Fire) ~= "function" then

        return nil,
            "Collect packet unavailable"
    end

    return packet
end

function HolyProFarmSetPipelineStatus()

    local runtime =
        HolyProFarmEnsureRuntime()

    local pendingCount =
        HolyProFarmGetPendingCount()

    local status =
        pendingCount > 0
        and (
            "Collecting "
            .. tostring(pendingCount)
        )
        or "Ready"

    if runtime.Status ~= status then

        HolyProFarmSetStatus(
            status
        )
    end

    return status
end

function HolyProFarmRecordPipelineConfirmed(key, pending)

    local runtime =
        HolyProFarmEnsureRuntime()

    runtime.Pending[key] =
        nil

    runtime.Cooldowns[key] =
        nil

    runtime.Confirmed +=
        1

    runtime.ConsecutiveFailures =
        0

    return true
end

function HolyProFarmRecordPipelineFailure(key, pending, reason)

    local runtime =
        HolyProFarmEnsureRuntime()

    local entry =
        type(pending) == "table"
        and pending.Entry
        or nil

    runtime.Pending[key] =
        nil

    runtime.Cooldowns[key] =
        os.clock()
        + 8

    runtime.Failed +=
        1

    runtime.ConsecutiveFailures +=
        1

    if runtime.ConsecutiveFailures >= 3 then

        runtime.ConsecutiveFailures =
            0

        HolyProFarmRequestSnapshot(
            "pipeline recovery"
        )
    end

    return entry,
        tostring(reason or "failed")
end

function HolyProFarmProcessPending(token)

    local runtime =
        HolyProFarmEnsureRuntime()

    local now =
        os.clock()

    for key, pending in pairs(runtime.Pending) do

        if runtime.Token ~= token then
            break
        end

        local entry =
            type(pending) == "table"
            and pending.Entry
            or nil

        if type(entry) ~= "table" then

            runtime.Pending[key] =
                nil

            continue
        end

        if HolyProFarmTargetExists(
            entry
        ) ~= true then

            HolyProFarmRecordPipelineConfirmed(
                key,
                pending
            )

            continue
        end

        local lastSentAt =
            tonumber(
                pending.LastSentAt
            )
            or now

        local attempts =
            math.max(
                1,
                math.floor(
                    tonumber(
                        pending.Attempts
                    )
                    or 1
                )
            )

        if pending.RetryReadyAt ~= nil then

            continue
        end

        if now - lastSentAt
            >= runtime.ConfirmationTimeout then

            if attempts < 2 then

                pending.RetryReadyAt =
                    now
                    + runtime.RetryDelay

            else

                HolyProFarmRecordPipelineFailure(
                    key,
                    pending,
                    "not confirmed"
                )
            end
        end
    end

    return true
end

function HolyProFarmFindRetryReady()

    local runtime =
        HolyProFarmEnsureRuntime()

    local now =
        os.clock()

    local bestKey =
        nil

    local bestPending =
        nil

    local bestTime =
        math.huge

    for key, pending in pairs(runtime.Pending) do

        local retryReadyAt =
            type(pending) == "table"
            and tonumber(
                pending.RetryReadyAt
            )
            or nil

        if retryReadyAt
        and retryReadyAt <= now
        and retryReadyAt < bestTime then

            bestKey =
                key

            bestPending =
                pending

            bestTime =
                retryReadyAt
        end
    end

    return bestKey,
        bestPending
end

function HolyProFarmSendRetry(token, packet, key, pending)

    local runtime =
        HolyProFarmEnsureRuntime()

    if runtime.Token ~= token
    or type(pending) ~= "table"
    or type(pending.Entry) ~= "table" then

        return false
    end

    local entry =
        pending.Entry

    if HolyProFarmTargetExists(
        entry
    ) ~= true then

        HolyProFarmRecordPipelineConfirmed(
            key,
            pending
        )

        return true
    end

    local ok =
        pcall(function()

            packet:Fire(
                entry.PlantId,
                entry.FruitId
            )
        end)

    runtime.NextSendAt =
        os.clock()
        + HolyProFarmReadCollectionDelay(
            HOLY_FARM_STATE.ProCollectionDelay
        )

    if ok ~= true then

        HolyProFarmRecordPipelineFailure(
            key,
            pending,
            "retry fire failed"
        )

        return false
    end

    pending.Attempts =
        (
            tonumber(
                pending.Attempts
            )
            or 1
        )
        + 1

    pending.LastSentAt =
        os.clock()

    pending.RetryReadyAt =
        nil

    return true
end

function HolyProFarmSendNewTarget(token, packet)

    local runtime =
        HolyProFarmEnsureRuntime()

    if runtime.Token ~= token then
        return false
    end

    if HolyProFarmGetPendingCount()
        >= runtime.MaxPending then

        return false
    end

    local entry =
        HolyProFarmFindTarget()

    if type(entry) ~= "table" then
        return false
    end

    local ok =
        pcall(function()

            packet:Fire(
                entry.PlantId,
                entry.FruitId
            )
        end)

    runtime.NextSendAt =
        os.clock()
        + HolyProFarmReadCollectionDelay(
            HOLY_FARM_STATE.ProCollectionDelay
        )

    if ok ~= true then

        runtime.Cooldowns[entry.Key] =
            os.clock()
            + 8

        runtime.Failed +=
            1

        runtime.ConsecutiveFailures +=
            1

        if runtime.ConsecutiveFailures >= 3 then

            runtime.ConsecutiveFailures =
                0

            HolyProFarmRequestSnapshot(
                "pipeline fire recovery"
            )
        end

        return false
    end

    runtime.Pending[entry.Key] = {
        Entry =
            entry,

        Attempts =
            1,

        LastSentAt =
            os.clock(),

        RetryReadyAt =
            nil,
    }

    return true
end

function HolyProFarmPipelineStep(token)

    local runtime =
        HolyProFarmEnsureRuntime()

    HolyProFarmProcessPending(
        token
    )

    if runtime.Token ~= token
    or HOLY_FARM_STATE.ProFruitCollector ~= true then

        return false
    end

    if os.clock() < (
        tonumber(runtime.NextSendAt)
        or 0
    ) then

        HolyProFarmSetPipelineStatus()

        return false
    end

    local packet =
        HolyProFarmGetPipelinePacket()

    if not packet then

        HolyProFarmSetStatus(
            "Unavailable"
        )

        runtime.NextSendAt =
            os.clock()
            + 1

        return false
    end

    local retryKey,
        retryPending =
        HolyProFarmFindRetryReady()

    local sent =
        false

    if retryKey
    and retryPending then

        sent =
            HolyProFarmSendRetry(
                token,
                packet,
                retryKey,
                retryPending
            )

    else

        sent =
            HolyProFarmSendNewTarget(
                token,
                packet
            )
    end

    HolyProFarmSetPipelineStatus()

    return sent
end

function HolyProFarmRunWorker(token)

    local runtime =
        HolyProFarmEnsureRuntime()

    while runtime.Token == token
    and HOLY_FARM_STATE.ProFruitCollector == true do

        HolyProFarmProcessPending(
            token
        )

        if HolyFarmAutoCollectBlocked() == true then

            if runtime.Status ~= "Paused" then

                HolyProFarmSetStatus(
                    "Paused"
                )
            end

            task.wait(
                0.05
            )

            continue
        end

        if runtime.SnapshotReady ~= true then

            if os.clock() - (
                tonumber(runtime.LastRequestAt)
                or 0
            ) >= 5 then

                HolyProFarmRequestSnapshot(
                    "waiting"
                )
            end

            task.wait(
                0.05
            )

            continue
        end

        if os.clock() - (
            tonumber(runtime.LastSnapshotAt)
            or 0
        ) >= 60 then

            HolyProFarmRequestSnapshot(
                "safety refresh"
            )
        end

        HolyProFarmPipelineStep(
            token
        )

        task.wait(
            0.01
        )
    end

    if runtime.Token == token then

        runtime.Running =
            false
    end
end

function HolyProFarmStart(reason)

    HolyFarmEnsureState()

    if HOLY_FARM_STATE.ProFruitCollector ~= true then
        return false
    end

    local runtime =
        HolyProFarmEnsureRuntime()

    if runtime.Running == true then
        return false
    end

    HolyFarmStopAutoCollect(
        "pro collector"
    )

    HolyProFarmDisconnectList(
        runtime.Connections
    )

    HolyProFarmDisconnectList(
        runtime.VisualConnections
    )

    runtime.Cache = {
        Plants = {},
    }

    runtime.Cooldowns =
        {}

    runtime.Pending =
        {}

    runtime.NextSendAt =
        0

    runtime.SnapshotReady =
        false

    runtime.Confirmed =
        0

    runtime.Failed =
        0

    runtime.ConsecutiveFailures =
        0

    runtime.Token =
        {}

    runtime.Running =
        true

    local token =
        runtime.Token

    if HolyProFarmConnectEvents() ~= true then

        runtime.Running =
            false

        runtime.Token =
            nil

        HolyProFarmSetStatus(
            "Unavailable"
        )

        return false
    end

    if HOLY_FARM_STATE.LowGardenDetail == true then

        HolyProFarmStartVisualBlocker()
    end

    HolyProFarmRequestSnapshot(
        reason or "start"
    )

    task.spawn(function()

        HolyProFarmRunWorker(
            token
        )
    end)

    return true
end

function HolyProFarmStop(reason)

    local runtime =
        HolyProFarmEnsureRuntime()

    runtime.Token =
        nil

    runtime.Running =
        false

    runtime.SnapshotReady =
        false

    runtime.Pending =
        {}

    runtime.NextSendAt =
        0

    HolyProFarmDisconnectList(
        runtime.Connections
    )

    HolyProFarmStopVisualBlocker()

    HolyProFarmSetStatus(
        "Disabled"
    )

    return true
end

function HolyProFarmSetEnabled(value)

    HolyFarmEnsureState()

    value =
        value == true

    HOLY_FARM_STATE.ProFruitCollector =
        value

    if value == true then

        HOLY_FARM_STATE.AutoCollectFruits =
            false

        if type(HOLY_FARM_UI.AutoCollectToggle) == "table"
        and type(HOLY_FARM_UI.AutoCollectToggle.SetValue) == "function" then

            pcall(function()

                HOLY_FARM_UI.AutoCollectToggle:SetValue(
                    false,
                    true
                )
            end)
        end

        HolyFarmStopAutoCollect(
            "pro enabled"
        )

        HolySaveFarmSettings()

        return HolyProFarmStart(
            "toggle on"
        )
    end

    HolySaveFarmSettings()

    return HolyProFarmStop(
        "toggle off"
    )
end

function HolyProFarmSetCollectionDelay(value)

    HolyFarmEnsureState()

    HOLY_FARM_STATE.ProCollectionDelay =
        HolyProFarmReadCollectionDelay(
            value
        )

    local runtime =
        HolyProFarmEnsureRuntime()

    runtime.NextSendAt =
        os.clock()
        + HOLY_FARM_STATE.ProCollectionDelay

    HolySaveFarmSettings()

    return HOLY_FARM_STATE.ProCollectionDelay
end

function HolyProFarmSetLowGardenDetail(value)

    HolyFarmEnsureState()

    HOLY_FARM_STATE.LowGardenDetail =
        value == true

    HolySaveFarmSettings()

    local runtime =
        HolyProFarmEnsureRuntime()

    if HOLY_FARM_STATE.LowGardenDetail == true
    and HOLY_FARM_STATE.ProFruitCollector == true
    and runtime.Running == true then

        return HolyProFarmStartVisualBlocker()
    end

    return HolyProFarmStopVisualBlocker()
end

function HolyFarmSetAutoCollectFruits(value)

    HolyFarmEnsureState()

    value =
        value == true

    if value == true
    and HOLY_FARM_STATE.ProFruitCollector == true then

        HOLY_FARM_STATE.ProFruitCollector =
            false

        if type(HOLY_FARM_UI.ProCollectorToggle) == "table"
        and type(HOLY_FARM_UI.ProCollectorToggle.SetValue) == "function" then

            pcall(function()

                HOLY_FARM_UI.ProCollectorToggle:SetValue(
                    false,
                    true
                )
            end)
        end

        HolyProFarmStop(
            "normal collector enabled"
        )
    end

    HOLY_FARM_STATE.AutoCollectFruits =
        value

    HolySaveFarmSettings()

    if HOLY_FARM_STATE.AutoCollectFruits == true then

        return HolyFarmStartAutoCollect(
            "toggle on"
        )
    end

    return HolyFarmStopAutoCollect(
        "toggle off"
    )
end

--==================================================
-- [2.125] FARM / AUTO TROWEL CORE
--==================================================

function HolyAutoTrowelNormalizePositionMethod(value)

    local text =
        HolyCleanText(
            value
        )

    if text:lower():find(
        "standing",
        1,
        true
    ) then

        return "Standing Position"
    end

    return "Click Position"
end

function HolyAutoTrowelNormalizeLayout(value)

    local text =
        HolyCleanText(
            value
        )

    if text:lower():find(
        "spiral",
        1,
        true
    ) then

        return "Compact Spiral"
    end

    return "Exact Point"
end

function HolyAutoTrowelReadMoveAmount(value)

    local amount =
        math.floor(
            tonumber(value)
            or 1
        )

    return math.clamp(
        amount,
        0,
        100000
    )
end

function HolyAutoTrowelReadSpacing(value)

    return math.clamp(
        tonumber(value)
        or 0.75,
        0,
        25
    )
end

function HolyAutoTrowelNormalizeSelection(value)

    local raw =
        HolyShopSelectionArray(
            value
        )

    local runtime =
        HOLY_AUTO_TROWEL_RUNTIME

    local output =
        {}

    local seen =
        {}

    for _, selectedValue in ipairs(raw) do

        local displayText =
            HolyCleanText(
                selectedValue
            )

        local plantName =
            runtime.DisplayToPlant[displayText]
            or displayText:gsub(
                "%s+%(%d+%)$",
                ""
            )

        plantName =
            HolyCleanText(
                plantName
            )

        if plantName:lower() == "all plants" then

            plantName =
                "All Plants"
        end

        if plantName ~= ""
        and seen[plantName] ~= true then

            seen[plantName] =
                true

            table.insert(
                output,
                plantName
            )
        end
    end

    table.sort(output, function(a, b)

        if a == "All Plants" then
            return true
        end

        if b == "All Plants" then
            return false
        end

        return tostring(a):lower()
            < tostring(b):lower()
    end)

    return output
end

function HolyAutoTrowelGetSettingsData()

    local state =
        HOLY_AUTO_TROWEL_STATE

    local targetLocal =
        nil

    if type(state.TargetLocal) == "table" then

        local x =
            tonumber(state.TargetLocal.X)

        local y =
            tonumber(state.TargetLocal.Y)

        local z =
            tonumber(state.TargetLocal.Z)

        if x and y and z then

            targetLocal = {
                X = x,
                Y = y,
                Z = z,
            }
        end
    end

    return {
        PositionMethod =
            HolyAutoTrowelNormalizePositionMethod(
                state.PositionMethod
            ),

        TargetLocal =
            targetLocal,

        SelectedPlants =
            HolyAutoTrowelNormalizeSelection(
                state.SelectedPlants
            ),

        MoveAmount =
            HolyAutoTrowelReadMoveAmount(
                state.MoveAmount
            ),

        Layout =
            HolyAutoTrowelNormalizeLayout(
                state.Layout
            ),

        Spacing =
            HolyAutoTrowelReadSpacing(
                state.Spacing
            ),
    }
end

function HolyAutoTrowelLoadSettingsData(data)

    if type(data) ~= "table" then
        return false
    end

    local state =
        HOLY_AUTO_TROWEL_STATE

    state.PositionMethod =
        HolyAutoTrowelNormalizePositionMethod(
            data.PositionMethod
        )

    state.SelectedPlants =
        HolyAutoTrowelNormalizeSelection(
            data.SelectedPlants
        )

    state.MoveAmount =
        HolyAutoTrowelReadMoveAmount(
            data.MoveAmount
        )

    state.Layout =
        HolyAutoTrowelNormalizeLayout(
            data.Layout
        )

    state.Spacing =
        HolyAutoTrowelReadSpacing(
            data.Spacing
        )

    local targetLocal =
        data.TargetLocal

    if type(targetLocal) == "table" then

        local x =
            tonumber(targetLocal.X)

        local y =
            tonumber(targetLocal.Y)

        local z =
            tonumber(targetLocal.Z)

        if x and y and z then

            state.TargetLocal = {
                X = x,
                Y = y,
                Z = z,
            }

        else

            state.TargetLocal =
                nil
        end

    else

        state.TargetLocal =
            nil
    end

    return true
end

function HolyAutoTrowelDisconnect(connection)

    if connection
    and type(connection.Disconnect) == "function" then

        pcall(function()

            connection:Disconnect()
        end)
    end
end

function HolyAutoTrowelGetPlotAnchor(plot)

    if typeof(plot) ~= "Instance" then
        return nil
    end

    local direct =
        plot:FindFirstChild(
            "GardenZonePart",
            true
        )

    if typeof(direct) == "Instance"
    and direct:IsA("BasePart") then

        return direct
    end

    for _, descendant in ipairs(plot:GetDescendants()) do

        if descendant:IsA("BasePart")
        and descendant.Name == "GardenZonePart" then

            return descendant
        end
    end

    return nil
end

function HolyAutoTrowelPointInsideAnchor(point, anchor)

    if typeof(point) ~= "Vector3"
    or typeof(anchor) ~= "Instance"
    or anchor:IsA("BasePart") ~= true then

        return false
    end

    local localPoint =
        anchor.CFrame:PointToObjectSpace(
            point
        )

    local halfX =
        math.abs(anchor.Size.X) * 0.5

    local halfZ =
        math.abs(anchor.Size.Z) * 0.5

    return math.abs(localPoint.X) <= halfX
        and math.abs(localPoint.Z) <= halfZ
end

function HolyAutoTrowelResolveGroundPoint(point)

    if typeof(point) ~= "Vector3" then

        return nil,
            "Invalid position."
    end

    local plot =
        HolyFarmResolveOwnPlot(
            false
        )

    if typeof(plot) ~= "Instance" then

        return nil,
            "Your garden plot is not ready."
    end

    local anchor =
        HolyAutoTrowelGetPlotAnchor(
            plot
        )

    if typeof(anchor) ~= "Instance" then

        return nil,
            "GardenZonePart was not found."
    end

    if HolyAutoTrowelPointInsideAnchor(
        point,
        anchor
    ) ~= true then

        return nil,
            "The selected position is outside your garden."
    end

    local filter =
        {}

    local character =
        LocalPlayer.Character

    if typeof(character) == "Instance" then

        table.insert(
            filter,
            character
        )
    end

    local plantsFolder =
        plot:FindFirstChild(
            "Plants"
        )

    if typeof(plantsFolder) == "Instance" then

        table.insert(
            filter,
            plantsFolder
        )
    end

    table.insert(
        filter,
        anchor
    )

    local marker =
        HOLY_AUTO_TROWEL_RUNTIME.Marker

    if typeof(marker) == "Instance" then

        table.insert(
            filter,
            marker
        )
    end

    local params =
        RaycastParams.new()

    params.FilterType =
        Enum.RaycastFilterType.Exclude

    params.FilterDescendantsInstances =
        filter

    params.IgnoreWater =
        true

    local rayStart =
        Vector3.new(
            point.X,
            anchor.Position.Y
                + math.abs(anchor.Size.Y) * 0.5
                + 100,
            point.Z
        )

    local result =
        workspace:Raycast(
            rayStart,
            Vector3.new(
                0,
                -1000,
                0
            ),
            params
        )

    if not result then

        return nil,
            "Could not find the garden floor."
    end

    if result.Instance:IsDescendantOf(
        plot
    ) ~= true then

        return nil,
            "The selected position did not hit your garden floor."
    end

    local groundPoint =
        result.Position

    if HolyAutoTrowelPointInsideAnchor(
        groundPoint,
        anchor
    ) ~= true then

        return nil,
            "The selected position is outside your garden."
    end

    return groundPoint,
        plot,
        anchor
end

function HolyAutoTrowelClearMarker()

    local runtime =
        HOLY_AUTO_TROWEL_RUNTIME

    runtime.MarkerToken =
        (
            tonumber(runtime.MarkerToken)
            or 0
        )
        + 1

    local marker =
        runtime.Marker

    runtime.Marker =
        nil

    if typeof(marker) == "Instance" then

        pcall(function()

            marker:Destroy()
        end)
    end
end

function HolyAutoTrowelShowMarker(point)

    HolyAutoTrowelClearMarker()

    if typeof(point) ~= "Vector3" then
        return false
    end

    local runtime =
        HOLY_AUTO_TROWEL_RUNTIME

    local marker =
        Instance.new(
            "Part"
        )

    marker.Name =
        "HolyAutoTrowelTarget"

    marker.Shape =
        Enum.PartType.Cylinder

    marker.Size =
        Vector3.new(
            0.12,
            2.4,
            2.4
        )

    marker.CFrame =
        CFrame.new(
            point
            + Vector3.new(
                0,
                0.08,
                0
            )
        )
        * CFrame.Angles(
            0,
            0,
            math.rad(90)
        )

    marker.Anchored =
        true

    marker.CanCollide =
        false

    marker.CanTouch =
        false

    marker.CanQuery =
        false

    marker.CastShadow =
        false

    marker.Material =
        Enum.Material.Neon

    marker.Color =
        Color3.fromRGB(
            180,
            120,
            255
        )

    marker.Transparency =
        0.22

    marker.Parent =
        workspace

    runtime.Marker =
        marker

    runtime.MarkerToken =
        (
            tonumber(runtime.MarkerToken)
            or 0
        )
        + 1

    local markerToken =
        runtime.MarkerToken

    task.delay(4, function()

        if runtime.MarkerToken == markerToken
        and runtime.Marker == marker then

            HolyAutoTrowelClearMarker()
        end
    end)

    return true
end

function HolyAutoTrowelGetWorldTarget()

    local targetLocal =
        HOLY_AUTO_TROWEL_STATE.TargetLocal

    if type(targetLocal) ~= "table" then

        return nil,
            "Set a position first."
    end

    local x =
        tonumber(targetLocal.X)

    local y =
        tonumber(targetLocal.Y)

    local z =
        tonumber(targetLocal.Z)

    if not x or not y or not z then

        return nil,
            "The saved position is invalid."
    end

    local plot =
        HolyFarmResolveOwnPlot(
            false
        )

    if typeof(plot) ~= "Instance" then

        return nil,
            "Your garden plot is not ready."
    end

    local anchor =
        HolyAutoTrowelGetPlotAnchor(
            plot
        )

    if typeof(anchor) ~= "Instance" then

        return nil,
            "GardenZonePart was not found."
    end

    local worldPoint =
        anchor.CFrame:PointToWorldSpace(
            Vector3.new(
                x,
                y,
                z
            )
        )

    if HolyAutoTrowelPointInsideAnchor(
        worldPoint,
        anchor
    ) ~= true then

        return nil,
            "The saved position is outside your garden."
    end

    return worldPoint,
        plot,
        anchor
end

function HolyAutoTrowelSetWorldPosition(point)

    local groundPoint,
        plot,
        anchor =
        HolyAutoTrowelResolveGroundPoint(
            point
        )

    if typeof(groundPoint) ~= "Vector3" then

        HolyNotify(
            "Auto Trowel",
            tostring(plot),
            4
        )

        return false
    end

    local localPoint =
        anchor.CFrame:PointToObjectSpace(
            groundPoint
        )

    HOLY_AUTO_TROWEL_STATE.TargetLocal = {
        X = localPoint.X,
        Y = localPoint.Y,
        Z = localPoint.Z,
    }

    HolySaveFarmSettings()

    HolyAutoTrowelShowMarker(
        groundPoint
    )

    HolyNotify(
        "Auto Trowel",
        "Trowel position saved.",
        3
    )

    return true
end

function HolyAutoTrowelCancelClickPosition(notifyUser)

    local runtime =
        HOLY_AUTO_TROWEL_RUNTIME

    HolyAutoTrowelDisconnect(
        runtime.ClickConnection
    )

    runtime.ClickConnection =
        nil

    if notifyUser == true then

        HolyNotify(
            "Auto Trowel",
            "Position selection cancelled.",
            3
        )
    end

    return true
end

function HolyAutoTrowelArmClickPosition()

    HolyAutoTrowelCancelClickPosition(
        false
    )

    local runtime =
        HOLY_AUTO_TROWEL_RUNTIME

    local mouse =
        LocalPlayer:GetMouse()

    HolyNotify(
        "Auto Trowel",
        "Click inside your garden. Right-click or press Escape to cancel.",
        5
    )

    runtime.ClickConnection =
        UserInputService.InputBegan:Connect(function(input, gameProcessed)

            if input.KeyCode == Enum.KeyCode.Escape
            or input.UserInputType == Enum.UserInputType.MouseButton2 then

                HolyAutoTrowelCancelClickPosition(
                    true
                )

                return
            end

            if gameProcessed == true then
                return
            end

            if input.UserInputType
                ~= Enum.UserInputType.MouseButton1 then

                return
            end

            local hit =
                mouse.Hit

            if typeof(hit) ~= "CFrame" then

                HolyNotify(
                    "Auto Trowel",
                    "Could not read the clicked position.",
                    4
                )

                return
            end

            local saved =
                HolyAutoTrowelSetWorldPosition(
                    hit.Position
                )

            if saved == true then

                HolyAutoTrowelCancelClickPosition(
                    false
                )
            end
        end)

    return true
end

function HolyAutoTrowelSetStandingPosition()

    local character =
        LocalPlayer.Character

    local root =
        character
        and character:FindFirstChild(
            "HumanoidRootPart"
        )

    if typeof(root) ~= "Instance" then

        HolyNotify(
            "Auto Trowel",
            "Your character is not ready.",
            4
        )

        return false
    end

    return HolyAutoTrowelSetWorldPosition(
        root.Position
    )
end

function HolyAutoTrowelUseSelectedPositionMethod()

    local method =
        HolyAutoTrowelNormalizePositionMethod(
            HOLY_AUTO_TROWEL_STATE.PositionMethod
        )

    if method == "Standing Position" then

        HolyAutoTrowelCancelClickPosition(
            false
        )

        return HolyAutoTrowelSetStandingPosition()
    end

    return HolyAutoTrowelArmClickPosition()
end

function HolyAutoTrowelClearPosition()

    HolyAutoTrowelCancelClickPosition(
        false
    )

    HolyAutoTrowelClearMarker()

    HOLY_AUTO_TROWEL_STATE.TargetLocal =
        nil

    HolySaveFarmSettings()

    HolyNotify(
        "Auto Trowel",
        "Saved position cleared.",
        3
    )

    return true
end

function HolyAutoTrowelOwnsPlant(plant, plantsFolder)

    if typeof(plant) ~= "Instance"
    or plant:IsA("Model") ~= true
    or plant.Parent ~= plantsFolder then

        return false
    end

    local ownUserId =
        tostring(
            LocalPlayer.UserId
        )

    local plantUserId =
        plant:GetAttribute(
            "UserId"
        )

    if plantUserId ~= nil
    and tostring(plantUserId) == ownUserId then

        return true
    end

    local prefix =
        ownUserId
        .. "_"

    return tostring(plant.Name):sub(
        1,
        #prefix
    ) == prefix
end

function HolyAutoTrowelReadPlantType(plant)

    local plantName =
        HolyFarmReadAttribute(
            plant,
            {
                "SeedName",
                "PlantName",
                "CropName",
                "DisplayName",
            }
        )

    return HolyFarmCleanPlantName(
        plantName
    )
end

function HolyAutoTrowelBuildDropdownValues()

    local runtime =
        HOLY_AUTO_TROWEL_RUNTIME

    runtime.DisplayToPlant =
        {
            ["All Plants"] =
                "All Plants",
        }

    runtime.PlantToDisplay =
        {
            ["All Plants"] =
                "All Plants",
        }

    local values = {
        "All Plants",
    }

    local plot =
        HolyFarmResolveOwnPlot(
            false
        )

    local plantsFolder =
        plot
        and plot:FindFirstChild(
            "Plants"
        )

    if typeof(plantsFolder) ~= "Instance" then

        return values
    end

    local counts =
        {}

    for _, plant in ipairs(plantsFolder:GetChildren()) do

        if HolyAutoTrowelOwnsPlant(
            plant,
            plantsFolder
        ) == true then

            local plantType =
                HolyAutoTrowelReadPlantType(
                    plant
                )

            if plantType ~= "" then

                counts[plantType] =
                    (
                        tonumber(
                            counts[plantType]
                        )
                        or 0
                    )
                    + 1
            end
        end
    end

    local names =
        {}

    for plantType in pairs(counts) do

        table.insert(
            names,
            plantType
        )
    end

    table.sort(names, function(a, b)

        return tostring(a):lower()
            < tostring(b):lower()
    end)

    for _, plantType in ipairs(names) do

        local display =
            plantType
            .. " ("
            .. tostring(counts[plantType])
            .. ")"

        runtime.DisplayToPlant[display] =
            plantType

        runtime.PlantToDisplay[plantType] =
            display

        table.insert(
            values,
            display
        )
    end

    return values
end

function HolyAutoTrowelGetSelectedDisplayValues()

    local runtime =
        HOLY_AUTO_TROWEL_RUNTIME

    local output =
        {}

    for _, plantName in ipairs(
        HOLY_AUTO_TROWEL_STATE.SelectedPlants
        or {}
    ) do

        local display =
            runtime.PlantToDisplay[plantName]

        if display then

            table.insert(
                output,
                display
            )
        end
    end

    return output
end

function HolyAutoTrowelRefreshPlantDropdown()

    local dropdown =
        HOLY_AUTO_TROWEL_UI.PlantsDropdown

    if type(dropdown) ~= "table" then
        return false
    end

    local runtime =
        HOLY_AUTO_TROWEL_RUNTIME

    local values =
        HolyAutoTrowelBuildDropdownValues()

    local selected =
        HolyAutoTrowelGetSelectedDisplayValues()

    runtime.UpdatingUI =
        true

    pcall(function()

        if type(dropdown.SetValues) == "function" then

            dropdown:SetValues(
                values
            )

        elseif type(dropdown.SetItems) == "function" then

            dropdown:SetItems(
                values
            )
        end
    end)

    pcall(function()

        if type(dropdown.SetValue) == "function" then

            dropdown:SetValue(
                selected
            )
        end
    end)

    runtime.UpdatingUI =
        false

    return true
end

function HolyAutoTrowelRefreshLayoutUI()

    local spacingInput =
        HOLY_AUTO_TROWEL_UI.SpacingInput

    if type(spacingInput) ~= "table"
    or type(spacingInput.SetVisible) ~= "function" then

        return false
    end

    local visible =
        HolyAutoTrowelNormalizeLayout(
            HOLY_AUTO_TROWEL_STATE.Layout
        ) == "Compact Spiral"

    pcall(function()

        spacingInput:SetVisible(
            visible
        )
    end)

    return true
end

function HolyAutoTrowelSetPositionMethod(value)

    HOLY_AUTO_TROWEL_STATE.PositionMethod =
        HolyAutoTrowelNormalizePositionMethod(
            value
        )

    HolyAutoTrowelCancelClickPosition(
        false
    )

    HolySaveFarmSettings()

    return HOLY_AUTO_TROWEL_STATE.PositionMethod
end

function HolyAutoTrowelSetSelectedPlants(value)

    HOLY_AUTO_TROWEL_STATE.SelectedPlants =
        HolyAutoTrowelNormalizeSelection(
            value
        )

    HolySaveFarmSettings()

    return HOLY_AUTO_TROWEL_STATE.SelectedPlants
end

function HolyAutoTrowelSetMoveAmount(value)

    HOLY_AUTO_TROWEL_STATE.MoveAmount =
        HolyAutoTrowelReadMoveAmount(
            value
        )

    HolySaveFarmSettings()

    return HOLY_AUTO_TROWEL_STATE.MoveAmount
end

function HolyAutoTrowelSetLayout(value)

    HOLY_AUTO_TROWEL_STATE.Layout =
        HolyAutoTrowelNormalizeLayout(
            value
        )

    HolySaveFarmSettings()

    HolyAutoTrowelRefreshLayoutUI()

    return HOLY_AUTO_TROWEL_STATE.Layout
