function HolyAutoTrowelSetSpacing(value)

    HOLY_AUTO_TROWEL_STATE.Spacing =
        HolyAutoTrowelReadSpacing(
            value
        )

    HolySaveFarmSettings()

    return HOLY_AUTO_TROWEL_STATE.Spacing
end

function HolyAutoTrowelResolvePackets()

    local runtime =
        HOLY_AUTO_TROWEL_RUNTIME

    if type(runtime.MovePacket) == "table"
    and type(runtime.MovePacket.Fire) == "function" then

        return runtime.MovePacket,
            runtime.RejectionPacket
    end

    local sharedModules =
        ReplicatedStorage:FindFirstChild(
            "SharedModules"
        )

    local networkingModule =
        sharedModules
        and sharedModules:FindFirstChild(
            "Networking"
        )

    if typeof(networkingModule) ~= "Instance"
    or networkingModule:IsA("ModuleScript") ~= true then

        return nil,
            nil,
            "SharedModules.Networking is missing."
    end

    local ok,
        networking =
        pcall(function()

            return require(
                networkingModule
            )
        end)

    if ok ~= true
    or type(networking) ~= "table" then

        return nil,
            nil,
            "Networking could not be loaded."
    end

    local trowelNetworking =
        networking.Trowel

    local movePacket =
        type(trowelNetworking) == "table"
        and trowelNetworking.MovePlant
        or nil

    if type(movePacket) ~= "table"
    or type(movePacket.Fire) ~= "function" then

        return nil,
            nil,
            "Trowel.MovePlant is missing."
    end

    runtime.MovePacket =
        movePacket

    runtime.RejectionPacket =
        trowelNetworking.MoveRejected
        or trowelNetworking.MovePlantRejected

    return runtime.MovePacket,
        runtime.RejectionPacket
end

function HolyAutoTrowelFindTool()

    local character =
        LocalPlayer.Character

    local backpack =
        LocalPlayer:FindFirstChildOfClass(
            "Backpack"
        )

    local function findIn(container)

        if typeof(container) ~= "Instance" then
            return nil
        end

        for _, child in ipairs(container:GetChildren()) do

            if child:IsA("Tool")
            and (
                child:GetAttribute("Trowel") ~= nil
                or tostring(child.Name):lower():find(
                    "trowel",
                    1,
                    true
                ) ~= nil
            ) then

                return child
            end
        end

        return nil
    end

    local tool =
        findIn(
            character
        )

    if tool then
        return tool
    end

    tool =
        findIn(
            backpack
        )

    if not tool then

        return nil,
            "A real Trowel was not found."
    end

    local humanoid =
        character
        and character:FindFirstChildOfClass(
            "Humanoid"
        )

    if typeof(humanoid) ~= "Instance" then

        return nil,
            "Your Humanoid is missing."
    end

    pcall(function()

        humanoid:EquipTool(
            tool
        )
    end)

    task.wait(
        0.15
    )

    if tool.Parent ~= character then

        return nil,
            "The Trowel could not be equipped."
    end

    return tool
end

function HolyAutoTrowelReadToolCount()

    local containers = {
        LocalPlayer.Character,
        LocalPlayer:FindFirstChildOfClass(
            "Backpack"
        ),
    }

    for _, container in ipairs(containers) do

        if typeof(container) == "Instance" then

            for _, child in ipairs(container:GetChildren()) do

                if child:IsA("Tool")
                and (
                    child:GetAttribute("Trowel") ~= nil
                    or tostring(child.Name):lower():find(
                        "trowel",
                        1,
                        true
                    ) ~= nil
                ) then

                    local count =
                        tonumber(
                            child:GetAttribute(
                                "Count"
                            )
                        )

                    if count then
                        return count
                    end
                end
            end
        end
    end

    return nil
end

function HolyAutoTrowelSelectedPlantMap()

    local map =
        {}

    for _, plantName in ipairs(
        HOLY_AUTO_TROWEL_STATE.SelectedPlants
        or {}
    ) do

        map[
            HolyCleanText(
                plantName
            )
        ] =
            true
    end

    return map
end

function HolyAutoTrowelBuildMoveList()

    local plot =
        HolyFarmResolveOwnPlot(
            false
        )

    local plantsFolder =
        plot
        and plot:FindFirstChild(
            "Plants"
        )

    if typeof(plantsFolder) ~= "Instance" then

        return {},
            "Your Plants folder is not ready."
    end

    local selected =
        HolyAutoTrowelSelectedPlantMap()

    local allPlants =
        selected["All Plants"] == true

    if allPlants ~= true
    and next(selected) == nil then

        return {},
            "Select at least one plant type."
    end

    local rows =
        {}

    for _, plant in ipairs(plantsFolder:GetChildren()) do

        if HolyAutoTrowelOwnsPlant(
            plant,
            plantsFolder
        ) == true then

            local plantType =
                HolyAutoTrowelReadPlantType(
                    plant
                )

            if allPlants == true
            or selected[plantType] == true then

                table.insert(rows, {
                    Plant =
                        plant,

                    PlantName =
                        plantType,

                    PlantId =
                        tostring(
                            plant.Name
                        ),
                })
            end
        end
    end

    table.sort(rows, function(a, b)

        if a.PlantName ~= b.PlantName then

            return tostring(a.PlantName):lower()
                < tostring(b.PlantName):lower()
        end

        return tostring(a.PlantId)
            < tostring(b.PlantId)
    end)

    local amount =
        HolyAutoTrowelReadMoveAmount(
            HOLY_AUTO_TROWEL_STATE.MoveAmount
        )

    if amount > 0
    and #rows > amount then

        local limited =
            {}

        for index = 1, amount do

            limited[index] =
                rows[index]
        end

        rows =
            limited
    end

    return rows
end

function HolyAutoTrowelGetDestination(target, index)

    local layout =
        HolyAutoTrowelNormalizeLayout(
            HOLY_AUTO_TROWEL_STATE.Layout
        )

    if layout ~= "Compact Spiral"
    or index <= 1 then

        return target
    end

    local spacing =
        HolyAutoTrowelReadSpacing(
            HOLY_AUTO_TROWEL_STATE.Spacing
        )

    if spacing <= 0 then
        return target
    end

    local angle =
        (index - 1)
        * 2.399963229728653

    local radius =
        spacing
        * math.sqrt(
            index - 1
        )

    return target
        + Vector3.new(
            math.cos(angle) * radius,
            0,
            math.sin(angle) * radius
        )
end

function HolyAutoTrowelPlantReachedTarget(plant, target)

    if typeof(plant) ~= "Instance"
    or plant.Parent == nil then

        return false
    end

    local ok,
        pivot =
        pcall(function()

            return plant:GetPivot()
        end)

    if ok ~= true then
        return false
    end

    return (
        pivot.Position
        - target
    ).Magnitude <= 0.15
end

function HolyAutoTrowelStop(notifyUser)

    local runtime =
        HOLY_AUTO_TROWEL_RUNTIME

    runtime.Token =
        nil

    HolyAutoTrowelCancelClickPosition(
        false
    )

    if notifyUser == true then

        HolyNotify(
            "Auto Trowel",
            runtime.Running == true
            and "Stopping Auto Trowel."
            or "Auto Trowel is not running.",
            3
        )
    end

    return true
end

function HolyAutoTrowelStart()

    local runtime =
        HOLY_AUTO_TROWEL_RUNTIME

    if runtime.Running == true then

        HolyNotify(
            "Auto Trowel",
            "Auto Trowel is already running.",
            3
        )

        return false
    end

    HolyAutoTrowelCancelClickPosition(
        false
    )

    local target,
        plot,
        anchor =
        HolyAutoTrowelGetWorldTarget()

    if typeof(target) ~= "Vector3" then

        HolyNotify(
            "Auto Trowel",
            tostring(plot),
            4
        )

        return false
    end

    local moveList,
        listReason =
        HolyAutoTrowelBuildMoveList()

    if #moveList <= 0 then

        HolyNotify(
            "Auto Trowel",
            tostring(
                listReason
                or "No matching plants were found."
            ),
            4
        )

        return false
    end

    local movePacket,
        rejectionPacket,
        packetReason =
        HolyAutoTrowelResolvePackets()

    if not movePacket then

        HolyNotify(
            "Auto Trowel",
            tostring(packetReason),
            4
        )

        return false
    end

    local tool,
        toolReason =
        HolyAutoTrowelFindTool()

    if not tool then

        HolyNotify(
            "Auto Trowel",
            tostring(toolReason),
            4
        )

        return false
    end

    local toolCount =
        HolyAutoTrowelReadToolCount()

    if toolCount
    and toolCount < #moveList then

        HolyNotify(
            "Auto Trowel",
            "Not enough Trowel uses. Need "
                .. tostring(#moveList)
                .. ", have "
                .. tostring(toolCount)
                .. ".",
            5
        )

        return false
    end

    local entries =
        {}

    for index, row in ipairs(moveList) do

        local destination =
            HolyAutoTrowelGetDestination(
                target,
                index
            )

        if HolyAutoTrowelPointInsideAnchor(
            destination,
            anchor
        ) ~= true then

            HolyNotify(
                "Auto Trowel",
                "The selected layout leaves your garden. Reduce the amount or spacing.",
                5
            )

            return false
        end

        local pivot =
            row.Plant:GetPivot()

        local _,
            yawRadians =
            pivot:ToOrientation()

        entries[index] = {
            Plant =
                row.Plant,

            PlantId =
                row.PlantId,

            Destination =
                destination,

            RotationDegrees =
                math.deg(
                    yawRadians
                ),

            Sent =
                false,

            Rejected =
                false,
        }
    end

    runtime.Running =
        true

    runtime.Token =
        {}

    local token =
        runtime.Token

    local rejected =
        {}

    HolyAutoTrowelDisconnect(
        runtime.RejectionConnection
    )

    runtime.RejectionConnection =
        nil

    local rejectionSignal =
        rejectionPacket
        and rejectionPacket.OnClientEvent

    if rejectionSignal
    and type(rejectionSignal.Connect) == "function" then

        local connection =
            rejectionSignal:Connect(function(plantId)

                plantId =
                    tostring(
                        plantId
                        or ""
                    )

                rejected[plantId] =
                    true
            end)

        runtime.RejectionConnection =
            connection
    end

    HolyNotify(
        "Auto Trowel",
        "Moving "
            .. tostring(#entries)
            .. " plant"
            .. (
                #entries == 1
                and ""
                or "s"
            )
            .. ".",
        3
    )

    task.spawn(function()

        local batchSize =
            8

        for index, entry in ipairs(entries) do

            if runtime.Token ~= token then
                break
            end

            local ok =
                pcall(function()

                    movePacket:Fire(
                        entry.PlantId,
                        entry.Destination,
                        entry.RotationDegrees
                    )
                end)

            entry.Sent =
                ok == true

            if ok ~= true then

                entry.FireFailed =
                    true
            end

            if index % batchSize == 0
            and index < #entries then

                task.wait()
            end
        end

        task.wait(
            0.75
        )

        if runtime.Token ~= token then

            if runtime.RejectionConnection then

                HolyAutoTrowelDisconnect(
                    runtime.RejectionConnection
                )

                runtime.RejectionConnection =
                    nil
            end

            runtime.Running =
                false

            return
        end

        local retry =
            {}

        for _, entry in ipairs(entries) do

            entry.Rejected =
                rejected[entry.PlantId] == true

            if entry.Sent ~= true
            or HolyAutoTrowelPlantReachedTarget(
                entry.Plant,
                entry.Destination
            ) ~= true then

                table.insert(
                    retry,
                    entry
                )
            end
        end

        for index, entry in ipairs(retry) do

            if runtime.Token ~= token then
                break
            end

            pcall(function()

                movePacket:Fire(
                    entry.PlantId,
                    entry.Destination,
                    entry.RotationDegrees
                )
            end)

            if index % batchSize == 0
            and index < #retry then

                task.wait()
            end
        end

        if #retry > 0 then

            task.wait(
                0.75
            )
        end

        local moved =
            0

        local failed =
            0

        for _, entry in ipairs(entries) do

            if HolyAutoTrowelPlantReachedTarget(
                entry.Plant,
                entry.Destination
            ) == true then

                moved =
                    moved + 1

            else

                failed =
                    failed + 1
            end
        end

        local stopped =
            runtime.Token ~= token

        if runtime.Token == token then

            runtime.Token =
                nil
        end

        runtime.Running =
            false

        HolyAutoTrowelDisconnect(
            runtime.RejectionConnection
        )

        runtime.RejectionConnection =
            nil

        HolyAutoTrowelRefreshPlantDropdown()

        if stopped ~= true then

            if failed <= 0 then

                HolyNotify(
                    "Auto Trowel",
                    "Moved "
                        .. tostring(moved)
                        .. " plant"
                        .. (
                            moved == 1
                            and ""
                            or "s"
                        )
                        .. " successfully.",
                    4
                )

            else

                HolyNotify(
                    "Auto Trowel",
                    "Moved "
                        .. tostring(moved)
                        .. ". Failed "
                        .. tostring(failed)
                        .. ".",
                    5
                )
            end
        end
    end)

    return true
end

--==================================================
-- [2.13] FARM / FRUIT DROP & PICKUP CORE
--==================================================

function HolyFruitAutomationCleanDisplayName(value)

    local text =
        HolyCleanText(
            value
        )

    text =
        text:gsub(
            "%s*%[[^%]]+%]",
            ""
        )

    text =
        text:gsub(
            "%s*%([^%)]+%)",
            ""
        )

    return HolyCleanText(
        text
    )
end

function HolyFruitAutomationReadNumber(value)

    if type(value) == "number" then
        return value
    end

    local text =
        tostring(value or "")

    local number =
        tonumber(
            text:match("%d+%.?%d*")
        )

    return tonumber(number)
        or 0
end

function HolyFruitAutomationReadDropLimit(value)

    local number =
        math.floor(
            HolyFruitAutomationReadNumber(
                value
            )
        )

    return math.max(
        0,
        number
    )
end

function HolyFruitAutomationDecodeData(raw)

    if type(raw) == "table" then
        return raw
    end

    if type(raw) ~= "string"
    or raw == "" then

        return {}
    end

    local ok,
        decoded =
        pcall(function()

            return HttpService:JSONDecode(
                raw
            )
        end)

    if ok == true
    and type(decoded) == "table" then

        return decoded
    end

    return {}
end

function HolyFruitAutomationReadAttribute(instance, names)

    if typeof(instance) ~= "Instance" then
        return nil
    end

    for _, name in ipairs(names or {}) do

        local ok,
            value =
            pcall(function()

                return instance:GetAttribute(
                    name
                )
            end)

        if ok == true
        and value ~= nil
        and tostring(value) ~= "" then

            return value
        end
    end

    return nil
end

function HolyFruitAutomationNormalizeFruitName(value)

    value =
        HolyCleanText(
            value
        )

    if value == "" then
        return ""
    end

    if type(HolyFarmNormalizePlantName) == "function" then

        return HolyFarmNormalizePlantName(
            value
        )
    end

    return value
end

function HolyFruitAutomationNormalizeFruitSelection(value)

    local raw =
        HolyShopSelectionArray(
            value
        )

    if #raw <= 0 then
        return {}
    end

    for _, fruitName in ipairs(raw) do

        if fruitName == "All" then
            return {}
        end
    end

    local validMap =
        {}

    if type(HolyFarmGetPlantValueMap) == "function" then

        validMap =
            HolyFarmGetPlantValueMap()
    end

    local output =
        {}

    local seen =
        {}

    for _, fruitName in ipairs(raw) do

        fruitName =
            HolyFruitAutomationNormalizeFruitName(
                fruitName
            )

        if fruitName ~= ""
        and fruitName ~= "All"
        and seen[fruitName] ~= true
        and (
            next(validMap) == nil
            or validMap[fruitName] == true
        ) then

            seen[fruitName] =
                true

            table.insert(
                output,
                fruitName
            )
        end
    end

    table.sort(output, function(a, b)

        return tostring(a):lower()
            < tostring(b):lower()
    end)

    return output
end

function HolyFruitAutomationNormalizeMutationSelection(value)

    local raw =
        HolyShopSelectionArray(
            value
        )

    if #raw <= 0 then
        return {}
    end

    for _, mutationName in ipairs(raw) do

        if mutationName == "All" then
            return {}
        end
    end

    local validMap =
        {}

    if type(HolyFarmGetMutationValueMap) == "function" then

        validMap =
            HolyFarmGetMutationValueMap()
    end

    local output =
        {}

    local seen =
        {}

    for _, mutationName in ipairs(raw) do

        if type(HolyFarmNormalizeMutationName) == "function" then

            mutationName =
                HolyFarmNormalizeMutationName(
                    mutationName
                )

        else

            mutationName =
                HolyCleanText(
                    mutationName
                )
        end

        if mutationName ~= ""
        and mutationName ~= "All"
        and seen[mutationName] ~= true
        and (
            next(validMap) == nil
            or validMap[mutationName] == true
        ) then

            seen[mutationName] =
                true

            table.insert(
                output,
                mutationName
            )
        end
    end

    table.sort(output, function(a, b)

        return tostring(a):lower()
            < tostring(b):lower()
    end)

    return output
end

function HolyFruitAutomationNormalizeWeightMode(value)

    local mode =
        HolyFarmNormalizeWeightMode(
            value
        )

    if mode == "Below" then
        return "Below"
    end

    return "Above"
end

function HolyFruitAutomationNormalizeValueMode(value)

    local mode =
        HolyFarmNormalizeWeightMode(
            value
        )

    if mode == "Above" then
        return "Above"
    end

    return "Below"
end

function HolyFruitAutomationReadValueThreshold(value)

    if type(HolySniperReadMaxPrice) == "function" then

        return HolySniperReadMaxPrice(
            value
        )
    end

    local text =
        HolyCleanText(
            value
        )

    text =
        text:gsub("¢", "")
            :gsub("%$", "")
            :gsub(",", "")
            :gsub("%s+", "")

    local lower =
        text:lower()

    if lower == ""
    or lower == "0"
    or lower == "none"
    or lower == "off"
    or lower == "no" then

        return 0
    end

    local multiplier =
        1

    if lower:find("b", 1, true) then

        multiplier =
            1000000000

    elseif lower:find("m", 1, true) then

        multiplier =
            1000000

    elseif lower:find("k", 1, true) then

        multiplier =
            1000
    end

    local rawNumber =
        lower:match("%d+%.?%d*")

    local number =
        tonumber(rawNumber)

    if number == nil then
        return 0
    end

    return math.max(
        0,
        math.floor(number * multiplier + 0.5)
    )
end

function HolyFruitAutomationBuildMutationText(info)

    info =
        type(info) == "table"
        and info
        or {}

    if HolyCleanText(info.RawMutation) ~= "" then

        return HolyCleanText(
            info.RawMutation
        )
    end

    local mutations =
        type(info.Mutations) == "table"
        and info.Mutations
        or {}

    local output =
        {}

    for _, mutationName in ipairs(mutations) do

        mutationName =
            HolyCleanText(
                mutationName
            )

        if mutationName ~= "" then

            table.insert(
                output,
                mutationName
            )
        end
    end

    return table.concat(
        output,
        ","
    )
end

function HolyFruitAutomationReadSizeMultiplierFromInfo(info)

    info =
        type(info) == "table"
        and info
        or {}

    local tool =
        info.Tool
        or info.Instance

    if typeof(tool) == "Instance" then

        local sizeMultiplier =
            tonumber(
                HolyFruitAutomationReadAttribute(
                    tool,
                    {
                        "SizeMultiplier",
                        "SizeMulti",
                        "ScaleMultiplier",
                        "ScaleMulti",
                        "Scale",
                        "SizeScale",
                    }
                )
            )

        if sizeMultiplier ~= nil
        and sizeMultiplier > 0 then

            return sizeMultiplier
        end
    end

    local weight =
        tonumber(
            info.WeightKg
        )
        or 0

    if weight > 0 then

        return math.max(
            0.01,
            weight
        )
    end

    return 1
end

function HolyFruitAutomationCalculateInfoValue(info)

    info =
        type(info) == "table"
        and info
        or {}

    local cached =
        tonumber(
            info.ValueNumber
            or info.Value
        )

    if cached ~= nil
    and cached > 0 then

        return cached
    end

    local tool =
        info.Tool
        or info.Instance

    local value =
        nil

    if type(HolyVisualReadFruitTool) == "function"
    and typeof(tool) == "Instance"
    and tool:IsA("Tool") then

        local ok,
            row =
            pcall(function()

                return HolyVisualReadFruitTool(
                    tool,
                    0
                )
            end)

        if ok == true
        and type(row) == "table" then

            value =
                tonumber(
                    row.Value
                )

            if value ~= nil
            and value > 0 then

                info.ValueNumber =
                    value

                info.ValueText =
                    row.ValueText
                    or (
                        type(HolyVisualFormatFruitValue) == "function"
                        and HolyVisualFormatFruitValue(value)
                    )
                    or tostring(value)

                return value
            end
        end
    end

    if value == nil
    and type(HolyVisualCalculateFruitValue) == "function" then

        local row = {
            Tool =
                tool,

            Name =
                HolyFruitAutomationNormalizeFruitName(
                    info.FruitName
                    or info.Name
                    or info.DisplayName
                ),

            RawName =
                HolyCleanText(
                    info.DisplayName
                    or info.FruitName
                    or ""
                ),

            RawMutation =
                HolyFruitAutomationBuildMutationText(
                    info
                ),

            Weight =
                tonumber(
                    info.WeightKg
                )
                or 0,

            SizeMultiplier =
                HolyFruitAutomationReadSizeMultiplierFromInfo(
                    info
                ),

            Index =
                0,
        }

        local ok,
            result =
            pcall(function()

                return HolyVisualCalculateFruitValue(
                    tool,
                    row
                )
            end)

        result =
            tonumber(result)

        if ok == true
        and result ~= nil
        and result > 0 then

            value =
                result
        end
    end

    value =
        tonumber(value)

    if value == nil
    or value <= 0 then

        return nil
    end

    value =
        math.floor(value + 0.5)

    info.ValueNumber =
        value

    if type(HolyVisualFormatFruitValue) == "function" then

        info.ValueText =
            HolyVisualFormatFruitValue(
                value
            )

    else

        info.ValueText =
            tostring(value)
    end

    return value
end

function HolyFruitAutomationPassesDropValueFilter(info)

    HolyFruitAutomationEnsureState()

    local threshold =
        HolyFruitAutomationReadValueThreshold(
            HOLY_FRUIT_AUTOMATION_STATE.ValueThreshold
            or "0"
        )

    if threshold <= 0 then
        return true
    end

    local value =
        HolyFruitAutomationCalculateInfoValue(
            info
        )

    if value == nil
    or value <= 0 then

        return false
    end

    local mode =
        HolyFruitAutomationNormalizeValueMode(
            HOLY_FRUIT_AUTOMATION_STATE.ValueMode
            or "Below"
        )

    if mode == "Above" then

        return value >= threshold
    end

    return value <= threshold
end

function HolyFruitAutomationPassesDropFilters(info)

    if HolyFruitAutomationPassesFilters(
        info
    ) ~= true then

        return false
    end

    return HolyFruitAutomationPassesDropValueFilter(
        info
    ) == true
end

function HolyFruitAutomationEnsureState()

    HOLY_FRUIT_AUTOMATION_STATE =
        type(HOLY_FRUIT_AUTOMATION_STATE) == "table"
        and HOLY_FRUIT_AUTOMATION_STATE
        or {}

    HOLY_FRUIT_AUTOMATION_STATE.AutoDropFruits =
        HOLY_FRUIT_AUTOMATION_STATE.AutoDropFruits == true

    HOLY_FRUIT_AUTOMATION_STATE.AutoCollectDroppedFruits =
        HOLY_FRUIT_AUTOMATION_STATE.AutoCollectDroppedFruits == true

    if HOLY_FRUIT_AUTOMATION_STATE.PickupMovement
        ~= "Nearby Only"
    and HOLY_FRUIT_AUTOMATION_STATE.PickupMovement
        ~= "Walk to Fruits" then

        HOLY_FRUIT_AUTOMATION_STATE.PickupMovement =
            "Nearby Only"
    end

    HOLY_FRUIT_AUTOMATION_STATE.SelectedFruits =
        HolyFruitAutomationNormalizeFruitSelection(
            HOLY_FRUIT_AUTOMATION_STATE.SelectedFruits
            or {}
        )

    HOLY_FRUIT_AUTOMATION_STATE.SelectedMutations =
        HolyFruitAutomationNormalizeMutationSelection(
            HOLY_FRUIT_AUTOMATION_STATE.SelectedMutations
            or {}
        )

    HOLY_FRUIT_AUTOMATION_STATE.WeightKg =
        tostring(
            HolyFarmReadWeightThresholdKg(
                HOLY_FRUIT_AUTOMATION_STATE.WeightKg
                or "0"
            )
        )

    HOLY_FRUIT_AUTOMATION_STATE.WeightMode =
        HolyFruitAutomationNormalizeWeightMode(
            HOLY_FRUIT_AUTOMATION_STATE.WeightMode
            or "Above"
        )

    HOLY_FRUIT_AUTOMATION_STATE.ValueMode =
        HolyFruitAutomationNormalizeValueMode(
            HOLY_FRUIT_AUTOMATION_STATE.ValueMode
            or "Below"
        )

    HOLY_FRUIT_AUTOMATION_STATE.ValueThreshold =
        tostring(
            HolyFruitAutomationReadValueThreshold(
                HOLY_FRUIT_AUTOMATION_STATE.ValueThreshold
                or "0"
            )
        )

    HOLY_FRUIT_AUTOMATION_STATE.DropLimit =
        tostring(
            HolyFruitAutomationReadDropLimit(
                HOLY_FRUIT_AUTOMATION_STATE.DropLimit
                or "0"
            )
        )

    return HOLY_FRUIT_AUTOMATION_STATE
end

function HolyFruitAutomationEnsureRuntime()

    HOLY_FRUIT_AUTOMATION_RUNTIME =
        type(HOLY_FRUIT_AUTOMATION_RUNTIME) == "table"
        and HOLY_FRUIT_AUTOMATION_RUNTIME
        or {}

    local runtime =
        HOLY_FRUIT_AUTOMATION_RUNTIME

    runtime.DroppedConnections =
        type(runtime.DroppedConnections) == "table"
        and runtime.DroppedConnections
        or {}

    runtime.DroppedCache =
        type(runtime.DroppedCache) == "table"
        and runtime.DroppedCache
        or {}

    runtime.DroppedLastAttempt =
        type(runtime.DroppedLastAttempt) == "table"
        and runtime.DroppedLastAttempt
        or {}

    runtime.DropLastAttempt =
        type(runtime.DropLastAttempt) == "table"
        and runtime.DropLastAttempt
        or {}

    runtime.DroppedThisRun =
        tonumber(runtime.DroppedThisRun)
        or 0

    runtime.PickupRange3D =
        math.clamp(
            tonumber(runtime.PickupRange3D)
            or 14.75,
            10,
            15.25
        )

    runtime.PickupHorizontalRange =
        math.clamp(
            tonumber(runtime.PickupHorizontalRange)
            or 14.75,
            10,
            15.25
        )

    runtime.PickupVerticalRange =
        math.clamp(
            tonumber(runtime.PickupVerticalRange)
            or 25,
            5,
            60
        )

    runtime.PickupScanDelay =
        math.clamp(
            tonumber(runtime.PickupScanDelay)
            or 0.06,
            0.04,
            0.50
        )

    runtime.PickupRetryDelay =
        math.clamp(
            tonumber(runtime.PickupRetryDelay)
            or 1.75,
            0.35,
            6
        )

    runtime.PickupResultTimeout =
        math.clamp(
            tonumber(runtime.PickupResultTimeout)
            or 2.35,
            0.75,
            6
        )

    runtime.DropScanDelay =
        math.clamp(
            tonumber(runtime.DropScanDelay)
            or 0.20,
            0.08,
            1.50
        )

    runtime.DropRetryDelay =
        math.clamp(
            tonumber(runtime.DropRetryDelay)
            or 1.15,
            0.35,
            6
        )

    runtime.DropRunning =
        runtime.DropRunning == true

    runtime.PickupRunning =
        runtime.PickupRunning == true

    runtime.PickupOwnsMovement =
        runtime.PickupOwnsMovement == true

    runtime.PickupMoving =
        runtime.PickupMoving == true

    runtime.PickupLastMoveAt =
        tonumber(
            runtime.PickupLastMoveAt
        )
        or 0

    runtime.PickupMoveInterval =
        math.clamp(
            tonumber(
                runtime.PickupMoveInterval
            )
            or 0.15,
            0.08,
            0.50
        )

    return runtime
end

function HolySaveFruitAutomationSettings()

    if HolyCanUseFiles() ~= true then
        return false
    end

    HolyEnsureFolder()
    HolyFruitAutomationEnsureState()

    local payload = {
        AutoDropFruits =
            HOLY_FRUIT_AUTOMATION_STATE.AutoDropFruits == true,

        AutoCollectDroppedFruits =
            HOLY_FRUIT_AUTOMATION_STATE.AutoCollectDroppedFruits == true,

        PickupMovement =
            HOLY_FRUIT_AUTOMATION_STATE.PickupMovement,

        SelectedFruits =
            HolyShopSelectionArray(
                HOLY_FRUIT_AUTOMATION_STATE.SelectedFruits
            ),

        SelectedMutations =
            HolyShopSelectionArray(
                HOLY_FRUIT_AUTOMATION_STATE.SelectedMutations
            ),

        WeightKg =
            tostring(
                HolyFarmReadWeightThresholdKg(
                    HOLY_FRUIT_AUTOMATION_STATE.WeightKg
                )
            ),

        WeightMode =
            HolyFruitAutomationNormalizeWeightMode(
                HOLY_FRUIT_AUTOMATION_STATE.WeightMode
            ),

        ValueMode =
            HolyFruitAutomationNormalizeValueMode(
                HOLY_FRUIT_AUTOMATION_STATE.ValueMode
            ),

        ValueThreshold =
            tostring(
                HolyFruitAutomationReadValueThreshold(
                    HOLY_FRUIT_AUTOMATION_STATE.ValueThreshold
                )
            ),

        DropLimit =
            tostring(
                HolyFruitAutomationReadDropLimit(
                    HOLY_FRUIT_AUTOMATION_STATE.DropLimit
                )
            ),
    }

    local encodeOk,
        encoded =
        pcall(function()

            return HttpService:JSONEncode(
                payload
            )
        end)

    if encodeOk ~= true
    or type(encoded) ~= "string" then

        return false
    end

    local writeOk =
        pcall(function()

            writefile(
                FRUIT_AUTOMATION_SETTINGS_FILE,
                encoded
            )
        end)

    return writeOk == true
end

function HolyLoadFruitAutomationSettings()

    if HolyCanUseFiles() ~= true then
        return false
    end

    local exists =
        false

    pcall(function()

        exists =
            isfile(
                FRUIT_AUTOMATION_SETTINGS_FILE
            )
    end)

    if exists ~= true then
        return false
    end

    local readOk,
        raw =
        pcall(function()

            return readfile(
                FRUIT_AUTOMATION_SETTINGS_FILE
            )
        end)

    if readOk ~= true
    or type(raw) ~= "string"
    or raw == "" then

        return false
    end

    local decodeOk,
        data =
        pcall(function()

            return HttpService:JSONDecode(
                raw
            )
        end)

    if decodeOk ~= true
    or type(data) ~= "table" then

        return false
    end

    HOLY_FRUIT_AUTOMATION_STATE.AutoDropFruits =
        data.AutoDropFruits == true

    HOLY_FRUIT_AUTOMATION_STATE.AutoCollectDroppedFruits =
        data.AutoCollectDroppedFruits == true
        or data.AutoPickupDroppedFruits == true
        or data.CollectDroppedFruits == true

    HOLY_FRUIT_AUTOMATION_STATE.PickupMovement =
        tostring(
            data.PickupMovement
            or "Nearby Only"
        )

    HOLY_FRUIT_AUTOMATION_STATE.SelectedFruits =
        HolyFruitAutomationNormalizeFruitSelection(
            data.SelectedFruits
            or data.Fruits
            or {}
        )

    HOLY_FRUIT_AUTOMATION_STATE.SelectedMutations =
        HolyFruitAutomationNormalizeMutationSelection(
            data.SelectedMutations
            or data.Mutations
            or {}
        )

    HOLY_FRUIT_AUTOMATION_STATE.WeightKg =
        tostring(
            HolyFarmReadWeightThresholdKg(
                data.WeightKg
                or "0"
            )
        )

    HOLY_FRUIT_AUTOMATION_STATE.WeightMode =
        HolyFruitAutomationNormalizeWeightMode(
            data.WeightMode
            or "Above"
        )

    HOLY_FRUIT_AUTOMATION_STATE.ValueMode =
        HolyFruitAutomationNormalizeValueMode(
            data.ValueMode
            or data.DropValueMode
            or "Below"
        )

    HOLY_FRUIT_AUTOMATION_STATE.ValueThreshold =
        tostring(
            HolyFruitAutomationReadValueThreshold(
                data.ValueThreshold
                or data.DropValueThreshold
                or data.Value
                or data.MinValue
                or data.MaxValue
                or "0"
            )
        )

    HOLY_FRUIT_AUTOMATION_STATE.DropLimit =
        tostring(
            HolyFruitAutomationReadDropLimit(
                data.DropLimit
                or "0"
            )
        )

    HolyFruitAutomationEnsureState()

    return true
end

function HolyFruitAutomationGetFruitDropdownValues()

    local values = {
        "All",
    }

    for _, fruitName in ipairs(
        HolyFarmGetPlantDropdownValues()
    ) do

        table.insert(
            values,
            fruitName
        )
    end

    return values
end

function HolyFruitAutomationGetMutationDropdownValues()

    local values = {
        "All",
    }

    for _, mutationName in ipairs(
        HolyFarmGetMutationDropdownValues()
    ) do

        table.insert(
            values,
            mutationName
        )
    end

    return values
end

function HolyFruitAutomationSelectedFruitMap()

    HolyFruitAutomationEnsureState()

    local map =
        {}

    for _, fruitName in ipairs(
        HOLY_FRUIT_AUTOMATION_STATE.SelectedFruits
        or {}
    ) do

        fruitName =
            HolyFruitAutomationNormalizeFruitName(
                fruitName
            )

        if fruitName ~= "" then

            map[fruitName] =
                true
        end
    end

    return map
end

function HolyFruitAutomationSelectedMutationMap()

    HolyFruitAutomationEnsureState()

    local map =
        {}

    for _, mutationName in ipairs(
        HOLY_FRUIT_AUTOMATION_STATE.SelectedMutations
        or {}
    ) do

        if type(HolyFarmNormalizeMutationName) == "function" then

            mutationName =
                HolyFarmNormalizeMutationName(
                    mutationName
                )

        else

            mutationName =
                HolyCleanText(
                    mutationName
                )
        end

        if mutationName ~= "" then

            map[mutationName] =
                true
        end
    end

    return map
end

function HolyFruitAutomationAddMutation(output, seen, value)

    output =
        type(output) == "table"
        and output
        or {}

    seen =
        type(seen) == "table"
        and seen
        or {}

    if type(value) == "table" then

        for key, childValue in pairs(value) do

            if type(key) == "number" then

                HolyFruitAutomationAddMutation(
                    output,
                    seen,
                    childValue
                )

            elseif childValue == true then

                HolyFruitAutomationAddMutation(
                    output,
                    seen,
                    key
                )
            end
        end

        return output
    end

    for _, part in ipairs(
        HolyFarmSplitMutationText(
            value
        )
    ) do

        local mutation =
            HolyFarmNormalizeMutationName(
                part
            )

        if mutation ~= ""
        and seen[mutation] ~= true then

            seen[mutation] =
                true

            table.insert(
                output,
                mutation
            )
        end
    end

    return output
end

function HolyFruitAutomationReadBracketMutations(displayName, output, seen)

    displayName =
        tostring(displayName or "")

    for bracket in displayName:gmatch("%[([^%]]+)%]") do

        local lower =
            bracket:lower()

        if lower:find("kg", 1, true) == nil then

            HolyFruitAutomationAddMutation(
                output,
                seen,
                bracket
            )
        end
    end

    return output
end

function HolyFruitAutomationReadCommonFruitInfo(instance, fallbackName)

    if typeof(instance) ~= "Instance" then
        return nil
    end

    local fruitData =
        HolyFruitAutomationDecodeData(
            HolyFruitAutomationReadAttribute(
                instance,
                {
                    "FruitData",
                    "ItemData",
                    "Data",
                }
            )
        )

    local displayName =
        HolyCleanText(
            HolyFruitAutomationReadAttribute(
                instance,
                {
                    "DisplayName",
                    "ItemName",
                    "Name",
                }
            )
            or fallbackName
            or instance.Name
        )

    local fruitName =
        HolyCleanText(
            fruitData.FruitName
            or fruitData.Fruit
            or fruitData.Name
            or HolyFruitAutomationReadAttribute(
                instance,
                {
                    "FruitName",
                    "SeedName",
                    "PlantName",
                    "CropName",
                    "ItemName",
                }
            )
            or ""
        )

    if fruitName == "" then

        fruitName =
            HolyFruitAutomationCleanDisplayName(
                displayName
            )
    end

    fruitName =
        HolyFruitAutomationNormalizeFruitName(
            fruitName
        )

    if fruitName == "" then
        return nil
    end

    local weight =
        tonumber(
            fruitData.Weight
            or fruitData.WeightKg
            or fruitData.Kg
            or fruitData.Mass
            or HolyFruitAutomationReadAttribute(
                instance,
                {
                    "Weight",
                    "WeightKg",
                    "Kg",
                    "Mass",
                }
            )
        )

    if weight == nil then

        weight =
            tonumber(
                tostring(displayName):match("([%d%.]+)%s*[Kk][Gg]")
            )
            or tonumber(
                tostring(instance.Name):match("([%d%.]+)%s*[Kk][Gg]")
            )
    end

    local mutations =
        {}

    local seen =
        {}

    HolyFruitAutomationAddMutation(
        mutations,
        seen,
        fruitData.Mutation
        or fruitData.Mutations
        or fruitData.Variant
        or fruitData.Type
        or HolyFruitAutomationReadAttribute(
            instance,
            {
                "Mutation",
                "Mutations",
                "Variant",
                "Type",
            }
        )
        or ""
    )

    HolyFruitAutomationReadBracketMutations(
        displayName,
        mutations,
        seen
    )

    table.sort(mutations, function(a, b)

        return tostring(a):lower()
            < tostring(b):lower()
    end)

    return {
        Instance =
            instance,

        FruitName =
            fruitName,

        DisplayName =
            displayName ~= ""
            and displayName
            or fruitName,

        WeightKg =
            tonumber(weight)
            or 0,

        Mutations =
            mutations,

        HadFruitData =
            next(fruitData) ~= nil,
    }
end

function HolyFruitAutomationLooksLikeFruit(info)

    if type(info) ~= "table" then
        return false
    end

    local fruitName =
        HolyFruitAutomationNormalizeFruitName(
            info.FruitName
        )

    if fruitName == "" then
        return false
    end

    local validMap =
        {}

    if type(HolyFarmGetPlantValueMap) == "function" then

        validMap =
            HolyFarmGetPlantValueMap()
    end

    if next(validMap) == nil then
        return true
    end

    if validMap[fruitName] == true then
        return true
    end

    return info.HadFruitData == true
end

function HolyFruitAutomationMutationListHasSelected(mutations, selectedMap)

    if type(mutations) ~= "table"
    or type(selectedMap) ~= "table" then

        return false
    end

    for _, mutation in ipairs(mutations) do

        if selectedMap[mutation] == true then
            return true
        end
    end

    return false
end

function HolyFruitAutomationPassesFilters(info)

    HolyFruitAutomationEnsureState()

    if type(info) ~= "table" then
        return false
    end

    if HolyFruitAutomationLooksLikeFruit(
        info
    ) ~= true then

        return false
    end

    local selectedFruits =
        HOLY_FRUIT_AUTOMATION_STATE.SelectedFruits
        or {}

    if #selectedFruits > 0 then

        local fruitMap =
            HolyFruitAutomationSelectedFruitMap()

        if fruitMap[
            HolyFruitAutomationNormalizeFruitName(
                info.FruitName
            )
        ] ~= true then

            return false
        end
    end

    local selectedMutations =
        HOLY_FRUIT_AUTOMATION_STATE.SelectedMutations
        or {}

    if #selectedMutations > 0 then

        local mutationMap =
            HolyFruitAutomationSelectedMutationMap()

        if HolyFruitAutomationMutationListHasSelected(
            info.Mutations,
            mutationMap
        ) ~= true then

            return false
        end
    end

    local threshold =
        HolyFarmReadWeightThresholdKg(
            HOLY_FRUIT_AUTOMATION_STATE.WeightKg
        )

    if threshold > 0 then

        local weight =
            tonumber(info.WeightKg)

        if weight == nil then
            return false
        end

        local mode =
            HolyFruitAutomationNormalizeWeightMode(
                HOLY_FRUIT_AUTOMATION_STATE.WeightMode
            )

        if mode == "Below" then
            return weight <= threshold
        end

        return weight >= threshold
    end

    return true
end

function HolyFruitAutomationGetCharacter()

    return LocalPlayer
        and LocalPlayer.Character
        or nil
end

function HolyFruitAutomationGetHumanoid()

    local character =
        HolyFruitAutomationGetCharacter()

    if typeof(character) ~= "Instance" then
        return nil
    end

    return character:FindFirstChildOfClass(
        "Humanoid"
    )
end

function HolyFruitAutomationGetRoot()

    local character =
        HolyFruitAutomationGetCharacter()

    if typeof(character) ~= "Instance" then
        return nil
    end

    return character:FindFirstChild(
        "HumanoidRootPart"
    )
    or character:FindFirstChild(
        "RootPart"
    )
    or character.PrimaryPart
end

function HolyFruitAutomationReadToolInfo(tool)

    if typeof(tool) ~= "Instance" then

        return nil
    end

    local isTool =
        tool:IsA("Tool")

    local isFruitProxy =
        tool:IsA("Configuration")
        and tool:GetAttribute("FruitProxy") == true

    if isTool ~= true
    and isFruitProxy ~= true then

        return nil
    end

    if tool:GetAttribute("HarvestedFruit") ~= true then

        return nil
    end

    local fruitId =
        tostring(
            tool:GetAttribute("Id")
            or ""
        )

    if fruitId == "" then

        return nil
    end

    local info =
        HolyFruitAutomationReadCommonFruitInfo(
            tool,
            tool.Name
        )

    if HolyFruitAutomationLooksLikeFruit(
        info
    ) ~= true then

        return nil
    end

    info.Tool =
        tool

    info.FruitId =
        fruitId

    info.IsFruitProxy =
        isFruitProxy

    return info
end

function HolyFruitAutomationGetFruitTools()

    local tools =
        {}

    local containers =
        {}

    local character =
        HolyFruitAutomationGetCharacter()

    if typeof(character) == "Instance" then

        table.insert(
            containers,
            character
        )
    end

    local backpack =
        LocalPlayer
        and LocalPlayer:FindFirstChildOfClass(
            "Backpack"
        )
        or nil

    if typeof(backpack) == "Instance" then

        table.insert(
            containers,
            backpack
        )
    end

    for _, container in ipairs(containers) do

        for _, child in ipairs(container:GetChildren()) do

            local info =
                HolyFruitAutomationReadToolInfo(
                    child
                )

            if HolyFruitAutomationPassesDropFilters(
                info
            ) == true then

                HolyFruitAutomationCalculateInfoValue(
                    info
                )

                table.insert(
                    tools,
                    info
                )
            end
        end
    end

    local valueThreshold =
        HolyFruitAutomationReadValueThreshold(
            HOLY_FRUIT_AUTOMATION_STATE.ValueThreshold
            or "0"
        )

    local valueMode =
        HolyFruitAutomationNormalizeValueMode(
            HOLY_FRUIT_AUTOMATION_STATE.ValueMode
            or "Below"
        )

    table.sort(tools, function(a, b)

        if valueThreshold > 0 then

            local valueA =
                tonumber(
                    a.ValueNumber
                    or HolyFruitAutomationCalculateInfoValue(a)
                )
                or 0

            local valueB =
                tonumber(
                    b.ValueNumber
                    or HolyFruitAutomationCalculateInfoValue(b)
                )
                or 0

            if valueA ~= valueB then

                if valueMode == "Below" then

                    return valueA < valueB
                end

                return valueA > valueB
            end
        end

        local weightA =
            tonumber(a.WeightKg)
            or 0

        local weightB =
            tonumber(b.WeightKg)
            or 0

        if weightA ~= weightB then
            return weightA > weightB
        end

        return tostring(a.FruitName)
            < tostring(b.FruitName)
    end)

    return tools
end

function HolyFruitAutomationInputManager()

    if type(HolyLoadingGetInputManager) == "function" then

        local manager =
            HolyLoadingGetInputManager()

        if manager then
            return manager
        end
    end

    local ok,
        manager =
        pcall(function()

            return game:GetService(
                "VirtualInputManager"
            )
        end)

    if ok == true then
        return manager
    end

    return nil
end

function HolyFruitAutomationPressBackspace()

    local inputManager =
        HolyFruitAutomationInputManager()

    if not inputManager then
        return false
    end

    local ok =
        pcall(function()

            inputManager:SendKeyEvent(
                true,
                Enum.KeyCode.Backspace,
                false,
                game
            )

            task.wait(
                0.05
            )

            inputManager:SendKeyEvent(
                false,
                Enum.KeyCode.Backspace,
                false,
                game
            )
        end)

    return ok == true
end

function HolyFruitAutomationToolLeftInventory(tool)

    if typeof(tool) ~= "Instance" then
        return true
    end

    local character =
        HolyFruitAutomationGetCharacter()

    local backpack =
        LocalPlayer
        and LocalPlayer:FindFirstChildOfClass(
            "Backpack"
        )
        or nil

    if tool.Parent == nil then
        return true
    end

    if typeof(character) == "Instance"
    and tool.Parent == character then

        return false
    end

    if typeof(backpack) == "Instance"
    and tool.Parent == backpack then

        return false
    end

    return true
end

function HolyFruitAutomationGetCallbackUpvalues(callback)

    if type(callback) ~= "function" then
        return nil
    end

    if type(getupvalues) == "function" then

        local success,
            values =
            pcall(
                getupvalues,
                callback
            )

        if success == true
        and type(values) == "table" then

            return values
        end
    end

    if type(debug) == "table"
    and type(debug.getupvalues) == "function" then

        local success,
            values =
            pcall(
                debug.getupvalues,
                callback
            )

        if success == true
        and type(values) == "table" then

            return values
        end
    end

    return nil
end

function HolyFruitAutomationFindCapturedInventoryTool(
    value,
    visited,
    depth
)

    if type(value) ~= "table" then

        return nil
    end

    visited =
        type(visited) == "table"
        and visited
        or {}

    if visited[value] then

        return nil
    end

    visited[value] =
        true

    local capturedTool =
        rawget(
            value,
            "Tool"
        )

    if typeof(capturedTool) == "Instance"
    and (
        capturedTool:IsA("Tool")
        or capturedTool:IsA("Configuration")
    ) then

        return capturedTool
    end

    depth =
        tonumber(depth)
        or 0

    if depth <= 0 then

        return nil
    end

    for _, childValue in pairs(value) do

        if type(childValue) == "table" then

            local result =
                HolyFruitAutomationFindCapturedInventoryTool(
                    childValue,
                    visited,
                    depth - 1
                )

            if typeof(result) == "Instance" then

                return result
            end
        end
    end

    return nil
end

function HolyFruitAutomationReadInventoryButtonTool(button)

    if typeof(button) ~= "Instance"
    or button:IsA("GuiButton") ~= true
    or type(getconnections) ~= "function" then

        return nil
    end

    local connectionSuccess,
        connections =
        pcall(
            getconnections,
            button.MouseButton1Click
        )

    if connectionSuccess ~= true
    or type(connections) ~= "table" then

        return nil
    end

    for _, connection in ipairs(connections) do

        local enabled =
            true

        local callback =
            nil

        pcall(function()

            enabled =
                connection.Enabled ~= false

            callback =
                connection.Function
                or connection.Callback
        end)

        if enabled == true
        and type(callback) == "function" then

            local upvalues =
                HolyFruitAutomationGetCallbackUpvalues(
                    callback
                )

            if type(upvalues) == "table" then

                for _, upvalue in pairs(upvalues) do

                    local capturedTool =
                        HolyFruitAutomationFindCapturedInventoryTool(
                            upvalue,
                            {},
                            3
                        )

                    if typeof(capturedTool) == "Instance" then

                        return capturedTool
                    end
                end
            end
        end
    end

    return nil
end

function HolyFruitAutomationGetInventoryGrid()

    local playerGui =
        LocalPlayer:FindFirstChild(
            "PlayerGui"
        )

    local backpackGui =
        playerGui
        and playerGui:FindFirstChild(
            "BackpackGui"
        )

    local backpackFrame =
        backpackGui
        and backpackGui:FindFirstChild(
            "Backpack"
        )

    local inventory =
        backpackFrame
        and backpackFrame:FindFirstChild(
            "Inventory"
        )

    local scrollingFrame =
        inventory
        and inventory:FindFirstChild(
            "ScrollingFrame"
        )

    local grid =
        scrollingFrame
        and scrollingFrame:FindFirstChild(
            "UIGridFrame"
        )

    if typeof(grid) == "Instance" then

        return grid
    end

    return nil
end

function HolyFruitAutomationFindInventoryButton(tool)

    if typeof(tool) ~= "Instance"
    or tool.Parent == nil then

        return nil
    end

    if tool:IsA("Tool") ~= true
    and tool:IsA("Configuration") ~= true then

        return nil
    end

    local runtime =
        HolyFruitAutomationEnsureRuntime()

    runtime.InventoryButtonCache =
        type(runtime.InventoryButtonCache) == "table"
        and runtime.InventoryButtonCache
        or setmetatable(
            {},
            {
                __mode =
                    "k",
            }
        )

    local cachedButton =
        runtime.InventoryButtonCache[tool]

    if typeof(cachedButton) == "Instance"
    and cachedButton.Parent ~= nil
    and HolyFruitAutomationReadInventoryButtonTool(
        cachedButton
    ) == tool then

        return cachedButton
    end

    runtime.InventoryButtonCache[tool] =
        nil

    local grid =
        HolyFruitAutomationGetInventoryGrid()

    if typeof(grid) ~= "Instance" then

        return nil
    end

    local matchedButton =
        nil

    for _, object in ipairs(
        grid:GetDescendants()
    ) do

        if object:IsA("GuiButton") then

            local capturedTool =
                HolyFruitAutomationReadInventoryButtonTool(
                    object
                )

            if typeof(capturedTool) == "Instance" then

                runtime.InventoryButtonCache[capturedTool] =
                    object

                if capturedTool == tool then

                    matchedButton =
                        object
                end
            end
        end
    end

    return matchedButton
end

function HolyFruitAutomationEquipDropTool(
    source,
    character,
    humanoid
)

    if typeof(source) ~= "Instance"
    or source.Parent == nil
    or typeof(character) ~= "Instance"
    or typeof(humanoid) ~= "Instance"
    or humanoid.Health <= 0 then

        return nil
    end

    local isTool =
        source:IsA("Tool")

    local isFruitProxy =
        source:IsA("Configuration")
        and source:GetAttribute("FruitProxy") == true

    if isTool ~= true
    and isFruitProxy ~= true then

        return nil
    end

    local fruitId =
        tostring(
            source:GetAttribute("Id")
            or ""
        )

    if fruitId == "" then

        return nil
    end

    local function findEquippedTool()

        if typeof(character) ~= "Instance"
        or character.Parent == nil then

            return nil
        end

        for _, child in ipairs(character:GetChildren()) do

            if child:IsA("Tool")
            and child:GetAttribute("HarvestedFruit") == true
            and tostring(
                child:GetAttribute("Id")
                or ""
            ) == fruitId then

                return child
            end
        end

        return nil
    end

    local alreadyEquipped =
        findEquippedTool()

    if alreadyEquipped then

        return alreadyEquipped
    end

    pcall(function()

        humanoid:UnequipTools()
    end)

    task.wait(
        0.15
    )

    local inventoryButton =
        HolyFruitAutomationFindInventoryButton(
            source
        )

    local inventoryActivationSucceeded =
        false

    if typeof(inventoryButton) == "Instance"
    and type(firesignal) == "function" then

        inventoryActivationSucceeded =
            pcall(
                firesignal,
                inventoryButton.MouseButton1Click
            )
    end

    if inventoryActivationSucceeded ~= true
    and isTool == true
    and source.Parent ~= nil then

        pcall(function()

            humanoid:EquipTool(
                source
            )
        end)
    end

    local equipDeadline =
        os.clock()
        + 5

    local fallbackAt =
        os.clock()
        + 2

    local fallbackUsed =
        false

    while os.clock() < equipDeadline
    and HOLY_FRUIT_AUTOMATION_STATE.AutoDropFruits == true do

        local equippedTool =
            findEquippedTool()

        if equippedTool then

            return equippedTool
        end

        if fallbackUsed ~= true
        and isTool == true
        and source.Parent ~= nil
        and os.clock() >= fallbackAt then

            fallbackUsed =
                true

            pcall(function()

                humanoid:EquipTool(
                    source
                )
            end)
        end

        task.wait(
            0.05
        )
    end

    return findEquippedTool()
end

function HolyFruitAutomationDropTool(tool)

    if typeof(tool) ~= "Instance"
    or tool.Parent == nil then

        return false
    end

    local isTool =
        tool:IsA("Tool")

    local isFruitProxy =
        tool:IsA("Configuration")
        and tool:GetAttribute("FruitProxy") == true

    if isTool ~= true
    and isFruitProxy ~= true then

        return false
    end

    if tool:GetAttribute(
        "HarvestedFruit"
    ) ~= true then

        return false
    end

    local fruitId =
        tostring(
            tool:GetAttribute(
                "Id"
            )
            or ""
        )

    if fruitId == "" then
        return false
    end

    local runtime =
        HolyFruitAutomationEnsureRuntime()

    local dropPacket =
        runtime.DropPacket

    if type(dropPacket) ~= "table"
    or type(dropPacket.Fire) ~= "function" then

        runtime.DropPacket =
            nil

        local sharedModules =
            ReplicatedStorage:FindFirstChild(
                "SharedModules"
            )

        local networkingModule =
            sharedModules
            and sharedModules:FindFirstChild(
                "Networking"
            )

        if typeof(networkingModule) ~= "Instance"
        or networkingModule:IsA("ModuleScript") ~= true then

            return false
        end

        local requireSuccess,
            networking =
            pcall(function()

                return require(
                    networkingModule
                )
            end)

        if requireSuccess ~= true
        or type(networking) ~= "table" then

            return false
        end

        dropPacket =
            type(networking.DroppedItem) == "table"
            and networking.DroppedItem.RequestDrop
            or nil

        if type(dropPacket) ~= "table"
        or type(dropPacket.Fire) ~= "function" then

            return false
        end

        runtime.DropPacket =
            dropPacket
    end

    local droppedFolder =
        workspace:FindFirstChild(
            "DroppedItems"
        )

    if typeof(droppedFolder) ~= "Instance" then

        return false
    end

    local character =
        HolyFruitAutomationGetCharacter()

    local humanoid =
        HolyFruitAutomationGetHumanoid()

    if typeof(character) ~= "Instance"
    or typeof(humanoid) ~= "Instance"
    or humanoid.Health <= 0 then

        return false
    end

    local equippedTool =
        HolyFruitAutomationEquipDropTool(
            tool,
            character,
            humanoid
        )

    if typeof(equippedTool) ~= "Instance"
    or equippedTool:IsA("Tool") ~= true
    or equippedTool.Parent ~= character then

        return false
    end

    if tostring(
        equippedTool:GetAttribute("Id")
        or ""
    ) ~= fruitId then

        return false
    end

    local equipSettledAt =
        os.clock()
        + 0.75

    while os.clock() < equipSettledAt
    and HOLY_FRUIT_AUTOMATION_STATE.AutoDropFruits == true do

        if equippedTool.Parent ~= character then

            return false
        end

        task.wait(
            0.05
        )
    end

    if HOLY_FRUIT_AUTOMATION_STATE.AutoDropFruits ~= true
    or equippedTool.Parent ~= character then

        return false
    end

    local addedItems =
        {}

    local childAddedConnection =
        droppedFolder.ChildAdded:Connect(function(item)

            table.insert(
                addedItems,
                item
            )
        end)

    local packetSuccess =
        pcall(function()

            dropPacket:Fire(
                "HarvestedFruits",
                fruitId
            )
        end)

    if packetSuccess ~= true then

        childAddedConnection:Disconnect()

        runtime.DropPacket =
            nil

        return false
    end

    local confirmationDeadline =
        os.clock()
        + 5

    local confirmedItem =
        nil

    while os.clock() < confirmationDeadline
    and HOLY_FRUIT_AUTOMATION_STATE.AutoDropFruits == true do

        for _, item in ipairs(addedItems) do

            if typeof(item) == "Instance" then

                local itemCategory =
                    tostring(
                        item:GetAttribute(
                            "ItemCategory"
                        )
                        or ""
                    )

                local itemName =
                    tostring(
                        item:GetAttribute(
                            "ItemName"
                        )
                        or ""
                    )

                local droppedBy =
                    tonumber(
                        item:GetAttribute(
                            "DroppedBy"
                        )
                    )

                if itemCategory == "HarvestedFruits"
                and itemName == fruitId
                and droppedBy == LocalPlayer.UserId then

                    confirmedItem =
                        item

                    break
                end
            end
        end

        if confirmedItem then
            break
        end

        task.wait(
            0.05
        )
    end

    childAddedConnection:Disconnect()

    if not confirmedItem then

        return false
    end

    local nextDropAt =
        os.clock()
        + 0.75

    while os.clock() < nextDropAt
    and HOLY_FRUIT_AUTOMATION_STATE.AutoDropFruits == true do

        task.wait(
            0.05
        )
    end

    return true
end

function HolyFruitAutomationTryDropInfo(info)

    local runtime =
        HolyFruitAutomationEnsureRuntime()

    info =
        type(info) == "table"
        and info
        or {}

    local tool =
        info.Tool

    if typeof(tool) ~= "Instance"
    or tool.Parent == nil then

        return false
    end

    local lastAttempt =
        tonumber(
            runtime.DropLastAttempt[tool]
        )
        or 0

    if os.clock() - lastAttempt < runtime.DropRetryDelay then
        return false
    end

    runtime.DropLastAttempt[tool] =
        os.clock()

    if HolyFruitAutomationPassesDropFilters(
        info
    ) ~= true then

        return false
    end

    local dropped =
        HolyFruitAutomationDropTool(
            tool
        )

    if dropped == true then

        runtime.DroppedThisRun =
            (
                tonumber(runtime.DroppedThisRun)
                or 0
            )
            + 1

        runtime.DropLastAttempt[tool] =
            nil

        return true
    end

    return false
end

function HolyFruitAutomationDropLimitReached()

    HolyFruitAutomationEnsureState()

    local runtime =
        HolyFruitAutomationEnsureRuntime()

    local limit =
        HolyFruitAutomationReadDropLimit(
            HOLY_FRUIT_AUTOMATION_STATE.DropLimit
        )

    if limit <= 0 then
        return false
    end

    return (
        tonumber(runtime.DroppedThisRun)
        or 0
    ) >= limit
end

function HolyFruitAutomationSyncToggles()

    local ui =
        type(HOLY_FRUIT_AUTOMATION_UI) == "table"
        and HOLY_FRUIT_AUTOMATION_UI
        or {}

    if type(ui.AutoDropToggle) == "table"
    and type(ui.AutoDropToggle.SetValue) == "function" then

        pcall(function()

            ui.AutoDropToggle:SetValue(
                HOLY_FRUIT_AUTOMATION_STATE.AutoDropFruits == true,
                true
            )
        end)
    end

    if type(ui.AutoPickupToggle) == "table"
    and type(ui.AutoPickupToggle.SetValue) == "function" then

        pcall(function()

            ui.AutoPickupToggle:SetValue(
                HOLY_FRUIT_AUTOMATION_STATE.AutoCollectDroppedFruits == true,
                true
            )
        end)
    end
end

function HolyFruitAutomationRunDropWorker(token)

    local runtime =
        HolyFruitAutomationEnsureRuntime()

    runtime.DropRunning =
        true

    runtime.DroppedThisRun =
        0

    while runtime.DropToken == token
    and HOLY_FRUIT_AUTOMATION_STATE.AutoDropFruits == true do

        if HolyFarmAutoCollectBlocked() == true then

            task.wait(
                0.20
            )

        elseif HolyFruitAutomationDropLimitReached() == true then

            HOLY_FRUIT_AUTOMATION_STATE.AutoDropFruits =
                false

            HolySaveFruitAutomationSettings()
            HolyFruitAutomationSyncToggles()

            if type(HolyNotify) == "function" then

                HolyNotify(
                    "HOLY Farm",
                    "Auto Drop Fruits reached the drop limit.",
                    4
                )
            end

            break

        else

            local targets =
                HolyFruitAutomationGetFruitTools()

            if #targets <= 0 then

                task.wait(
                    runtime.DropScanDelay
                )

            else

                for _, info in ipairs(targets) do

                    if runtime.DropToken ~= token
                    or HOLY_FRUIT_AUTOMATION_STATE.AutoDropFruits ~= true then

                        break
                    end

                    if HolyFruitAutomationDropLimitReached() == true then
                        break
                    end

                    HolyFruitAutomationTryDropInfo(
                        info
                    )

                    task.wait(
                        0.05
                    )
                end

                task.wait(
                    runtime.DropScanDelay
                )
            end
        end
    end

    if runtime.DropToken == token then

        runtime.DropRunning =
            false
    end
end

function HolyFruitAutomationStartDrop(reason)

    HolyFruitAutomationEnsureState()

    if HOLY_FRUIT_AUTOMATION_STATE.AutoDropFruits ~= true then
        return false
    end

    local runtime =
        HolyFruitAutomationEnsureRuntime()

    if runtime.DropRunning == true then
        return false
    end

    runtime.DropLastAttempt =
        {}

    runtime.DroppedThisRun =
        0

    runtime.DropToken =
        {}

    local token =
        runtime.DropToken

    runtime.DropRunning =
        true

    task.spawn(function()

        HolyFruitAutomationRunDropWorker(
            token
        )
    end)

    return true
end

function HolyFruitAutomationStopDrop(reason)

    local runtime =
        HolyFruitAutomationEnsureRuntime()

    runtime.DropToken =
        nil

    runtime.DropRunning =
        false

    runtime.DropLastAttempt =
        {}

    return true
end

function HolyFruitAutomationGetDroppedFolder()

    local folder =
        workspace:FindFirstChild(
            "DroppedItems"
        )

    if typeof(folder) == "Instance" then
        return folder
    end

    folder =
        workspace:FindFirstChild(
            "DroppedItems",
            true
        )

    if typeof(folder) == "Instance" then
        return folder
    end

    return nil
end

function HolyFruitAutomationGetDroppedPrompt(item)

    if typeof(item) ~= "Instance" then
        return nil
    end

    local anchor =
        item:FindFirstChild(
            "PromptAnchor",
            true
        )

    if typeof(anchor) == "Instance" then

        local prompt =
            anchor:FindFirstChildWhichIsA(
                "ProximityPrompt",
                true
            )

        if typeof(prompt) == "Instance" then
            return prompt
        end
    end

    return item:FindFirstChildWhichIsA(
        "ProximityPrompt",
        true
    )
end

function HolyFruitAutomationGetDroppedPromptPart(item)

    local prompt =
        HolyFruitAutomationGetDroppedPrompt(
            item
        )

    if typeof(prompt) == "Instance" then

        local parent =
            prompt.Parent

        if typeof(parent) == "Instance" then

            if parent:IsA("BasePart") then
                return parent
            end

            if parent:IsA("Attachment")
            and typeof(parent.Parent) == "Instance"
            and parent.Parent:IsA("BasePart") then

                return parent.Parent
            end
        end
    end

    if typeof(item) == "Instance"
    and item:IsA("Model")
    and item.PrimaryPart then

        return item.PrimaryPart
    end

    if typeof(item) == "Instance" then

        return item:FindFirstChildWhichIsA(
            "BasePart",
            true
        )
    end

    return nil
end

function HolyFruitAutomationDroppedGetDistances(item)

    local root =
        HolyFruitAutomationGetRoot()

    local part =
        HolyFruitAutomationGetDroppedPromptPart(
            item
        )

    if typeof(root) ~= "Instance"
    or root:IsA("BasePart") ~= true
    or typeof(part) ~= "Instance"
    or part:IsA("BasePart") ~= true then

        return nil,
            nil,
            nil
    end

    local delta =
        root.Position
        - part.Position

    local horizontal =
        Vector3.new(
            delta.X,
            0,
            delta.Z
        ).Magnitude

    local vertical =
        math.abs(
            delta.Y
        )

    return delta.Magnitude,
        horizontal,
        vertical
end

function HolyFruitAutomationReadDroppedInfo(item, forceRefresh)

    local runtime =
        HolyFruitAutomationEnsureRuntime()

    if typeof(item) ~= "Instance"
    or item.Parent == nil then

        runtime.DroppedCache[item] =
            nil

        runtime.DroppedLastAttempt[item] =
            nil

        return nil
    end

    if forceRefresh ~= true
    and type(runtime.DroppedCache[item]) == "table" then

        local cached =
            runtime.DroppedCache[item]

        if cached.Item == item
        and item.Parent ~= nil then

            return cached
        end
    end

    local prompt =
        HolyFruitAutomationGetDroppedPrompt(
            item
        )

    if typeof(prompt) ~= "Instance"
    or prompt:IsA("ProximityPrompt") ~= true then

        return nil
    end

    local info =
        HolyFruitAutomationReadCommonFruitInfo(
            item,
            item:GetAttribute("DisplayName")
            or prompt.ObjectText
            or item.Name
        )

    if HolyFruitAutomationLooksLikeFruit(
        info
    ) ~= true then

        return nil
    end

    info.Item =
        item

    info.Prompt =
        prompt

    runtime.DroppedCache[item] =
        info

    return info
end

function HolyFruitAutomationDroppedDistanceAllowed(item)

    local runtime =
        HolyFruitAutomationEnsureRuntime()

    local distance3D,
        horizontal,
        vertical =
        HolyFruitAutomationDroppedGetDistances(
            item
        )

    if distance3D == nil then

        return false,
            distance3D,
            horizontal,
            vertical
    end

    if distance3D <= runtime.PickupRange3D then

        return true,
            distance3D,
            horizontal,
            vertical
    end

    if horizontal <= runtime.PickupHorizontalRange
    and vertical <= runtime.PickupVerticalRange then

        return true,
            distance3D,
            horizontal,
            vertical
    end

    return false,
        distance3D,
        horizontal,
        vertical
end

function HolyFruitAutomationFireDroppedPrompt(prompt)

    if typeof(prompt) ~= "Instance"
    or prompt:IsA("ProximityPrompt") ~= true
    or prompt.Parent == nil then

        return false,
            "missing prompt"
    end

    local oldEnabled =
        prompt.Enabled

    local oldDistance =
        prompt.MaxActivationDistance

    local oldHold =
        prompt.HoldDuration

    local oldLineOfSight =
        prompt.RequiresLineOfSight

    pcall(function()

        prompt.Enabled =
            true

        prompt.MaxActivationDistance =
            9999

        prompt.HoldDuration =
            0

        prompt.RequiresLineOfSight =
            false
    end)

    local ok,
        err =
        false,
        nil

    if type(fireproximityprompt) == "function" then

        ok,
            err =
            pcall(function()

                fireproximityprompt(
                    prompt
                )
            end)

    else

        ok,
            err =
            pcall(function()

                prompt:InputHoldBegin()

                task.wait(
                    0.06
                )

                prompt:InputHoldEnd()
            end)
    end

    task.delay(0.50, function()

        if typeof(prompt) == "Instance"
        and prompt.Parent ~= nil then

            pcall(function()

                prompt.Enabled =
                    oldEnabled

                prompt.MaxActivationDistance =
                    oldDistance

                prompt.HoldDuration =
                    oldHold

                prompt.RequiresLineOfSight =
                    oldLineOfSight
            end)
        end
    end)

    return ok == true,
        err
end

function HolyFruitAutomationWaitDroppedRemoved(item, timeout)

    local startedAt =
        os.clock()

    timeout =
        tonumber(timeout)
        or 2.35

    while os.clock() - startedAt <= timeout do

        if typeof(item) ~= "Instance"
        or item.Parent == nil then

            return true
        end

        task.wait(
            0.05
        )
    end

    return false
end

function HolyFruitAutomationTryPickupDroppedInfo(info)

    local runtime =
        HolyFruitAutomationEnsureRuntime()

    info =
        type(info) == "table"
        and info
        or {}

    local item =
        info.Item

    if typeof(item) ~= "Instance"
    or item.Parent == nil then

        runtime.DroppedCache[item] =
            nil

        runtime.DroppedLastAttempt[item] =
            nil

        return false
    end

    info =
        HolyFruitAutomationReadDroppedInfo(
            item,
            false
        )

    if HolyFruitAutomationPassesFilters(
        info
    ) ~= true then

        return false
    end

    local distanceAllowed =
        HolyFruitAutomationDroppedDistanceAllowed(
            item
        )

    if distanceAllowed ~= true then
        return false
    end

    local lastAttempt =
        tonumber(
            runtime.DroppedLastAttempt[item]
        )
        or 0

    if os.clock() - lastAttempt < runtime.PickupRetryDelay then
        return false
    end

    runtime.DroppedLastAttempt[item] =
        os.clock()

    local fired =
        HolyFruitAutomationFireDroppedPrompt(
            info.Prompt
        )

    if fired ~= true then
        return false
    end

    local removed =
        HolyFruitAutomationWaitDroppedRemoved(
            item,
            runtime.PickupResultTimeout
        )

    if removed == true then

        runtime.DroppedCache[item] =
            nil

        runtime.DroppedLastAttempt[item] =
            nil

        return true
    end

    return false
end

function HolyFruitAutomationGetDroppedTargets()

    local folder =
        HolyFruitAutomationGetDroppedFolder()

    local targets =
        {}

    if typeof(folder) ~= "Instance" then
        return targets
    end

    for _, item in ipairs(folder:GetChildren()) do

        if item:IsA("Model") then

            local info =
                HolyFruitAutomationReadDroppedInfo(
                    item,
                    false
                )

            if HolyFruitAutomationPassesFilters(
                info
            ) == true then

                table.insert(
                    targets,
                    info
                )
            end
        end
    end

    table.sort(targets, function(a, b)

        local distanceA =
            HolyFruitAutomationDroppedGetDistances(
                a.Item
            )
            or math.huge

        local distanceB =
            HolyFruitAutomationDroppedGetDistances(
                b.Item
            )
            or math.huge

        return distanceA < distanceB
    end)

    return targets
end

function HolyFruitAutomationConnectDroppedFolder()

    local runtime =
        HolyFruitAutomationEnsureRuntime()

    HolyFarmDisconnectConnectionList(
        runtime.DroppedConnections
    )

    runtime.DroppedConnections =
        {}

    local folder =
        HolyFruitAutomationGetDroppedFolder()

    if typeof(folder) ~= "Instance" then
        return false
    end

    table.insert(
        runtime.DroppedConnections,
        folder.ChildRemoved:Connect(function(item)

            runtime.DroppedCache[item] =
                nil

            runtime.DroppedLastAttempt[item] =
                nil
        end)
    )

    return true
end

function HolyFruitAutomationPickupMovementEnabled()

    HolyFruitAutomationEnsureState()

    return HOLY_FRUIT_AUTOMATION_STATE.AutoCollectDroppedFruits == true
        and HOLY_FRUIT_AUTOMATION_STATE.PickupMovement
            == "Walk to Fruits"
end

function HolyFruitAutomationOfflineCutsceneActive()

    local playerGui =
        LocalPlayer:FindFirstChild(
            "PlayerGui"
        )

    local offlineGui =
        playerGui
        and playerGui:FindFirstChild(
            "OfflineAnimation"
        )

    if typeof(offlineGui) ~= "Instance"
    or offlineGui:IsA("ScreenGui") ~= true
    or offlineGui.Enabled ~= true then

        return false
    end

    local function visibleThroughParents(object)

        if typeof(object) ~= "Instance"
        or object:IsA("GuiObject") ~= true then

            return false
        end

        local current =
            object

        while current
        and current ~= offlineGui do

            if current:IsA("GuiObject")
            and current.Visible ~= true then

                return false
            end

            current =
                current.Parent
        end

        return current == offlineGui
    end

    local bottomBar =
        offlineGui:FindFirstChild(
            "BottomBar"
        )

    local topBar =
        offlineGui:FindFirstChild(
            "TopBar"
        )

    local holdLabel =
        bottomBar
        and bottomBar:FindFirstChild(
            "HTSLabel"
        )

    local title =
        topBar
        and topBar:FindFirstChild(
            "Title"
        )

    return visibleThroughParents(
        holdLabel
    )
    or visibleThroughParents(
        title
    )
end

function HolyFruitAutomationPickupHigherPriorityActive()

    if HolyFarmAutoCollectBlocked() == true then

        return true
    end

    if type(HOLY_WATERING_REJOIN_STATE) == "table"
    and HOLY_WATERING_REJOIN_STATE.Enabled == true then

        return true
    end

    if type(HOLY_WATERING_REJOIN_RUNTIME) == "table"
    and (
        HOLY_WATERING_REJOIN_RUNTIME.Running == true
        or HOLY_WATERING_REJOIN_RUNTIME.Teleporting == true
    ) then

        return true
    end

    if HolyFruitAutomationOfflineCutsceneActive() == true then

        return true
    end

    return false
end

function HolyFruitAutomationStopPickupMovement()

    local runtime =
        HolyFruitAutomationEnsureRuntime()

    if runtime.PickupMoving ~= true then
        return false
    end

    runtime.PickupMoving =
        false

    local humanoid =
        HolyFruitAutomationGetHumanoid()

    local root =
        HolyFruitAutomationGetRoot()

    if humanoid
    and root then

        pcall(function()

            humanoid:MoveTo(
                root.Position
            )
        end)
    end

    return true
end

function HolyFruitAutomationAcquirePickupMovement()

    local runtime =
        HolyFruitAutomationEnsureRuntime()

    if runtime.PickupOwnsMovement == true then

        return true
    end

    runtime.PickupOwnsMovement =
        true

    if type(HolyFarmMiddleStop) == "function" then

        HolyFarmMiddleStop(
            "dropped fruit walking"
        )
    end

    return true
end

function HolyFruitAutomationReleasePickupMovement()

    local runtime =
        HolyFruitAutomationEnsureRuntime()

    local previouslyOwned =
        runtime.PickupOwnsMovement == true

    HolyFruitAutomationStopPickupMovement()

    runtime.PickupOwnsMovement =
        false

    runtime.PickupTarget =
        nil

    runtime.PickupLastDropPosition =
        nil

    if previouslyOwned ~= true then

        return false
    end

    task.defer(function()

        task.wait(
            0.15
        )

        if HolyFruitAutomationPickupMovementEnabled() == true then
            return
        end

        if HolyFruitAutomationPickupHigherPriorityActive() == true then
            return
        end

        if HOLY_DEV_UI_STATE.AutoFarmMiddle == true
        and type(HolyFarmMiddleStart) == "function" then

            HolyFarmMiddleStart(
                "dropped fruit walking ended"
            )
        end
    end)

    return true
end

function HolyFruitAutomationPickupOwnsMovement()

    local runtime =
        HolyFruitAutomationEnsureRuntime()

    return HolyFruitAutomationPickupMovementEnabled() == true
        and runtime.PickupOwnsMovement == true
end

function HolyFruitAutomationWalkToDroppedInfo(
    info
)

    local runtime =
        HolyFruitAutomationEnsureRuntime()

    info =
        type(info) == "table"
        and info
        or {}

    local item =
        info.Item

    if typeof(item) ~= "Instance"
    or item.Parent == nil then

        runtime.PickupTarget =
            nil

        HolyFruitAutomationStopPickupMovement()

        return false
    end

    local part =
        HolyFruitAutomationGetDroppedPromptPart(
            item
        )

    local humanoid =
        HolyFruitAutomationGetHumanoid()

    local root =
        HolyFruitAutomationGetRoot()

    if typeof(part) ~= "Instance"
    or part:IsA("BasePart") ~= true
    or typeof(humanoid) ~= "Instance"
    or typeof(root) ~= "Instance"
    or root:IsA("BasePart") ~= true
    or humanoid.Health <= 0 then

        HolyFruitAutomationStopPickupMovement()

        return false
    end

    runtime.PickupTarget =
        item

    runtime.PickupLastDropPosition =
        part.Position

    local distanceAllowed =
        HolyFruitAutomationDroppedDistanceAllowed(
            item
        )

    if distanceAllowed == true then

        HolyFruitAutomationStopPickupMovement()

        return true
    end

    local now =
        os.clock()

    if now - runtime.PickupLastMoveAt
        >= runtime.PickupMoveInterval then

        runtime.PickupLastMoveAt =
            now

        runtime.PickupMoving =
            true

        pcall(function()

            humanoid.Sit =
                false

            humanoid.PlatformStand =
                false

            humanoid.AutoRotate =
                true

            humanoid:MoveTo(
                part.Position
            )
        end)
    end

    return false
end

function HolyFruitAutomationContinueToRemovedTarget()

    local runtime =
        HolyFruitAutomationEnsureRuntime()

    local target =
        runtime.PickupTarget

    if typeof(target) ~= "Instance"
    or target.Parent ~= nil then

        return "None"
    end

    local savedPosition =
        runtime.PickupLastDropPosition

    if typeof(savedPosition) ~= "Vector3" then

        runtime.PickupTarget =
            nil

        HolyFruitAutomationStopPickupMovement()

        return "Unavailable"
    end

    local humanoid =
        HolyFruitAutomationGetHumanoid()

    local root =
        HolyFruitAutomationGetRoot()

    if typeof(humanoid) ~= "Instance"
    or typeof(root) ~= "Instance"
    or root:IsA("BasePart") ~= true
    or humanoid.Health <= 0 then

        return "Waiting"
    end

    local flatTarget =
        Vector3.new(
            savedPosition.X,
            root.Position.Y,
            savedPosition.Z
        )

    local delta =
        flatTarget
        - root.Position

    local horizontalDistance =
        Vector3.new(
            delta.X,
            0,
            delta.Z
        ).Magnitude

    if horizontalDistance <= 4.5 then

        HolyFruitAutomationStopPickupMovement()

        runtime.PickupTarget =
            nil

        runtime.PickupLastDropPosition =
            nil

        return "Arrived"
    end

    local now =
        os.clock()

    if now - runtime.PickupLastMoveAt
        >= runtime.PickupMoveInterval then

        runtime.PickupLastMoveAt =
            now

        runtime.PickupMoving =
            true

        pcall(function()

            humanoid.Sit =
                false

            humanoid.PlatformStand =
                false

            humanoid.AutoRotate =
                true

            humanoid:MoveTo(
                flatTarget
            )
        end)
    end

    return "Moving"
end

function HolyFruitAutomationRunPickupWorker(token)

    local runtime =
        HolyFruitAutomationEnsureRuntime()

    runtime.PickupRunning =
        true

    HolyFruitAutomationConnectDroppedFolder()

    while runtime.PickupToken == token
    and HOLY_FRUIT_AUTOMATION_STATE.AutoCollectDroppedFruits == true do

        local walkingEnabled =
            HolyFruitAutomationPickupMovementEnabled()

        if walkingEnabled == true then

            HolyFruitAutomationAcquirePickupMovement()

        elseif runtime.PickupOwnsMovement == true then

            HolyFruitAutomationReleasePickupMovement()
        end

        if HolyFruitAutomationPickupHigherPriorityActive() == true then

            if runtime.PickupMoving == true then

                HolyFruitAutomationStopPickupMovement()
            end

            task.wait(
                0.20
            )

            continue
        end

        local removedTargetStatus =
            HolyFruitAutomationContinueToRemovedTarget()

        if removedTargetStatus == "Moving"
        or removedTargetStatus == "Waiting" then

            task.wait(
                runtime.PickupScanDelay
            )

            continue
        end

        local targets =
            HolyFruitAutomationGetDroppedTargets()

        if #targets <= 0 then

            if runtime.PickupMoving == true then

                HolyFruitAutomationStopPickupMovement()
            end

            runtime.PickupTarget =
                nil

            task.wait(
                runtime.PickupScanDelay
            )

            continue
        end

        if walkingEnabled == true then

            local info =
                targets[1]

            local inRange =
                HolyFruitAutomationWalkToDroppedInfo(
                    info
                )

            if inRange == true then

                HolyFruitAutomationTryPickupDroppedInfo(
                    info
                )

                HolyFruitAutomationStopPickupMovement()
            end

            task.wait(
                runtime.PickupScanDelay
            )

        else

            for _, info in ipairs(targets) do

                if runtime.PickupToken ~= token
                or HOLY_FRUIT_AUTOMATION_STATE.AutoCollectDroppedFruits ~= true then

                    break
                end

                HolyFruitAutomationTryPickupDroppedInfo(
                    info
                )

                task.wait(
                    0.02
                )
            end

            task.wait(
                runtime.PickupScanDelay
            )
        end
    end

    if runtime.PickupToken == token then

        runtime.PickupRunning =
            false

        HolyFruitAutomationReleasePickupMovement()
    end
end

function HolyFruitAutomationStartPickup(reason)

    HolyFruitAutomationEnsureState()

    if HOLY_FRUIT_AUTOMATION_STATE.AutoCollectDroppedFruits ~= true then

        return false
    end

    local runtime =
        HolyFruitAutomationEnsureRuntime()

    if runtime.PickupRunning == true then

        if HolyFruitAutomationPickupMovementEnabled() == true then

            HolyFruitAutomationAcquirePickupMovement()
        end

        return false
    end

    runtime.DroppedCache =
        {}

    runtime.DroppedLastAttempt =
        {}

    runtime.PickupTarget =
        nil

    runtime.PickupMoving =
        false

    runtime.PickupLastMoveAt =
        0

    runtime.PickupToken =
        {}

    local token =
        runtime.PickupToken

    runtime.PickupRunning =
        true

    if HolyFruitAutomationPickupMovementEnabled() == true then

        HolyFruitAutomationAcquirePickupMovement()
    end

    task.spawn(function()

        HolyFruitAutomationRunPickupWorker(
            token
        )
    end)

    return true
end

function HolyFruitAutomationStopPickup(reason)

    local runtime =
        HolyFruitAutomationEnsureRuntime()

    runtime.PickupToken =
        nil

    runtime.PickupRunning =
        false

    HolyFruitAutomationReleasePickupMovement()

    HolyFarmDisconnectConnectionList(
        runtime.DroppedConnections
    )

    runtime.DroppedConnections =
        {}

    runtime.DroppedCache =
        {}

    runtime.DroppedLastAttempt =
        {}

    runtime.PickupTarget =
        nil

    return true
end

function HolyFruitAutomationSetAutoDropFruits(value)

    HolyFruitAutomationEnsureState()

    HOLY_FRUIT_AUTOMATION_STATE.AutoDropFruits =
        value == true

    HolySaveFruitAutomationSettings()

    if HOLY_FRUIT_AUTOMATION_STATE.AutoDropFruits == true then

        return HolyFruitAutomationStartDrop(
            "toggle on"
        )
    end

    return HolyFruitAutomationStopDrop(
        "toggle off"
    )
end

function HolyFruitAutomationSetAutoCollectDroppedFruits(value)

    HolyFruitAutomationEnsureState()

    HOLY_FRUIT_AUTOMATION_STATE.AutoCollectDroppedFruits =
        value == true

    HolySaveFruitAutomationSettings()

    if HOLY_FRUIT_AUTOMATION_STATE.AutoCollectDroppedFruits == true then

        return HolyFruitAutomationStartPickup(
            "toggle on"
        )
    end

    return HolyFruitAutomationStopPickup(
        "toggle off"
    )
end

function HolyFruitAutomationSetPickupMovement(value)

    HolyFruitAutomationEnsureState()

    value =
        tostring(value)

    if value ~= "Nearby Only"
    and value ~= "Walk to Fruits" then

        value =
            "Nearby Only"
    end

    HOLY_FRUIT_AUTOMATION_STATE.PickupMovement =
        value

    HolySaveFruitAutomationSettings()

    if HOLY_FRUIT_AUTOMATION_STATE.AutoCollectDroppedFruits == true then

        if value == "Walk to Fruits" then

            HolyFruitAutomationAcquirePickupMovement()

            HolyFruitAutomationStartPickup(
                "movement changed"
            )

        else

            HolyFruitAutomationReleasePickupMovement()
        end

    else

        HolyFruitAutomationReleasePickupMovement()
    end

    return value
end

