function HolyFruitAutomationRefreshDropdowns(forceRefresh)

    HOLY_FRUIT_AUTOMATION_UI =
        type(HOLY_FRUIT_AUTOMATION_UI) == "table"
        and HOLY_FRUIT_AUTOMATION_UI
        or {}

    if forceRefresh == true then

        if type(HolyFarmInvalidatePlantNameCache) == "function" then

            HolyFarmInvalidatePlantNameCache()
        end

        if type(HolyFarmInvalidateMutationNameCache) == "function" then

            HolyFarmInvalidateMutationNameCache()
        end
    end

    HolyFruitAutomationEnsureState()

    local fruitsDropdown =
        HOLY_FRUIT_AUTOMATION_UI.FruitsDropdown

    if type(fruitsDropdown) == "table" then

        local values =
            HolyFruitAutomationGetFruitDropdownValues()

        pcall(function()

            if type(fruitsDropdown.SetValues) == "function" then

                fruitsDropdown:SetValues(
                    values
                )

            elseif type(fruitsDropdown.SetItems) == "function" then

                fruitsDropdown:SetItems(
                    values
                )
            end
        end)

        pcall(function()

            if type(fruitsDropdown.SetValue) == "function" then

                fruitsDropdown:SetValue(
                    HOLY_FRUIT_AUTOMATION_STATE.SelectedFruits
                )
            end
        end)
    end

    local mutationsDropdown =
        HOLY_FRUIT_AUTOMATION_UI.MutationsDropdown

    if type(mutationsDropdown) == "table" then

        local values =
            HolyFruitAutomationGetMutationDropdownValues()

        pcall(function()

            if type(mutationsDropdown.SetValues) == "function" then

                mutationsDropdown:SetValues(
                    values
                )

            elseif type(mutationsDropdown.SetItems) == "function" then

                mutationsDropdown:SetItems(
                    values
                )
            end
        end)

        pcall(function()

            if type(mutationsDropdown.SetValue) == "function" then

                mutationsDropdown:SetValue(
                    HOLY_FRUIT_AUTOMATION_STATE.SelectedMutations
                )
            end
        end)
    end

    return true
end

function HolySniperNormalizeAnySelection(value)

    local selection =
        HolyShopSelectionArray(
            value
        )

    if #selection <= 0 then

        return {
            "Any",
        }
    end

    for _, itemName in ipairs(selection) do

        if itemName == "Any" then

            return {
                "Any",
            }
        end
    end

    return selection
end

function HolySniperGetPetSizesModule()

    local petSizes =
        HolyDataGetModule(
            "PetSizes"
        )

    if type(petSizes) ~= "table" then
        return {}
    end

    return petSizes
end

function HolySniperGetPetTypesModule()

    local petTypes =
        HolyDataGetModule(
            "PetTypes"
        )

    if type(petTypes) ~= "table" then
        return {}
    end

    return petTypes
end

function HolySniperNormalizeSizeName(value)

    local text =
        HolyCleanText(
            value
        )

    local lower =
        text:lower()

    if lower == ""
    or lower == "none"
    or lower == "nil"
    or lower == "normal"
    or lower == "regular" then

        return "Normal"
    end

    if lower == "mega"
    or lower == "huge" then

        return "Huge"
    end

    local petSizes =
        HolySniperGetPetSizesModule()

    if type(petSizes.Normalize) == "function" then

        local ok,
            result =
            pcall(function()

                return petSizes.Normalize(
                    text
                )
            end)

        result =
            HolyCleanText(
                ok == true
                and result
                or ""
            )

        if result ~= "" then

            if result == "Mega" then
                return "Huge"
            end

            return result
        end
    end

    return text
end

function HolySniperAddSortedValue(values, seen, value)

    value =
        HolyCleanText(
            value
        )

    if value == "" then
        return false
    end

    if value == "Mega" then
        value =
            "Huge"
    end

    if seen[value] == true then
        return false
    end

    seen[value] =
        true

    table.insert(
        values,
        value
    )

    return true
end

function HolySniperSortSizeValues(values)

    table.sort(values, function(a, b)

        local order = {
            Any = 0,
            Normal = 1,
            Big = 2,
            Huge = 3,
        }

        local rankA =
            order[a]
            or 50

        local rankB =
            order[b]
            or 50

        if rankA ~= rankB then
            return rankA < rankB
        end

        return tostring(a) < tostring(b)
    end)
end

function HolySniperSortVariantValues(values)

    table.sort(values, function(a, b)

        local order = {
            Any = 0,
            Normal = 1,
            Rainbow = 2,
        }

        local rankA =
            order[a]
            or 50

        local rankB =
            order[b]
            or 50

        if rankA ~= rankB then
            return rankA < rankB
        end

        return tostring(a) < tostring(b)
    end)
end

function HolySniperGetSizeValues()

    local values =
        {}

    local seen =
        {}

    HolySniperAddSortedValue(
        values,
        seen,
        "Any"
    )

    HolySniperAddSortedValue(
        values,
        seen,
        "Normal"
    )

    local petSizes =
        HolySniperGetPetSizesModule()

    local function addSizeFromKey(key)

        key =
            HolyCleanText(
                key
            )

        if key == "" then
            return
        end

        local normalized =
            HolySniperNormalizeSizeName(
                key
            )

        if normalized ~= ""
        and normalized ~= "Normal" then

            HolySniperAddSortedValue(
                values,
                seen,
                normalized
            )
        end
    end

    if type(petSizes.Scales) == "table" then

        for key in pairs(petSizes.Scales) do

            addSizeFromKey(
                key
            )
        end
    end

    if type(petSizes.BoostMultipliers) == "table" then

        for key in pairs(petSizes.BoostMultipliers) do

            addSizeFromKey(
                key
            )
        end
    end

    HolySniperSortSizeValues(
        values
    )

    return values
end

function HolySniperSizeValueMap()

    local map =
        {}

    for _, value in ipairs(HolySniperGetSizeValues()) do

        if value ~= "Any" then

            map[value] =
                true
        end
    end

    return map
end

function HolySniperNormalizeSizeSelection(value)

    local selection =
        HolyShopSelectionArray(
            value
        )

    if #selection <= 0 then

        return {
            "Any",
        }
    end

    for _, itemName in ipairs(selection) do

        if itemName == "Any" then

            return {
                "Any",
            }
        end
    end

    local validMap =
        HolySniperSizeValueMap()

    local output =
        {}

    local seen =
        {}

    for _, itemName in ipairs(selection) do

        local normalized =
            HolySniperNormalizeSizeName(
                itemName
            )

        if validMap[normalized] == true
        and seen[normalized] ~= true then

            seen[normalized] =
                true

            table.insert(
                output,
                normalized
            )
        end
    end

    if #output <= 0 then

        return {
            "Normal",
        }
    end

    HolySniperSortSizeValues(
        output
    )

    return output
end

function HolySniperPetTypeIsValid(typeName)

    typeName =
        HolyCleanText(
            typeName
        )

    if typeName == "" then
        return false
    end

    if typeName == "Normal" then
        return true
    end

    local petTypes =
        HolySniperGetPetTypesModule()

    if type(petTypes.IsValid) == "function" then

        local ok,
            result =
            pcall(function()

                return petTypes.IsValid(
                    typeName
                )
            end)

        if ok == true then
            return result == true
        end
    end

    return false
end

function HolySniperNormalizeVariantName(value)

    local text =
        HolyCleanText(
            value
        )

    local lower =
        text:lower()

    if lower == ""
    or lower == "none"
    or lower == "nil"
    or lower == "normal"
    or lower == "regular" then

        return "Normal"
    end

    return text
end

function HolySniperGetVariantValues()

    local values =
        {}

    local seen =
        {}

    HolySniperAddSortedValue(
        values,
        seen,
        "Any"
    )

    HolySniperAddSortedValue(
        values,
        seen,
        "Normal"
    )

    local petTypes =
        HolySniperGetPetTypesModule()

    for key, value in pairs(petTypes) do

        if type(value) == "string" then

            local normalized =
                HolySniperNormalizeVariantName(
                    value
                )

            if normalized ~= "Normal"
            and HolySniperPetTypeIsValid(normalized) == true then

                HolySniperAddSortedValue(
                    values,
                    seen,
                    normalized
                )
            end
        end

        if type(key) == "string"
        and type(value) ~= "function"
        and key ~= "BOOST_MULTIPLIER" then

            local normalized =
                HolySniperNormalizeVariantName(
                    key
                )

            if normalized ~= "Normal"
            and HolySniperPetTypeIsValid(normalized) == true then

                HolySniperAddSortedValue(
                    values,
                    seen,
                    normalized
                )
            end
        end
    end

    -- Safe fallback only if the module did not expose string variants.
    if seen.Rainbow ~= true
    and HolySniperPetTypeIsValid("Rainbow") == true then

        HolySniperAddSortedValue(
            values,
            seen,
            "Rainbow"
        )
    end

    HolySniperSortVariantValues(
        values
    )

    return values
end

function HolySniperVariantValueMap()

    local map =
        {}

    for _, value in ipairs(HolySniperGetVariantValues()) do

        if value ~= "Any" then

            map[value] =
                true
        end
    end

    return map
end

function HolySniperNormalizeVariantSelection(value)

    local selection =
        HolyShopSelectionArray(
            value
        )

    if #selection <= 0 then

        return {
            "Any",
        }
    end

    for _, itemName in ipairs(selection) do

        if itemName == "Any" then

            return {
                "Any",
            }
        end
    end

    local validMap =
        HolySniperVariantValueMap()

    local output =
        {}

    local seen =
        {}

    for _, itemName in ipairs(selection) do

        local normalized =
            HolySniperNormalizeVariantName(
                itemName
            )

        -- Gold is ignored unless PetTypes ever marks it as valid.
        if validMap[normalized] == true
        and seen[normalized] ~= true then

            seen[normalized] =
                true

            table.insert(
                output,
                normalized
            )
        end
    end

    if #output <= 0 then

        return {
            "Normal",
        }
    end

    HolySniperSortVariantValues(
        output
    )

    return output
end

function HolySniperNormalizePriority(value)

    local text =
        HolyCleanText(
            value
        )
        :lower()

    if text:find("high", 1, true) then
        return "High"
    end

    if text:find("low", 1, true) then
        return "Low"
    end

    return "Medium"
end

function HolySniperNormalizeMovementMode(value)

    local text =
        HolyCleanText(
            value
        )
        :lower()

    if text:find("teleport", 1, true) then
        return "Teleport"
    end

    return "Walk"
end

function HolyDefenseNormalizeMovement(value)

    local text =
        HolyCleanText(
            value
        )
        :lower()

    if text:find("hybrid", 1, true) then
        return "Hybrid"
    end

    if text:find("tween", 1, true) then
        return "Tween"
    end

    return "Walk"
end

function HolyDefenseNormalizeGear(value)

    local text =
        HolyCleanText(
            value
        )

    local lower =
        text:lower()

    if lower == "shovel" then
        return "Shovel"
    end

    return "Strawberry Sniper"
end

function HolySniperNormalizeBuyMode(value)

    local text =
        HolyCleanText(
            value
        )
        :lower()

    if text:find("hold", 1, true) then
        return "Hold"
    end

    return "Instant"
end

function HolySniperNormalizeReturnTiming(value)

    local text =
        HolyCleanText(
            value
        )
        :lower()

    if text:find("each", 1, true)
    or text:find("buy", 1, true) then

        return "After Buy"
    end

    return "After Batch"
end

function HolySniperNormalizeReturnMode(value)

    local text =
        HolyCleanText(
            value
        )
        :lower()

    if text:find("teleport", 1, true) then
        return "Teleport"
    end

    return "Walk"
end

function HolySniperNormalizeReturnDestination(value)

    local text =
        HolyCleanText(
            value
        )
        :lower()

    if text:find("saved", 1, true)
    or text:find("position", 1, true) then

        return "Saved Position"
    end

    return "Farm Center"
end

function HolySniperNormalizeAutoHopTiming(value)

    local text =
        HolyCleanText(
            value
        )
        :lower()

    if text:find("fast", 1, true)
    or text:find("during", 1, true)
    or text:find("before", 1, true) then

        return "Fast - During Loading"
    end

    return "Safe - After Loading"
end

function HolySniperReadHopDelay(value)

    local text =
        HolyCleanText(
            value
        )

    text =
        text:gsub(
            "[sS]",
            ""
        )

    local number =
        tonumber(
            text
        )

    if not number then

        number =
            5
    end

    return math.max(
        0,
        number
    )
end

function HolySniperFormatDelay(value)

    local number =
        HolySniperReadHopDelay(
            value
        )

    if math.abs(number - math.floor(number)) < 0.001 then

        return tostring(
            math.floor(number)
        )
    end

    return tostring(
        math.floor(number * 100 + 0.5) / 100
    )
end

function HolySniperReadAmount(value)

    local amount =
        math.floor(
            tonumber(value)
            or 999
        )

    return math.clamp(
        amount,
        1,
        999
    )
end

function HolySniperReadMaxPrice(value)

    local text =
        HolyCleanText(
            value
        )

    text =
        text:gsub("¢", "")
            :gsub("%$", "")
            :gsub(",", "")
            :gsub("%s+", "")

    local lower =
        text:lower()

    if lower == ""
    or lower == "0"
    or lower == "none"
    or lower == "off"
    or lower == "no" then

        return 0
    end

    local multiplier =
        1

    if lower:find("b", 1, true) then

        multiplier =
            1000000000

    elseif lower:find("m", 1, true) then

        multiplier =
            1000000

    elseif lower:find("k", 1, true) then

        multiplier =
            1000
    end

    local rawNumber =
        lower:match("%d+%.?%d*")

    local number =
        tonumber(rawNumber)

    if number == nil then
        return 0
    end

    return math.max(
        0,
        math.floor(number * multiplier + 0.5)
    )
end

function HolySniperFormatMaxPrice(value)

    local number =
        HolySniperReadMaxPrice(
            value
        )

    if number <= 0 then
        return "No Cap"
    end

    return "Max "
        .. HolySniperFormatMoney(
            number
        )
end

function HolySniperArrayText(values, fallback)

    values =
        HolyShopSelectionArray(
            values
        )

    fallback =
        tostring(fallback or "Any")

    if #values <= 0 then
        return fallback
    end

    if #values == 1
    and values[1] == "Any" then
        return fallback
    end

    return table.concat(
        values,
        "/"
    )
end

function HolySniperGetPetData()

    local petData =
        HolyDataGetModule(
            "PetData"
        )

    if type(petData) ~= "table" then
        return {}
    end

    return petData
end

function HolySniperIsPetDataRow(key, row)

    if type(key) ~= "string" then
        return false
    end

    if type(row) ~= "table" then
        return false
    end

    if type(row.DisplayName) == "string"
    or type(row.BasePrice) == "number"
    or type(row.Rarity) == "string"
    or type(row.SpawnChance) == "number" then

        return true
    end

    return false
end

function HolySniperPetAliasKey(value)

    return HolyCleanText(
        value
    )
        :lower()
        :gsub("[%s_%-%[%]%(%)%.]", "")
end

function HolySniperBuildPetMaps()

    local values = {
        "Any Pet",
    }

    local seen = {
        ["Any Pet"] = true,
    }

    local displayToKey = {
        ["Any Pet"] = "*",
    }

    local keyToDisplay = {
        ["*"] = "Any Pet",
    }

    local petData =
        HolySniperGetPetData()

    for key, row in pairs(petData) do

        if HolySniperIsPetDataRow(key, row) == true then

            local internalKey =
                HolyCleanText(
                    key
                )

            local displayName =
                HolyCleanText(
                    row.DisplayName
                    or row.PetName
                    or row.Name
                    or key
                )

            if internalKey ~= ""
            and displayName ~= "" then

                if seen[displayName] ~= true then

                    seen[displayName] =
                        true

                    table.insert(
                        values,
                        displayName
                    )
                end

                displayToKey[displayName] =
                    internalKey

                keyToDisplay[internalKey] =
                    displayName
            end
        end
    end

    table.sort(values, function(a, b)

        if a == "Any Pet" then
            return true
        end

        if b == "Any Pet" then
            return false
        end

        return tostring(a) < tostring(b)
    end)

    if #values <= 1 then

        values = {
            "Any Pet",
            "Raccoon",
        }

        displayToKey["Any Pet"] =
            "*"

        displayToKey.Raccoon =
            "Raccoon"

        keyToDisplay["*"] =
            "Any Pet"

        keyToDisplay.Raccoon =
            "Raccoon"
    end

    HOLY_SNIPER_STATE.PetDisplayToKey =
        displayToKey

    HOLY_SNIPER_STATE.PetKeyToDisplay =
        keyToDisplay

    return values,
        displayToKey,
        keyToDisplay
end

function HolySniperGetPetValues()

    local values =
        HolySniperBuildPetMaps()

    return values
end

function HolySniperGetDefaultPetName()

    local values =
        HolySniperGetPetValues()

    for _, petName in ipairs(values) do

        if petName == "Raccoon" then
            return "Raccoon"
        end
    end

    return values[1]
        or "Raccoon"
end

function HolySniperResolvePetKey(value)

    local text =
        HolyCleanText(
            value
        )

    local lower =
        text:lower()

    if lower == "any"
    or lower == "all"
    or lower == "any pet"
    or lower == "all pets"
    or lower == "*" then

        return "*"
    end

    if text == "" then
        return "Raccoon"
    end

    HolySniperGetPetValues()

    local displayToKey =
        type(HOLY_SNIPER_STATE.PetDisplayToKey) == "table"
        and HOLY_SNIPER_STATE.PetDisplayToKey
        or {}

    local keyToDisplay =
        type(HOLY_SNIPER_STATE.PetKeyToDisplay) == "table"
        and HOLY_SNIPER_STATE.PetKeyToDisplay
        or {}

    if displayToKey[text] then
        return displayToKey[text]
    end

    if keyToDisplay[text] then
        return text
    end

    local wantedAlias =
        HolySniperPetAliasKey(
            text
        )

    for internalKey, displayName in pairs(keyToDisplay) do

        if HolySniperPetAliasKey(internalKey) == wantedAlias
        or HolySniperPetAliasKey(displayName) == wantedAlias then

            return internalKey
        end
    end

    return text
end

function HolySniperResolvePetDisplay(value)

    local text =
        HolyCleanText(
            value
        )

    local lower =
        text:lower()

    if lower == "any"
    or lower == "all"
    or lower == "any pet"
    or lower == "all pets"
    or lower == "*" then

        return "Any Pet"
    end

    if text == "" then
        return HolySniperGetDefaultPetName()
    end

    HolySniperGetPetValues()

    local displayToKey =
        type(HOLY_SNIPER_STATE.PetDisplayToKey) == "table"
        and HOLY_SNIPER_STATE.PetDisplayToKey
        or {}

    local keyToDisplay =
        type(HOLY_SNIPER_STATE.PetKeyToDisplay) == "table"
        and HOLY_SNIPER_STATE.PetKeyToDisplay
        or {}

    if displayToKey[text] then
        return text
    end

    if keyToDisplay[text] then
        return keyToDisplay[text]
    end

    local wantedAlias =
        HolySniperPetAliasKey(
            text
        )

    for internalKey, displayName in pairs(keyToDisplay) do

        if HolySniperPetAliasKey(internalKey) == wantedAlias
        or HolySniperPetAliasKey(displayName) == wantedAlias then

            return displayName
        end
    end

    return text
end

function HolySniperNormalizeFilter(row)

    row =
        type(row) == "table"
        and row
        or {}

    local rawPet =
        row.Pet
        or row.PetName
        or row.Name
        or HolySniperGetDefaultPetName()

    local petName =
        HolySniperResolvePetDisplay(
            rawPet
        )

    if petName == "" then

        petName =
            HolySniperGetDefaultPetName()
    end

    local maxPrice =
        HolySniperReadMaxPrice(
            row.MaxPrice
            or row.Max
            or row.PriceLimit
            or row.BuilderMaxPrice
            or 0
        )

    return {
        Pet =
            petName,

        PetKey =
            HolySniperResolvePetKey(
                petName
            ),

        Sizes =
            HolySniperNormalizeSizeSelection(
                row.Sizes
                or row.Size
                or {
                    "Any",
                }
            ),

        Variants =
            HolySniperNormalizeVariantSelection(
                row.Variants
                or row.Variant
                or {
                    "Any",
                }
            ),

        MaxPrice =
            maxPrice,

        Amount =
            999,

        Priority =
            HolySniperNormalizePriority(
                row.Priority
                or "Medium"
            ),

        Enabled =
            row.Enabled ~= false,
    }
end

function HolySniperNormalizeWatchlist(value)

    local output =
        {}

    if type(value) ~= "table" then
        return output
    end

    for _, row in ipairs(value) do

        table.insert(
            output,
            HolySniperNormalizeFilter(
                row
            )
        )
    end

    return output
end

function HolySniperFilterKey(row)

    row =
        HolySniperNormalizeFilter(
            row
        )

    return table.concat({
        HolyCleanText(
            row.PetKey
            or HolySniperResolvePetKey(
                row.Pet
            )
        ):lower(),

        HolySniperArrayText(row.Sizes, "Any"):lower(),

        HolySniperArrayText(row.Variants, "Any"):lower(),

        tostring(
            tonumber(row.MaxPrice)
            or 0
        ),
    }, "|")
end

function HolySniperGetBasePrice(row)

    local petKey =
        ""

    if type(row) == "table" then

        petKey =
            HolyCleanText(
                row.PetKey
                or HolySniperResolvePetKey(
                    row.Pet
                )
            )

    else

        petKey =
            HolyCleanText(
                HolySniperResolvePetKey(
                    row
                )
            )
    end

    if petKey == "" then
        return 0
    end

    local petData =
        HolySniperGetPetData()

    local data =
        type(petData) == "table"
        and petData[petKey]
        or nil

    if type(data) ~= "table" then
        return 0
    end

    return tonumber(data.BasePrice)
        or 0
end

function HolySniperFormatMoney(value)

    value =
        math.max(
            0,
            tonumber(value)
            or 0
        )

    if value >= 1000000 then

        return "$"
            .. string.format(
                "%.1fM",
                value / 1000000
            )
    end

    if value >= 1000 then

        return "$"
            .. string.format(
                "%.0fK",
                value / 1000
            )
    end

    return "$"
        .. tostring(
            math.floor(value)
        )
end

function HolySniperShortValue(value)

    value =
        HolyCleanText(
            value
        )

    if value == "Mega" then
        return "Huge"
    end

    if value == "Rainbow" then
        return "Rb"
    end

    if value == "Normal" then
        return "Norm"
    end

    return value
end

function HolySniperShortArrayText(values, fallback)

    values =
        HolyShopSelectionArray(
            values
        )

    fallback =
        tostring(fallback or "Any")

    if #values <= 0 then
        return fallback
    end

    if #values == 1
    and values[1] == "Any" then
        return fallback
    end

    local output =
        {}

    for _, value in ipairs(values) do

        if value ~= "Any" then

            table.insert(
                output,
                HolySniperShortValue(
                    value
                )
            )
        end
    end

    if #output <= 0 then
        return fallback
    end

    return table.concat(
        output,
        "+"
    )
end

function HolySniperPriorityRank(value)

    value =
        HolySniperNormalizePriority(
            value
        )

    if value == "High" then
        return 1
    end

    if value == "Medium" then
        return 2
    end

    return 3
end

function HolySniperPriorityShort(value)

    value =
        HolySniperNormalizePriority(
            value
        )

    return value:sub(
        1,
        1
    )
end

function HolySniperSortWatchlist(watchlist)

    table.sort(watchlist, function(a, b)

        local priceA =
            tonumber(a.ValueNumber)
            or HolySniperGetBasePrice(a)

        local priceB =
            tonumber(b.ValueNumber)
            or HolySniperGetBasePrice(b)

        if priceA ~= priceB then
            return priceA > priceB
        end

        local rankA =
            HolySniperPriorityRank(
                a.Priority
            )

        local rankB =
            HolySniperPriorityRank(
                b.Priority
            )

        if rankA ~= rankB then
            return rankA < rankB
        end

        return tostring(a.Pet) < tostring(b.Pet)
    end)

    return watchlist
end

function HolySniperMatchesSearch(row, searchText)

    searchText =
        HolyCleanText(
            searchText
        )
        :lower()

    if searchText == "" then
        return true
    end

    local haystack =
        table.concat({
            tostring(row.Pet or ""),
            tostring(row.PetKey or ""),
            tostring(row.Value or ""),
            tostring(row.Size or ""),
            tostring(row.Variant or ""),
            tostring(row.MaxPrice or ""),
            tostring(row.Amount or ""),
            tostring(row.Priority or ""),
            tostring(row.PriorityFull or ""),
        }, " "):lower()

    return haystack:find(
        searchText,
        1,
        true
    ) ~= nil
end

function HolySniperBuildAllWatchlistRows()

    local rows =
        {}

    local searchText =
        HolyCleanText(
            HOLY_SNIPER_STATE.WatchlistSearch
            or ""
        )

    for sourceIndex, row in ipairs(HOLY_SNIPER_STATE.Watchlist or {}) do

        local filter =
            HolySniperNormalizeFilter(
                row
            )

        local price =
            HolySniperGetBasePrice(
                filter
            )

        local maxPriceText =
            HolySniperFormatMaxPrice(
                filter.MaxPrice
            )

        local tableRow = {
            SourceIndex =
                sourceIndex,

            Pet =
                tostring(filter.Pet),

            PetKey =
                tostring(filter.PetKey),

            Value =
                HolySniperFormatMoney(
                    price
                ),

            ValueNumber =
                price,

            MaxPrice =
                maxPriceText,

            MaxPriceNumber =
                tonumber(filter.MaxPrice)
                or 0,

            Size =
                HolySniperShortArrayText(
                    filter.Sizes,
                    "Any"
                ),

            Variant =
                HolySniperShortArrayText(
                    filter.Variants,
                    "Any"
                ),

            Amount =
                maxPriceText,

            AmountNumber =
                tonumber(filter.MaxPrice)
                or 0,

            Priority =
                HolySniperPriorityShort(
                    filter.Priority
                ),

            PriorityFull =
                HolySniperNormalizePriority(
                    filter.Priority
                ),
        }

        if HolySniperMatchesSearch(
            tableRow,
            searchText
        ) == true then

            table.insert(
                rows,
                tableRow
            )
        end
    end

    HolySniperSortWatchlist(
        rows
    )

    return rows
end

function HolySniperGetWatchlistPageSize()

    local pageSize =
        math.floor(
            tonumber(
                HOLY_SNIPER_STATE.WatchlistPageSize
            )
            or 7
        )

    return math.clamp(
        pageSize,
        1,
        20
    )
end

function HolySniperGetWatchlistPageCount(totalRows)

    totalRows =
        math.max(
            0,
            math.floor(
                tonumber(totalRows)
                or 0
            )
        )

    local pageSize =
        HolySniperGetWatchlistPageSize()

    return math.max(
        1,
        math.ceil(
            totalRows / pageSize
        )
    )
end

function HolySniperClampWatchlistPage(totalRows)

    local pageCount =
        HolySniperGetWatchlistPageCount(
            totalRows
        )

    local page =
        math.floor(
            tonumber(
                HOLY_SNIPER_STATE.WatchlistPage
            )
            or 1
        )

    page =
        math.clamp(
            page,
            1,
            pageCount
        )

    HOLY_SNIPER_STATE.WatchlistPage =
        page

    return page,
        pageCount
end

function HolySniperBuildWatchlistRows()

    local allRows =
        HolySniperBuildAllWatchlistRows()

    local page,
        pageCount =
        HolySniperClampWatchlistPage(
            #allRows
        )

    local pageSize =
        HolySniperGetWatchlistPageSize()

    local firstIndex =
        ((page - 1) * pageSize) + 1

    local lastIndex =
        math.min(
            #allRows,
            firstIndex + pageSize - 1
        )

    local pageRows =
        {}

    for index = firstIndex, lastIndex do

        if type(allRows[index]) == "table" then

            table.insert(
                pageRows,
                allRows[index]
            )
        end
    end

    return pageRows,
        {
            Page =
                page,

            PageCount =
                pageCount,

            TotalRows =
                #allRows,

            FirstIndex =
                firstIndex,

            LastIndex =
                lastIndex,
        }
end

function HolySniperBuildWatchlistPageText()

    local allRows =
        HolySniperBuildAllWatchlistRows()

    local page,
        pageCount =
        HolySniperClampWatchlistPage(
            #allRows
        )

    return "Page "
        .. tostring(page)
        .. "/"
        .. tostring(pageCount)
end

function HolySniperSetWatchlistPage(page)

    local allRows =
        HolySniperBuildAllWatchlistRows()

    local pageCount =
        HolySniperGetWatchlistPageCount(
            #allRows
        )

    HOLY_SNIPER_STATE.WatchlistPage =
        math.clamp(
            math.floor(
                tonumber(page)
                or 1
            ),
            1,
            pageCount
        )

    HOLY_SNIPER_STATE.SelectedWatchlistSourceIndex =
        nil

    if HOLY_SNIPER_UI
    and type(HOLY_SNIPER_UI.WatchlistTable) == "table"
    and type(HOLY_SNIPER_UI.WatchlistTable.SetSelected) == "function" then

        HOLY_SNIPER_UI.WatchlistTable:SetSelected(
            nil
        )
    end

    HolySniperRefreshUI()

    return true
end

function HolySniperWatchlistPrevPage()

    return HolySniperSetWatchlistPage(
        (
            tonumber(
                HOLY_SNIPER_STATE.WatchlistPage
            )
            or 1
        )
        - 1
    )
end

function HolySniperWatchlistNextPage()

    return HolySniperSetWatchlistPage(
        (
            tonumber(
                HOLY_SNIPER_STATE.WatchlistPage
            )
            or 1
        )
        + 1
    )
end


function HolySniperBuildWatchlistText()

    local rows =
        HolySniperBuildWatchlistRows()

    if #rows <= 0 then

        return "No active watchlist filters."
    end

    local lines =
        {}

    for index, row in ipairs(rows) do

        lines[#lines + 1] =
            tostring(index)
            .. ". "
            .. tostring(row.Value)
            .. " "
            .. tostring(row.Priority)
            .. " "
            .. tostring(row.Pet)
            .. " "
            .. tostring(row.Size)
            .. " "
            .. tostring(row.Variant)
            .. " "
            .. tostring(row.MaxPrice or row.Amount or "No Cap")
    end

    return table.concat(
        lines,
        "\n"
    )
end

function HolySniperBuildStatusText()

    return "Status: "
        .. tostring(
            HOLY_SNIPER_STATE.Status
            or "Ready"
        )
end

function HolySniperAddLabel(groupbox, text)

    if type(groupbox) ~= "table"
    or type(groupbox.AddLabel) ~= "function" then

        return nil
    end

    local ok,
        label =
        pcall(function()

            return groupbox:AddLabel({
                Text =
                    tostring(text or ""),
            })
        end)

    if ok == true then
        return label
    end

    ok,
        label =
        pcall(function()

            return groupbox:AddLabel(
                tostring(text or "")
            )
        end)

    if ok == true then
        return label
    end

    return nil
end

function HolySniperSetLabel(label, text)

    text =
        tostring(text or "")

    if type(label) == "table" then

        if type(label.SetText) == "function" then

            pcall(function()

                label:SetText(
                    text
                )
            end)

            return true
        end

        if label.TextLabel
        and typeof(label.TextLabel) == "Instance" then

            pcall(function()

                label.TextLabel.Text =
                    text
            end)

            return true
        end
    end

    if typeof(label) == "Instance" then

        pcall(function()

            label.Text =
                text
        end)

        return true
    end

    return false
end

function HolySniperRefreshUI()

    HOLY_SNIPER_UI =
        type(HOLY_SNIPER_UI) == "table"
        and HOLY_SNIPER_UI
        or {}

    HolySniperSetLabel(
        HOLY_SNIPER_UI.StatusLabel,
        HolySniperBuildStatusText()
    )

    local pageRows,
        pageInfo =
        HolySniperBuildWatchlistRows()

    if type(HOLY_SNIPER_UI.WatchlistTable) == "table"
    and type(HOLY_SNIPER_UI.WatchlistTable.SetRows) == "function" then

        HOLY_SNIPER_UI.WatchlistTable:SetRows(
            pageRows
        )

    else

        HolySniperSetLabel(
            HOLY_SNIPER_UI.WatchlistLabel,
            HolySniperBuildWatchlistText()
        )
    end

    local pager =
        HOLY_SNIPER_UI.WatchlistPager

    if type(pager) == "table" then

        local page =
            tonumber(
                pageInfo
                and pageInfo.Page
            )
            or 1

        local pageCount =
            tonumber(
                pageInfo
                and pageInfo.PageCount
            )
            or 1

        if type(pager.SetText) == "function" then

            pager:SetText(
                "Page",
                "Page "
                .. tostring(page)
                .. "/"
                .. tostring(pageCount)
            )
        end

        if type(pager.SetDisabled) == "function" then

            pager:SetDisabled(
                "Prev",
                page <= 1
            )

            pager:SetDisabled(
                "Next",
                page >= pageCount
            )
        end
    end
end

function HolySniperSetStatus(status)

    HOLY_SNIPER_STATE.Status =
        tostring(status or "Ready")

    HolySniperRefreshUI()
end

function HolySniperGetCharacter()

    return LocalPlayer
        and LocalPlayer.Character
        or nil
end

function HolySniperGetCharacterHumanoid()

