        workspace:FindFirstChild(
            "Map"
        )

    local root =
        map
        and map:FindFirstChild(
            "WildPetSpawns"
        )
        or nil

    if typeof(root) == "Instance" then
        return root
    end

    root =
        workspace:FindFirstChild(
            "WildPetSpawns",
            true
        )

    if typeof(root) == "Instance" then
        return root
    end

    return nil
end

function HolySniperGetWildPetRefRoot()

    local map =
        workspace:FindFirstChild(
            "Map"
        )

    local root =
        map
        and map:FindFirstChild(
            "WildPetRef"
        )
        or nil

    if typeof(root) == "Instance" then
        return root
    end

    root =
        workspace:FindFirstChild(
            "WildPetRef",
            true
        )

    if typeof(root) == "Instance" then
        return root
    end

    return nil
