function HolySniperUuidFromName(value)

    value =
        tostring(value or "")

    return value:match(
        "WildPet_([%w%-]+)$"
    )
    or value:match(
        "_WildPet_([%w%-]+)$"
    )
    or value:match(
        "([%w]+%-%w+%-%w+%-%w+%-%w+)"
    )
    or ""
end

function HolySniperReadModelAttribute(instance, names)

    if typeof(instance) ~= "Instance" then
        return ""
    end

    for _, name in ipairs(names or {}) do

        local ok,
            value =
            pcall(function()

                return instance:GetAttribute(
                    name
                )
            end)

        value =
            HolyCleanText(
                ok == true
                and value
                or ""
            )

        if value ~= "" then
            return value
        end
    end

    return ""
end

function HolySniperFindRefForModel(model)

    if typeof(model) ~= "Instance" then
        return nil,
            ""
    end

    local refs =
        HolySniperGetWildPetRefRoot()

    if typeof(refs) ~= "Instance" then
        return nil,
            ""
    end

    local uuid =
        HolySniperUuidFromName(
            model.Name
        )

    if uuid ~= "" then

        local direct =
            refs:FindFirstChild(
                "WildPet_"
                .. uuid
            )

        if typeof(direct) == "Instance" then

            return direct,
                uuid
        end

        for _, ref in ipairs(refs:GetChildren()) do

            if tostring(ref.Name):find(
                uuid,
                1,
                true
            ) then

                return ref,
                    uuid
            end
        end
    end

    local modelPetName =
        HolySniperReadModelAttribute(
            model,
            {
                "PetName",
                "Pet",
                "DisplayName",
                "Name",
            }
        )

    if modelPetName ~= "" then

        for _, ref in ipairs(refs:GetChildren()) do

            local refPetName =
                HolySniperReadModelAttribute(
                    ref,
                    {
                        "PetName",
                        "Pet",
                        "DisplayName",
                        "Name",
                    }
                )

            if refPetName == modelPetName then

                return ref,
                    uuid
            end
        end
    end

    return nil,
        uuid
end

function HolySniperFindBuyPrompt(model)

    if typeof(model) ~= "Instance" then
        return nil
    end

    local directRoot =
        model:FindFirstChild(
            "RootPart"
        )
        or model:FindFirstChild(
            "RigPart"
        )
        or model.PrimaryPart

    local directPrompt =
        directRoot
        and directRoot:FindFirstChild(
            "BuyPrompt"
        )
        or nil

    if typeof(directPrompt) == "Instance"
    and directPrompt:IsA("ProximityPrompt") then

        return directPrompt
    end

    for _, descendant in ipairs(model:GetDescendants()) do

        if descendant:IsA("ProximityPrompt") then

            local action =
                HolyCleanText(
                    descendant.ActionText
                )
                :lower()

            local name =
                tostring(
                    descendant.Name
                    or ""
                )
                :lower()

            if action == "buy"
            or action:find("buy", 1, true)
            or name:find("buy", 1, true) then

                return descendant
            end
        end
    end

    return nil
end

function HolySniperGetPromptPosition(prompt, model)

    if typeof(prompt) == "Instance" then

        local parent =
            prompt.Parent

        if typeof(parent) == "Instance" then

            if parent:IsA("BasePart") then
                return parent.Position
            end

            if parent:IsA("Attachment") then
                return parent.WorldPosition
            end
        end
    end

    return HolySniperGetModelPosition(
        model
    )
end

function HolySniperReadLivePetName(model, ref)

    local attrName =
        HolySniperReadModelAttribute(
            ref,
            {
                "PetName",
                "Pet",
                "PetTypeName",
                "DisplayName",
                "Name",
            }
        )

    if attrName == "" then

        attrName =
            HolySniperReadModelAttribute(
                model,
                {
                    "PetName",
                    "Pet",
                    "PetTypeName",
                    "DisplayName",
                    "Name",
                }
            )
    end

    if attrName ~= "" then

        return HolySniperResolvePetDisplay(
            attrName
        )
    end

    local rawName =
        tostring(
            model
            and model.Name
            or ""
        )

    local fromWildName =
        rawName:match(
            "^WildPet_([^_]+)_"
        )
        or rawName:match(
            "^WildPet_([^_]+)"
        )
        or ""

    fromWildName =
        HolyCleanText(
            fromWildName
        )

    if fromWildName ~= "" then

        return HolySniperResolvePetDisplay(
            fromWildName
        )
    end

    return ""
end

function HolySniperReadModelBooleanAttribute(instance, names)

    if typeof(instance) ~= "Instance" then
        return false
    end

    for _, name in ipairs(names or {}) do

        local ok,
            value =
            pcall(function()

                return instance:GetAttribute(
                    name
                )
            end)

        if ok == true then

            if value == true then
                return true
            end

            local text =
                tostring(value or "")
                    :lower()

            if text == "true"
            or text == "1"
            or text == "yes" then

                return true
            end

            local number =
                tonumber(value)

            if number ~= nil
            and number == 1 then

                return true
            end
        end
    end

    return false
end

function HolySniperReadModelNumberAttribute(instance, names)

    if typeof(instance) ~= "Instance" then
        return nil
    end

    for _, name in ipairs(names or {}) do

        local ok,
            value =
            pcall(function()

                return instance:GetAttribute(
                    name
                )
            end)

        if ok == true then

            local number =
                tonumber(value)

            if number ~= nil then
                return number
            end
        end
    end

    return nil
end

function HolySniperReadLiveSize(model, ref)

    local rawSize =
        HolySniperReadModelAttribute(
            ref,
            {
                "PetSize",
                "Size",
                "DisplaySize",
                "ScaleType",
                "WildPetSize",
                "PetScaleType",
                "VariantSize",
            }
        )

    if rawSize == "" then

        rawSize =
            HolySniperReadModelAttribute(
                model,
                {
                    "PetSize",
                    "Size",
                    "DisplaySize",
                    "ScaleType",
                    "WildPetSize",
                    "PetScaleType",
                    "VariantSize",
                }
            )
    end

    if rawSize ~= "" then

        return HolySniperNormalizeSizeName(
            rawSize
        )
    end

    local scale =
        HolySniperReadModelNumberAttribute(
            ref,
            {
                "Scale",
                "PetScale",
                "SizeScale",
                "SizeMulti",
                "ScaleMultiplier",
            }
        )

    if scale == nil then

        scale =
            HolySniperReadModelNumberAttribute(
                model,
                {
                    "Scale",
                    "PetScale",
                    "SizeScale",
                    "SizeMulti",
                    "ScaleMultiplier",
                }
            )
    end

    if scale == nil then

        scale =
            1

        if typeof(model) == "Instance" then

            pcall(function()

                scale =
                    model:GetScale()
            end)
        end
    end

    scale =
        tonumber(scale)
        or 1

    if scale >= 3.25 then
        return "Huge"
    end

    if scale >= 1.50 then
        return "Big"
    end

    return "Normal"
end

function HolySniperReadLiveVariant(model, ref)

    if HolySniperReadModelBooleanAttribute(
        ref,
        {
            "Rainbow",
            "IsRainbow",
            "PetRainbow",
            "RainbowPet",
        }
    ) == true then

        return "Rainbow"
    end

    if HolySniperReadModelBooleanAttribute(
        model,
        {
            "Rainbow",
            "IsRainbow",
            "PetRainbow",
            "RainbowPet",
        }
    ) == true then

        return "Rainbow"
    end

    local rawVariant =
        HolySniperReadModelAttribute(
            ref,
            {
                "PetType",
                "Type",
                "Variant",
                "PetVariant",
                "DisplayType",
                "DisplayVariant",
                "Mutation",
                "WildPetType",
                "PetTypeName",
            }
        )

    if rawVariant == "" then

        rawVariant =
            HolySniperReadModelAttribute(
                model,
                {
                    "PetType",
                    "Type",
                    "Variant",
                    "PetVariant",
                    "DisplayType",
                    "DisplayVariant",
                    "Mutation",
                    "WildPetType",
                    "PetTypeName",
                }
            )
    end

    if rawVariant ~= "" then

        rawVariant =
            HolySniperNormalizeVariantName(
                rawVariant
            )

        if rawVariant == "Rainbow" then
            return "Rainbow"
        end

        if rawVariant ~= "Normal"
        and HolySniperPetTypeIsValid(rawVariant) == true then

            return rawVariant
        end

        return "Normal"
    end

    local refName =
        tostring(
            ref
            and ref.Name
            or ""
        )
        :lower()

    local modelName =
        tostring(
            model
            and model.Name
            or ""
        )
        :lower()

    if refName:find("rainbow", 1, true)
    or modelName:find("rainbow", 1, true) then

        return "Rainbow"
    end

    return "Normal"
end

function HolySniperGetModelPosition(model)

    if typeof(model) ~= "Instance" then
        return nil
    end

    local rootPart =
        model:FindFirstChild(
            "RootPart"
        )
        or model:FindFirstChild(
            "RigPart"
        )
        or model.PrimaryPart

    if typeof(rootPart) == "Instance"
    and rootPart:IsA("BasePart") then

        return rootPart.Position
    end

    local ok,
        pivot =
        pcall(function()

            return model:GetPivot()
        end)

    if ok == true
    and typeof(pivot) == "CFrame" then

        return pivot.Position
    end

    return nil
end

function HolySniperReadShecklesObject()

    local roots = {
        LocalPlayer,
        LocalPlayer and LocalPlayer:FindFirstChild("leaderstats"),
        LocalPlayer and LocalPlayer:FindFirstChild("PlayerData"),
    }

    for _, root in ipairs(roots) do

        if typeof(root) == "Instance" then

            for _, name in ipairs({
                "Sheckles",
                "Sheckle",
                "Money",
                "Cash",
                "Coins",
            }) do

                local object =
                    root:FindFirstChild(
                        name,
                        true
                    )

                if object
                and object:IsA("ValueBase")
                and tonumber(object.Value) then

                    return object
                end
            end
        end
    end

    return nil
end

function HolySniperReadSheckles()

    local object =
        HolySniperReadShecklesObject()

    if object then

        return tonumber(object.Value)
            or 0
    end

    return nil
end

function HolySniperReadEntryPrice(ref, prompt, petName, petKey)

    local refPrice =
        tonumber(
            HolySniperReadModelAttribute(
                ref,
                {
                    "Price",
                    "Cost",
                }
            )
        )

    if refPrice
    and refPrice > 0 then

        return refPrice
    end

    if typeof(prompt) == "Instance" then

        local text =
            HolyCleanText(
                prompt.ObjectText
            )

        local raw =
            text:match(
                "([%d,]+)"
            )

        if raw then

            local price =
                tonumber(
                    raw:gsub(",", "")
                )

            if price
            and price > 0 then

                return price
            end
        end
    end

    return HolySniperGetBasePrice({
        Pet =
            petName,

        PetKey =
            petKey,
    })
end

function HolySniperRawBuyable(model, ref, prompt)

    if typeof(model) ~= "Instance"
    or model.Parent == nil then

        return false,
            "spawn missing"
    end

    if typeof(ref) ~= "Instance"
    or ref.Parent == nil then

        return false,
            "ref missing"
    end

    if typeof(prompt) ~= "Instance"
    or prompt:IsA("ProximityPrompt") ~= true
    or prompt.Parent == nil then

        return false,
            "prompt missing"
    end

    if prompt.Enabled ~= true then

        return false,
            "prompt disabled"
    end

    local ownerUserId =
        tonumber(
            HolySniperReadModelAttribute(
                ref,
                {
                    "OwnerUserId",
                }
            )
        )
        or 0

    local ownerName =
        HolyCleanText(
            HolySniperReadModelAttribute(
                ref,
                {
                    "OwnerName",
                }
            )
        )

    local state =
        HolyCleanText(
            HolySniperReadModelAttribute(
                ref,
                {
                    "State",
                }
            )
        )

    if ownerUserId ~= 0 then

        return false,
            "already owned"
    end

    if ownerName ~= "" then

        return false,
            "already owned"
    end

    if state ~= ""
    and state ~= "wandering"
    and state ~= "wandering_walking" then

        return false,
            "state "
            .. state
    end

    return true,
        "buyable"
end

function HolySniperBuildLiveEntry(model)

    if typeof(model) ~= "Instance"
    or model:IsA("Model") ~= true then

        return nil
    end

    local ref,
        uuid =
        HolySniperFindRefForModel(
            model
        )

    local prompt =
        HolySniperFindBuyPrompt(
            model
        )

    local petName =
        HolySniperReadLivePetName(
            model,
            ref
        )

    if petName == "" then
        return nil
    end

    local petKey =
        HolySniperResolvePetKey(
            petName
        )

    local position =
        HolySniperGetPromptPosition(
            prompt,
            model
        )

    local root =
        HolySniperGetCharacterRoot()

    local distance =
        999999

    if typeof(position) == "Vector3"
    and typeof(root) == "Instance"
    and root:IsA("BasePart") then

        distance =
            (
                root.Position
                - position
            ).Magnitude
    end

    local size =
    HolySniperReadLiveSize(
        model,
        ref
    )

    local variant =
        HolySniperReadLiveVariant(
            model,
            ref
        )

    local debugId =
        ""

    pcall(function()

        debugId =
            model:GetDebugId()
    end)

    local buyable,
        buyableReason =
        HolySniperRawBuyable(
            model,
            ref,
            prompt
        )

    local promptRange =
        12

    if typeof(prompt) == "Instance"
    and prompt:IsA("ProximityPrompt") then

        promptRange =
            tonumber(prompt.MaxActivationDistance)
            or 12
    end

    local key =
        uuid ~= ""
        and uuid
        or (
            debugId ~= ""
            and debugId
            or tostring(model.Name)
        )

    local entry = {
        Key =
            key,

        UUID =
            uuid,

        Model =
            model,

        Ref =
            ref,

        Prompt =
            prompt,

        Pet =
            petName,

        PetKey =
            petKey,

        Size =
            size,

        Variant =
            variant,

        Position =
            position,

        Distance =
            distance,

        PromptRange =
            promptRange,

        Buyable =
            buyable == true,

        BuyableReason =
            tostring(buyableReason or ""),

        Price =
            HolySniperReadEntryPrice(
                ref,
                prompt,
                petName,
                petKey
            ),

        BasePrice =
            HolySniperGetBasePrice({
                Pet =
                    petName,

                PetKey =
                    petKey,
            }),
    }

    return entry
end

function HolySniperRefreshEntry(entry)

    if type(entry) ~= "table" then
        return nil
    end

    if typeof(entry.Model) ~= "Instance"
    or entry.Model.Parent == nil then

        return nil
    end

    return HolySniperBuildLiveEntry(
        entry.Model
    )
end

function HolySniperEntryKey(entry)

    if type(entry) ~= "table" then
        return ""
    end

    return HolyCleanText(
        entry.UUID
        or entry.Key
        or ""
    )
end

function HolySniperPetBuyProtectionEnsure()

    HOLY_SNIPER_RUNTIME =
        type(HOLY_SNIPER_RUNTIME) == "table"
        and HOLY_SNIPER_RUNTIME
        or {}

    HOLY_SNIPER_RUNTIME.BuyProtection =
        type(HOLY_SNIPER_RUNTIME.BuyProtection) == "table"
        and HOLY_SNIPER_RUNTIME.BuyProtection
        or {
            Active = false,
        }

    return HOLY_SNIPER_RUNTIME.BuyProtection
end

function HolySniperPetBuyStateLooksPending(value)

    local state =
        HolyCleanText(
            value
        )
        :lower()

    state =
        state:gsub(
            "%s+",
            "_"
        )

    if state == "" then
        return false
    end

    if state == "walking_to_garden"
    or state == "waiting_for_garden"
    or state == "going_to_garden"
    or state == "moving_to_garden"
    or state == "traveling_to_garden"
    or state == "travelling_to_garden"
    or state == "pathing_to_garden"
    or state == "returning_to_garden" then

        return true
    end

    if state:find("_to_garden", 1, true) then
        return true
    end

    if state:find("garden", 1, true)
    and (
        state:find("walk", 1, true)
        or state:find("wait", 1, true)
        or state:find("go", 1, true)
        or state:find("move", 1, true)
        or state:find("travel", 1, true)
        or state:find("path", 1, true)
        or state:find("return", 1, true)
    ) then

        return true
    end

    return false
end

function HolySniperFindPetBuyProtectionRef(lock)

    lock =
        type(lock) == "table"
        and lock
        or {}

    local key =
        HolyCleanText(
            lock.UUID
            or lock.Key
            or lock.EntryKey
        )

    if key == "" then
        return nil
    end

    local root =
        HolySniperGetWildPetRefRoot()

    if typeof(root) ~= "Instance" then
        return nil
    end

    local direct =
        root:FindFirstChild(
            "WildPet_"
            .. key
        )

    if typeof(direct) == "Instance" then
        return direct
    end

    for _, child in ipairs(root:GetChildren()) do

        if tostring(child.Name):find(
            key,
            1,
            true
        ) then

            return child
        end
    end

    return nil
end

function HolySniperArmPetBuyProtection(entry, reason)

    local lock =
        HolySniperPetBuyProtectionEnsure()

    entry =
        type(entry) == "table"
        and entry
        or {}

    local now =
        os.clock()

    local key =
        HolySniperEntryKey(
            entry
        )

    lock.Active =
        true

    lock.EntryKey =
        key

    lock.Key =
        key

    lock.UUID =
        HolyCleanText(
            entry.UUID
            or entry.Key
            or key
        )

    lock.Pet =
        HolyCleanText(
            entry.Pet
            or entry.PetName
            or entry.DisplayName
            or "pet"
        )

    lock.Ref =
        entry.Ref

    lock.StartedAt =
        now

    lock.ConfirmedAt =
        tonumber(lock.ConfirmedAt)
        or 0

    lock.MinUntil =
        now
        + (
            tonumber(HOLY_SNIPER_PET_BUY_SETTLE_SECONDS)
            or 18
        )

    lock.HardUntil =
        now
        + (
            tonumber(HOLY_SNIPER_PET_BUY_HARD_TIMEOUT)
            or 120
        )

    lock.Reason =
        tostring(reason or "buy pending")

    lock.LastStatusAt =
        0

    lock.LastNotifyAt =
        0

    HOLY_SNIPER_RUNTIME.BuyProtectionActive =
        true

    return true
end

function HolySniperTouchPetBuyProtection(entry, reason)

    local lock =
        HolySniperPetBuyProtectionEnsure()

    if lock.Active ~= true then

        return HolySniperArmPetBuyProtection(
            entry,
            reason
        )
    end

    local now =
        os.clock()

    entry =
        type(entry) == "table"
        and entry
        or {}

    if entry.Ref ~= nil then
        lock.Ref =
            entry.Ref
    end

    local key =
        HolySniperEntryKey(
            entry
        )

    if key ~= "" then

        lock.EntryKey =
            key

        lock.Key =
            key

        lock.UUID =
            HolyCleanText(
                entry.UUID
                or entry.Key
                or key
            )
    end

    if reason ~= nil then

        lock.Reason =
            tostring(reason)
    end

    lock.ConfirmedAt =
        now

    lock.MinUntil =
        math.max(
            tonumber(lock.MinUntil)
            or 0,
            now
            + (
                tonumber(HOLY_SNIPER_PET_BUY_SETTLE_SECONDS)
                or 18
            )
        )

    HOLY_SNIPER_RUNTIME.BuyProtectionActive =
        true

    return true
end

function HolySniperClearPetBuyProtection(reason)

    local lock =
        HolySniperPetBuyProtectionEnsure()

    if lock.Active ~= true then
        return false
    end

    lock.Active =
        false

    lock.Reason =
        tostring(reason or "clear")

    lock.Ref =
        nil

    lock.EntryKey =
        ""

    lock.Key =
        ""

    lock.UUID =
        ""

    lock.Pet =
        ""

    lock.StartedAt =
        0

    lock.ConfirmedAt =
        0

    lock.MinUntil =
        0

    lock.HardUntil =
        0

    HOLY_SNIPER_RUNTIME.BuyProtectionActive =
        false

    return true
end

function HolySniperPetBuyProtectionActive()

    local lock =
        HolySniperPetBuyProtectionEnsure()

    if lock.Active ~= true then

        HOLY_SNIPER_RUNTIME.BuyProtectionActive =
            false

        return false,
            "clear"
    end

    local now =
        os.clock()

    local hardUntil =
        tonumber(lock.HardUntil)
        or 0

    if hardUntil > 0
    and now >= hardUntil then

        HolySniperClearPetBuyProtection(
            "hard timeout"
        )

        return false,
            "hard timeout"
    end

    if HOLY_SNIPER_RUNTIME.Buying == true then

        HOLY_SNIPER_RUNTIME.BuyProtectionActive =
            true

        return true,
            "buying"
    end

    local ref =
        lock.Ref

    if typeof(ref) ~= "Instance"
    or ref.Parent == nil then

        ref =
            HolySniperFindPetBuyProtectionRef(
                lock
            )

        lock.Ref =
            ref
    end

    local state =
        ""

    local ownerUserId =
        0

    local ownerName =
        ""

    if typeof(ref) == "Instance"
    and ref.Parent ~= nil then

        state =
            HolySniperReadModelAttribute(
                ref,
                {
                    "State",
                    "PetState",
                }
            )

        ownerUserId =
            tonumber(
                HolySniperReadModelAttribute(
                    ref,
                    {
                        "OwnerUserId",
                        "OwnerUserID",
                        "Owner",
                        "UserId",
                        "UserID",
                    }
                )
            )
            or 0

        ownerName =
            HolyCleanText(
                HolySniperReadModelAttribute(
                    ref,
                    {
                        "OwnerName",
                        "OwnerDisplayName",
                    }
                )
            )
    end

    local ownedByLocal =
        ownerUserId == tonumber(LocalPlayer.UserId)
        or (
            ownerName ~= ""
            and ownerName == HolyCleanText(LocalPlayer.Name)
        )

    if HolySniperPetBuyStateLooksPending(state) == true then

        HOLY_SNIPER_RUNTIME.BuyProtectionActive =
            true

        lock.Reason =
            state ~= ""
            and state
            or "going to garden"

        return true,
            lock.Reason
    end

    if ownedByLocal == true then

        HOLY_SNIPER_RUNTIME.BuyProtectionActive =
            true

        lock.Reason =
            "owned by you, settling"

        return true,
            lock.Reason
    end

    local minUntil =
        tonumber(lock.MinUntil)
        or 0

    if now < minUntil then

        HOLY_SNIPER_RUNTIME.BuyProtectionActive =
            true

        return true,
            tostring(lock.Reason or "settling")
    end

    HolySniperClearPetBuyProtection(
        "settled"
    )

    return false,
        "settled"
end

function HolySniperPetBuyProtectionBlocks(actionName, notify)

    local active,
        reason =
        HolySniperPetBuyProtectionActive()

    if active ~= true then
        return false
    end

    local lock =
        HolySniperPetBuyProtectionEnsure()

    local now =
        os.clock()

    if now - (
        tonumber(lock.LastStatusAt)
        or 0
    ) >= 1.25 then

        lock.LastStatusAt =
            now

        if type(HolySniperSetStatus) == "function" then

            HolySniperSetStatus(
                tostring(actionName or "Action")
                .. " blocked: pet buy pending"
            )
        end

        if type(HolyServerSetStatus) == "function" then

            HolyServerSetStatus(
                tostring(actionName or "Action")
                .. " blocked: pet buy pending"
            )
        end
    end

    if notify == true
    and now - (
        tonumber(lock.LastNotifyAt)
        or 0
    ) >= 3 then

        lock.LastNotifyAt =
            now

        if type(HolyNotify) == "function" then

            HolyNotify(
                "HOLY Protection",
                tostring(actionName or "Action")
                .. " blocked while pet is settling: "
                .. tostring(reason or "pending"),
                4
            )
        end
    end

    return true
end

