    for _, listName in ipairs({
        "Connections",
        "GearConnections",
    }) do

        local connections =
            HOLY_DEFENSE_RUNTIME[listName]

        if type(connections) == "table" then

            for _, connection in ipairs(connections) do

                pcall(function()

