    MonitorToken = nil,
    MonitorScanDelay = 0.15,

    Target = nil,
    Entry = nil,
    Filter = nil,

    TargetPetId = "",
    TargetPetName = "",
    TargetMissingAt = 0,
    CompletionStartedAt = 0,

    InventoryConfirmed = false,
