    InventoryBaselineInstances = {},
    InventoryBaselineIds = {},
    CompletedTargets = {},
    LastInventoryCheckAt = 0,

    Connections = {},
    GearConnections = {},

    GearLockActive = false,
    DefenseTool = nil,
    EquipPending = false,
    ReequipToken = 0,
    ReequipCooldown = 0.18,

    RebuyCount = 0,
    MaxRebuys = 3,

    LastEquipAt = 0,
    LastMoveAt = 0,
    LastMoveToAt = 0,
    LastShotAt = 0,
    LastShovelAt = 0,
    LastPreAimAt = 0,

