}

function HolyDefenseEnsureRuntime()

    HOLY_DEFENSE_RUNTIME =
        type(HOLY_DEFENSE_RUNTIME) == "table"
        and HOLY_DEFENSE_RUNTIME
        or {}

    local runtime =
        HOLY_DEFENSE_RUNTIME

    runtime.Connections =
        type(runtime.Connections) == "table"
        and runtime.Connections
        or {}

    runtime.GearConnections =
        type(runtime.GearConnections) == "table"
        and runtime.GearConnections
        or {}

    runtime.InventoryBaselineInstances =
        type(runtime.InventoryBaselineInstances) == "table"
        and runtime.InventoryBaselineInstances
        or {}

    runtime.InventoryBaselineIds =
        type(runtime.InventoryBaselineIds) == "table"
        and runtime.InventoryBaselineIds
        or {}

    runtime.CompletedTargets =
        type(runtime.CompletedTargets) == "table"
        and runtime.CompletedTargets
        or {}

    runtime.ReequipToken =
        tonumber(runtime.ReequipToken)
        or 0

    runtime.ReequipCooldown =
        math.clamp(
            tonumber(runtime.ReequipCooldown)
            or 0.18,
            0.08,
            1
        )

    runtime.MonitorScanDelay =
        math.clamp(
            tonumber(runtime.MonitorScanDelay)
            or 0.15,
            0.08,
            1
        )

    runtime.MaxRebuys =
        tonumber(runtime.MaxRebuys)
        or 3

    return runtime
end

function HolyDefenseDisconnect()

    local runtime =
        HolyDefenseEnsureRuntime()

    for _, connection in ipairs(runtime.Connections or {}) do

        pcall(function()

            connection:Disconnect()
        end)
    end

    runtime.Connections =
        {}
end

function HolyDefenseAddConnection(connection)

    local runtime =
        HolyDefenseEnsureRuntime()

    if connection ~= nil then

        table.insert(
            runtime.Connections,
            connection
        )
    end

    return connection
end

function HolyDefenseReadAttr(instance, name)

    if typeof(instance) ~= "Instance" then
        return nil
    end

    local ok,
        value =
        pcall(function()

            return instance:GetAttribute(
                name
            )
        end)

    if ok == true then
        return value
    end

    return nil
end

function HolyDefenseGetPosition(object)

    if typeof(object) ~= "Instance" then
        return nil
    end

    if object:IsA("BasePart") then
        return object.Position
    end

    if object:IsA("Model") then

        local ok,
            pivot =
            pcall(function()

                return object:GetPivot()
            end)

        if ok == true
        and typeof(pivot) == "CFrame" then

            return pivot.Position
        end
    end

    local part =
        object:FindFirstChild(
            "HumanoidRootPart",
            true
        )
        or object:FindFirstChild(
            "RootPart",
            true
        )
        or object:FindFirstChildWhichIsA(
            "BasePart",
            true
        )

    if typeof(part) == "Instance"
    and part:IsA("BasePart") then

        return part.Position
    end

    return nil
end

function HolyDefenseDeepGet(root, path)

    local current =
        root

    for part in tostring(path or ""):gmatch("[^%.]+") do

        if type(current) ~= "table" then
            return nil
        end

        current =
            current[part]
    end

    return current
end

function HolyDefenseGetNetworking()

    local runtime =
        HolyDefenseEnsureRuntime()

    if type(runtime.Networking) == "table" then
        return runtime.Networking
    end

    local networking =
        nil

    if type(HolyShopRequireModule) == "function" then

        networking =
            HolyShopRequireModule(
                "SharedModules.Networking"
            )
    end

    if type(networking) ~= "table" then

        local module =
            ReplicatedStorage:FindFirstChild("SharedModules")
            and ReplicatedStorage.SharedModules:FindFirstChild("Networking")

        if typeof(module) == "Instance"
        and module:IsA("ModuleScript") then

            local ok,
                result =
                pcall(function()

                    return require(
                        module
                    )
                end)

            if ok == true
            and type(result) == "table" then

                networking =
                    result
            end
        end
    end

    runtime.Networking =
        type(networking) == "table"
        and networking
        or nil

    return runtime.Networking
end

function HolyDefenseResolvePackets()

    local runtime =
        HolyDefenseEnsureRuntime()

    local networking =
        HolyDefenseGetNetworking()

    if type(networking) ~= "table" then
        return false
    end

    runtime.WildTamePacket =
        runtime.WildTamePacket
        or HolyDefenseDeepGet(
            networking,
            "Pets.WildPetTame"
        )

    runtime.StrawberryPacket =
        runtime.StrawberryPacket
        or HolyDefenseDeepGet(
            networking,
            "StrawberrySniper.Fire"
        )

    runtime.ShovelSwingPacket =
        runtime.ShovelSwingPacket
        or HolyDefenseDeepGet(
            networking,
            "Shovel.SwingShovel"
        )

    runtime.ShovelHitPacket =
        runtime.ShovelHitPacket
        or HolyDefenseDeepGet(
            networking,
            "Shovel.HitPlayer"
        )

    runtime.PetScarePacket =
        runtime.PetScarePacket
        or HolyDefenseDeepGet(
            networking,
            "Pets.ScarePet"
        )

    return true
end

function HolyDefenseFirePacket(packet, ...)

    if type(packet) ~= "table"
    or type(packet.Fire) ~= "function" then

        return false
    end

    local ok =
        pcall(function(...)

            packet:Fire(
                ...
            )
        end, ...)

    return ok == true
end

