function HolyLoadingPathOf(instance)

    if typeof(instance) ~= "Instance" then
        return tostring(instance)
    end

    local ok,
        result =
        pcall(function()

            return instance:GetFullName()
        end)

    if ok == true then
        return tostring(result)
    end

    return tostring(instance)
end

function HolyLoadingGetText(instance)

    if typeof(instance) ~= "Instance" then
        return ""
    end

    if instance:IsA("TextLabel")
    or instance:IsA("TextButton")
    or instance:IsA("TextBox") then

        local ok,
            text =
            pcall(function()

                return instance.Text
            end)

        if ok == true then

            return HolyCleanText(
                text
            )
        end
    end

    return ""
end

function HolyLoadingGetTextTransparency(instance)

    local value =
        nil

    if typeof(instance) ~= "Instance" then
        return nil
    end

    pcall(function()

        if instance:IsA("TextLabel")
        or instance:IsA("TextButton")
        or instance:IsA("TextBox") then

            value =
                instance.TextTransparency
        end
    end)

    return tonumber(value)
end

function HolyLoadingVisibleChainReady(instance)

    if typeof(instance) ~= "Instance" then
        return false
    end

    local current =
        instance

    while current
    and current ~= game do

        if current:IsA("GuiObject") then

            local visible =
                false

            local absSize =
                Vector2.zero

            pcall(function()

                visible =
                    current.Visible == true

                absSize =
                    current.AbsoluteSize
            end)

            if visible ~= true then
                return false
            end

            if current == instance
            and (
                typeof(absSize) ~= "Vector2"
                or absSize.X <= 2
                or absSize.Y <= 2
            ) then

                return false
            end
        end

        if current:IsA("LayerCollector") then

            local enabled =
                false

            pcall(function()

                enabled =
                    current.Enabled == true
            end)

            if enabled ~= true then
                return false
            end
        end

        if current == workspace then
            break
        end

        current =
            current.Parent
    end

    return true
end

function HolyLoadingGetGuiCenter(instance)

    if typeof(instance) ~= "Instance"
    or instance:IsA("GuiObject") ~= true then

        return nil
    end

    local position =
        nil

    local size =
        nil

    pcall(function()

        position =
            instance.AbsolutePosition

        size =
            instance.AbsoluteSize
    end)

    if typeof(position) ~= "Vector2"
    or typeof(size) ~= "Vector2" then

        return nil
    end

    return Vector2.new(
        position.X + size.X / 2,
        position.Y + size.Y / 2
    )
end

function HolyLoadingGetScreenCenter()

    local camera =
        workspace.CurrentCamera

    local viewport =
        camera
        and camera.ViewportSize
        or Vector2.new(
            1280,
            720
        )

    return Vector2.new(
        viewport.X / 2,
        viewport.Y / 2
    )
end

function HolyLoadingClickAt(position)

    if typeof(position) ~= "Vector2" then
        return false
    end

    local inputManager =
        HolyLoadingGetInputManager()

    if not inputManager then
        return false
    end

    pcall(function()

        inputManager:SendMouseMoveEvent(
            position.X,
            position.Y,
            game
        )
    end)

    task.wait(
        0.025
    )

    pcall(function()

        inputManager:SendMouseButtonEvent(
            position.X,
            position.Y,
            0,
            true,
            game,
            0
        )
    end)

    task.wait(
        0.055
    )

    pcall(function()

        inputManager:SendMouseButtonEvent(
            position.X,
            position.Y,
            0,
            false,
            game,
            0
        )
    end)

    return true
end

function HolyLoadingPressKey(keyCode)

    local inputManager =
        HolyLoadingGetInputManager()

    if not inputManager then
        return false
    end

    pcall(function()

        inputManager:SendKeyEvent(
            true,
            keyCode,
            false,
            game
        )
    end)

    task.wait(
        0.055
    )

    pcall(function()

        inputManager:SendKeyEvent(
            false,
            keyCode,
            false,
            game
        )
    end)

    return true
end

function HolyLoadingGetWorkspaceLoadingGui()

    local menu =
        workspace:FindFirstChild(
            "LoadingScreenMenu"
        )

    if not menu then

        menu =
            workspace:FindFirstChild(
                "LoadingScreenMenu",
                true
            )
    end

    if not menu then
        return nil
    end

    local loadingGui =
        menu:FindFirstChild(
            "LoadingGui"
        )

    if not loadingGui then

        loadingGui =
            menu:FindFirstChild(
                "LoadingGui",
                true
            )
    end

    return loadingGui
end

function HolyLoadingGetInnerFrame()

    local loadingGui =
        HolyLoadingGetWorkspaceLoadingGui()

    if not loadingGui then
        return nil
    end

    local variant =
        loadingGui:FindFirstChild(
            "Variant1Frame",
            true
        )

    if not variant then
        return nil
    end

    return variant:FindFirstChild(
        "InnerFrame",
        true
    )
