    },
}

function HolyShopRequireModule(path)

    local current =
        ReplicatedStorage

    for part in tostring(path or ""):gmatch("[^%.]+") do

        current =
            current
            and current:FindFirstChild(part)
            or nil
    end

    if typeof(current) ~= "Instance"
    or current:IsA("ModuleScript") ~= true then

        return nil
    end

    local ok,
        result =
        pcall(function()

            return require(
                current
            )
        end)

    if ok ~= true then
        return nil
    end

    return result
end

function HolyDataLogOnce(key, ...)

    HOLY_DATA_STATE =
        type(HOLY_DATA_STATE) == "table"
        and HOLY_DATA_STATE
        or {}

    HOLY_DATA_STATE.Logged =
        type(HOLY_DATA_STATE.Logged) == "table"
        and HOLY_DATA_STATE.Logged
        or {}

    key =
        tostring(key or "")

    if key ~= ""
    and HOLY_DATA_STATE.Logged[key] == true then
        return false
    end

    if key ~= "" then

        HOLY_DATA_STATE.Logged[key] =
            true
    end

    print(
        "[HOLY DATA]",
        ...
    )

    return true
end

function HolyDataFindSharedModule(moduleName)

    moduleName =
        HolyCleanText(
            moduleName
        )

    if moduleName == "" then
        return nil,
            "empty module"
    end

    local sharedData =
        ReplicatedStorage:FindFirstChild(
            "SharedData"
        )

    if typeof(sharedData) ~= "Instance" then

        return nil,
            "SharedData missing"
    end

    local module =
        sharedData:FindFirstChild(
            moduleName
        )

    if typeof(module) ~= "Instance"
    or module:IsA("ModuleScript") ~= true then

        return nil,
            moduleName .. " missing"
    end

    return module,
        "found"
end

function HolyDataTryRequireModule(moduleName)

    HOLY_DATA_STATE =
        type(HOLY_DATA_STATE) == "table"
        and HOLY_DATA_STATE
        or {}

    HOLY_DATA_STATE.Modules =
        type(HOLY_DATA_STATE.Modules) == "table"
        and HOLY_DATA_STATE.Modules
        or {}

    moduleName =
        HolyCleanText(
            moduleName
        )

    if moduleName == "" then
        return nil,
            "empty module"
    end

    local cached =
        HOLY_DATA_STATE.Modules[moduleName]

    if type(cached) == "table" then
        return cached,
            "cached"
    end

    local module,
        findReason =
        HolyDataFindSharedModule(
            moduleName
        )

    if typeof(module) ~= "Instance" then
        return nil,
            findReason
    end

    local ok,
        result =
        pcall(function()

            return require(
                module
            )
        end)

    if ok ~= true
    or type(result) ~= "table" then

        return nil,
            "require failed"
    end

    HOLY_DATA_STATE.Modules[moduleName] =
        result

    HolyDataLogOnce(
        "loaded:" .. moduleName,
        moduleName .. " loaded."
    )

    return result,
        "loaded"
end

function HolyDataGetModule(moduleName)

    local result =
        HolyDataTryRequireModule(
            moduleName
        )

    if type(result) ~= "table" then
        return nil
    end

    return result
end

function HolyDataCountPetDataRows(petData)

    if type(petData) ~= "table" then
        return 0
    end

    local count =
        0

    for key, row in pairs(petData) do

        if type(HolySniperIsPetDataRow) == "function"
        and HolySniperIsPetDataRow(key, row) == true then

            count =
                count + 1
        end
    end

    return count
end

function HolyDataListHasValue(values, value)

    value =
        HolyCleanText(
            value
        )

    if value == "" then
        return false
    end

    for _, item in ipairs(values or {}) do

        if item == value then
            return true
        end
    end

    return false
end

function HolyDataSetDropdownValues(dropdown, values, selected)

    if type(dropdown) ~= "table" then
        return false
    end

    values =
        type(values) == "table"
        and values
        or {
            "Raccoon",
        }

    selected =
        HolyCleanText(
            selected
        )

    if selected == "" then
        selected =
            "Raccoon"
    end

    pcall(function()

        if type(dropdown.SetValues) == "function" then

            dropdown:SetValues(
                values
            )

        elseif type(dropdown.SetItems) == "function" then

            dropdown:SetItems(
                values
            )
        end
    end)

    if type(dropdown.SetValue) == "function" then

        pcall(function()

            dropdown:SetValue(
                selected
            )
        end)
    end

    return true
end

function HolyDataRefreshPetDropdowns()

    local values =
        HolySniperGetPetValues()

    if type(values) ~= "table"
    or #values <= 0 then

        values = {
            "Any Pet",
            "Raccoon",
        }
    end

    local selected =
        HolySniperResolvePetDisplay(
            HOLY_SNIPER_STATE.BuilderPet
            or "Raccoon"
        )

    if HolyDataListHasValue(values, selected) ~= true then

        selected =
            HolyDataListHasValue(values, "Raccoon") == true
            and "Raccoon"
            or values[1]
            or "Raccoon"
    end

    HOLY_SNIPER_STATE.BuilderPet =
        selected

    local options =
        HOLY_DEV_LIBRARY
        and HOLY_DEV_LIBRARY.Options
        or Options

    if type(options) == "table" then

        HolyDataSetDropdownValues(
            options.HolySniperPetFilter,
            values,
            selected
        )
    end

    if type(HolyServerFinderApplyFilterOptions) == "function"
    and type(HOLY_SERVER_FINDER_HUD) == "table" then

        HolyServerFinderApplyFilterOptions(
            HOLY_SERVER_FINDER_HUD
        )
    end

    if type(HolySniperRefreshUI) == "function" then

        HolySniperRefreshUI()
    end

    HolyDataLogOnce(
        "pet-dropdown-refreshed",
        "Pet dropdown refreshed."
    )

    return true
end

function HolyDataStartPetLoader(reason)

    HOLY_DATA_STATE =
        type(HOLY_DATA_STATE) == "table"
        and HOLY_DATA_STATE
        or {}

    if HOLY_DATA_STATE.LoaderStarted == true then
        return false
    end

    HOLY_DATA_STATE.LoaderStarted =
        true

    HolyDataLogOnce(
        "petdata-waiting",
        "PetData waiting..."
    )

    task.spawn(function()

        local retryDelays = {
            0,
            0.15,
            0.35,
            0.75,
            1.20,
            1.80,
            2.50,
        }

        local lastReason =
            "not started"

        for _, delay in ipairs(retryDelays) do

            if delay > 0 then

                task.wait(
                    delay
                )
            end

            HolyDataTryRequireModule(
                "PetSizes"
            )

            HolyDataTryRequireModule(
                "PetTypes"
            )

            local petData,
                petReason =
                HolyDataTryRequireModule(
                    "PetData"
                )

            lastReason =
                tostring(petReason or "unknown")

            local count =
                HolyDataCountPetDataRows(
                    petData
                )

            if count > 0 then

                HOLY_DATA_STATE.PetDataReady =
                    true

                HOLY_DATA_STATE.PetDataCount =
                    count

                HolyDataLogOnce(
                    "petdata-loaded",
                    "PetData loaded: "
                        .. tostring(count)
                        .. " pets."
                )

                HolyDataRefreshPetDropdowns()

                return
            end
        end

        HOLY_DATA_STATE.PetDataReady =
            false

        HOLY_DATA_STATE.PetDataCount =
            0

        HolyDataLogOnce(
            "petdata-failed",
            "PetData unavailable after startup retries. Using Raccoon fallback. Last: "
                .. tostring(lastReason)
        )
    end)

    return true
end

function HolyShopAddItemRow(rows, name, price)

    name =
        HolyCleanText(name)

    if name == "" then
        return
    end

    rows[name] =
        rows[name]
        or {
            Name = name,
            Price = 0,
        }

    rows[name].Price =
        math.max(
            tonumber(rows[name].Price)
            or 0,
            tonumber(price)
            or 0
        )
end

function HolyShopModuleEnabled(modulePath, functionName, itemName, fallback)

    local module =
        HolyShopRequireModule(
            modulePath
        )

    local callback =
        type(module) == "table"
        and module[functionName]
        or nil

    if type(callback) ~= "function" then
        return fallback ~= false
    end

    local ok,
        result =
        pcall(
            callback,
            itemName
        )

    if ok ~= true then

        ok,
            result =
            pcall(
                callback,
                module,
                itemName
            )
    end

    if ok == true
    and type(result) == "boolean" then

        return result
    end

    return fallback ~= false
end

function HolyShopFlagEnabled(modulePath, itemName, fallback)

    local module =
        HolyShopRequireModule(
            modulePath
        )

    local enabledOverrides =
        type(module) == "table"
        and module.EnabledOverrides
        or nil

    local valueTable =
        type(enabledOverrides) == "table"
        and enabledOverrides.Value
        or nil

    if type(valueTable) == "table"
    and valueTable[itemName] ~= nil then

        return valueTable[itemName] == true
    end

    return fallback ~= false
end

function HolyShopAddStockRows(category, rows)

    -- Dropdown names must come from real shop data only.
    -- StockValues can contain hidden, future, or internal items.
    return false
end

function HolyShopBuildSeedRows()

    local rows =
        {}

    local data =
        HolyShopRequireModule(
            "SharedModules.SeedData"
        )

    if type(data) == "table" then

        for _, row in pairs(data) do

            if type(row) == "table" then

                local seedName =
                    HolyCleanText(
                        row.SeedName
                    )

                if seedName ~= ""
                and row.RestockShop == true
                and HolyShopModuleEnabled(
                    "SharedModules.SeedShopEnabled",
                    "IsSeedEnabled",
                    seedName,
                    true
                ) == true then

                    HolyShopAddItemRow(
                        rows,
                        seedName,
                        row.PurchasePrice
                    )
                end
            end
        end
    end

    return rows
end

function HolyShopBuildGearRows()

    local rows =
        {}

    local data =
        HolyShopRequireModule(
            "SharedModules.GearShopData"
        )

    data =
        type(data) == "table"
        and data.Data
        or nil

    if type(data) == "table" then

        for _, row in pairs(data) do

            if type(row) == "table" then

                local itemName =
                    HolyCleanText(
                        row.ItemName
                    )

                if itemName ~= ""
                and row.HideFromShop ~= true
                and HolyShopModuleEnabled(
                    "SharedModules.GearShopABTest",
                    "IsGearEnabled",
                    itemName,
                    true
                ) == true
                and HolyShopFlagEnabled(
                    "SharedModules.Flags.GearShopFlags",
                    itemName,
                    true
                ) == true then

                    HolyShopAddItemRow(
                        rows,
                        itemName,
                        row.Cost
                    )
                end
            end
        end
    end

    return rows
end

function HolyShopBuildPropRows()

    local rows =
        {}

    local data =
        HolyShopRequireModule(
            "SharedModules.CrateData"
        )

    if type(data) == "table"
    and type(data.GetAllCrates) == "function" then

        local ok,
            crates =
            pcall(function()

                return data.GetAllCrates()
            end)

        if ok ~= true
        or type(crates) ~= "table" then

            ok,
                crates =
                pcall(
                    data.GetAllCrates,
                    data
                )
        end

        if ok == true
        and type(crates) == "table" then

            for key, row in pairs(crates) do

                if type(row) == "table" then

                    local crateName =
                        HolyCleanText(
                            row.Name
                            or key
                        )

                    if crateName ~= ""
                    and HolyShopModuleEnabled(
                        "SharedModules.CrateShopEnabled",
                        "IsCrateEnabled",
                        crateName,
                        true
                    ) == true
                    and HolyShopFlagEnabled(
                        "SharedModules.Flags.CrateShopFlags",
                        crateName,
                        true
                    ) == true then

                        HolyShopAddItemRow(
                            rows,
                            crateName,
                            row.Cost
                        )
                    end
                end
            end
        end
    end

    return rows
end

function HolyShopGetItemRows(category)

    HOLY_SHOP_STATE.ItemCache =
        type(HOLY_SHOP_STATE.ItemCache) == "table"
        and HOLY_SHOP_STATE.ItemCache
        or {}

    if type(HOLY_SHOP_STATE.ItemCache[category]) == "table" then

        return HOLY_SHOP_STATE.ItemCache[category]
    end

    local map =
        {}

    if category == "Seeds" then

        map =
            HolyShopBuildSeedRows()

    elseif category == "Gear" then

        map =
            HolyShopBuildGearRows()

    elseif category == "Props" then

        map =
            HolyShopBuildPropRows()
    end

    local rows =
        {}

    for _, row in pairs(map) do

        table.insert(
            rows,
            row
        )
    end

    table.sort(rows, function(a, b)

        local priceA =
            tonumber(a.Price)
            or 0

        local priceB =
            tonumber(b.Price)
            or 0

        if priceA ~= priceB then
            return priceA > priceB
        end

        return tostring(a.Name) < tostring(b.Name)
    end)

    HOLY_SHOP_STATE.ItemCache[category] =
        rows

    return rows
end

function HolyShopGetDropdownValues(category)

    local values = {
        "All",
    }

    for _, row in ipairs(HolyShopGetItemRows(category)) do

        table.insert(
            values,
            row.Name
        )
    end

    return values
end

function HolyShopNormalizeSelection(value)

    local output =
        {}

    if type(value) == "table" then

        for key, enabled in pairs(value) do

            if type(key) == "number" then

                local text =
                    HolyCleanText(enabled)

                if text ~= "" then

                    output[text] =
                        true
                end

            elseif enabled == true then

                local text =
                    HolyCleanText(key)

                if text ~= "" then

                    output[text] =
                        true
                end
            end
        end

    elseif type(value) == "string" then

        local text =
            HolyCleanText(value)

        if text ~= "" then

            output[text] =
                true
        end
    end

    return output
end

function HolyShopGetSelection(category)

    if category == "Seeds" then

        return HolyShopNormalizeSelection(
            HOLY_SHOP_STATE.SelectedSeeds
        )

    elseif category == "Gear" then

        return HolyShopNormalizeSelection(
            HOLY_SHOP_STATE.SelectedGear
        )

    elseif category == "Props" then

        return HolyShopNormalizeSelection(
            HOLY_SHOP_STATE.SelectedProps
        )
    end

    return {}
end

function HolyShopCategoryEnabled(category)

    if category == "Seeds" then
        return HOLY_SHOP_STATE.AutoBuySeeds == true
    end

    if category == "Gear" then
        return HOLY_SHOP_STATE.AutoBuyGear == true
    end

    if category == "Props" then
        return HOLY_SHOP_STATE.AutoBuyProps == true
    end

    return false
end

function HolyShopGetSelectedRows(category)

    local selection =
        HolyShopGetSelection(category)

    local hasSelection =
        false

    for _ in pairs(selection) do

        hasSelection =
            true

        break
    end

    if hasSelection ~= true then
        return {}
    end

    local useAll =
        selection.All == true

    local rows =
        {}

    for _, row in ipairs(HolyShopGetItemRows(category)) do

        if useAll == true
        or selection[row.Name] == true then

            table.insert(
                rows,
                row
            )
        end
    end

    return rows
end

function HolyShopGetStockValue(category, itemName)

    local config =
        HOLY_SHOP_CATEGORIES[category]

    local valueObject =
        config
        and ReplicatedStorage:FindFirstChild("StockValues")
        and ReplicatedStorage.StockValues:FindFirstChild(config.ShopName)
        and ReplicatedStorage.StockValues[config.ShopName]:FindFirstChild("Items")
        and ReplicatedStorage.StockValues[config.ShopName].Items:FindFirstChild(itemName)
        or nil

    if typeof(valueObject) ~= "Instance"
    or valueObject:IsA("ValueBase") ~= true then

        return 0
    end

    local value =
        0

    pcall(function()

        value =
            valueObject.Value
    end)

    return math.max(
        0,
        math.floor(
            tonumber(value)
            or 0
        )
    )
end

function HolyShopGetRestockKey(category)

    local config =
        HOLY_SHOP_CATEGORIES[category]

    local shop =
        config
        and ReplicatedStorage:FindFirstChild("StockValues")
        and ReplicatedStorage.StockValues:FindFirstChild(config.ShopName)
        or nil

    local value =
        0

    if typeof(shop) == "Instance" then

        local last =
            shop:FindFirstChild("UnixLastRestock")

        if last
        and last:IsA("ValueBase") then

            pcall(function()

                value =
                    last.Value
            end)
        end
    end

    return tostring(value)
end

function HolyShopResolvePacket(category)

    local config =
        HOLY_SHOP_CATEGORIES[category]

    if type(config) ~= "table" then
        return nil
    end

    HOLY_SHOP_STATE.PacketCache =
        type(HOLY_SHOP_STATE.PacketCache) == "table"
        and HOLY_SHOP_STATE.PacketCache
        or {}

    if HOLY_SHOP_STATE.PacketCache[category] ~= nil then

        return HOLY_SHOP_STATE.PacketCache[category]
    end

    local networking =
        HolyShopRequireModule(
            "SharedModules.Networking"
        )

    local packet =
        type(networking) == "table"
        and networking[config.PacketShop]
        and networking[config.PacketShop][config.PacketName]
        or nil

    if type(packet) ~= "table"
    or type(packet.Fire) ~= "function" then

        HOLY_SHOP_STATE.PacketCache[category] =
            false

        return nil
    end

    HOLY_SHOP_STATE.PacketCache[category] =
        packet

    return packet
end

function HolyShopFireBurst(category, itemName, amount)

    local packet =
        HolyShopResolvePacket(category)

    if type(packet) ~= "table" then
        return 0
    end

    amount =
        math.clamp(
            math.floor(
                tonumber(amount)
                or 0
            ),
            0,
            tonumber(HOLY_SHOP_STATE.MaxBurstFires)
            or 120
        )

    local fired =
        0

    local yieldEvery =
        math.max(
            1,
            math.floor(
                tonumber(HOLY_SHOP_STATE.YieldEvery)
                or 24
            )
        )

    for index = 1, amount do

        local ok =
            pcall(function()

                packet:Fire(
                    itemName
                )
            end)

        if ok == true then

            fired =
                fired + 1
        end

        if index % yieldEvery == 0 then

            task.wait()
        end
    end

    return fired
end

function HolyShopRunCategory(category)

    if HolyShopCategoryEnabled(category) ~= true then
        return false
    end

    local rows =
        HolyShopGetSelectedRows(category)

    if #rows <= 0 then
        return false
    end

    HOLY_SHOP_STATE.BurstAttempts =
        type(HOLY_SHOP_STATE.BurstAttempts) == "table"
        and HOLY_SHOP_STATE.BurstAttempts
        or {}

    local restockKey =
        HolyShopGetRestockKey(category)

    for _, row in ipairs(rows) do

        if HolyShopCategoryEnabled(category) ~= true then
            return true
        end

        local stock =
            HolyShopGetStockValue(
                category,
                row.Name
            )

        if stock > 0 then

            local attemptKey =
                tostring(category)
                .. "|"
                .. tostring(row.Name)
                .. "|"
                .. tostring(restockKey)
                .. "|"
                .. tostring(stock)

            if HOLY_SHOP_STATE.BurstAttempts[attemptKey] ~= true then

                HOLY_SHOP_STATE.BurstAttempts[attemptKey] =
                    true

                HolyShopFireBurst(
                    category,
                    row.Name,
                    stock
                )
            end
        end
    end

    return true
end

function HolyShopQueueCategory(category)

    HOLY_SHOP_STATE.PendingCategories =
        type(HOLY_SHOP_STATE.PendingCategories) == "table"
        and HOLY_SHOP_STATE.PendingCategories
        or {}

    HOLY_SHOP_STATE.PendingCategories[category] =
        true

    if HOLY_SHOP_STATE.WorkerRunning == true then
        return
    end

    HOLY_SHOP_STATE.WorkerRunning =
        true

    task.spawn(function()

        while true do

            local pending =
                HOLY_SHOP_STATE.PendingCategories

            HOLY_SHOP_STATE.PendingCategories =
                {}

            local hasPending =
                false

            for _ in pairs(pending) do

                hasPending =
                    true

                break
            end

            if hasPending ~= true then
                break
            end

            if pending.Seeds == true then

                HolyShopRunCategory(
                    "Seeds"
                )
            end

            if pending.Gear == true then

                HolyShopRunCategory(
                    "Gear"
                )
            end

            if pending.Props == true then

                HolyShopRunCategory(
                    "Props"
                )
            end

            task.wait()
        end

        HOLY_SHOP_STATE.WorkerRunning =
            false
    end)
end

function HolyShopQueueAll()

    if HOLY_SHOP_STATE.AutoBuySeeds == true then

        HolyShopQueueCategory(
            "Seeds"
        )
    end

    if HOLY_SHOP_STATE.AutoBuyGear == true then

        HolyShopQueueCategory(
            "Gear"
        )
    end

    if HOLY_SHOP_STATE.AutoBuyProps == true then

        HolyShopQueueCategory(
            "Props"
        )
    end
end

function HolyShopConnectStockSignals()

    if HOLY_SHOP_STATE.StockConnected == true then
        return
    end

    HOLY_SHOP_STATE.StockConnected =
        true

    HOLY_SHOP_STATE.StockConnections =
        type(HOLY_SHOP_STATE.StockConnections) == "table"
        and HOLY_SHOP_STATE.StockConnections
        or {}

    for category, config in pairs(HOLY_SHOP_CATEGORIES) do

        local items =
            ReplicatedStorage:FindFirstChild("StockValues")
            and ReplicatedStorage.StockValues:FindFirstChild(config.ShopName)
            and ReplicatedStorage.StockValues[config.ShopName]:FindFirstChild("Items")
            or nil

        if typeof(items) == "Instance" then

            for _, child in ipairs(items:GetChildren()) do

                if child:IsA("ValueBase") then

                    table.insert(
                        HOLY_SHOP_STATE.StockConnections,
                        child.Changed:Connect(function()

                            HolyShopQueueCategory(
                                category
                            )
                        end)
                    )
                end
            end

            table.insert(
                HOLY_SHOP_STATE.StockConnections,
                items.ChildAdded:Connect(function(child)

                    if child:IsA("ValueBase") then

                        task.defer(function()

                            HolyShopQueueCategory(
                                category
                            )
                        end)
                    end
                end)
            )
        end
    end
end

--==================================================
-- [2.55] AUCTION CORE
--==================================================

function HolyAuctionEnsureBaseState()

    HOLY_SHOP_STATE =
        type(HOLY_SHOP_STATE) == "table"
        and HOLY_SHOP_STATE
        or {}

    HOLY_SHOP_STATE.AutoBuyAuctions =
        HOLY_SHOP_STATE.AutoBuyAuctions == true

    HOLY_SHOP_STATE.AuctionWatchlist =
        HolyAuctionNormalizeWatchlist(
            HOLY_SHOP_STATE.AuctionWatchlist
        )

    HOLY_SHOP_STATE.AuctionWatchlistSelectedKey =
        tostring(
            HOLY_SHOP_STATE.AuctionWatchlistSelectedKey
            or ""
        )

    HOLY_SHOP_STATE.AuctionRoundRobinIndex =
        math.max(
            0,
            math.floor(
                tonumber(
                    HOLY_SHOP_STATE.AuctionRoundRobinIndex
                )
                or 0
            )
        )

    HOLY_SHOP_STATE.AuctionKnownItems =
        HolyShopSelectionArray(
            HOLY_SHOP_STATE.AuctionKnownItems
            or {}
        )

    HOLY_SHOP_STATE.AuctionBuyUntilSoldOut =
        HOLY_SHOP_STATE.AuctionBuyUntilSoldOut ~= false

    HOLY_SHOP_STATE.AuctionStatus =
        tostring(
            HOLY_SHOP_STATE.AuctionStatus
            or "Ready"
        )

    HOLY_SHOP_STATE.AuctionWorkerRunning =
        HOLY_SHOP_STATE.AuctionWorkerRunning == true

    HOLY_SHOP_STATE.AuctionWatcherStarted =
        HOLY_SHOP_STATE.AuctionWatcherStarted == true

    HOLY_SHOP_STATE.AuctionNextBuyAt =
        tonumber(HOLY_SHOP_STATE.AuctionNextBuyAt)
        or 0

    HOLY_SHOP_STATE.AuctionLastLots =
        type(HOLY_SHOP_STATE.AuctionLastLots) == "table"
        and HOLY_SHOP_STATE.AuctionLastLots
        or {}

    HOLY_SHOP_STATE.AuctionAttemptedLots =
        type(HOLY_SHOP_STATE.AuctionAttemptedLots) == "table"
        and HOLY_SHOP_STATE.AuctionAttemptedLots
        or {}

    HOLY_SHOP_STATE.AuctionConnections =
        type(HOLY_SHOP_STATE.AuctionConnections) == "table"
        and HOLY_SHOP_STATE.AuctionConnections
        or {}

    HOLY_SHOP_STATE.AuctionStockMap =
        type(HOLY_SHOP_STATE.AuctionStockMap) == "table"
        and HOLY_SHOP_STATE.AuctionStockMap
        or {}

    HOLY_SHOP_STATE.AuctionServerNow =
        tonumber(HOLY_SHOP_STATE.AuctionServerNow)
        or 0

    HOLY_SHOP_STATE.AuctionLastStockUpdateAt =
        tonumber(HOLY_SHOP_STATE.AuctionLastStockUpdateAt)
        or 0

    HOLY_SHOP_STATE.AuctionItemCache =
        type(HOLY_SHOP_STATE.AuctionItemCache) == "table"
        and HOLY_SHOP_STATE.AuctionItemCache
        or nil

    return HOLY_SHOP_STATE
end

function HolyAuctionItemKey(value)

    return HolyCleanText(
        value
    )
        :lower()
        :gsub("[%s_%-%[%]%(%)%.'\"_/{}:]", "")
end

function HolyAuctionSafeTonumber(value)

    local ok,
        result =
        pcall(function()

            return tonumber(
                value
            )
        end)

    if ok == true
    and result ~= nil then

        return result
    end

    return nil
end

function HolyAuctionReadMoney(value)

    if type(value) == "number" then

        return math.max(
            0,
            math.floor(value + 0.5)
        )
    end

    local text =
        HolyCleanText(
            value
        )

    if text == "" then
        return 0
    end

    text =
        text:gsub("¢", "")
            :gsub("%$", "")
            :gsub(",", "")
            :gsub("%s+", "")

    local lower =
        text:lower()

    local multiplier =
        1

    if lower:find("b", 1, true) then

        multiplier =
            1000000000

    elseif lower:find("m", 1, true) then

        multiplier =
            1000000

    elseif lower:find("k", 1, true) then

        multiplier =
            1000
    end

    local rawNumber =
        lower:match("%d+%.?%d*")

    local number =
        HolyAuctionSafeTonumber(
            rawNumber
        )

    if number == nil then
        return 0
    end

    return math.max(
        0,
        math.floor(
            number * multiplier + 0.5
        )
    )
end

function HolyAuctionFormatMoney(value)

    value =
        math.max(
            0,
            tonumber(value)
            or 0
        )

    if value >= 1000000000 then

        return string.format(
            "%.2fB¢",
            value / 1000000000
        )
    end

    if value >= 1000000 then

        return string.format(
            "%.2fM¢",
            value / 1000000
        )
    end

    if value >= 1000 then

        return string.format(
            "%.2fK¢",
            value / 1000
        )
    end

    return tostring(
        math.floor(value)
    )
        .. "¢"
end

function HolyAuctionNormalizeWatchlist(value)

    local output = {}
    local seen = {}

    for _, rawEntry in ipairs(
        type(value) == "table"
        and value
        or {}
    ) do

        local name = ""
        local maxPrice = 0

        if type(rawEntry) == "table" then

            name =
                HolyCleanText(
                    rawEntry.Name
                    or rawEntry.Item
                    or rawEntry.DisplayName
                )

            maxPrice =
                HolyAuctionReadMoney(
                    rawEntry.MaxPrice
                    or rawEntry.Price
                    or rawEntry.Limit
                )

        elseif type(rawEntry) == "string" then

            name =
                HolyCleanText(
                    rawEntry
                )
        end

        local key =
            HolyAuctionItemKey(
                name
            )

        if key ~= ""
        and key ~= "all"
        and maxPrice > 0
        and seen[key] ~= true then

            seen[key] = true

            output[#output + 1] = {
                Name = name,
                MaxPrice = maxPrice,
            }
        end
    end

    return output
end

function HolyAuctionGetWatchEntry(itemName)

    local wantedKey =
        HolyAuctionItemKey(
            itemName
        )

    for index, entry in ipairs(
        HOLY_SHOP_STATE.AuctionWatchlist
        or {}
    ) do

        if HolyAuctionItemKey(entry.Name) == wantedKey then

            return entry,
                index
        end
    end

    return nil,
        nil
end

function HolyAuctionGetWatchMax(itemName)

    local entry =
        HolyAuctionGetWatchEntry(
            itemName
        )

    return type(entry) == "table"
        and HolyAuctionReadMoney(
            entry.MaxPrice
        )
        or 0
end

function HolyAuctionGetWatchNames()

    local names = {}

    for _, entry in ipairs(
        HOLY_SHOP_STATE.AuctionWatchlist
        or {}
    ) do

        names[#names + 1] =
            tostring(
                entry.Name
            )
    end

    return names
end

function HolyAuctionGetSelectedWatchEntry()

    local selectedKey =
        tostring(
            HOLY_SHOP_STATE.AuctionWatchlistSelectedKey
            or ""
        )

    for index, entry in ipairs(
        HOLY_SHOP_STATE.AuctionWatchlist
        or {}
    ) do

        if HolyAuctionItemKey(entry.Name) == selectedKey then

            return entry,
                index
        end
    end

    return nil,
        nil
end

function HolyAuctionUpsertWatchItem(itemName, maxPrice)

    HolyAuctionEnsureState()

    itemName =
        HolyCleanText(
            itemName
        )

    maxPrice =
        HolyAuctionReadMoney(
            maxPrice
        )

    if itemName == ""
    or HolyAuctionItemKey(itemName) == "all" then

        return false,
            "Select an auction item."
    end

    if maxPrice <= 0 then

        return false,
            "Enter a valid maximum price."
    end

    local entry =
        HolyAuctionGetWatchEntry(
            itemName
        )

    if type(entry) == "table" then

        entry.Name =
            itemName

        entry.MaxPrice =
            maxPrice

    else

        table.insert(
            HOLY_SHOP_STATE.AuctionWatchlist,
            {
                Name = itemName,
                MaxPrice = maxPrice,
            }
        )
    end

    HOLY_SHOP_STATE.AuctionWatchlistSelectedKey =
        HolyAuctionItemKey(
            itemName
        )

    HOLY_SHOP_STATE.AuctionNextRetryAt =
        0

    HolyAuctionRememberKnownItem(
        itemName
    )

    HolySaveShopSettings()

    if type(HolyAuctionRefreshWatchlistUI) == "function" then

        HolyAuctionRefreshWatchlistUI(
            true
        )
    end

    HolyAuctionRefreshUI()

    if HOLY_SHOP_STATE.AutoBuyAuctions == true then

        HolyAuctionQueueWorker(
            "watchlist changed"
        )
    end

    return true
end

function HolyAuctionRemoveWatchItem(itemName)

    HolyAuctionEnsureState()

    local entry,
        index =
        HolyAuctionGetWatchEntry(
            itemName
        )

    if type(entry) ~= "table"
    or index == nil then

        return false
    end

    local removedKey =
        HolyAuctionItemKey(
            entry.Name
        )

    table.remove(
        HOLY_SHOP_STATE.AuctionWatchlist,
        index
    )

    if HOLY_SHOP_STATE.AuctionWatchlistSelectedKey == removedKey then

        HOLY_SHOP_STATE.AuctionWatchlistSelectedKey =
            ""
    end

    HOLY_SHOP_STATE.AuctionRoundRobinIndex =
        math.min(
            HOLY_SHOP_STATE.AuctionRoundRobinIndex,
            #HOLY_SHOP_STATE.AuctionWatchlist
        )

    HOLY_SHOP_STATE.AuctionNextRetryAt =
        0

    HolySaveShopSettings()

    if type(HolyAuctionRefreshWatchlistUI) == "function" then

        HolyAuctionRefreshWatchlistUI(
            true
        )
    end

    HolyAuctionRefreshUI()

    return true
end

function HolyAuctionReadStock(value)

    local text =
        HolyCleanText(
            value
        )

    local lower =
        text:lower()

    if lower == ""
    or lower:find("sold", 1, true)
    or lower:find("out", 1, true)
    or lower:find("expired", 1, true) then

        return 0
    end

    -- Strict UI stock safety:
    -- only trust text like "x19,631 in Stock".
    if lower:find("stock", 1, true) == nil then
        return 0
    end

    local raw =
        text:match("x%s*([%d,]+)")
        or text:match("([%d,]+)")

    if raw == nil then
        return 0
    end

    local digits =
        tostring(raw or "")

    digits =
        digits:gsub(
            ",",
            ""
        )

    local number =
        HolyAuctionSafeTonumber(
            digits
        )

    return math.max(
        0,
        math.floor(
            number
            or 0
        )
    )
end

function HolyAuctionGetFlags()

    HolyAuctionEnsureState()

    if type(
        HOLY_SHOP_STATE.AuctionFlagsModule
    ) == "table" then

        return HOLY_SHOP_STATE.AuctionFlagsModule
    end

    local flags =
        HolyShopRequireModule(
            "SharedModules.Flags.AuctioneerFlags"
        )

    if type(flags) == "table" then

        HOLY_SHOP_STATE.AuctionFlagsModule =
            flags

        return flags
    end

    return nil
end

function HolyAuctionReadFlagNumber(
    flagName,
    fallback
)

    local flags =
        HolyAuctionGetFlags()

    local flag =
        type(flags) == "table"
        and flags[flagName]
        or nil

    local value =
        nil

    if type(flag) == "table" then

        value =
            flag.Value

        if type(value) == "function" then

            local ok,
                result =
                pcall(
                    value,
                    flag
                )

            if ok == true then

                value =
                    result
            end
        end

        if tonumber(value) == nil then

            value =
                flag.DefaultValue
        end

    elseif tonumber(flag) ~= nil then

        value =
            flag
    end

    return tonumber(value)
        or tonumber(fallback)
        or 0
end

function HolyAuctionReadDebounce()

    return math.clamp(
        HolyAuctionReadFlagNumber(
            "PurchaseDebounceSeconds",
            0.2
        ),
        0.05,
        5
    )
end

function HolyAuctionReadCooldown()

    local serverCooldown =
        math.clamp(
            HolyAuctionReadFlagNumber(
                "PurchaseCooldownSeconds",
                10
            ),
            0.2,
            120
        )

    local safetyMargin =
        math.max(
            0.25,
            HolyAuctionReadDebounce()
        )

    return serverCooldown
        + safetyMargin
end

function HolyAuctionAddCandidate(rows, name, source, data)

    name =
        HolyCleanText(
            name
        )

    if name == ""
    or name == "All"
    or name == "None"
    or name == "Normal"
    or name == "Big"
    or name == "Huge"
    or name == "Mega"
    or #name > 80
    or name:find("table:", 1, true) then

        return false
    end

    source =
        HolyCleanText(
            source
        )

    local blockedUnlessLive = {
        Gold = true,
        Rainbow = true,
        Mega = true,
        Default = true,
        Wood = true,
        Stone = true,
        White = true,
        Light = true,
        Star = true,
        Flower = true,
        Pole = true,
        Stick = true,
        Spike = true,
        Cupid = true,
        Lantern = true,
        Futuristic = true,
    }

    if blockedUnlessLive[name] == true
    and source ~= "LiveAuctionGui"
    and source ~= "KnownAuctionItems" then

        return false
    end

    if name == "Test Egg"
    and source ~= "LiveAuctionGui"
    and source ~= "KnownAuctionItems" then

        return false
    end

    local key =
        HolyAuctionItemKey(
            name
        )

    if key == "" then
        return false
    end

    rows[key] =
        rows[key]
        or {
            Name = name,
            Sources = {},
            Price = 0,
        }

    rows[key].Sources[source ~= "" and source or "Unknown"] =
        true

    data =
        type(data) == "table"
        and data
        or {}

    rows[key].Category =
        rows[key].Category
        or data.Category

    rows[key].Rarity =
        rows[key].Rarity
        or data.Rarity

    rows[key].Price =
        math.max(
            tonumber(rows[key].Price)
            or 0,
            tonumber(data.Price)
            or tonumber(data.Cost)
            or 0
        )

    return true
end

function HolyAuctionScanCrateCandidates(rows)

    local data =
        HolyShopRequireModule(
            "SharedModules.CrateData"
        )

    if type(data) == "table"
    and type(data.GetAllCrates) == "function" then

        local ok,
            crates =
            pcall(function()

                return data.GetAllCrates()
            end)

        if ok ~= true
        or type(crates) ~= "table" then

            ok,
                crates =
                pcall(
                    data.GetAllCrates,
                    data
                )
        end

        if ok == true
        and type(crates) == "table" then

            for key, row in pairs(crates) do

                if type(row) == "table" then

                    HolyAuctionAddCandidate(
                        rows,
                        row.Name
                            or key,
                        "CrateData",
                        {
                            Category =
                                "Crate",

                            Rarity =
                                row.Rarity,

                            Cost =
                                row.Cost,
                        }
                    )
                end
            end
        end
    end

    local root =
        ReplicatedStorage:FindFirstChild("SharedModules")
        and ReplicatedStorage.SharedModules:FindFirstChild("CrateData")
        or nil

    if typeof(root) == "Instance" then

        for _, child in ipairs(root:GetChildren()) do

            if child:IsA("ModuleScript") then

                local ok,
                    row =
                    pcall(function()

                        return require(child)
                    end)

                if ok == true
                and type(row) == "table" then

                    HolyAuctionAddCandidate(
                        rows,
                        row.Name
                            or child.Name,
                        "CrateData",
                        {
                            Category =
                                "Crate",

                            Rarity =
                                row.Rarity,

                            Cost =
                                row.Cost,
                        }
                    )

                else

                    HolyAuctionAddCandidate(
                        rows,
                        child.Name,
                        "CrateData",
                        {
                            Category =
                                "Crate",
                        }
                    )
                end
            end
        end
    end
end

function HolyAuctionScanGuildCrateCandidates(rows)

    local root =
        ReplicatedStorage:FindFirstChild("SharedModules")
        and ReplicatedStorage.SharedModules:FindFirstChild("GuildCrateData")
        or nil

    if typeof(root) ~= "Instance" then
        return false
    end

    for _, child in ipairs(root:GetChildren()) do

        if child:IsA("ModuleScript") then

            local ok,
                row =
                pcall(function()

                    return require(child)
                end)

            row =
                ok == true
                and type(row) == "table"
                and row
                or {}

            HolyAuctionAddCandidate(
                rows,
                row.Name
                    or row.CrateName
                    or child.Name,
                "GuildCrateData",
                {
                    Category =
                        "Guild Crate",

                    Rarity =
                        row.Rarity,

                    Cost =
                        row.Cost,
                }
            )
        end
    end

    return true
end

function HolyAuctionScanGearCandidates(rows)

