function HolyAuctionScanSeedCandidates(rows)

    local data =
        HolyShopRequireModule(
            "SharedModules.SeedData"
        )

    data =
        type(data) == "table"
        and (
            data.Data
            or data
        )
        or {}

    for _, row in pairs(data) do

        if type(row) == "table" then

            local seedName =
                HolyCleanText(
                    row.SeedName
                    or row.Name
                )

            if seedName ~= "" then

                HolyAuctionAddCandidate(
                    rows,
                    seedName,
                    "SeedData",
                    {
                        Category =
                            "Seed",

                        Rarity =
                            row.Rarity
                            or row.SeedRarity,

