function HolyAuctionHudApplyScale()

    local hud =
        HOLY_AUCTION_HUD

    if type(hud) ~= "table"
    or typeof(hud.ScaleObject) ~= "Instance" then

        return false
    end

    local scale =
        HolyAuctionReadHudScale(
            HOLY_SHOP_STATE.AuctionHudScale
            or "80%"
        )

    hud.ScaleObject.Scale =
        scale / 100

    if typeof(hud.ScaleButton) == "Instance" then

        hud.ScaleButton.Text =
            HolyAuctionFormatHudScale(
                scale
            )
    end

    return true
end

function HolyAuctionHudSavePosition(frame)

    if typeof(frame) ~= "Instance"
    or frame:IsA("GuiObject") ~= true then

        return false
    end

    HOLY_SHOP_STATE.AuctionHudPosition = {
        X =
            frame.Position.X.Offset,

        Y =
            frame.Position.Y.Offset,
    }

    return true
end

function HolyAuctionHudMakeDraggable(
    frame,
    handles
)

    if typeof(frame) ~= "Instance"
    or frame:IsA("GuiObject") ~= true then

        return nil
    end

    local handleList =
        {}

    if typeof(handles) == "Instance" then

        handleList[1] =
            handles

    elseif type(handles) == "table" then

        for _, handle in ipairs(handles) do

            if typeof(handle) == "Instance"
            and handle:IsA("GuiObject") then

                handleList[#handleList + 1] =
                    handle
            end
        end
    end

    if #handleList <= 0 then

        handleList[1] =
            frame
    end

    local controller = {
        Active =
            false,

        ActiveHandle =
            nil,

        PointerInput =
            nil,

        DragStart =
            nil,

        StartPosition =
            nil,

        Dragged =
            false,

        SuppressUntil =
            {},
    }

    function controller:ConsumeClick(handle)

        local suppressUntil =
            tonumber(
                self.SuppressUntil[handle]
            )
            or 0

        self.SuppressUntil[handle] =
            nil

        return os.clock()
            <= suppressUntil
    end

    local function clampPosition(
        x,
        y
    )

        local viewportSize =
            Vector2.new(
                1920,
                1080
            )

        pcall(function()

            local camera =
                workspace.CurrentCamera

            if camera then

                viewportSize =
                    camera.ViewportSize
            end
        end)

        local frameSize =
            frame.AbsoluteSize

        local maximumX =
            math.max(
                0,
                viewportSize.X
                    - frameSize.X
            )

        local maximumY =
            math.max(
                0,
                viewportSize.Y
                    - frameSize.Y
            )

        return math.clamp(
            x,
            0,
            maximumX
        ),
            math.clamp(
                y,
                0,
                maximumY
            )
    end

    local function beginDrag(
        handle,
        input
    )

        if controller.Active == true then
            return
        end

        local inputType =
            input.UserInputType

        if inputType ~= Enum.UserInputType.MouseButton1
        and inputType ~= Enum.UserInputType.Touch then

            return
        end

        controller.Active =
            true

        controller.ActiveHandle =
            handle

        controller.PointerInput =
            input

        controller.DragStart =
            input.Position

        controller.StartPosition =
            frame.Position

        controller.Dragged =
            false
    end

    local function finishDrag()

        if controller.Active ~= true then
            return
        end

        local activeHandle =
            controller.ActiveHandle

        local wasDragged =
            controller.Dragged == true

        controller.Active =
            false

        controller.ActiveHandle =
            nil

        controller.PointerInput =
            nil

        controller.DragStart =
            nil

        controller.StartPosition =
            nil

        controller.Dragged =
            false

        if wasDragged == true then

            controller.SuppressUntil[
                activeHandle
            ] =
                os.clock() + 0.40

            HolyAuctionHudSavePosition(
                frame
            )

            HolySaveShopSettings()
        end
    end

    for _, handle in ipairs(handleList) do

        HolyAuctionHudAddConnection(
            handle.InputBegan:Connect(function(input)

                beginDrag(
                    handle,
                    input
                )
            end)
        )
    end

    HolyAuctionHudAddConnection(
        UserInputService.InputChanged:Connect(function(input)

            if controller.Active ~= true
            or controller.DragStart == nil
            or controller.StartPosition == nil then

                return
            end

            local inputType =
                input.UserInputType

            if inputType ~= Enum.UserInputType.MouseMovement
            and inputType ~= Enum.UserInputType.Touch then

                return
            end

            if inputType == Enum.UserInputType.Touch
            and input ~= controller.PointerInput then

                return
            end

            local delta =
                input.Position
                - controller.DragStart

            if delta.Magnitude >= 4 then

                controller.Dragged =
                    true

                controller.SuppressUntil[
                    controller.ActiveHandle
                ] =
                    os.clock() + 0.40
            end

            if controller.Dragged ~= true then
                return
            end

            local x =
                controller.StartPosition.X.Offset
                + delta.X

            local y =
                controller.StartPosition.Y.Offset
                + delta.Y

            x,
                y =
                clampPosition(
                    x,
                    y
                )

            frame.Position =
                UDim2.fromOffset(
                    x,
                    y
                )
        end)
    )

    HolyAuctionHudAddConnection(
        UserInputService.InputEnded:Connect(function(input)

            if controller.Active ~= true then
                return
            end

            local inputType =
                input.UserInputType

            if inputType == Enum.UserInputType.MouseButton1 then

                finishDrag()

            elseif inputType == Enum.UserInputType.Touch
            and input == controller.PointerInput then

                finishDrag()
            end
        end)
    )

    return controller
end

function HolyAuctionHudStart()

    HolyAuctionEnsureState()

    if HOLY_SHOP_STATE.AuctionHudEnabled ~= true then
        return false
    end

    local alreadyOpen =
        false

    pcall(function()

        alreadyOpen =
            type(HOLY_AUCTION_HUD) == "table"
            and typeof(HOLY_AUCTION_HUD.ScreenGui) == "Instance"
            and HOLY_AUCTION_HUD.ScreenGui.Parent ~= nil
    end)

    if alreadyOpen == true then
        return true
    end

    return HolyAuctionHudCreateUI()
end

function HolyAuctionSetHudVisible(value, reason)

    HolyAuctionEnsureState()

    HOLY_SHOP_STATE.AuctionHudEnabled =
        value == true

    HolySaveShopSettings()

    if HOLY_SHOP_STATE.AuctionHudEnabled == true then

        HolyAuctionHudStart()

        HolyAuctionRequestSnapshot()

        HolyAuctionRefreshUI()

        HolyAuctionSetStatus(
            "Live HUD on"
        )

        return true
    end

    HolyAuctionHudDestroy()

    HolyAuctionSetStatus(
        "Live HUD off"
    )

    if HOLY_SHOP_STATE.AutoBuyAuctions ~= true then

        HolyAuctionRestoreOffscreen()
    end

    return true
end

function HolyAuctionSetHudScale(value)

    HolyAuctionEnsureState()

    HOLY_SHOP_STATE.AuctionHudScale =
        HolyAuctionFormatHudScale(
            value
        )

    HolySaveShopSettings()

    HolyAuctionHudApplyScale()

    return true
end

function HolyAuctionRefreshUI()

    HolyAuctionEnsureState()

    HOLY_SHOP_UI =
        type(HOLY_SHOP_UI) == "table"
        and HOLY_SHOP_UI
        or {}

    local rows =
        HolyAuctionScanLiveLots()

    HolyAuctionSetLabel(
        HOLY_SHOP_UI.AuctionLiveLabel,
        HolyAuctionBuildLiveText(
            rows
        )
    )

    HolyAuctionSetStatus(
        HOLY_SHOP_STATE.AuctionStatus
    )

    HOLY_SHOP_STATE.AuctionWatchlistUIDirty =
        true

    if HOLY_SHOP_STATE.AuctionHudEnabled == true then

        HolyAuctionHudRefresh(
            rows
        )
    end

    return rows
end

function HolyAuctionSelectionMap()

    local map = {}

    for _, entry in ipairs(
        HOLY_SHOP_STATE.AuctionWatchlist
        or {}
    ) do

        map[
            HolyAuctionItemKey(
                entry.Name
            )
        ] = true
    end

    return map
end

function HolyAuctionSelectionAllows(name)

    return HolyAuctionGetWatchMax(
        name
    ) > 0
end

function HolyAuctionPriceAllows(row)

    row =
        type(row) == "table"
        and row
        or {}

    local desiredPrice =
        HolyAuctionGetWatchMax(
            row.Name
        )

    local currentPrice =
        tonumber(
            row.Price
        )
        or 0

    return desiredPrice > 0
        and currentPrice > 0
        and currentPrice <= desiredPrice
end

function HolyAuctionResolvePurchasePacket(forceRefresh)

    HolyAuctionEnsureState()

    HOLY_SHOP_STATE.AuctionPacketCache =
        type(HOLY_SHOP_STATE.AuctionPacketCache) == "table"
        and HOLY_SHOP_STATE.AuctionPacketCache
        or {}

    if forceRefresh == true then

        HOLY_SHOP_STATE.AuctionPacketCache.PurchaseLot =
            nil
    end

    local cached =
        HOLY_SHOP_STATE.AuctionPacketCache.PurchaseLot

    if type(cached) == "table"
    and type(cached.Fire) == "function" then

        return cached
    end

    local networking =
        HolyShopRequireModule(
            "SharedModules.Networking"
        )

    local packet =
        type(networking) == "table"
        and type(networking.Auctioneer) == "table"
        and networking.Auctioneer.PurchaseLot
        or nil

    if type(packet) ~= "table"
    or type(packet.Fire) ~= "function" then

        HOLY_SHOP_STATE.AuctionPacketCache.PurchaseLot =
            false

        return nil
    end

    HOLY_SHOP_STATE.AuctionPacketCache.PurchaseLot =
        packet

    return packet
end

function HolyAuctionFindBuyTarget()

    HolyAuctionEnsureState()

    local watchlist =
        HOLY_SHOP_STATE.AuctionWatchlist
        or {}

    if #watchlist <= 0 then

        return nil,
            "Add an item to the Auction Watchlist"
    end

    local rows =
        HolyAuctionScanLiveLots()

    if #rows <= 0 then

        return nil,
            "Loading auctions"
    end

    local eligibleByIndex = {}
    local selectedTooExpensive = nil
    local selectedStale = nil
    local selectedBoughtOnce = false
    local selectedFound = false

    for _, row in ipairs(rows) do

        local entry,
            watchIndex =
            HolyAuctionGetWatchEntry(
                row.Name
            )

        if type(entry) == "table" then

            selectedFound = true

            row.WatchlistIndex =
                watchIndex

            row.WatchlistMaxPrice =
                HolyAuctionReadMoney(
                    entry.MaxPrice
                )

            local alreadyAttempted =
                HOLY_SHOP_STATE.AuctionAttemptedLots[
                    tostring(
                        row.LotId
                    )
                ] == true

            if HOLY_SHOP_STATE.AuctionBuyUntilSoldOut ~= true
            and alreadyAttempted == true then

                selectedBoughtOnce =
                    true

            elseif row.Active == true then

                local stale,
                    staleReason =
                    HolyAuctionRowStale(
                        row,
                        true
                    )

                if stale == true then

                    selectedStale =
                        selectedStale
                        or staleReason

                elseif HolyAuctionPriceAllows(row) == true then

                    eligibleByIndex[watchIndex] =
                        row

                else

                    local currentRatio =
                        (
                            tonumber(row.Price)
                            or math.huge
                        )
                        / math.max(
                            1,
                            row.WatchlistMaxPrice
                        )

                    local previousRatio =
                        selectedTooExpensive
                        and selectedTooExpensive.Ratio
                        or math.huge

                    if currentRatio < previousRatio then

                        selectedTooExpensive = {
                            Row = row,
                            Ratio = currentRatio,
                            MaxPrice = row.WatchlistMaxPrice,
                        }
                    end
                end
            end
        end
    end

    local lastIndex =
        math.clamp(
            math.floor(
                tonumber(
                    HOLY_SHOP_STATE.AuctionRoundRobinIndex
                )
                or 0
            ),
            0,
            #watchlist
        )

    for offset = 1, #watchlist do

        local watchIndex =
            (
                (
                    lastIndex + offset - 1
                )
                % #watchlist
            )
            + 1

        local row =
            eligibleByIndex[
                watchIndex
            ]

        if type(row) == "table" then

            return row,
                "Ready"
        end
    end

    if type(selectedTooExpensive) == "table" then

        local row =
            selectedTooExpensive.Row

        return nil,
            "Waiting: "
            .. tostring(row.Name)
            .. " "
            .. HolyAuctionFormatMoney(row.Price)
            .. " > "
            .. HolyAuctionFormatMoney(
                selectedTooExpensive.MaxPrice
            )
    end

    if selectedStale ~= nil then

        return nil,
            "Waiting for stock"
    end

    if selectedBoughtOnce == true
    and HOLY_SHOP_STATE.AuctionBuyUntilSoldOut ~= true then

        return nil,
            "Bought once"
    end

    if selectedFound == true then

        return nil,
            "Watchlist items unavailable"
    end

    return nil,
        "Waiting for watchlist items"
end

function HolyAuctionQueueWorker(reason)

    HolyAuctionEnsureState()

    if type(HolyDevTrace) == "function" then

        HolyDevTrace(
            "Auction",
            "WorkerQueued",
            {
                Reason =
                    tostring(
                        reason
                        or "queue"
                    ),

                WorkerRunning =
                    HOLY_SHOP_STATE.AuctionWorkerRunning
                    == true,

                PendingLotId =
                    HOLY_SHOP_STATE.AuctionPendingLotId,

                NextBuyIn =
                    math.max(
                        0,
                        (
                            tonumber(
                                HOLY_SHOP_STATE.AuctionNextBuyAt
                            )
                            or 0
                        ) - os.clock()
                    ),
            }
        )
    end

    if HOLY_SHOP_STATE.AuctionWorkerRunning == true then

        if type(HolyDevTrace) == "function" then

            HolyDevTrace(
                "Auction",
                "WorkerQueueSkipped",
                {
                    Reason =
                        "already running",
                },
                "Warning"
            )
        end

        return false
    end

    HOLY_SHOP_STATE.AuctionWorkerRunning =
        true

    task.spawn(function()

        local ok,
            err =
            pcall(function()

                HolyAuctionRunWorker(
                    reason or "queue"
                )
            end)

        if ok ~= true then

            HolyAuctionSetStatus(
                "Error: "
                    .. tostring(err)
            )
        end

        HOLY_SHOP_STATE.AuctionWorkerRunning =
            false
    end)

    return true
end

function HolyAuctionRequestSnapshot()

    local networking =
        HolyShopRequireModule(
            "SharedModules.Networking"
        )

    local request =
        type(networking) == "table"
        and type(networking.Auctioneer) == "table"
        and networking.Auctioneer.RequestSnapshot
        or nil

    if type(request) ~= "table"
    or type(request.Fire) ~= "function" then

        return false
    end

    local ok =
        pcall(function()

            request:Fire()
        end)

    return ok == true
end

