function HolyAuctionSetServerClock(serverNow)

    serverNow =
        tonumber(serverNow)

    if serverNow == nil
    or serverNow <= 0 then

        return false
    end

    HOLY_SHOP_STATE.AuctionServerNow =
        serverNow

    HOLY_SHOP_STATE.AuctionServerClockAt =
        os.clock()

    return true
end

function HolyAuctionEstimatedServerNow()

    HolyAuctionEnsureState()

    local serverNow =
        tonumber(
            HOLY_SHOP_STATE.AuctionServerNow
        )
        or 0

    local clockAt =
        tonumber(
            HOLY_SHOP_STATE.AuctionServerClockAt
        )
        or 0

    if serverNow > 0
    and clockAt > 0 then

        return serverNow
            + math.max(
                0,
                os.clock() - clockAt
            )
    end

    local synchronizedTime =
        nil

    pcall(function()

        synchronizedTime =
            workspace:GetServerTimeNow()
    end)

    synchronizedTime =
        tonumber(
            synchronizedTime
        )

    if synchronizedTime ~= nil
    and synchronizedTime > 0 then

        return synchronizedTime
    end

    return os.time()
end

function HolyAuctionGetCallbackUpvalues(callback)

    if type(callback) ~= "function" then
        return nil
    end

    if type(getupvalues) == "function" then

        local ok,
            values =
            pcall(
                getupvalues,
                callback
            )

        if ok == true
        and type(values) == "table" then

            return values
        end
    end

    if type(debug) == "table"
    and type(debug.getupvalues) == "function" then

        local ok,
            values =
            pcall(
                debug.getupvalues,
                callback
            )

        if ok == true
        and type(values) == "table" then

            return values
        end
    end

    return nil
end

function HolyAuctionFindCapturedLot(
    value,
    visited,
    depth
)

    if type(value) ~= "table" then
        return nil
    end

    visited =
        type(visited) == "table"
        and visited
        or {}

    if visited[value] == true then
        return nil
    end

    visited[value] =
        true

    local lotId =
        tostring(
            rawget(value, "lotId")
            or rawget(value, "LotId")
            or ""
        )

    if lotId:match(
        "^auction:%d+:%d+$"
    )
    and tonumber(
        rawget(value, "startPrice")
        or rawget(value, "StartPrice")
    ) ~= nil then

        return value
    end

    depth =
        tonumber(depth)
        or 0

    if depth <= 0 then
        return nil
    end

    local cursor =
        nil

    local inspected =
        0

    while inspected < 300 do

        local ok,
            key,
            child =
            pcall(
                next,
                value,
                cursor
            )

        if ok ~= true
        or key == nil then

            break
        end

        cursor =
            key

        inspected +=
            1

        if type(child) == "table" then

            local found =
                HolyAuctionFindCapturedLot(
                    child,
                    visited,
                    depth - 1
                )

            if type(found) == "table" then

                return found
            end
        end
    end

    return nil
end

function HolyAuctionCollectPassiveLots()

    local lotsById =
        {}

    if type(getconnections) ~= "function" then
        return {}
    end

    local auctionGui =
        HolyAuctionFindAuctionGui()

    if typeof(auctionGui) ~= "Instance" then
        return {}
    end

    for _, object in ipairs(
        auctionGui:GetDescendants()
    ) do

        if object:IsA("GuiButton")
        and tostring(object.Name) == "BuyButton" then

            local signal =
                nil

            pcall(function()

                signal =
                    object.Activated
            end)

            if signal ~= nil then

                local ok,
                    connections =
                    pcall(
                        getconnections,
                        signal
                    )

                if ok == true
                and type(connections) == "table" then

                    for _, connection in ipairs(connections) do

                        local callback =
                            nil

                        pcall(function()

                            callback =
                                connection.Function
                                or connection.Callback
                        end)

                        local upvalues =
                            HolyAuctionGetCallbackUpvalues(
                                callback
                            )

                        if type(upvalues) == "table" then

                            local lot =
                                HolyAuctionFindCapturedLot(
                                    upvalues,
                                    {},
                                    6
                                )

                            if type(lot) == "table" then

                                local lotId =
                                    tostring(
                                        lot.lotId
                                        or lot.LotId
                                        or ""
                                    )

                                if lotId ~= "" then

                                    lotsById[lotId] =
                                        lot
                                end
                            end
                        end
                    end
                end
            end
        end
    end

    local lots =
        {}

    for _, lot in pairs(lotsById) do

        lots[#lots + 1] =
            lot
    end

    table.sort(lots, function(a, b)

        return (
            HolyAuctionExtractSlot(
                a.lotId
                or a.LotId
            )
            or 999
        ) < (
            HolyAuctionExtractSlot(
                b.lotId
                or b.LotId
            )
            or 999
        )
    end)

    return lots
end

function HolyAuctionPassiveBootstrap(force)

    HolyAuctionEnsureState()

    local nowClock =
        os.clock()

    local previousScan =
        tonumber(
            HOLY_SHOP_STATE.AuctionPassiveScanAt
        )
        or 0

    if force ~= true
    and nowClock - previousScan < 2 then

        return false
    end

    HOLY_SHOP_STATE.AuctionPassiveScanAt =
        nowClock

    local lots =
        HolyAuctionCollectPassiveLots()

    if #lots < 5 then
        return false
    end

    local cycleCounts =
        {}

    local bestCycle =
        nil

    local bestCount =
        0

    for _, lot in ipairs(lots) do

        local lotId =
            tostring(
                lot.lotId
                or lot.LotId
                or ""
            )

        local cycle =
            HolyAuctionExtractCycle(
                lotId
            )

        if cycle ~= nil then

            cycleCounts[cycle] =
                (
                    cycleCounts[cycle]
                    or 0
                )
                + 1

            if cycleCounts[cycle] > bestCount then

                bestCycle =
                    cycle

                bestCount =
                    cycleCounts[cycle]
            end
        end
    end

    if bestCycle == nil
    or bestCount < 5 then

        return false
    end

    local serverNow =
        HolyAuctionEstimatedServerNow()

    local rollInterval =
        tonumber(
            HOLY_SHOP_STATE.AuctionRollIntervalSeconds
        )
        or 1800

    local expectedCycle =
        math.floor(
            serverNow / rollInterval
        ) * rollInterval

    if bestCycle ~= expectedCycle then

        return false
    end

    if tonumber(
        HOLY_SHOP_STATE.AuctionManifestCycle
    ) == bestCycle
    and #HOLY_SHOP_STATE.AuctionManifest >= bestCount then

        return true
    end

    local applied =
        HolyAuctionApplyManifestPayload(
            {
                manifest = {
                    lots =
                        lots,
                },

                rollWindowUnix =
                    bestCycle,

                rollIntervalSeconds =
                    rollInterval,

                serverNow =
                    serverNow,
            },
            "Current auction"
        )

    if applied == true then

        HolyAuctionSetStatus(
            "Auctions loaded"
        )

        return true
    end

    return false
end

function HolyAuctionReadPassiveStock(lotId)

    lotId =
        tostring(
            lotId
            or ""
        )

    if lotId == "" then
        return nil, ""
    end

    local auctionGui =
        HolyAuctionFindAuctionGui()

    local scrollingFrame =
        auctionGui
        and HolyAuctionFindScrollingFrame(
            auctionGui
        )
        or nil

    if typeof(scrollingFrame) ~= "Instance" then

        return nil, ""
    end

    local lotFrame =
        scrollingFrame:FindFirstChild(
            "Lot_"
            .. lotId
        )

    if typeof(lotFrame) ~= "Instance" then

        return nil, ""
    end

    local stockText =
        HolyAuctionFindText(
            lotFrame,
            "Stock_Text"
        )

    stockText =
        HolyCleanText(
            stockText
        )

    if stockText == "" then

        return nil, ""
    end

    return HolyAuctionReadStock(
        stockText
    ),
        stockText
end

function HolyAuctionGetAuctioneerModule()

    HolyAuctionEnsureState()

    if type(HOLY_SHOP_STATE.AuctioneerModule) == "table" then

        return HOLY_SHOP_STATE.AuctioneerModule
    end

    local auctioneer =
        HolyShopRequireModule(
            "SharedModules.Auctioneer"
        )

    if type(auctioneer) == "table" then

        HOLY_SHOP_STATE.AuctioneerModule =
            auctioneer

        return auctioneer
    end

    return nil
end

function HolyAuctionDisplayName(lot)

    lot =
        type(lot) == "table"
        and lot
        or {}

    local displayName =
        HolyCleanText(
            lot.displayName
            or lot.DisplayName
            or lot.name
            or lot.Name
        )

    if displayName ~= "" then

        return displayName
    end

    local auctioneer =
        HolyAuctionGetAuctioneerModule()

    if type(auctioneer) == "table"
    and type(auctioneer.DisplayName) == "function" then

        local ok,
            result =
            pcall(
                auctioneer.DisplayName,
                lot
            )

        if ok == true then

            displayName =
                HolyCleanText(
                    result
                )
        end
    end

    if displayName == "" then

        displayName =
            HolyCleanText(
                lot.item
                or lot.Item
                or lot.listingId
                or lot.LotId
                or lot.lotId
                or "Unknown Auction Item"
            )
    end

    return displayName
end

function HolyAuctionPrimitiveLot(lot)

    local result =
        {}

    for key, value in pairs(lot or {}) do

        local valueType =
            type(value)

        if valueType == "string"
        or valueType == "number"
        or valueType == "boolean" then

            result[tostring(key)] =
                value
        end
    end

    result.lotId =
        tostring(
            lot.lotId
            or lot.LotId
            or result.lotId
            or ""
        )

    result.displayName =
        HolyAuctionDisplayName(
            lot
        )

    return result
end

function HolyAuctionSaveManifestCache()

    HolyAuctionEnsureState()

    if HolyCanUseFiles() ~= true then
        return false
    end

    if #HOLY_SHOP_STATE.AuctionManifest <= 0 then
        return false
    end

    HolyEnsureFolder()

    local safeLots =
        {}

    for _, lot in ipairs(HOLY_SHOP_STATE.AuctionManifest) do

        table.insert(
            safeLots,
            HolyAuctionPrimitiveLot(
                lot
            )
        )
    end

    local payload = {
        Version =
            "HOLY_AUCTION_MANIFEST_CACHE_V3",

        PlaceId =
            game.PlaceId,

        Cycle =
            HOLY_SHOP_STATE.AuctionManifestCycle,

        Hash =
            HOLY_SHOP_STATE.AuctionManifestHash,

        RollIntervalSeconds =
            HOLY_SHOP_STATE.AuctionRollIntervalSeconds,

        SavedAt =
            os.time(),

        Lots =
            safeLots,
    }

    local encodedOk,
        encoded =
        pcall(function()

            return HttpService:JSONEncode(
                payload
            )
        end)

    if encodedOk ~= true then
        return false
    end

    return pcall(function()

        writefile(
            HOLY_AUCTION_MANIFEST_CACHE_FILE,
            encoded
        )
    end)
end

function HolyAuctionRefreshNetworkReady()

    HolyAuctionEnsureState()

    local manifestCycle =
        tonumber(
            HOLY_SHOP_STATE.AuctionManifestCycle
        )

    local stockCycle =
        HolyAuctionCalculateStockCycle()

    local ready =
        manifestCycle ~= nil
        and stockCycle ~= nil
        and manifestCycle == stockCycle
        and #HOLY_SHOP_STATE.AuctionManifest > 0

    if ready == true then

        for _, lot in ipairs(HOLY_SHOP_STATE.AuctionManifest) do

            local lotId =
                tostring(
                    lot.lotId
                    or lot.LotId
                    or ""
                )

            if lotId == ""
            or HOLY_SHOP_STATE.AuctionStockMap[lotId] == nil then

                ready =
                    false

                break
            end
        end
    end

    HOLY_SHOP_STATE.AuctionNetworkReady =
        ready

    if ready == true then

        HOLY_SHOP_STATE.AuctionDataMode =
            "Network ready"

    elseif manifestCycle == nil then

        HOLY_SHOP_STATE.AuctionDataMode =
            "Waiting manifest"

    elseif stockCycle == nil then

        HOLY_SHOP_STATE.AuctionDataMode =
            "Waiting stock"

    else

        HOLY_SHOP_STATE.AuctionDataMode =
            "Syncing cycles "
            .. tostring(manifestCycle)
            .. "/"
            .. tostring(stockCycle)
    end

    return ready
end

function HolyAuctionApplyManifestPayload(payload, source)

    HolyAuctionEnsureState()

    payload =
        type(payload) == "table"
        and payload
        or {}

    local manifest =
        type(payload.manifest) == "table"
        and payload.manifest
        or payload

    local sourceLots =
        type(manifest.lots) == "table"
        and manifest.lots
        or (
            type(manifest.Lots) == "table"
            and manifest.Lots
            or nil
        )

    if type(sourceLots) ~= "table" then

        return false,
            "manifest lots missing"
    end

    local lots =
        {}

    local byLotId =
        {}

    local cycleCounts =
        {}

    local bestCycle =
        nil

    local bestCycleCount =
        0

    for _, rawLot in pairs(sourceLots) do

        if type(rawLot) == "table" then

            local lot =
                rawLot

            local lotId =
                tostring(
                    lot.lotId
                    or lot.LotId
                    or ""
                )

            if lotId ~= "" then

                lot.lotId =
                    lotId

                lot.displayName =
                    HolyAuctionDisplayName(
                        lot
                    )

                table.insert(
                    lots,
                    lot
                )

                byLotId[lotId] =
                    lot

                local cycle =
                    HolyAuctionExtractCycle(
                        lotId
                    )

                if cycle ~= nil then

                    cycleCounts[cycle] =
                        (
                            cycleCounts[cycle]
                            or 0
                        )
                        + 1

                    if cycleCounts[cycle] > bestCycleCount then

                        bestCycle =
                            cycle

                        bestCycleCount =
                            cycleCounts[cycle]
                    end
                end
            end
        end
    end

    if #lots <= 0 then

        return false,
            "manifest contains no lots"
    end

    if bestCycle == nil then

        bestCycle =
            tonumber(
                payload.rollWindowUnix
                or manifest.rollWindowUnix
            )
    end

    table.sort(lots, function(a, b)

        return (
            HolyAuctionExtractSlot(
                a.lotId
            )
            or 999
        ) < (
            HolyAuctionExtractSlot(
                b.lotId
            )
            or 999
        )
    end)

    local previousCycle =
        tonumber(
            HOLY_SHOP_STATE.AuctionManifestCycle
        )

    if previousCycle ~= nil
    and bestCycle ~= nil
    and previousCycle ~= bestCycle then

        HOLY_SHOP_STATE.AuctionAttemptedLots =
            {}

        HOLY_SHOP_STATE.AuctionNextBuyAt =
            0

        HOLY_SHOP_STATE.AuctionNextRetryAt =
            0

        HOLY_SHOP_STATE.AuctionPendingLotId =
            nil

        HOLY_SHOP_STATE.AuctionPendingPrice =
            nil

        HOLY_SHOP_STATE.AuctionPendingName =
            nil

        HOLY_SHOP_STATE.AuctionPendingSentAt =
            0

        HOLY_SHOP_STATE.AuctionLastSentLotId =
            ""

        HOLY_SHOP_STATE.AuctionLastSentName =
            ""

        HOLY_SHOP_STATE.AuctionLastSentAt =
            0
    end

    HOLY_SHOP_STATE.AuctionManifest =
        lots

    HOLY_SHOP_STATE.AuctionManifestByLotId =
        byLotId

    HOLY_SHOP_STATE.AuctionManifestCycle =
        bestCycle

    HOLY_SHOP_STATE.AuctionManifestHash =
        tostring(
            manifest.hash
            or manifest.Hash
            or payload.hash
            or ""
        )

    HOLY_SHOP_STATE.AuctionManifestSource =
        tostring(
            source
            or "Packet 335"
        )

    HOLY_SHOP_STATE.AuctionManifestReceivedAt =
        os.clock()

    HOLY_SHOP_STATE.AuctionRollIntervalSeconds =
        tonumber(
            payload.rollIntervalSeconds
            or manifest.rollIntervalSeconds
        )
        or HOLY_SHOP_STATE.AuctionRollIntervalSeconds
        or 1800

    HolyAuctionSetServerClock(
        payload.serverNow
        or manifest.serverNow
    )

    -- Intentionally do not read payload.stock here.
    -- Snapshot stock can still belong to the previous cycle.

    for _, lot in ipairs(lots) do

        HolyAuctionRememberKnownItem(
            lot.displayName
        )
    end

    HolyAuctionRefreshNetworkReady()

    if source ~= "Cache" then

        HolyAuctionSaveManifestCache()
    end

    HolyAuctionRefreshDropdown(
        true
    )

    return true
end

function HolyAuctionLoadManifestCache()

    HolyAuctionEnsureState()

    if HolyCanUseFiles() ~= true then
        return false
    end

    local existsOk,
        exists =
        pcall(function()

            return isfile(
                HOLY_AUCTION_MANIFEST_CACHE_FILE
            )
        end)

    if existsOk ~= true
    or exists ~= true then

        return false
    end

    local readOk,
        raw =
        pcall(function()

            return readfile(
                HOLY_AUCTION_MANIFEST_CACHE_FILE
            )
        end)

    if readOk ~= true then
        return false
    end

    local decodeOk,
        cache =
        pcall(function()

            return HttpService:JSONDecode(
                raw
            )
        end)

    if decodeOk ~= true
    or type(cache) ~= "table"
    or tonumber(cache.PlaceId) ~= game.PlaceId
    or type(cache.Lots) ~= "table" then

        return false
    end

    return HolyAuctionApplyManifestPayload(
        {
            manifest = {
                lots =
                    cache.Lots,

                hash =
                    cache.Hash,
            },

            rollWindowUnix =
                cache.Cycle,

            rollIntervalSeconds =
                cache.RollIntervalSeconds,
        },
        "Cache"
    )
end

function HolyAuctionCurrentPrice(lot, serverNow)

    lot =
        type(lot) == "table"
        and lot
        or {}

    serverNow =
        tonumber(serverNow)
        or HolyAuctionEstimatedServerNow()

    if serverNow <= 0 then

        return nil,
            "server clock missing"
    end

    local auctioneer =
        HolyAuctionGetAuctioneerModule()

    if type(auctioneer) ~= "table"
    or type(auctioneer.CurrentPrice) ~= "function" then

        return nil,
            "Auctioneer.CurrentPrice missing"
    end

    local ok,
        price =
        pcall(
            auctioneer.CurrentPrice,
            lot,
            serverNow
        )

    price =
        tonumber(price)

    if ok ~= true
    or price == nil
    or price ~= price
    or price == math.huge
    or price <= 0 then

        return nil,
            "CurrentPrice failed"
    end

    return math.max(
        1,
        math.floor(
            price + 0.5
        )
    )
end

function HolyAuctionIsNetworkLotActive(lot, serverNow, stock)

    stock =
        math.max(
            0,
            math.floor(
                tonumber(stock)
                or 0
            )
        )

    if stock <= 0 then
        return false
    end

    local auctioneer =
        HolyAuctionGetAuctioneerModule()

    if type(auctioneer) == "table"
    and type(auctioneer.IsActive) == "function" then

        local ok,
            active =
            pcall(
                auctioneer.IsActive,
                lot,
                serverNow,
                stock
            )

        if ok == true
        and type(active) == "boolean" then

            return active
        end
    end

    local expiresAt =
        tonumber(
            lot.expiresAt
            or lot.ExpiresAt
        )

    if expiresAt ~= nil
    and serverNow > 0
    and serverNow >= expiresAt then

        return false
    end

    return true
end

function HolyAuctionRowStale(row, requireServerStock)

    HolyAuctionEnsureState()

    row =
        type(row) == "table"
        and row
        or {}

    if HOLY_SHOP_STATE.AuctionNetworkReady ~= true then

        return true,
            "network not synchronized"
    end

    if row.Network ~= true then

        return true,
            "not network data"
    end

    local manifestCycle =
        tonumber(
            HOLY_SHOP_STATE.AuctionManifestCycle
        )

    local stockCycle =
        tonumber(
            HolyAuctionGetStockCycle()
        )

    if manifestCycle == nil
    or stockCycle == nil
    or manifestCycle ~= stockCycle
    or tonumber(row.Cycle) ~= manifestCycle then

        return true,
            "cycle mismatch"
    end

    if requireServerStock == true then

        local lotId =
            tostring(
                row.LotId
                or ""
            )

        if HOLY_SHOP_STATE.AuctionStockMap[lotId] == nil then

            return true,
                "stock missing"
        end
    end

    return false,
        ""
end

function HolyAuctionScanLiveLots()

    HolyAuctionEnsureState()

    HolyAuctionRestoreOffscreen()

    HolyAuctionRefreshNetworkReady()

    local rows =
        {}

    local serverNow =
        HolyAuctionEstimatedServerNow()

    local manifestCycle =
        tonumber(
            HOLY_SHOP_STATE.AuctionManifestCycle
        )

    local rollInterval =
        tonumber(
            HOLY_SHOP_STATE.AuctionRollIntervalSeconds
        )
        or 1800

    if manifestCycle ~= nil
    and serverNow > 0 then

        HOLY_SHOP_STATE.AuctionRefreshSeconds =
            math.max(
                0,
                manifestCycle
                    + rollInterval
                    - serverNow
            )

        HOLY_SHOP_STATE.AuctionRefreshReadAt =
            os.clock()

        HOLY_SHOP_STATE.AuctionRefreshText =
            "Refresh in "
            .. HolyAuctionFormatDuration(
                HOLY_SHOP_STATE.AuctionRefreshSeconds
            )
    end

    for _, lot in ipairs(HOLY_SHOP_STATE.AuctionManifest) do

        local lotId =
            tostring(
                lot.lotId
                or lot.LotId
                or ""
            )

        local serverStock =
            HOLY_SHOP_STATE.AuctionStockMap[
                lotId
            ]

        local passiveStock,
            passiveStockText =
            HolyAuctionReadPassiveStock(
                lotId
            )

        local stockValue =
            serverStock

        local stockSource =
            "Server"

        if stockValue == nil then

            stockValue =
                passiveStock

            stockSource =
                passiveStock ~= nil
                and "Display"
                or "Unknown"
        end

        local stockKnown =
            stockValue ~= nil

        local stock =
            math.max(
                0,
                math.floor(
                    tonumber(stockValue)
                    or 0
                )
            )

        local price =
            HolyAuctionCurrentPrice(
                lot,
                serverNow
            )

        local expiresAt =
            tonumber(
                lot.expiresAt
                or lot.ExpiresAt
            )

        local expired =
            expiresAt ~= nil
            and serverNow > 0
            and serverNow >= expiresAt

        local networkReady =
            HOLY_SHOP_STATE.AuctionNetworkReady == true
            and serverStock ~= nil

        local active =
            stockKnown == true
            and price ~= nil
            and HolyAuctionIsNetworkLotActive(
                lot,
                serverNow,
                stock
            )

        local remaining =
            expiresAt ~= nil
            and serverNow > 0
            and math.max(
                0,
                expiresAt - serverNow
            )
            or math.max(
                0,
                HOLY_SHOP_STATE.AuctionRefreshSeconds
                or 0
            )

        local count =
            math.max(
                1,
                math.floor(
                    tonumber(
                        lot.count
                        or lot.Count
                    )
                    or 1
                )
            )

        table.insert(
            rows,
            {
                LotId =
                    lotId,

                Cycle =
                    HolyAuctionExtractCycle(
                        lotId
                    ),

                Slot =
                    HolyAuctionExtractSlot(
                        lotId
                    ),

                Name =
                    HolyAuctionDisplayName(
                        lot
                    ),

                Stock =
                    stock,

                ServerStock =
                    serverStock,

                DisplayStock =
                    passiveStock,

                StockKnown =
                    stockKnown,

                StockSource =
                    stockSource,

                StockText =
                    stockKnown == true
                    and (
                        "x"
                        .. tostring(stock)
                    )
                    or "--",

                Price =
                    price or 0,

                PriceText =
                    price ~= nil
                    and HolyAuctionFormatMoney(
                        price
                    )
                    or "--",

                AmountText =
                    count > 1
                    and (
                        "x"
                        .. tostring(count)
                    )
                    or "",

                Timer =
                    HolyAuctionFormatDuration(
                        remaining
                    ),

                SoldOut =
                    stockKnown == true
                    and stock <= 0,

                Expired =
                    expired,

                Active =
                    active == true,

                SortIndex =
                    HolyAuctionExtractSlot(
                        lotId
                    )
                    or 999,

                Cached =
                    HOLY_SHOP_STATE.AuctionManifestSource == "Cache",

                Network =
                    true,

                NetworkReady =
                    networkReady,

                Manifest =
                    lot,
            }
        )
    end

    table.sort(rows, function(a, b)

        local selectedA =
            HolyAuctionSelectionAllows(
                a.Name
            )

        local selectedB =
            HolyAuctionSelectionAllows(
                b.Name
            )

        if selectedA ~= selectedB then

            return selectedA == true
        end

        if a.Active ~= b.Active then

            return a.Active == true
        end

        return tonumber(a.SortIndex)
            < tonumber(b.SortIndex)
    end)

    HOLY_SHOP_STATE.AuctionLastLots =
        rows

    HOLY_SHOP_STATE.AuctionLastScanAt =
        os.clock()

    return rows
end

function HolyAuctionBuildLiveText(rows)

    rows =
        type(rows) == "table"
        and rows
        or HolyAuctionScanLiveLots()

    if #rows <= 0 then

        return "Live: Loading auctions..."
    end

    local parts =
        {}

    for index, row in ipairs(rows) do

        if index > 3 then
            break
        end

        local stockText =
            row.StockKnown == true
            and (
                "x"
                .. tostring(row.Stock)
            )
            or "--"

        parts[#parts + 1] =
            tostring(row.Name)
            .. " "
            .. stockText
            .. " "
            .. tostring(row.PriceText)
    end

    if #rows > 3 then

        parts[#parts + 1] =
            "+"
            .. tostring(#rows - 3)
            .. " more"
    end

    return "Live: "
        .. HolyAuctionRefreshHeaderText()
        .. " | "
        .. table.concat(
            parts,
            " | "
        )
end

function HolyAuctionRepriceRow(row)

    HolyAuctionEnsureState()

    if HOLY_SHOP_STATE.AuctionNetworkReady ~= true then

        return nil,
            "network not synchronized"
    end

    local lotId =
        tostring(
            type(row) == "table"
            and row.LotId
            or ""
        )

    local manifestLot =
        HOLY_SHOP_STATE.AuctionManifestByLotId[
            lotId
        ]

    if type(manifestLot) ~= "table" then

        return nil,
            "manifest lot missing"
    end

    local stock =
        HOLY_SHOP_STATE.AuctionStockMap[
            lotId
        ]

    if stock == nil then

        return nil,
            "server stock missing"
    end

    local serverNow =
        HolyAuctionEstimatedServerNow()

    local price,
        priceReason =
        HolyAuctionCurrentPrice(
            manifestLot,
            serverNow
        )

    if price == nil then

        return nil,
            priceReason
    end

    local result =
        {}

    for key, value in pairs(row or {}) do

        result[key] =
            value
    end

    result.Price =
        price

    result.PriceText =
        HolyAuctionFormatMoney(
            price
        )

    result.Stock =
        math.max(
            0,
            math.floor(
                tonumber(stock)
                or 0
            )
        )

    result.ServerStock =
        stock

    result.Active =
        HolyAuctionIsNetworkLotActive(
            manifestLot,
            serverNow,
            stock
        )

    result.Network =
        true

    result.NetworkReady =
        true

    result.Manifest =
        manifestLot

    if result.Active ~= true then

        return nil,
            "Auction unavailable"
    end

    if HolyAuctionSelectionAllows(
        result.Name
    ) ~= true then

        return nil,
            "Item is not selected"
    end

    if HolyAuctionPriceAllows(
        result
    ) ~= true then

        return nil,
            "Price is above Max Price"
    end

    local stale,
        staleReason =
        HolyAuctionRowStale(
            result,
            true
        )

    if stale == true then

        return nil,
            staleReason == "stock stale"
            and "Waiting for stock"
            or "Auction data is updating"
    end

    if HOLY_SHOP_STATE
        .AuctionBuyUntilSoldOut ~= true
    and HOLY_SHOP_STATE
        .AuctionAttemptedLots[
            tostring(result.LotId)
        ] == true then

        return nil,
            "Bought once"
    end

    return result
end

function HolyAuctionFirePurchase(row)

    local finalRow,
        safetyReason =
        HolyAuctionRepriceRow(
            row
        )

    if type(finalRow) ~= "table" then

        return false,
            tostring(
                safetyReason
                or "reprice failed"
            )
    end

    local lotId =
        tostring(
            finalRow.LotId
        )

    local price =
        math.max(
            1,
            math.floor(
                tonumber(finalRow.Price)
                or 0
            )
        )

    if HOLY_SHOP_STATE.AuctionDryRun == true then

        HOLY_SHOP_STATE.AuctionLastDecision =
            "DRY RUN eligible: "
            .. tostring(finalRow.Name)
            .. " at "
            .. HolyAuctionFormatMoney(price)

        return true,
            "dry run",
            finalRow
    end

    local packet =
        HolyAuctionResolvePurchasePacket(
            false
        )

    if type(packet) ~= "table" then

        packet =
            HolyAuctionResolvePurchasePacket(
                true
            )
    end

    if type(packet) ~= "table"
    or type(packet.Fire) ~= "function" then

        return false,
            "PurchaseLot packet missing"
    end

    if type(HolyDevTrace) == "function" then

        HolyDevTrace(
            "Auction",
            "PurchaseFireBegin",
            {
                LotId = lotId,
                Name = finalRow.Name,
                Price = price,
            }
        )
    end

    local ok,
        result =
        pcall(function()

            return packet:Fire(
                lotId,
                price
            )
        end)

    if type(HolyDevTrace) == "function" then

        HolyDevTrace(
            "Auction",
            "PurchaseFireReturned",
            {
                LotId = lotId,
                Name = finalRow.Name,
                Price = price,
                LocalSuccess = ok == true,

                Error =
                    ok ~= true
                    and tostring(result)
                    or nil,
            },
            ok == true
            and "Info"
            or "Error"
        )
    end

    if ok ~= true then

        return false,
            tostring(result)
    end

    HOLY_SHOP_STATE.AuctionAttemptedLots[lotId] =
        true

    HOLY_SHOP_STATE.AuctionPendingLotId =
        lotId

    HOLY_SHOP_STATE.AuctionPendingPrice =
        price

    local sentAt =
        os.clock()

    local sentName =
        tostring(
            finalRow.Name
            or "Auction item"
        )

    HOLY_SHOP_STATE.AuctionPendingName =
        sentName

    HOLY_SHOP_STATE.AuctionPendingSentAt =
        sentAt

    HOLY_SHOP_STATE.AuctionLastSentLotId =
        lotId

    HOLY_SHOP_STATE.AuctionLastSentName =
        sentName

    HOLY_SHOP_STATE.AuctionLastSentAt =
        sentAt

    if type(HolyDevTrace) == "function" then

        HolyDevTrace(
            "Auction",
            "PendingSet",
            {
                LotId = lotId,
                Name = sentName,
                Price = price,
                SentAt = sentAt,
            }
        )
    end

    HOLY_SHOP_STATE.AuctionLastDecision =
        "Purchase sent: "
        .. tostring(finalRow.Name)
        .. " at "
        .. HolyAuctionFormatMoney(price)

    return true,
        "packet fired",
        finalRow
end

function HolyAuctionAttemptPurchase(reason, automatic)

    HolyAuctionEnsureState()

    if automatic == true
    and HOLY_SHOP_STATE.AutoBuyAuctions ~= true then

        return false
    end

    local now =
        os.clock()

    if type(HolyDevTrace) == "function" then

        HolyDevTrace(
            "Auction",
            "PurchaseAttempt",
            {
                Reason =
                    tostring(
                        reason
                        or "unknown"
                    ),

                Automatic =
                    automatic == true,

                WorkerRunning =
                    HOLY_SHOP_STATE.AuctionWorkerRunning
                    == true,

                PendingLotId =
                    HOLY_SHOP_STATE.AuctionPendingLotId,

                NextBuyIn =
                    math.max(
                        0,
                        (
                            tonumber(
                                HOLY_SHOP_STATE.AuctionNextBuyAt
                            )
                            or 0
                        ) - now
                    ),

                Decision =
                    HOLY_DEV_SUITE_RUNTIME.RecorderActive
                        == true
                    and type(HolyDevRecorderAuctionDecisionState)
                        == "function"
                    and HolyDevRecorderAuctionDecisionState()
                    or nil,
            }
        )
    end

    local pendingLotId =
        HolyCleanText(
            HOLY_SHOP_STATE.AuctionPendingLotId
        )

    local pendingSentAt =
        tonumber(
            HOLY_SHOP_STATE.AuctionPendingSentAt
        )
        or 0

    local pendingTimeout =
        math.max(
            2,
            HolyAuctionReadDebounce()
                + 0.5
        )

    if pendingLotId ~= ""
    and pendingSentAt > 0
    and now - pendingSentAt < pendingTimeout then

        if type(HolyDevTrace) == "function" then

            HolyDevTrace(
                "Auction",
                "PurchaseBlocked",
                {
                    Reason = "pending result",
                    LotId = pendingLotId,

                    Remaining =
                        math.max(
                            0,
                            pendingTimeout
                            - (
                                now
                                - pendingSentAt
                            )
                        ),
                },
                "Warning"
            )
        end

        HolyAuctionSetStatus(
            "Processing purchase..."
        )

        return false
    end

    if pendingLotId ~= ""
    and pendingSentAt > 0
    and now - pendingSentAt >= pendingTimeout then

        if type(HolyDevTrace) == "function" then

            HolyDevTrace(
                "Auction",
                "PendingExpired",
                {
                    LotId = pendingLotId,
                    Age = now - pendingSentAt,
                    Timeout = pendingTimeout,
                },
                "Warning"
            )
        end

        HOLY_SHOP_STATE.AuctionPendingLotId =
            nil

        HOLY_SHOP_STATE.AuctionPendingPrice =
            nil

        HOLY_SHOP_STATE.AuctionPendingName =
            nil

        HOLY_SHOP_STATE.AuctionPendingSentAt =
            0
    end

    local nextBuyAt =
        tonumber(
            HOLY_SHOP_STATE.AuctionNextBuyAt
        )
        or 0

    if now < nextBuyAt then

        if type(HolyDevTrace) == "function" then

            HolyDevTrace(
                "Auction",
                "PurchaseBlocked",
                {
                    Reason = "client cooldown",
                    Remaining = nextBuyAt - now,
                },
                "Warning"
            )
        end

        HolyAuctionSetStatus(
            "Cooldown "
            .. tostring(
                math.max(
                    1,
                    math.ceil(
                        nextBuyAt - now
                    )
                )
            )
            .. "s"
        )

        return false
    end

    local nextRetryAt =
        tonumber(
            HOLY_SHOP_STATE.AuctionNextRetryAt
        )
        or 0

    if now < nextRetryAt then

        if type(HolyDevTrace) == "function" then

            HolyDevTrace(
                "Auction",
                "PurchaseBlocked",
                {
                    Reason = "retry delay",
                    Remaining = nextRetryAt - now,
                }
            )
        end

        return false
    end

    local target,
        targetReason =
        HolyAuctionFindBuyTarget()

    if type(target) ~= "table" then

        targetReason =
            tostring(
                targetReason
                or "Waiting"
            )

        HOLY_SHOP_STATE.AuctionLastDecision =
            targetReason

        HOLY_SHOP_STATE.AuctionLastBlockReason =
            targetReason

        if type(HolyDevTrace) == "function" then

            HolyDevTrace(
                "Auction",
                "NoTarget",
                {
                    Reason = targetReason,

                    Decision =
                        HOLY_DEV_SUITE_RUNTIME.RecorderActive
                            == true
                        and type(HolyDevRecorderAuctionDecisionState)
                            == "function"
                        and HolyDevRecorderAuctionDecisionState()
                        or nil,
                }
            )
        end

        local lowerReason =
            targetReason:lower()

        local retryDelay =
            1

        if lowerReason:find(
            "stock",
            1,
            true
        )
        or lowerReason:find(
            "updating",
            1,
            true
        ) then

            retryDelay =
                2

        elseif lowerReason:find(
            "bought once",
            1,
            true
        ) then

            retryDelay =
                5
        end

        HOLY_SHOP_STATE.AuctionNextRetryAt =
            now + retryDelay

        HolyAuctionSetStatus(
            targetReason
        )

        return false
    end

    if type(HolyDevTrace) == "function" then

        HolyDevTrace(
            "Auction",
            "TargetSelected",
            {
                LotId = target.LotId,
                Name = target.Name,
                Price = target.Price,
                Stock = target.Stock,
                WatchlistIndex = target.WatchlistIndex,

                Decision =
                    HOLY_DEV_SUITE_RUNTIME.RecorderActive
                        == true
                    and type(HolyDevRecorderAuctionDecisionState)
                        == "function"
                    and HolyDevRecorderAuctionDecisionState()
                    or nil,
            }
        )
    end

    local ok,
        fireMode,
        finalRow =
        HolyAuctionFirePurchase(
            target
        )

    if ok ~= true then

        local blockReason =
            tostring(
                fireMode
                or "Purchase unavailable"
            )

        HOLY_SHOP_STATE.AuctionLastBlockReason =
            blockReason

        HOLY_SHOP_STATE.AuctionLastDecision =
            blockReason

        if type(HolyDevTrace) == "function" then

            HolyDevTrace(
                "Auction",
                "PurchaseRejectedLocally",
                {
                    Reason = blockReason,
                    LotId = target.LotId,
                    Name = target.Name,
                },
                "Error"
            )
        end

        HOLY_SHOP_STATE.AuctionNextRetryAt =
            now + 2

        HolyAuctionSetStatus(
            blockReason
        )

        return false
    end

    finalRow =
        type(finalRow) == "table"
        and finalRow
        or target

    HOLY_SHOP_STATE.AuctionLastBlockReason =
        ""

    local watchIndex =
        tonumber(
            finalRow.WatchlistIndex
        )

    if watchIndex ~= nil then

        HOLY_SHOP_STATE.AuctionRoundRobinIndex =
            watchIndex
    end

    if fireMode == "dry run" then

        HOLY_SHOP_STATE.AuctionNextRetryAt =
            now + 1

        HolyAuctionSetStatus(
            "Test ready: "
            .. tostring(finalRow.Name)
            .. " at "
            .. tostring(finalRow.PriceText)
        )

        return true
    end

    HOLY_SHOP_STATE.AuctionNextRetryAt =
        0

    HOLY_SHOP_STATE.AuctionNextBuyAt =
        now
        + HolyAuctionReadCooldown()

    HolyAuctionSetStatus(
        "Buying "
        .. tostring(finalRow.Name)
        .. " at "
        .. tostring(finalRow.PriceText)
    )

    return true
end

function HolyAuctionManualBuyOnce(reason)

    return HolyAuctionAttemptPurchase(
        reason or "manual",
        false
    )
end

function HolyAuctionRunWorker(reason)

    return HolyAuctionAttemptPurchase(
        reason or "automatic",
        true
    )
end

function HolyAuctionConnectPacketSignals()

    HolyAuctionEnsureState()

    if HOLY_SHOP_STATE.AuctionSignalsConnected == true then
        return true
    end

    local networking =
        HolyShopRequireModule(
            "SharedModules.Networking"
        )

    local auction =
        type(networking) == "table"
        and type(networking.Auctioneer) == "table"
        and networking.Auctioneer
        or nil

    if type(auction) ~= "table" then

        HolyAuctionSetStatus(
            "Auction networking missing"
        )

        return false
    end

    local function connectPacket(packetName, callback)

        local packet =
            auction[packetName]

        if type(packet) ~= "table"
        or packet.OnClientEvent == nil then

            return false
        end

        local ok,
            connection =
            pcall(function()

                return packet.OnClientEvent:Connect(
                    callback
                )
            end)

        if ok == true
        and connection ~= nil then

            table.insert(
                HOLY_SHOP_STATE.AuctionConnections,
                connection
            )

            return true
        end

        return false
    end

    connectPacket(
        "Snapshot",
        function(payload)

            local applied,
                applyReason =
                HolyAuctionApplyManifestPayload(
                    payload,
                    "Packet 335"
                )

            if applied == true then

                HolyAuctionSetStatus(
                    "Updating auctions..."
                )

            else

                warn(
                    "[HOLY Auction] Update rejected: "
                    .. tostring(applyReason)
                )

                HolyAuctionSetStatus(
                    "Could not update auctions"
                )
            end

            task.defer(function()

                HolyAuctionRefreshUI()
            end)
        end
    )

    connectPacket(
        "StockUpdate",
        function(payload)

            HolyAuctionEnsureState()

            if type(payload) == "table"
            and type(payload.stock) == "table" then

                local nextStock =
                    {}

                for lotId, stock in pairs(payload.stock) do

                    nextStock[
                        tostring(lotId)
                    ] =
                        math.max(
                            0,
                            math.floor(
                                tonumber(stock)
                                or 0
                            )
                        )
                end

                HOLY_SHOP_STATE.AuctionStockMap =
                    nextStock

                HOLY_SHOP_STATE.AuctionLastStockUpdateAt =
                    os.clock()

                if type(HolyDevTrace) == "function" then

                    HolyDevTrace(
                        "Auction",
                        "StockUpdate",
                        {
                            Stock = nextStock,
                            ServerNow = payload.serverNow,

                            PendingLotId =
                                HOLY_SHOP_STATE.AuctionPendingLotId,
                        }
                    )
                end

                HolyAuctionSetServerClock(
                    payload.serverNow
                )

                HolyAuctionCalculateStockCycle()

                local ready =
                    HolyAuctionRefreshNetworkReady()

                HOLY_SHOP_STATE.AuctionNextRetryAt =
                    0

                if ready == true then

                    HolyAuctionSetStatus(
                        HOLY_SHOP_STATE.AuctionDryRun == true
                        and "Test Mode ready"
                        or "Auto Buy ready"
                    )

                else

                    HolyAuctionSetStatus(
                        "Updating auctions..."
                    )
                end
            end

            task.defer(function()

                HolyAuctionRefreshUI()

                if HOLY_SHOP_STATE.AutoBuyAuctions == true
                and HOLY_SHOP_STATE.AuctionNetworkReady == true then

                    HolyAuctionQueueWorker(
                        "stock update"
                    )
                end
            end)
        end
    )

    connectPacket(
        "PurchaseResult",
        function(...)

            local arguments = {
                ...,
            }

            local lotId =
                ""

            local success =
                false

            local resultReason =
                nil

            if type(arguments[1]) == "table" then

                local payload =
                    arguments[1]

                lotId =
                    HolyCleanText(
                        payload.lotId
                        or payload.LotId
                        or payload.id
                    )

                success =
                    payload.success == true
                    or payload.Success == true

                resultReason =
                    payload.reason
                    or payload.Reason
                    or payload.message
                    or payload.Message

            else

                lotId =
                    HolyCleanText(
                        arguments[1]
                    )

                success =
                    arguments[2] == true

                resultReason =
                    arguments[3]
            end

            if lotId == "" then

                lotId =
                    tostring(
                        HOLY_SHOP_STATE.AuctionPendingLotId
                        or HOLY_SHOP_STATE.AuctionLastSentLotId
                        or ""
                    )
            end

            local pendingName =
                HolyCleanText(
                    HOLY_SHOP_STATE.AuctionPendingName
                )

            if pendingName == "" then

                pendingName =
                    HolyCleanText(
                        HOLY_SHOP_STATE.AuctionLastSentName
                    )
            end

            if pendingName == "" then

                pendingName =
                    "Auction item"
            end

            local pendingSentAt =
                tonumber(
                    HOLY_SHOP_STATE.AuctionPendingSentAt
                )
                or 0

            if pendingSentAt <= 0 then

                pendingSentAt =
                    tonumber(
                        HOLY_SHOP_STATE.AuctionLastSentAt
                    )
                    or 0
            end

            if pendingSentAt <= 0 then

                pendingSentAt =
                    os.clock()
            end

            if type(HolyDevTrace) == "function" then

                HolyDevTrace(
                    "Auction",
                    "PurchaseResult",
                    {
                        LotId = lotId,
                        Success = success == true,
                        Reason = resultReason,

                        PendingLotId =
                            HOLY_SHOP_STATE.AuctionPendingLotId,

                        PendingName =
                            pendingName,

                        PendingSentAt =
                            pendingSentAt,

                        ResultLatency =
                            math.max(
                                0,
                                os.clock()
                                - pendingSentAt
                            ),
                    },
                    success == true
                    and "Info"
                    or "Error"
                )
            end

            if success == true then

                local nextAllowedAt =
                    pendingSentAt
                    + HolyAuctionReadCooldown()

                HOLY_SHOP_STATE.AuctionNextBuyAt =
                    math.max(
                        tonumber(
                            HOLY_SHOP_STATE.AuctionNextBuyAt
                        )
                        or 0,
                        nextAllowedAt
                    )

                HOLY_SHOP_STATE.AuctionNextRetryAt =
                    0

                if HOLY_SHOP_STATE
                    .AuctionBuyUntilSoldOut == true then

                    HolyAuctionSetStatus(
                        "Bought "
                        .. pendingName
                    )

                else

                    HolyAuctionSetStatus(
                        "Bought once"
                    )
                end

            else

                HOLY_SHOP_STATE.AuctionAttemptedLots[lotId] =
                    nil

                local reasonText =
                    tostring(
                        resultReason
                        or "unknown"
                    )

                local lowerReason =
                    reasonText:lower()

                warn(
                    "[HOLY Auction] Purchase rejected: "
                    .. reasonText
                )

                if lowerReason:find(
                    "cooldown",
                    1,
                    true
                )
                or lowerReason:find(
                    "too fast",
                    1,
                    true
                )
                or lowerReason:find(
                    "debounce",
                    1,
                    true
                ) then

                    HOLY_SHOP_STATE.AuctionNextBuyAt =
                        os.clock()
                        + HolyAuctionReadCooldown()

                    HOLY_SHOP_STATE.AuctionNextRetryAt =
                        0

                    HolyAuctionSetStatus(
                        "Waiting for cooldown"
                    )

                elseif lowerReason:find(
                    "money",
                    1,
                    true
                )
                or lowerReason:find(
                    "fund",
                    1,
                    true
                )
                or lowerReason:find(
                    "currency",
                    1,
                    true
                )
                or lowerReason:find(
                    "afford",
                    1,
                    true
                ) then

                    HOLY_SHOP_STATE.AuctionNextBuyAt =
                        0

                    HOLY_SHOP_STATE.AuctionNextRetryAt =
                        os.clock() + 30

                    HolyAuctionSetStatus(
                        "Not enough money"
                    )

                elseif lowerReason:find(
                    "stock",
                    1,
                    true
                )
                or lowerReason:find(
                    "sold",
                    1,
                    true
                )
                or lowerReason:find(
                    "expired",
                    1,
                    true
                )
                or lowerReason:find(
                    "inactive",
                    1,
                    true
                )
                or lowerReason:find(
                    "unavailable",
                    1,
                    true
                ) then

                    HOLY_SHOP_STATE.AuctionNextBuyAt =
                        0

                    HOLY_SHOP_STATE.AuctionNextRetryAt =
                        os.clock() + 5

                    HolyAuctionSetStatus(
                        "Waiting for stock"
                    )

                elseif lowerReason:find(
                    "price",
                    1,
                    true
                )
                or lowerReason:find(
                    "mismatch",
                    1,
                    true
                )
                or lowerReason:find(
                    "changed",
                    1,
                    true
                ) then

                    HOLY_SHOP_STATE.AuctionNextBuyAt =
                        0

                    HOLY_SHOP_STATE.AuctionNextRetryAt =
                        os.clock() + 1

                    HolyAuctionSetStatus(
                        "Price changed"
                    )

                else

                    HOLY_SHOP_STATE.AuctionNextBuyAt =
                        0

                    HOLY_SHOP_STATE.AuctionNextRetryAt =
                        os.clock() + 5

                    HolyAuctionSetStatus(
                        "Purchase failed"
                    )
                end
            end

            HOLY_SHOP_STATE.AuctionPendingLotId =
                nil

            HOLY_SHOP_STATE.AuctionPendingPrice =
                nil

            HOLY_SHOP_STATE.AuctionPendingName =
                nil

            HOLY_SHOP_STATE.AuctionPendingSentAt =
                0

            if lotId == ""
            or tostring(
                HOLY_SHOP_STATE.AuctionLastSentLotId
            ) == lotId then

                HOLY_SHOP_STATE.AuctionLastSentLotId =
                    ""

                HOLY_SHOP_STATE.AuctionLastSentName =
                    ""

                HOLY_SHOP_STATE.AuctionLastSentAt =
                    0
            end

            task.defer(function()

                HolyAuctionRefreshUI()
            end)
        end
    )

    HOLY_SHOP_STATE.AuctionSignalsConnected =
        true

    return true
end

function HolyAuctionStartWatcher()

    HolyAuctionEnsureState()

    if HOLY_SHOP_STATE.AuctionWatcherStarted == true then
        return false
    end

    HOLY_SHOP_STATE.AuctionWatcherStarted =
        true

    HolyAuctionRestoreOffscreen()

    HolyAuctionLoadManifestCache()

    HolyAuctionPassiveBootstrap(
        true
    )

    HolyAuctionConnectPacketSignals()

    HolyAuctionRequestSnapshot()

    task.spawn(function()

        while HOLY_SHOP_STATE.AuctionWatcherStarted == true do

            HolyAuctionPassiveBootstrap(
                false
            )

            HolyAuctionRefreshUI()

            if HOLY_SHOP_STATE.AutoBuyAuctions == true
            and HOLY_SHOP_STATE.AuctionNetworkReady == true then

                HolyAuctionQueueWorker(
                    "network watcher"
                )
            end

            task.wait(
                HOLY_SHOP_STATE.AutoBuyAuctions == true
                and 0.25
                or 0.75
            )
        end
    end)

    task.defer(function()

        HolyAuctionRefreshDropdown(
            true
        )

        HolyAuctionRefreshUI()

        if HOLY_SHOP_STATE.AuctionHudEnabled == true then

            HolyAuctionHudStart()
        end
    end)

    return true
end


