            8,
            10,
            14
        )

    miniButton.BackgroundTransparency =
        0.25

    miniButton.TextColor3 =
        Color3.fromRGB(
            255,
            91,
            167
        )

    miniButton.TextSize =
        11

    miniButton.Visible =
        minimized

    miniButton.ZIndex =
        20

    HOLY_AUCTION_HUD.MiniButton =
        miniButton

    local miniDot =
        HolyAuctionHudCreate(
            "Frame",
            {
                BackgroundColor3 =
                    Color3.fromRGB(
                        105,
                        229,
                        160
                    ),

                BorderSizePixel = 0,

                Position =
                    UDim2.fromOffset(
                        25,
                        2
                    ),

                Size =
                    UDim2.fromOffset(
                        6,
                        6
                    ),

                Visible = false,
                ZIndex = 21,
                Parent = miniButton,
            }
        )

    HolyAuctionHudCorner(
        miniDot,
        UDim.new(
            1,
            0
        )
    )

    HOLY_AUCTION_HUD.MiniDot =
        miniDot

        local dragController =
        nil


    local function applyMinimizedState(isMinimized)

        HOLY_SHOP_STATE.AuctionHudMinimized =
            isMinimized == true

        local currentMinimized =
            HOLY_SHOP_STATE.AuctionHudMinimized == true

        top.Visible =
            not currentMinimized

        body.Visible =
            not currentMinimized

        miniButton.Visible =
            currentMinimized

        holder.BackgroundTransparency =
            currentMinimized
            and 1
            or 0.12

        holderStroke.Enabled =
            not currentMinimized

        holder.Size =
            currentMinimized
            and UDim2.fromOffset(
                34,
                34
            )
            or UDim2.fromOffset(
                480,
                tonumber(
                    HOLY_AUCTION_HUD.ExpandedHeight
                )
                or expandedHeight
            )

        HolySaveShopSettings()

        HolyAuctionHudRefresh()
    end

    HolyAuctionHudAddConnection(
        minimizeButton.MouseButton1Click:Connect(function()

            applyMinimizedState(
                true
            )
        end)
    )

    HolyAuctionHudAddConnection(
        miniButton.MouseButton1Click:Connect(function()

            if dragController
            and dragController:ConsumeClick(
                miniButton
            ) == true then

                return
            end

            applyMinimizedState(
                false
            )
        end)
    )

    HolyAuctionHudAddConnection(
        closeButton.MouseButton1Click:Connect(function()

            HolyAuctionSetHudVisible(
                false,
                "closed"
            )
        end)
    )

    dragController =
        HolyAuctionHudMakeDraggable(
            holder,
            {
                top,
                miniButton,
            }
        )

    HolyAuctionHudApplyScale()

    return true
end

function HolyAuctionHudRefresh(rows)

    HolyAuctionEnsureState()

    if HOLY_SHOP_STATE.AuctionHudEnabled ~= true then
        return false
    end

    HolyAuctionHudStart()

    local hud =
        HOLY_AUCTION_HUD

    if type(hud) ~= "table"
    or typeof(hud.Holder) ~= "Instance" then

        return false
    end

    rows =
        type(rows) == "table"
        and rows
        or HOLY_SHOP_STATE.AuctionLastLots
        or {}

    local networkHealthy =
        HOLY_SHOP_STATE.AuctionNetworkReady == true

    local selected =
        HolyAuctionGetWatchNames()

    local function readDecision(row)

        local selectedRow =
            HolyAuctionSelectionAllows(
                row.Name
            )

        local maxPrice =
            HolyAuctionGetWatchMax(
                row.Name
            )

        if row.Expired == true then

            return {
                Text = "ENDED",
                TextColor = Color3.fromRGB(126, 133, 148),
                PillColor = Color3.fromRGB(28, 31, 39),
                PillTransparency = 0.52,
                Selected = selectedRow,
                Inactive = true,
            }
        end

        if row.StockKnown == true
        and (
            tonumber(row.Stock)
            or 0
        ) <= 0 then

            return {
                Text = "SOLD",
                TextColor = Color3.fromRGB(126, 133, 148),
                PillColor = Color3.fromRGB(28, 31, 39),
                PillTransparency = 0.52,
                Selected = selectedRow,
                Inactive = true,
            }
        end

        if selectedRow == true
        and maxPrice <= 0 then

            return {
                Text = "NO LIMIT",
                TextColor = Color3.fromRGB(245, 199, 100),
                PillColor = Color3.fromRGB(55, 40, 15),
                PillTransparency = 0.28,
                Selected = true,
                Inactive = false,
            }
        end

        if selectedRow == true
        and (
            tonumber(row.Price)
            or math.huge
        ) > maxPrice then

            return {
                Text = "OVER CAP",
                TextColor = Color3.fromRGB(245, 199, 100),
                PillColor = Color3.fromRGB(55, 40, 15),
                PillTransparency = 0.28,
                Selected = true,
                Inactive = false,
            }
        end

        if selectedRow == true
        and networkHealthy == true
        and row.NetworkReady == true then

            return {
                Text = "READY",
                TextColor = Color3.fromRGB(105, 229, 160),
                PillColor = Color3.fromRGB(22, 69, 44),
                PillTransparency = 0.20,
                Selected = true,
                Inactive = false,
            }
        end

        if selectedRow == true then

            return {
                Text = "WAIT",
                TextColor = Color3.fromRGB(245, 199, 100),
                PillColor = Color3.fromRGB(55, 40, 15),
                PillTransparency = 0.34,
                Selected = true,
                Inactive = false,
            }
        end

        return {
            Text = "LIVE",
            TextColor = Color3.fromRGB(155, 162, 175),
            PillColor = Color3.fromRGB(25, 29, 38),
            PillTransparency = 0.52,
            Selected = false,
            Inactive = false,
        }
    end

    local readyCount =
        0

    for _, row in ipairs(rows) do

        if type(row) == "table" then

            local decision =
                readDecision(
                    row
                )

            if decision.Text == "READY" then

                readyCount =
                    readyCount + 1
            end
        end
    end

    local visibleRows =
        math.min(
            6,
            #rows
        )

    local layoutRows =
        math.max(
            1,
            visibleRows
        )

    local listHeight =
        31
        + (layoutRows * 31)

    local bodyHeight =
        52
        + listHeight

    local expandedHeight =
        46
        + bodyHeight

    hud.ExpandedHeight =
        expandedHeight

    if HOLY_SHOP_STATE.AuctionHudMinimized ~= true then

        hud.Holder.Size =
            UDim2.fromOffset(
                480,
                expandedHeight
            )

        if typeof(hud.Body) == "Instance" then

            hud.Body.Size =
                UDim2.fromOffset(
                    480,
                    bodyHeight
                )
        end

        if typeof(hud.ListSurface) == "Instance" then

            hud.ListSurface.Size =
                UDim2.fromOffset(
                    480,
                    listHeight
                )
        end
    end

    if typeof(hud.HealthDot) == "Instance" then

        hud.HealthDot.BackgroundColor3 =
            networkHealthy == true
            and Color3.fromRGB(
                105,
                229,
                160
            )
            or Color3.fromRGB(
                245,
                199,
                100
            )
    end

    if typeof(hud.AutoBadge) == "Instance"
    and typeof(hud.AutoPill) == "Instance" then

        if HOLY_SHOP_STATE.AutoBuyAuctions == true then

            if HOLY_SHOP_STATE.AuctionDryRun == true then

                hud.AutoBadge.Text =
                    "AUTO TEST"

                hud.AutoBadge.TextColor3 =
                    Color3.fromRGB(
                        245,
                        199,
                        100
                    )

                hud.AutoPill.BackgroundColor3 =
                    Color3.fromRGB(
                        157,
                        103,
                        255
                    )

                hud.AutoPill.BackgroundTransparency =
                    0.76

            else

                hud.AutoBadge.Text =
                    "AUTO ON"

                hud.AutoBadge.TextColor3 =
                    Color3.fromRGB(
                        255,
                        111,
                        176
                    )

                hud.AutoPill.BackgroundColor3 =
                    Color3.fromRGB(
                        255,
                        61,
                        145
                    )

                hud.AutoPill.BackgroundTransparency =
                    0.78
            end

        else

            hud.AutoBadge.Text =
                "AUTO OFF"

            hud.AutoBadge.TextColor3 =
                Color3.fromRGB(
                    155,
                    162,
                    175
                )

            hud.AutoPill.BackgroundColor3 =
                Color3.fromRGB(
                    55,
                    61,
                    74
                )

            hud.AutoPill.BackgroundTransparency =
                0.65
        end
    end

    if typeof(hud.TargetsValue) == "Instance" then

        hud.TargetsValue.Text =
            tostring(#selected)
            .. (
                #selected == 1
                and " watched"
                or " watched"
            )
    end

    if typeof(hud.LimitValue) == "Instance" then

        hud.LimitValue.Text =
            #selected > 0
            and "Per item"
            or "Not set"
    end

    if typeof(hud.ReadyValue) == "Instance" then

        hud.ReadyValue.Text =
            tostring(readyCount)
            .. (
                readyCount == 1
                and " auction"
                or " auctions"
            )

        hud.ReadyValue.TextColor3 =
            readyCount > 0
            and Color3.fromRGB(
                105,
                229,
                160
            )
            or Color3.fromRGB(
                145,
                151,
                164
            )
    end

    if typeof(hud.EmptyLabel) == "Instance" then

        hud.EmptyLabel.Visible =
            #rows <= 0

        hud.EmptyLabel.Text =
            networkHealthy == true
            and "No active auction lots"
            or "Waiting for auction data"
    end

    for index = 1, 6 do

        local rowUi =
            hud.RowFrames
            and hud.RowFrames[index]
            or nil

        local row =
            rows[index]

        if type(rowUi) == "table" then

            if type(row) ~= "table" then

                rowUi.Holder.Visible =
                    false

            else

                rowUi.Holder.Visible =
                    true

                local decision =
                    readDecision(
                        row
                    )

                local displayName =
                    tostring(
                        row.Name
                        or "--"
                    )

                if HolyCleanText(
                    row.AmountText
                ) ~= "" then

                    displayName =
                        displayName
                        .. " "
                        .. tostring(
                            row.AmountText
                        )
                end

                rowUi.Name.Text =
                    displayName

                rowUi.Price.Text =
                    tostring(
                        row.PriceText
                        or HolyAuctionFormatMoney(
                            row.Price
                        )
                        or "--"
                    )

                rowUi.Stock.Text =
                    row.StockKnown == true
                    and (
                        tostring(
                            math.max(
                                0,
                                math.floor(
                                    tonumber(row.Stock)
                                    or 0
                                )
                            )
                        )
                    )
                    or "--"

                rowUi.Decision.Text =
                    decision.Text

                rowUi.Decision.TextColor3 =
                    decision.TextColor

                rowUi.DecisionPill.BackgroundColor3 =
                    decision.PillColor

                rowUi.DecisionPill.BackgroundTransparency =
                    decision.PillTransparency

                if decision.Selected == true then

                    rowUi.Holder.BackgroundColor3 =
                        Color3.fromRGB(
                            50,
                            21,
                            39
                        )

                    rowUi.Holder.BackgroundTransparency =
                        0.18

                    rowUi.Accent.Visible =
                        true

                    if typeof(rowUi.Stroke) == "Instance" then

                        rowUi.Stroke.Color =
                            Color3.fromRGB(
                                255,
                                79,
                                157
                            )

                        rowUi.Stroke.Transparency =
                            0.05

                        rowUi.Stroke.Thickness =
                            1.25
                    end

                    rowUi.Name.TextColor3 =
                        Color3.fromRGB(
                            255,
                            229,
                            242
                        )

                else

                    rowUi.Holder.BackgroundColor3 =
                        Color3.fromRGB(
                            15,
                            18,
                            24
                        )

                    rowUi.Holder.BackgroundTransparency =
                        decision.Inactive == true
                        and 0.48
                        or 0.32

                    rowUi.Accent.Visible =
                        false

                    if typeof(rowUi.Stroke) == "Instance" then

                        rowUi.Stroke.Color =
                            Color3.fromRGB(
                                54,
                                59,
                                72
                            )

                        rowUi.Stroke.Transparency =
                            decision.Inactive == true
                            and 0.55
                            or 0.32

                        rowUi.Stroke.Thickness =
                            1
                    end

                    rowUi.Name.TextColor3 =
                        decision.Inactive == true
                        and Color3.fromRGB(
                            143,
                            150,
                            163
                        )
                        or Color3.fromRGB(
                            236,
                            239,
                            245
                        )
                end

                rowUi.Price.TextColor3 =
                    decision.Inactive == true
                    and Color3.fromRGB(
                        143,
                        150,
                        163
                    )
                    or Color3.fromRGB(
                        225,
                        228,
                        235
                    )

                rowUi.Stock.TextColor3 =
                    decision.Inactive == true
                    and Color3.fromRGB(
                        118,
                        125,
                        139
                    )
                    or Color3.fromRGB(
                        155,
                        162,
                        175
                    )
            end
        end
    end

    if typeof(hud.MiniDot) == "Instance" then

        if readyCount > 0 then

            hud.MiniDot.Visible =
                true

            hud.MiniDot.BackgroundColor3 =
                Color3.fromRGB(
                    105,
                    229,
                    160
                )

        elseif networkHealthy ~= true then

            hud.MiniDot.Visible =
                true

            hud.MiniDot.BackgroundColor3 =
                Color3.fromRGB(
                    245,
                    199,
                    100
                )

        else

            hud.MiniDot.Visible =
                false
        end
    end

    return true
end

