    pcall(function()

        local hud =
            playerGui
            and playerGui:FindFirstChild(
                "HUD"
            )

        local currencies =
            hud
            and hud:FindFirstChild(
                "Currencies"
            )

        local friendBoost =
            currencies
            and currencies:FindFirstChild(
                "FriendBoost"
            )

        local label =
            friendBoost
            and friendBoost:FindFirstChild(
                "TextLabel",
                true
            )

        if label
        and label:IsA("TextLabel") then

            text =
                label.Text
        end
    end)

    local percent =
        tonumber(
            tostring(text):match("(%d+%.?%d*)%s*%%")
