    if type(flag) == "table" then

        if type(flag.Get) == "function" then

            local ok,
                result =
                pcall(function()

                    return flag:Get()
                end)

            if ok == true
            and tonumber(result) then

                return tonumber(result)
            end
        end

        if tonumber(flag.Value) then

            return tonumber(flag.Value)
        end
    end

    return 1
