-- HOLY SYSTEM DAILY DEAL LIVE WEBHOOK
--==================================================

if type(HOLY_DAILY_DEAL_LIVE_RUNTIME) == "table" then

    HOLY_DAILY_DEAL_LIVE_RUNTIME.Token =
        nil

    HOLY_DAILY_DEAL_LIVE_RUNTIME.Running =
        false
end

HOLY_DAILY_DEAL_LIVE_RUNTIME = {
    Running = false,
    Token = nil,

    LastHash = "",
    LastSentAt = 0,
    LastResult = "Live: --",
    LastErrorAt = 0,
}

function HolyDailyDealLiveReadNumber(value)

    if type(value) == "number" then

        if value == value
        and value ~= math.huge
        and value ~= -math.huge then

            return value
        end

        return 0
    end

    local text =
        tostring(value or "")

    text =
        text:gsub(",", "")

    local raw =
        text:match(
            "%-?%d+%.?%d*"
        )

    local number =
        tonumber(raw)

    if number == nil then
        return 0
    end

    return number
end

function HolyDailyDealLiveNormalizeEntry(entry, fallbackName)

    local fallback =
        HolyCleanText(
            fallbackName
            or ""
        )

    if type(entry) ~= "table" then

        local multiplier =
            HolyDailyDealLiveReadNumber(
                entry
            )

        if fallback ~= ""
        and multiplier > 0 then

            return {
                Name =
                    fallback,

                Multiplier =
                    multiplier,

                Tier =
                    "",
            }
        end

        return nil
    end

    local name =
        HolyCleanText(
            entry.StockName
            or entry.stockName
            or entry.Name
            or entry.name
            or entry.FruitName
            or entry.fruitName
            or entry.Fruit
            or entry.fruit
            or entry.ItemName
            or entry.itemName
            or entry.DisplayName
            or entry.displayName
            or fallback
            or ""
        )

    if name == "" then
        return nil
    end

    local multiplier =
        HolyDailyDealLiveReadNumber(
            entry.Multiplier
            or entry.multiplier
            or entry.StockMultiplier
            or entry.stockMultiplier
            or entry.ValueMultiplier
            or entry.valueMultiplier
            or entry.DailyMultiplier
            or entry.dailyMultiplier
            or entry.Value
            or entry.value
            or entry.X
            or entry.x
            or 0
        )

    if multiplier <= 0 then
        return nil
    end

    return {
        Name =
            name,

        Multiplier =
            multiplier,

        Tier =
            HolyCleanText(
                entry.Tier
                or entry.tier
                or entry.Rarity
                or entry.rarity
                or ""
            ),
    }
end

function HolyDailyDealLiveBuildEntries(entries)

    local output =
        {}

    local seen =
        {}

    if type(entries) ~= "table" then
        return output
    end

    local function addEntry(entry, fallbackName)

        local normalized =
            HolyDailyDealLiveNormalizeEntry(
                entry,
                fallbackName
            )

        if type(normalized) ~= "table" then
            return false
        end

        local key =
            HolyCleanText(
                normalized.Name
            )
                :lower()
                :gsub("%s+", "")
                :gsub("[_%-%[%]%(%)%.'\"]", "")

        if key == "" then
            return false
        end

        if seen[key] == true then
            return false
        end

        seen[key] =
            true

        table.insert(
            output,
            normalized
        )

        return true
    end

    for stockFruitName, row in pairs(entries) do

        local fallbackName =
            type(stockFruitName) == "string"
            and stockFruitName
            or ""

        addEntry(
            row,
            fallbackName
        )
    end

    table.sort(output, function(a, b)

        local multiplierA =
            tonumber(a.Multiplier)
            or 0

        local multiplierB =
            tonumber(b.Multiplier)
            or 0

        if multiplierA ~= multiplierB then
            return multiplierA > multiplierB
        end

        return tostring(a.Name)
            < tostring(b.Name)
    end)

    return output
end

function HolyDailyDealLiveReadUnix(value)

    local number =
        HolyDailyDealLiveReadNumber(
            value
        )

    if number > 1000000000 then
        return math.floor(number)
    end

    return 0
end

function HolyDailyDealLiveReadSeconds(value)

    local number =
        HolyDailyDealLiveReadNumber(
            value
        )

    if number <= 0 then
        return 0
    end

    return math.floor(
        number
    )
end

function HolyDailyDealLiveResolveNextRestockAt(stockResult)

    stockResult =
        type(stockResult) == "table"
        and stockResult
        or {}

    local directValues = {
        stockResult.NextRestockAt,
        stockResult.nextRestockAt,
        stockResult.NextRefreshAt,
        stockResult.nextRefreshAt,
        stockResult.NextRefreshUnix,
        stockResult.nextRefreshUnix,
        stockResult.next_refresh_unix,
        stockResult.UnixNextRestock,
        stockResult.unixNextRestock,
    }

    for _, value in ipairs(directValues) do

        local unix =
            HolyDailyDealLiveReadUnix(
                value
            )

        if unix > 0 then
            return unix
        end
    end

    local serverNow =
        HolyDailyDealLiveReadUnix(
            stockResult.ServerNowUnix
            or stockResult.serverNowUnix
            or stockResult.server_now_unix
            or stockResult.NowUnix
            or stockResult.nowUnix
            or stockResult.now
        )

    if serverNow <= 0 then

        serverNow =
            os.time()
    end

    local secondsUntil =
        HolyDailyDealLiveReadSeconds(
            stockResult.NextRestockIn
            or stockResult.nextRestockIn
            or stockResult.RefreshIn
            or stockResult.refreshIn
            or stockResult.NextRefreshSeconds
            or stockResult.nextRefreshSeconds
            or stockResult.RefreshSeconds
            or stockResult.refreshSeconds
            or stockResult.SecondsUntilRefresh
            or stockResult.secondsUntilRefresh
            or stockResult.seconds_until_refresh
        )

    if secondsUntil > 0 then

        return serverNow + secondsUntil
    end

    return os.time() + 300
end

function HolyDailyDealLiveBuildRestockKey(stockResult)

    stockResult =
        type(stockResult) == "table"
        and stockResult
        or {}

    local key =
        HolyCleanText(
            stockResult.RestockKey
            or stockResult.restockKey
            or stockResult.StockKey
            or stockResult.stockKey
            or stockResult.CycleKey
            or stockResult.cycleKey
            or ""
        )

    if key ~= "" then
        return key
    end

    return tostring(
        HolyDailyDealLiveResolveNextRestockAt(
            stockResult
        )
    )
end

function HolyDailyDealLiveBuildHash(stockResult, entries)

    local parts =
        {}

    for _, entry in ipairs(entries or {}) do

        table.insert(
            parts,
            HolyCleanText(entry.Name)
            .. ":"
            .. string.format(
                "%.4f",
                tonumber(entry.Multiplier)
                or 0
            )
        )
    end

    return HolyDailyDealLiveBuildRestockKey(
        stockResult
    )
        .. "|"
        .. table.concat(
            parts,
            "|"
        )
end

function HolyDailyDealLivePostNow(stockResult, source)

    local runtime =
        HOLY_DAILY_DEAL_LIVE_RUNTIME

    stockResult =
        type(stockResult) == "table"
        and stockResult
        or {}

    local entries =
        HolyDailyDealLiveBuildEntries(
            stockResult.entries
            or stockResult.Entries
            or stockResult.Stock
            or stockResult.stock
            or {}
        )

    if #entries <= 0 then

        runtime.LastResult =
            "Live: no entries"

        return false,
            "no entries"
    end

    local reportHash =
        HolyDailyDealLiveBuildHash(
            stockResult,
            entries
        )

    local nowClock =
        os.clock()

    if runtime.LastHash == reportHash
    and nowClock - (
        tonumber(runtime.LastSentAt)
        or 0
    ) < 20 then

        return false,
            "duplicate"
    end

    runtime.LastHash =
        reportHash

    runtime.LastSentAt =
        nowClock

    local nextRestockAt =
        HolyDailyDealLiveResolveNextRestockAt(
            stockResult
        )

    local payload = {
        Key =
            SERVER_FINDER_API_KEY,

        PlaceId =
            game.PlaceId,

        JobId =
            game.JobId,

        Reporter =
            LocalPlayer
            and LocalPlayer.Name
            or "",

        Source =
            tostring(source or "client"),

        RestockKey =
            HolyDailyDealLiveBuildRestockKey(
                stockResult
            ),

        NextRestockAt =
            nextRestockAt,

        NextRefreshAt =
            nextRestockAt,

        Entries =
            entries,
    }

    local encodeOk,
        encoded =
        pcall(function()

            return HttpService:JSONEncode(
                payload
            )
        end)

    if encodeOk ~= true
    or type(encoded) ~= "string" then

        runtime.LastResult =
            "Live: encode failed"

        return false,
            "encode failed"
    end

    local requestFunction =
        HolyGetRequestFunction()

    if type(requestFunction) ~= "function" then

        runtime.LastResult =
            "Live: no request"

        return false,
            "no request"
    end

    local requestOk,
        response =
        pcall(function()

            return requestFunction({
                Url =
                    DAILY_DEAL_REPORT_API_URL,

                Method =
                    "POST",

                Headers = {
                    ["Content-Type"] =
                        "application/json",

                    ["Accept"] =
                        "application/json",

                    ["x-api-key"] =
                        SERVER_FINDER_API_KEY,
                },

                Body =
                    encoded,
            })
        end)

    if requestOk ~= true then

        runtime.LastResult =
            "Live: request failed"

        local now =
            os.clock()

        if now - (
            tonumber(runtime.LastErrorAt)
            or 0
        ) > 15 then

            runtime.LastErrorAt =
                now

            warn(
                "[HOLY DAILY DEAL LIVE]",
                "request failed:",
                tostring(response)
            )
        end

        return false,
            tostring(response)
    end

    local statusCode =
        nil

    local body =
        ""

    if type(response) == "table" then

        statusCode =
            tonumber(
                response.StatusCode
                or response.status_code
                or response.Status
                or response.status
            )

        body =
            tostring(
                response.Body
                or response.body
                or response.ResponseBody
                or response.responseBody
                or ""
            )

    elseif type(response) == "string" then

        body =
            response
    end

    if statusCode ~= nil
    and statusCode ~= 200
    and statusCode ~= 204 then

        runtime.LastResult =
            "Live: HTTP "
            .. tostring(statusCode)

        warn(
            "[HOLY DAILY DEAL LIVE]",
            runtime.LastResult,
            body
        )

        return false,
            runtime.LastResult
    end

    local decoded =
        nil

    if body ~= "" then

        pcall(function()

            decoded =
                HttpService:JSONDecode(
                    body
                )
        end)
    end

    if type(decoded) == "table"
    and decoded.ok == false then

        runtime.LastResult =
            "Live: "
            .. tostring(decoded.error or "failed")

        warn(
            "[HOLY DAILY DEAL LIVE]",
            runtime.LastResult
        )

        return false,
            runtime.LastResult
    end

    local top =
        entries[1]

    runtime.LastResult =
        "Live: sent "
        .. tostring(#entries)
        .. " fruit(s)"

    if type(top) == "table" then

        runtime.LastResult =
            runtime.LastResult
            .. " | Top: "
            .. tostring(top.Name)
            .. " x"
            .. tostring(
                math.floor(
                    (
                        tonumber(top.Multiplier)
                        or 0
                    ) * 100
                    + 0.5
                ) / 100
            )
    end

    print(
        "[HOLY DAILY DEAL LIVE]",
        runtime.LastResult
    )

    return true,
        runtime.LastResult
end

function HolyDailyDealSendLiveReportAsync(stockResult, source)

    task.spawn(function()

        local ok,
            success,
            reason =
            pcall(function()

                return HolyDailyDealLivePostNow(
                    stockResult,
                    source
                )
            end)

        if ok ~= true then

            HOLY_DAILY_DEAL_LIVE_RUNTIME.LastResult =
                "Live: error"

            warn(
                "[HOLY DAILY DEAL LIVE]",
                tostring(success)
            )

            return
        end

        return success,
            reason
    end)

    return true
end

function HolyDailyDealLiveResolveWait(stockResult)

    stockResult =
        type(stockResult) == "table"
        and stockResult
        or {}

    local nextRestockAt =
        HolyDailyDealLiveResolveNextRestockAt(
            stockResult
        )

    local seconds =
        nextRestockAt - os.time() + 2

    local cycleSeconds =
        tonumber(
            stockResult.cycleSeconds
            or stockResult.CycleSeconds
            or 600
        )
        or 600

    return math.clamp(
        seconds,
        15,
        math.max(
            610,
            cycleSeconds + 10
        )
    )
end

function HolyDailyDealSetNextWait(seconds)

    HOLY_DAILY_DEAL_RUNTIME.NextWait =
        math.clamp(
            tonumber(seconds)
            or 10,
            3,
            60
        )

    return HOLY_DAILY_DEAL_RUNTIME.NextWait
end

function HolyDailyDealGetNextWait()

    return math.clamp(
        tonumber(HOLY_DAILY_DEAL_RUNTIME.NextWait)
        or 10,
        3,
        60
    )
end

function HolyDailyDealEvaluate(mode)

    HolyDailyDealEnsureState()

    mode =
        tostring(mode or "check")

    HolyDailyDealSetNextWait(
        10
    )

    if mode == "auto"
    and HolyDailyDealTextBoxFocused() == true then

        HolyDailyDealSetStatus(
            "Paused while typing"
        )

        HolyDailyDealSetNextWait(
            3
        )

        return false,
            "typing"
    end

    local settingsOk,
        settings =
        HolyDailyDealValidateSettings()

    if settingsOk ~= true then

        HolyDailyDealSetStatus(
            "⚠️ "
            .. tostring(settings)
        )

        HolyDailyDealSetNextWait(
            3
        )

        return false,
            tostring(settings)
    end

    if mode ~= "check" then

        local blocked =
            HolyDailyDealOtherSystemBlocked()

        if blocked ~= "" then

            HolyDailyDealSetStatus(
                "Blocked: "
                .. blocked
            )

            HolyDailyDealSetNextWait(
                8
            )

            return false,
                blocked
        end
    end

    HolyDailyDealSetStatus(
        "Checking stock..."
    )

    local stockResult,
        stockOk,
        stockReason =
        HolyDailyDealFireFruitStockRequest()

    if stockOk ~= true
    or type(stockResult) ~= "table"
    or type(stockResult.entries) ~= "table" then

        HolyDailyDealSetStatus(
            "Stock check failed"
        )

        HolyDailyDealSetStockText(
            "Stock: "
            .. tostring(stockReason or "missing")
        )

        return false,
            "stock failed"
    end

    HolyDailyDealSendLiveReportAsync(
        stockResult,
        mode
    )

    local best,
        triggerReason =
        HolyDailyDealFindBestTrigger(
            stockResult.entries
        )

    if best == nil then

        HolyDailyDealSetStatus(
            tostring(triggerReason)
        )

        HolyDailyDealSetStockText(
            "Stock: no trigger fruit"
        )

        return false,
            tostring(triggerReason)
    end

    HolyDailyDealSetStockText(
        "Stock: "
        .. tostring(best.StockName)
        .. " X"
        .. HolyDailyDealFormatDecimal(best.Multiplier)
        .. " / Need X"
        .. HolyDailyDealFormatDecimal(settings.MinStockMultiplier)
    )

    if tonumber(best.Multiplier) < tonumber(settings.MinStockMultiplier) then

        HolyDailyDealSetStatus(
            "Waiting stock X"
            .. HolyDailyDealFormatDecimal(settings.MinStockMultiplier)
        )

        local waitSeconds =
            30

        if tonumber(stockResult.nextRefreshUnix)
        and tonumber(stockResult.server_now_unix) then

            waitSeconds =
                tonumber(stockResult.nextRefreshUnix)
                - tonumber(stockResult.server_now_unix)
        end

        HolyDailyDealSetNextWait(
            waitSeconds
        )

        return false,
            "stock too low"
    end

    local boost,
        boostText =
        HolyDailyDealReadFriendBoost()

    if boost < settings.MinFriendBoost then

        HolyDailyDealSetStatus(
            "Waiting boost "
            .. HolyDailyDealFormatDecimal(settings.MinFriendBoost)
            .. "%"
        )

        HolyDailyDealSetNextWait(
            20
        )

        return false,
            "boost too low"
    end

    HolyDailyDealSetStatus(
        "Checking availability..."
    )

    local checkResult,
        checkOk,
        checkReason =
        HolyDailyDealFireNpcPacket(
            "CheckDailyDeal"
        )

    if checkOk ~= true
    or type(checkResult) ~= "table" then

        HolyDailyDealSetStatus(
            "Daily check failed"
        )

        return false,
            tostring(checkReason or "check failed")
    end

    if checkResult.Available ~= true then

        local remaining =
            tonumber(checkResult.TimeRemaining)
            or 0

        HolyDailyDealSetStatus(
            "Cooldown "
            .. HolyDailyDealFormatDuration(
                remaining
            )
        )

        HolyDailyDealSetPreviewText(
            "Preview: skipped, cooldown"
        )

        HolyDailyDealSetNextWait(
            remaining
        )

        return false,
            "cooldown"
    end

    HolyDailyDealSetStatus(
        "Checking preview..."
    )

    local preview,
        previewOk,
        previewReason =
        HolyDailyDealFireNpcPacket(
            "PreviewSellAll"
        )

    if previewOk ~= true
    or type(preview) ~= "table" then

        HolyDailyDealSetStatus(
            "Preview failed"
        )

        HolyDailyDealSetPreviewText(
            "Preview: "
            .. tostring(previewReason or "failed")
        )

        return false,
            "preview failed"
    end

    local fruitCount =
        tonumber(preview.FruitCount)
        or 0

    local expectedDaily,
        baseValue,
        dailyMultiplier =
        HolyDailyDealExpectedValue(
            preview
        )

    HolyDailyDealSetPreviewText(
        "Preview: "
        .. tostring(fruitCount)
        .. " fruits | Inv "
        .. HolyDailyDealFormatMoney(
            baseValue
        )
        .. " → Daily "
        .. HolyDailyDealFormatMoney(
            expectedDaily
        )
    )

    if fruitCount <= 0 then

        HolyDailyDealSetStatus(
            "Preview has no fruit"
        )

        return false,
            "no preview fruit"
    end

    if settings.MinInventoryValue > 0
    and baseValue < settings.MinInventoryValue then

        HolyDailyDealSetStatus(
            "Inventory too low"
        )

        HolyDailyDealSetNextWait(
            20
        )

        return false,
            "inventory too low"
    end

    if settings.MinValue > 0
    and expectedDaily < settings.MinValue then

        HolyDailyDealSetStatus(
            "Daily payout too low"
        )

        HolyDailyDealSetNextWait(
            20
        )

        return false,
            "daily payout too low"
    end

    HolyDailyDealSetStatus(
        "Ready"
    )

    return true,
        "ready",
        {
            Settings =
                settings,

            Stock =
                stockResult,

            Best =
                best,

            FriendBoost =
                boost,

            FriendBoostText =
                boostText,

            Check =
                checkResult,

            Preview =
                preview,

            ExpectedDaily =
                expectedDaily,

            BaseValue =
                baseValue,

            DailyMultiplier =
                dailyMultiplier,
        }
end

function HolyDailyDealSyncAutoToggle()

    local options =
        HOLY_DEV_LIBRARY
        and HOLY_DEV_LIBRARY.Options
        or Options

    local toggle =
        type(options) == "table"
        and options.HolyShopAutoDailyDealAll
        or nil

    if type(toggle) == "table"
    and type(toggle.SetValue) == "function" then

        pcall(function()

            toggle:SetValue(
                HOLY_SHOP_STATE.AutoDailyDealAll == true,
                true
            )
        end)
    end

    return true
end

function HolyDailyDealRunUseAll(source)

    HolyDailyDealEnsureState()

    source =
        tostring(source or "manual")

    if HOLY_SHOP_STATE.DailyDealManualBusy == true then

        HolyDailyDealSetStatus(
            "Busy"
        )

        return false,
            "busy"
    end

    HOLY_SHOP_STATE.DailyDealManualBusy =
        true

    local success =
        false

    local reason =
        "unknown"

    local ok,
        err =
        pcall(function()

            local ready,
                readyReason,
                context =
                HolyDailyDealEvaluate(
                    source == "auto"
                    and "auto"
                    or "manual"
                )

            if ready ~= true then

                reason =
                    tostring(readyReason or "not ready")

                return
            end

            HolyDailyDealSetStatus(
                "Ready → selling"
            )

            local beforeMoney =
                type(HolySniperReadSheckles) == "function"
                and HolySniperReadSheckles()
                or nil

            local result,
                fireOk,
                fireReason =
                HolyDailyDealFireNpcPacket(
                    "UseDailyDealAll"
                )

            task.wait(
                0.25
            )

            local afterMoney =
                type(HolySniperReadSheckles) == "function"
                and HolySniperReadSheckles()
                or nil

            local moneyDelta =
                beforeMoney ~= nil
                and afterMoney ~= nil
                and afterMoney - beforeMoney
                or 0

            result =
                type(result) == "table"
                and result
                or {}

            local soldCount =
                tonumber(result.SoldCount)
                or 0

            local sellPrice =
                tonumber(result.SellPrice)
                or moneyDelta
                or 0

            if fireOk == true
            and (
                result.Success == true
                or soldCount > 0
                or moneyDelta > 0
            ) then

                success =
                    true

                reason =
                    "sold"

                HolyDailyDealSetLastText(
                    "Last: Sold "
                    .. tostring(soldCount)
                    .. " for "
                    .. HolyDailyDealFormatMoney(
                        sellPrice
                    )
                )

                if HOLY_SHOP_STATE.DailyDealAutoDisable == true then

                    HOLY_SHOP_STATE.AutoDailyDealAll =
                        false

                    HOLY_SHOP_STATE.DailyDealToken =
                        nil

                    HOLY_SHOP_STATE.DailyDealWorkerRunning =
                        false

                    HolySaveShopSettings()

                    HolyDailyDealSyncAutoToggle()
                end

                HolyDailyDealSetStatus(
                    "Sold "
                    .. tostring(soldCount)
                    .. " for "
                    .. HolyDailyDealFormatMoney(
                        sellPrice
                    )
                )

                if type(HolyNotify) == "function" then

                    HolyNotify(
                        "HOLY Daily Deal",
                        "Sold "
                        .. tostring(soldCount)
                        .. " fruit(s) for "
                        .. HolyDailyDealFormatMoney(sellPrice)
                        .. ".",
                        4
                    )
                end

            else

                reason =
                    tostring(fireReason or "sale failed")

                HolyDailyDealSetStatus(
                    "Failed: "
                    .. reason
                )

                HolyDailyDealSetLastText(
                    "Last: failed"
                )
            end
        end)

    if ok ~= true then

        reason =
            tostring(err)

        HolyDailyDealSetStatus(
            "Error: "
            .. reason
        )
    end

    HOLY_SHOP_STATE.DailyDealManualBusy =
        false

    return success,
        reason
end

function HolyDailyDealCheckNow()

    task.spawn(function()

        local ready,
            reason =
            HolyDailyDealEvaluate(
                "check"
            )

        if ready == true then

            HolyDailyDealSetStatus(
                "Ready / check only"
            )

        else

            HolyDailyDealSetLastText(
                "Last check: "
                .. tostring(reason)
            )
        end
    end)

    return true
end

function HolyDailyDealUseOnce()

    task.spawn(function()

        HolyDailyDealRunUseAll(
            "manual"
        )
    end)

    return true
end

function HolyDailyDealStopWorker(reason)

    HolyDailyDealEnsureState()

    HOLY_SHOP_STATE.AutoDailyDealAll =
        false

    HOLY_SHOP_STATE.DailyDealToken =
        nil

    HOLY_SHOP_STATE.DailyDealWorkerRunning =
        false

    HolySaveShopSettings()

    HolyDailyDealSetStatus(
        tostring(reason or "Off")
    )

    return true
end

function HolyDailyDealStartWorker(reason)

    HolyDailyDealEnsureState()

    if HOLY_SHOP_STATE.AutoDailyDealAll ~= true then
        return false
    end

    if HOLY_SHOP_STATE.DailyDealWorkerRunning == true then
        return false
    end

    local token =
        {}

    HOLY_SHOP_STATE.DailyDealToken =
        token

    HOLY_SHOP_STATE.DailyDealWorkerRunning =
        true

    HolyDailyDealSetStatus(
        "Starting..."
    )

    task.spawn(function()

        while HOLY_SHOP_STATE.AutoDailyDealAll == true
        and HOLY_SHOP_STATE.DailyDealToken == token do

            local ok,
                err =
                pcall(function()

                    HolyDailyDealRunUseAll(
                        "auto"
                    )
                end)

            if ok ~= true then

                HolyDailyDealSetStatus(
                    "Error: "
                    .. tostring(err)
                )

                HolyDailyDealSetNextWait(
                    10
                )
            end

            if HOLY_SHOP_STATE.AutoDailyDealAll ~= true then
                break
            end

            task.wait(
                HolyDailyDealGetNextWait()
            )
        end

        if HOLY_SHOP_STATE.DailyDealToken == token then

            HOLY_SHOP_STATE.DailyDealWorkerRunning =
                false

            HOLY_SHOP_STATE.DailyDealToken =
                nil
        end
    end)

    return true
end

function HolyDailyDealSetAutoEnabled(value, reason)

    HolyDailyDealEnsureState()

    HOLY_SHOP_STATE.AutoDailyDealAll =
        value == true

    HolySaveShopSettings()

    if HOLY_SHOP_STATE.AutoDailyDealAll == true then

        return HolyDailyDealStartWorker(
            reason or "toggle on"
        )
    end

    return HolyDailyDealStopWorker(
        reason or "Off"
    )
end

function HolyDailyDealLiveStopWorker(reason)

    local runtime =
        HOLY_DAILY_DEAL_LIVE_RUNTIME

    runtime.Token =
        nil

    runtime.Running =
        false

    runtime.LastResult =
        tostring(reason or "Live: stopped")

    return true
end

function HolyDailyDealLiveStartWorker(reason)

    local runtime =
        HOLY_DAILY_DEAL_LIVE_RUNTIME

    if runtime.Running == true
    and runtime.Token ~= nil then

        return false
    end

    local token =
        {}

    runtime.Token =
        token

    runtime.Running =
        true

    runtime.LastResult =
        "Live: starting"

    task.spawn(function()

        task.wait(
            8
        )

        while runtime.Token == token do

            local waitSeconds =
                45

            local requestOk,
                stockResult,
                stockOk,
                stockReason =
                pcall(function()

                    return HolyDailyDealFireFruitStockRequest()
                end)

            if requestOk == true
            and stockOk == true
            and type(stockResult) == "table"
            and type(stockResult.entries) == "table" then

                HolyDailyDealSendLiveReportAsync(
                    stockResult,
                    "live"
                )

                waitSeconds =
                    HolyDailyDealLiveResolveWait(
                        stockResult
                    )

            else

                runtime.LastResult =
                    "Live: stock failed"

                local now =
                    os.clock()

                if now - (
                    tonumber(runtime.LastErrorAt)
                    or 0
                ) > 20 then

                    runtime.LastErrorAt =
                        now

                    warn(
                        "[HOLY DAILY DEAL LIVE]",
                        "stock failed:",
                        tostring(stockReason)
                    )
                end
            end

            local untilClock =
                os.clock()
                + waitSeconds

            while runtime.Token == token
            and os.clock() < untilClock do

                task.wait(
                    1
                )
            end
        end

        if runtime.Token == token then

            runtime.Running =
                false

            runtime.Token =
                nil
        end
    end)

    return true
end

task.defer(function()

    task.wait(
        8
    )

    if type(HolyDailyDealFireFruitStockRequest) == "function" then

        HolyDailyDealLiveStartWorker(
            "script load"
        )
    end
end)

