            "TextLabel"
        )

    label.BackgroundTransparency =
        1

    label.Position =
        UDim2.fromOffset(
            10,
            y
        )

    label.Size =
        UDim2.new(
            1,
            -20,
            0,
            size
        )

    label.Text =
        tostring(text or "")

    label.TextSize =
        size

    label.TextTransparency =
        transparency or 0.08

    label.TextXAlignment =
        Enum.TextXAlignment.Left

    label.TextYAlignment =
        Enum.TextYAlignment.Center

    label.TextTruncate =
        Enum.TextTruncate.AtEnd

    local scheme =
        HOLY_DEV_LIBRARY
        and HOLY_DEV_LIBRARY.Scheme
        or {}

    label.TextColor3 =
        scheme.FontColor
        or Color3.fromRGB(
            245,
            245,
            247
        )

    label.FontFace =
        scheme.Font
        or Font.fromEnum(
            Enum.Font.GothamMedium
        )

    label.ZIndex =
        parent.ZIndex + 2

    label.Parent =
        parent

    return label
end

function HolyDoubleMakeHudDraggable(holder)

    if typeof(holder) ~= "Instance" then
        return false
    end

    local dragging =
        false

    local dragInput =
        nil

    local dragStart =
        nil

    local startPosition =
        nil

    HOLY_DOUBLE_HUD.Connections =
        HOLY_DOUBLE_HUD.Connections
        or {}

    table.insert(
        HOLY_DOUBLE_HUD.Connections,
        holder.InputBegan:Connect(function(input)

            if input.UserInputType == Enum.UserInputType.MouseButton1
            or input.UserInputType == Enum.UserInputType.Touch then

                dragging =
                    true

                dragStart =
                    input.Position

                startPosition =
                    holder.Position

                input.Changed:Connect(function()

                    if input.UserInputState == Enum.UserInputState.End then

                        dragging =
                            false

                        HolyDoubleSaveHudPosition()
                    end
                end)
            end
        end)
    )

    table.insert(
        HOLY_DOUBLE_HUD.Connections,
        holder.InputChanged:Connect(function(input)

            if input.UserInputType == Enum.UserInputType.MouseMovement
            or input.UserInputType == Enum.UserInputType.Touch then

                dragInput =
                    input
            end
        end)
    )

    table.insert(
        HOLY_DOUBLE_HUD.Connections,
        UserInputService.InputChanged:Connect(function(input)

            if input ~= dragInput
            or dragging ~= true
            or dragStart == nil
            or startPosition == nil then

                return
            end

            local delta =
                input.Position - dragStart

            holder.Position =
                UDim2.fromOffset(
                    startPosition.X.Offset + delta.X,
                    startPosition.Y.Offset + delta.Y
                )
        end)
    )

    return true
end

function HolyDoubleDestroyHud()

    if type(HOLY_DOUBLE_HUD) == "table"
    and type(HOLY_DOUBLE_HUD.Connections) == "table" then

        for _, connection in ipairs(HOLY_DOUBLE_HUD.Connections) do

            pcall(function()

                connection:Disconnect()
            end)
        end
    end

    if type(HOLY_DOUBLE_HUD) == "table"
    and typeof(HOLY_DOUBLE_HUD.Holder) == "Instance" then

        pcall(function()

            HOLY_DOUBLE_HUD.Holder:Destroy()
        end)
    end

    if type(HOLY_DOUBLE_HUD) == "table"
    and typeof(HOLY_DOUBLE_HUD.ScreenGui) == "Instance" then

        pcall(function()

            HOLY_DOUBLE_HUD.ScreenGui:Destroy()
        end)
    end

    HOLY_DOUBLE_HUD =
        {}

    return true
end

