        )

    stroke.Transparency =
        0.42

    stroke.Thickness =
        1

    stroke.Parent =
        holder

    local accent =
        Instance.new(
            "Frame"
        )

    accent.BackgroundColor3 =
        scheme.AccentColor
        or Color3.fromRGB(
            232,
            45,
            67
        )

    accent.BackgroundTransparency =
        0.05

    accent.BorderSizePixel =
        0

    accent.Position =
        UDim2.fromOffset(
            0,
            0
        )

    accent.Size =
        UDim2.new(
            0,
            3,
            1,
            0
        )

    accent.ZIndex =
        holder.ZIndex + 1

    accent.Parent =
        holder

    local accentCorner =
        Instance.new(
            "UICorner"
        )

    accentCorner.CornerRadius =
