                44,
                12,
                0.15
            ),

        NextLabel =
            HolyDoubleMakeHudLabel(
                holder,
                "⏭️ Next: --",
                61,
                12,
                0.22
            ),

        StateLabel =
            HolyDoubleMakeHudLabel(
                holder,
                "⚡ Ready",
                75,
                11,
                0.28
            ),
    }

    HolyDoubleMakeHudDraggable(
