    pcall(function()

        attrs =
            tool:GetAttributes()
    end)

    return type(attrs) == "table"
        and attrs
        or {}
end

function HolySellKey(value)

    return HolyCleanText(
        value
    )
        :lower()
        :gsub("[%s_%-%[%]%(%)%.]", "")
end

function HolySellFruitNameCandidates(fruitName)

    fruitName =
        HolyCleanText(
            fruitName
        )

    local candidates =
        {}

    local seen =
        {}

    local function add(value)

        value =
            HolyCleanText(
                value
            )

        if value == ""
        or seen[value] == true then
            return
        end

        seen[value] =
            true

        table.insert(
            candidates,
            value
        )
    end

    add(
        fruitName
    )

    local prefixes = {
        "Baby ",
        "Big ",
        "Huge ",
        "Mega ",
        "Small ",
        "Large ",
        "Giant ",
        "Gold ",
        "Golden ",
        "Rainbow ",
    }

    for _, prefix in ipairs(prefixes) do

        if fruitName:sub(1, #prefix):lower() == prefix:lower() then

            add(
                fruitName:sub(
                    #prefix + 1
                )
            )
        end
    end

    return candidates
end

function HolySellBuildRarityMap()

    if type(HOLY_SHOP_STATE.SellRarityMap) == "table" then

        return HOLY_SHOP_STATE.SellRarityMap
    end

    local map =
        {}

    local data =
        HolyShopRequireModule(
            "SharedModules.SeedData"
        )

    if type(data) == "table" then

        for _, row in pairs(data) do

            if type(row) == "table" then

                local seedName =
                    HolyCleanText(
                        row.SeedName
                        or row.Name
                        or row.FruitName
                        or row.CropName
                    )

                local rarity =
                    HolyCleanText(
                        row.Rarity
                        or row.SeedRarity
                        or row.FruitRarity
                        or ""
                    )

                if seedName ~= ""
                and rarity ~= "" then

                    map[
                        HolySellKey(
                            seedName
                        )
                    ] =
                        rarity
                end
            end
        end
    end

    HOLY_SHOP_STATE.SellRarityMap =
        map

    return map
end

function HolySellListInsertSorted(map, value)

    value =
        HolyCleanText(
            value
        )

    if value == "" then
        return
    end

    map[value] =
        true
end

function HolySellMapToValues(map, includeAll, includeNone)

    local values =
        {}

    if includeAll == true then

        table.insert(
            values,
            "All"
        )
    end

    if includeNone == true then

        table.insert(
            values,
            "None"
        )
    end

    local sorted =
        {}

    for value in pairs(map or {}) do

        if value ~= "All"
        and value ~= "None" then

            table.insert(
                sorted,
                value
            )
        end
    end

    table.sort(sorted, function(a, b)

        return tostring(a) < tostring(b)
    end)

    for _, value in ipairs(sorted) do

        table.insert(
            values,
            value
        )
    end

    return values
end

function HolySellAppendValue(values, seen, value)

    value =
        HolyCleanText(
            value
        )

    if value == ""
    or seen[value] == true then
        return
    end

    seen[value] =
        true

    table.insert(
        values,
        value
    )
end

function HolySellGetFruitDropdownValues()

    local values = {
        "All",
    }

    local seen = {
        All = true,
    }

    local data =
        HolyShopRequireModule(
            "SharedModules.SeedData"
        )

    local rows =
        {}

    if type(data) == "table" then

        for _, row in pairs(data) do

            if type(row) == "table"
            and row.MutationSeed ~= true then

                local fruitName =
                    HolyCleanText(
                        row.FruitName
                        or row.SeedName
                        or row.CropName
                        or row.Name
                    )

                if fruitName ~= "" then

                    table.insert(
                        rows,
                        fruitName
                    )
                end
            end
        end
    end

    table.sort(rows, function(a, b)

        return tostring(a) < tostring(b)
    end)

    for _, fruitName in ipairs(rows) do

        HolySellAppendValue(
            values,
            seen,
            fruitName
        )
    end

    return values
end

