function HolySellReadWeightSetting(value)

    local number =
        tonumber(
            tostring(value or "0")
                :match("[%d%.]+")
        )

    return math.max(
        0,
        tonumber(number)
        or 0
    )
end

function HolySellNormalizeValueMode(value)

    local mode =
        HolyFarmNormalizeWeightMode(
            value
        )

    if mode == "Above" then
        return "Above"
    end

    return "Below"
end

function HolySellReadValueThreshold(value)

    local text =
        HolyCleanText(
            value
        )

    text =
        text:gsub("¢", "")
            :gsub("%$", "")
            :gsub(",", "")
            :gsub("%s+", "")

    local lower =
        text:lower()

    if lower == ""
    or lower == "0"
    or lower == "none"
    or lower == "off"
    or lower == "no" then

        return 0
    end

    if type(HolyDailyDealStrictMoney) == "function" then

        local ok,
            result =
            pcall(function()

                return HolyDailyDealStrictMoney(
                    lower,
                    0,
                    nil
                )
            end)

        result =
            tonumber(result)

        if ok == true
        and result ~= nil
        and result >= 0 then

            return math.floor(
                result + 0.5
            )
        end
    end

    local numberText,
        suffix =
        lower:match("^(%d+%.?%d*)([a-z]*)$")

    local number =
        tonumber(numberText)

    if number == nil then
        return 0
    end

    local multipliers = {
        [""] = 1,

        k = 1000,
        thousand = 1000,

        m = 1000000,
        mil = 1000000,
        million = 1000000,

        b = 1000000000,
        bil = 1000000000,
        billion = 1000000000,

        t = 1000000000000,
        tril = 1000000000000,
        trillion = 1000000000000,

        q = 1000000000000000,
        qa = 1000000000000000,
        quad = 1000000000000000,
        quadrillion = 1000000000000000,
    }

    local multiplier =
        multipliers[suffix or ""]

    if multiplier == nil then
        multiplier = 1
    end

    return math.max(
        0,
        math.floor(number * multiplier + 0.5)
    )
end

function HolySellFormatValue(value)

    value =
        tonumber(value)

    if value == nil then
        return "$0"
    end

    if type(HolyVisualFormatFruitValue) == "function" then

        return HolyVisualFormatFruitValue(
            value
        )
    end

    return tostring(
        math.floor(value + 0.5)
    )
end

function HolySellGetToolValue(tool)

    if HolySellLooksLikeFruitTool(tool) ~= true then
        return nil
    end

    if type(HolyVisualReadFruitTool) == "function" then

        local ok,
            row =
            pcall(function()

                return HolyVisualReadFruitTool(
                    tool,
                    0
                )
            end)

        if ok == true
        and type(row) == "table" then

            local value =
                tonumber(
                    row.Value
                )

            if value ~= nil
            and value > 0 then

                return math.floor(value + 0.5),
                    row.ValueText
                    or HolySellFormatValue(value)
            end
        end
    end

    if type(HolyVisualCalculateFruitValue) == "function" then

        local attrs =
            HolySellGetToolAttributes(
                tool
            )

        local weight =
            HolySellGetToolWeight(
                tool
            )

        local sizeMultiplier =
            tonumber(
                attrs.SizeMultiplier
                or attrs.SizeMulti
                or attrs.ScaleMultiplier
                or attrs.ScaleMulti
                or attrs.Scale
                or attrs.SizeScale
            )

        if sizeMultiplier == nil
        or sizeMultiplier <= 0 then

            sizeMultiplier =
                math.max(
                    0.01,
                    tonumber(weight)
                    or 0
                )
        end

        local row = {
            Tool =
                tool,

            Name =
                HolySellGetToolFruitName(
                    tool
                ),

            RawName =
                tostring(
                    tool
                    and tool.Name
                    or ""
                ),

            RawMutation =
                HolySellGetRawToolMutation(
                    tool
                ),

            Weight =
                tonumber(weight)
                or 0,

            SizeMultiplier =
                sizeMultiplier,

            Index =
                0,
        }

        local ok,
            result =
            pcall(function()

                return HolyVisualCalculateFruitValue(
                    tool,
                    row
                )
            end)

        result =
            tonumber(result)

        if ok == true
        and result ~= nil
        and result > 0 then

            return math.floor(result + 0.5),
                HolySellFormatValue(result)
        end
    end

    return nil
end

function HolySellValueFilterActive()

    if HOLY_SHOP_STATE.UseSellFilters ~= true then
        return false
    end

    return HolySellReadValueThreshold(
        HOLY_SHOP_STATE.SellValueThreshold
        or "0"
    ) > 0
end

function HolySellPassesValueFilter(tool)

    local threshold =
        HolySellReadValueThreshold(
            HOLY_SHOP_STATE.SellValueThreshold
            or "0"
        )

    if threshold <= 0 then
        return true
    end

    local value =
        HolySellGetToolValue(
            tool
        )

    value =
        tonumber(value)

    if value == nil
    or value <= 0 then

        return false
    end

    local mode =
        HolySellNormalizeValueMode(
            HOLY_SHOP_STATE.SellValueMode
            or "Below"
        )

    if mode == "Above" then

        return value >= threshold
    end

    return value <= threshold
end

function HolySellSortQueue()

    HOLY_SHOP_STATE.SellQueue =
        type(HOLY_SHOP_STATE.SellQueue) == "table"
        and HOLY_SHOP_STATE.SellQueue
        or {}

    if HolySellValueFilterActive() ~= true then
        return false
    end

    local mode =
        HolySellNormalizeValueMode(
            HOLY_SHOP_STATE.SellValueMode
            or "Below"
        )

    table.sort(HOLY_SHOP_STATE.SellQueue, function(a, b)

        a =
            type(a) == "table"
            and a
            or {}

        b =
            type(b) == "table"
            and b
            or {}

        local valueA =
            tonumber(a.Value)
            or 0

        local valueB =
            tonumber(b.Value)
            or 0

        if valueA ~= valueB then

            if mode == "Above" then

                return valueA > valueB
            end

            return valueA < valueB
        end

        local weightA =
            tonumber(a.Weight)
            or 0

        local weightB =
            tonumber(b.Weight)
            or 0

        if weightA ~= weightB then
            return weightA > weightB
        end

        return tostring(a.Name or "")
            < tostring(b.Name or "")
    end)

    return true
end

function HolySellClearQueue()

    HOLY_SHOP_STATE.SellQueue =
        {}

    HOLY_SHOP_STATE.SellQueueMap =
        {}

    return true
end

function HolySellIsPetTool(instance)

    if typeof(instance) ~= "Instance" then
        return false
    end

    local attrs =
        HolySellGetToolAttributes(
            instance
        )

    if attrs.PetId ~= nil
    or attrs.PetID ~= nil
    or attrs.Pet ~= nil
    or attrs.PetName ~= nil then

        return true
    end

    return false
end

function HolySellIsBlockedToolName(toolName)

    local lower =
        tostring(toolName or "")
            :lower()

    local blockedWords = {
        "shovel",
        "trowel",
        "build",
        "sprinkler",
        "watering can",
        "crate",
        "teleporter",
        "gnome",
        "pot",
        "flashbang",
        "magnet",
        "trap",
    }

    for _, word in ipairs(blockedWords) do

        if lower:find(word, 1, true) then
            return true
        end
    end

    return false
end

function HolySellLooksLikeFruitTool(instance)

    if typeof(instance) ~= "Instance" then
        return false
    end

    if instance:IsA("Tool") ~= true
    and instance:IsA("Configuration") ~= true then

        return false
    end

    if HolySellIsPetTool(instance) == true then
        return false
    end

    local attrs =
        HolySellGetToolAttributes(
            instance
        )

    local fruitId =
        attrs.Id
        or attrs.FruitId
        or attrs.FruitID
        or attrs.UUID
        or attrs.Uuid
        or attrs.Guid
        or attrs.GUID

    local fruitName =
        attrs.FruitName
        or attrs.Fruit

    local hasWeight =
        attrs.Weight ~= nil
        or attrs.WeightKg ~= nil
        or attrs.WeightKG ~= nil
        or attrs.KG ~= nil
        or attrs.Kg ~= nil

    if attrs.HarvestedFruit == true
    and fruitId ~= nil
    and tostring(fruitId) ~= ""
    and fruitName ~= nil
    and tostring(fruitName) ~= ""
    and (
        attrs.FruitProxy == true
        or instance:IsA("Tool") == true
        or hasWeight == true
    ) then

        return true
    end

    return false
end

function HolySellReadFruitIdFromValue(value)

    local text =
        HolyCleanText(
            value
        )

    if text == "" then
        return ""
    end

    local uuid =
        text:match(
            "[%w]+%-%w+%-%w+%-%w+%-%w+"
        )

    if uuid then
        return uuid
    end

    return text
end

function HolySellResolveFruitId(tool)

    if HolySellLooksLikeFruitTool(tool) ~= true then
        return ""
    end

    local attrs =
        HolySellGetToolAttributes(
            tool
        )

    local value =
        attrs.Id
        or attrs.FruitId
        or attrs.FruitID
        or attrs.UUID
        or attrs.Uuid
        or attrs.Guid
        or attrs.GUID

    if value ~= nil
    and tostring(value) ~= "" then

        return HolySellReadFruitIdFromValue(
            value
        )
    end

    return ""
end

function HolySellGetToolFruitName(tool)

    if typeof(tool) ~= "Instance" then
        return ""
    end

    local attrs =
        HolySellGetToolAttributes(
            tool
        )

    return HolyCleanText(
        attrs.FruitName
        or attrs.Fruit
        or ""
    )
end

function HolySellGetToolRarity(tool)

    local attrs =
        HolySellGetToolAttributes(
            tool
        )

    local direct =
        HolyCleanText(
            attrs.Rarity
            or attrs.FruitRarity
            or attrs.CropRarity
            or ""
        )

    if direct ~= "" then
        return direct
    end

    local fruitName =
        HolySellGetToolFruitName(
            tool
        )

    local rarityMap =
        HolySellBuildRarityMap()

    for _, candidate in ipairs(HolySellFruitNameCandidates(fruitName)) do

        local rarity =
            rarityMap[
                HolySellKey(
                    candidate
                )
            ]

        if HolyCleanText(rarity) ~= "" then

            return HolyCleanText(
                rarity
            )
        end
    end

    return ""
end

function HolySellGetRawToolMutation(tool)

    local attrs =
        HolySellGetToolAttributes(
            tool
        )

    return HolyCleanText(
        attrs.Mutation
        or attrs.Mutations
        or ""
    )
end

function HolySellIsVariantMutation(value)

    value =
        HolyCleanText(
            value
        )

    return value == "Gold"
        or value == "Rainbow"
end

function HolySellGetToolMutation(tool)

    local mutation =
        HolySellGetRawToolMutation(
            tool
        )

    if mutation == ""
    or HolySellIsVariantMutation(mutation) == true then

        return "None"
    end

    return mutation
end

function HolySellGetToolVariant(tool)

    local attrs =
        HolySellGetToolAttributes(
            tool
        )

    local variant =
        HolyCleanText(
            attrs.Variant
            or attrs.FruitVariant
            or attrs.PlantVariant
            or attrs.Type
            or ""
        )

    if variant ~= "" then

        return variant
    end

    local rawMutation =
        HolySellGetRawToolMutation(
            tool
        )

    if HolySellIsVariantMutation(rawMutation) == true then

        return rawMutation
    end

    return "Normal"
end

function HolySellGetToolWeight(tool)

    local attrs =
        HolySellGetToolAttributes(
            tool
        )

    local value =
        tonumber(
            attrs.WeightKg
            or attrs.WeightKG
            or attrs.KG
            or attrs.Kg
            or attrs.Weight
            or attrs.Mass
        )

    if value then
        return value
    end

    local name =
        tostring(
            tool
            and tool.Name
            or ""
        )

    value =
        tonumber(
            name:match("([%d%.]+)%s*[Kk][Gg]")
        )

    return tonumber(value)
        or 0
end

function HolySellSelectedMap(value)

    return HolyShopNormalizeSelection(
        value
    )
end

function HolySellPassesSelectedMap(map, itemName)

    itemName =
        HolyCleanText(
            itemName
        )

    if type(map) ~= "table" then
        return true
    end

    local hasAny =
        false

    for _ in pairs(map) do

        hasAny =
            true

        break
    end

    if hasAny ~= true then
        return true
    end

    if map.All == true then
        return true
    end

    return itemName ~= ""
        and map[itemName] == true
end

function HolySellPassesFilters(tool)

    if HolySellLooksLikeFruitTool(tool) ~= true then
        return false
    end

    if HOLY_SHOP_STATE.UseSellFilters ~= true then
        return true
    end

    local fruitMap =
        HolySellSelectedMap(
            HOLY_SHOP_STATE.SellFruits
        )

    local rarityMap =
        HolySellSelectedMap(
            HOLY_SHOP_STATE.SellRarities
        )

    local mutationMap =
        HolySellSelectedMap(
            HOLY_SHOP_STATE.SellMutations
        )

    local variantMap =
        HolySellSelectedMap(
            HOLY_SHOP_STATE.SellVariants
        )

    local protectMutationMap =
        HolySellSelectedMap(
            HOLY_SHOP_STATE.ProtectMutations
        )

    local protectVariantMap =
        HolySellSelectedMap(
            HOLY_SHOP_STATE.ProtectVariants
        )

    local fruitName =
        HolySellGetToolFruitName(
            tool
        )

    local rarity =
        HolySellGetToolRarity(
            tool
        )

    local mutation =
        HolySellGetToolMutation(
            tool
        )

    local variant =
        HolySellGetToolVariant(
            tool
        )

    if protectMutationMap[mutation] == true then
        return false
    end

    if protectVariantMap[variant] == true then
        return false
    end

    if HolySellPassesSelectedMap(fruitMap, fruitName) ~= true then
        return false
    end

    if HolySellPassesSelectedMap(rarityMap, rarity) ~= true then
        return false
    end

    if HolySellPassesSelectedMap(mutationMap, mutation) ~= true then
        return false
    end

    if HolySellPassesSelectedMap(variantMap, variant) ~= true then
        return false
    end

    local weight =
        HolySellGetToolWeight(
            tool
        )

    local minWeight =
        HolySellReadWeightSetting(
            HOLY_SHOP_STATE.MinWeightKg
        )

    local maxWeight =
        HolySellReadWeightSetting(
            HOLY_SHOP_STATE.MaxWeightKg
        )

    if minWeight > 0
    and weight < minWeight then

        return false
    end

    if maxWeight > 0
    and weight > maxWeight then

        return false
    end

    if HolySellPassesValueFilter(
        tool
    ) ~= true then

        return false
    end

    return true
end

function HolySellGetFruitTools()

    local fruits =
        {}

    local roots = {
        LocalPlayer
        and LocalPlayer.Character
        or nil,

        LocalPlayer
        and LocalPlayer:FindFirstChildOfClass("Backpack")
        or nil,
    }

    for _, root in ipairs(roots) do

        if typeof(root) == "Instance" then

            for _, child in ipairs(root:GetChildren()) do

                if HolySellLooksLikeFruitTool(child) == true then

                    table.insert(
                        fruits,
                        child
                    )
                end
            end
        end
    end

    table.sort(fruits, function(a, b)

        return tostring(a.Name) < tostring(b.Name)
    end)

    return fruits
end

--==================================================
-- [2.665] VISUAL / FRUIT VALUE OVERLAY
--==================================================

function HolyVisualGetRuntime()

    HOLY_VISUAL_RUNTIME =
        type(HOLY_VISUAL_RUNTIME) == "table"
        and HOLY_VISUAL_RUNTIME
        or {}

    local runtime =
        HOLY_VISUAL_RUNTIME

    runtime.Labels =
        type(runtime.Labels) == "table"
        and runtime.Labels
        or {}

    runtime.GardenFruitLabels =
        type(runtime.GardenFruitLabels) == "table"
        and runtime.GardenFruitLabels
        or {}

    runtime.SprinklerTimerLabels =
        type(runtime.SprinklerTimerLabels) == "table"
        and runtime.SprinklerTimerLabels
        or {}

    runtime.SprinklerTimerOriginalStates =
        type(runtime.SprinklerTimerOriginalStates) == "table"
        and runtime.SprinklerTimerOriginalStates
        or {}

    runtime.SprinklerTimerUpdateDelay =
        math.clamp(
            tonumber(runtime.SprinklerTimerUpdateDelay)
            or 0.25,
            0.1,
            2
        )

    runtime.UpdateDelay =
        math.clamp(
            tonumber(runtime.UpdateDelay)
            or 0.75,
            0.25,
            2
        )

    runtime.GardenFruitUpdateDelay =
        math.clamp(
            tonumber(runtime.GardenFruitUpdateDelay)
            or 1.0,
            0.35,
            3
        )

    runtime.GardenFruitMaxLabels =
        math.clamp(
            math.floor(
                tonumber(runtime.GardenFruitMaxLabels)
                or 160
            ),
            20,
            250
        )

    return runtime
end

function HolyVisualGetPlayerGui()

    if not LocalPlayer then
        return nil
    end

    return LocalPlayer:FindFirstChildOfClass(
        "PlayerGui"
    )
    or LocalPlayer:FindFirstChild(
        "PlayerGui"
    )
end

function HolyVisualLoadValueCaches(forceRefresh)

    local runtime =
        HolyVisualGetRuntime()

    if forceRefresh ~= true
    and runtime.ValueCachesLoaded == true then

        return runtime
    end

    runtime.FruitValueCalc =
        nil

    runtime.SellValueData =
        nil

    runtime.MutationMultipliers =
        {}

    local fruitValueCalc =
        HolyShopRequireModule(
            "SharedModules.FruitValueCalc"
        )

    if type(fruitValueCalc) == "function" then

        runtime.FruitValueCalc =
            fruitValueCalc

    elseif type(fruitValueCalc) == "table" then

        runtime.FruitValueCalc =
            fruitValueCalc.Calculate
            or fruitValueCalc.GetValue
            or fruitValueCalc.GetFruitValue
            or fruitValueCalc.Value
    end

    runtime.SellValueData =
        HolyShopRequireModule(
            "SharedModules.SellValueData"
        )

    local sharedModules =
        ReplicatedStorage:FindFirstChild(
            "SharedModules"
        )

    local mutationData =
        sharedModules
        and sharedModules:FindFirstChild(
            "MutationData"
        )
        or nil

    if typeof(mutationData) == "Instance" then

        for _, module in ipairs(mutationData:GetChildren()) do

            if module:IsA("ModuleScript") then

                local ok,
                    result =
                    pcall(function()

                        return require(
                            module
                        )
                    end)

                if ok == true
                and type(result) == "table" then

                    local multiplier =
                        tonumber(
                            result.PriceMultiplier
                            or result.SellMultiplier
                            or result.ValueMultiplier
                            or result.Multiplier
                            or result.Boost
                        )

                    if multiplier ~= nil
                    and multiplier > 0 then

                        runtime.MutationMultipliers[module.Name] =
                            multiplier
                    end
                end
            end
        end
    end

    runtime.ValueCachesLoaded =
        true

    return runtime
end

function HolyVisualNameKey(value)

    local text =
        HolyCleanText(
            value
        )
        :lower()

    text =
        text:gsub(
            "%b[]",
            ""
        )

    text =
        text:gsub(
            "[%s_%-%[%]%(%)%.'\"_/{}]",
            ""
        )

    return text
end

function HolyVisualParseKg(value)

    local number =
        tonumber(
            tostring(value or "")
                :match("([%d%.]+)%s*[Kk][Gg]")
        )

    return tonumber(number)
        or 0
end

function HolyVisualStripBracketText(value)

    local text =
        HolyCleanText(
            value
        )

    text =
        text:gsub(
            "%s*%b[]",
            ""
        )

    text =
        text:gsub(
            "%s+",
            " "
        )

    return HolyCleanText(
        text
    )
end

function HolyVisualParseBracketMutation(value)

    local text =
        tostring(value or "")

    local bracket =
        text:match(
            "%[([^%]]+)%]"
        )

    bracket =
        HolyCleanText(
            bracket
        )

    if bracket == "" then
        return ""
    end

    if bracket:lower():find("kg", 1, true) then
        return ""
    end

    return bracket
end

function HolyVisualRoundKg(value)

    value =
        tonumber(value)
        or 0

    if value <= 0 then
        return 0
    end

    return math.floor(
        value * 100 + 0.5
    ) / 100
end

function HolyVisualMutationMultiplier(rawMutation)

    local runtime =
        HolyVisualLoadValueCaches(
            false
        )

    local multipliers =
        type(runtime.MutationMultipliers) == "table"
        and runtime.MutationMultipliers
        or {}

    rawMutation =
        HolyCleanText(
            rawMutation
        )

    if rawMutation == "" then
        return 1
    end

    local multiplier =
        1

    for part in rawMutation:gmatch("[^,%|/;]+") do

        part =
            HolyCleanText(
                part
            )

        if part ~= "" then

            for mutationName, mutationMultiplier in pairs(multipliers) do

                if HolyVisualNameKey(mutationName) == HolyVisualNameKey(part) then

                    multiplier =
                        multiplier
                        * (
                            tonumber(mutationMultiplier)
                            or 1
                        )
                end
            end
        end
    end

    return math.max(
        1,
        multiplier
    )
end

function HolyVisualFormatFruitValue(value)

    value =
        math.max(
            0,
            tonumber(value)
            or 0
        )

    if value >= 1000000000 then

        return "$"
            .. string.format(
                "%.1fB",
                value / 1000000000
            )
    end

    if value >= 1000000 then

        return "$"
            .. string.format(
                "%.1fM",
                value / 1000000
            )
    end

    if value >= 1000 then

        return "$"
            .. string.format(
                "%.1fK",
                value / 1000
            ):gsub(
                "%.0K",
                "K"
            )
    end

    return "$"
        .. tostring(
            math.floor(value + 0.5)
        )
end

function HolyVisualCalculateFruitValue(tool, row)

    row =
        type(row) == "table"
        and row
        or {}

    local runtime =
        HolyVisualLoadValueCaches(
            false
        )

    local value =
        nil

    local fruitValueCalc =
        runtime.FruitValueCalc

    if type(fruitValueCalc) == "function" then

        local unpackFunction =
            table.unpack
            or unpack

        local attempts = {
            {
                row.Name,
                row.SizeMultiplier,
                tool,
                tool,
                tool,
            },

            {
                row.Name,
                row.SizeMultiplier,
                tool,
            },

            {
                row.Name,
                row.SizeMultiplier,
            },

            {
                tool,
            },

            {
                row,
            },
        }

        for _, args in ipairs(attempts) do

            local ok,
                result =
                pcall(function()

                    return fruitValueCalc(
                        unpackFunction(
                            args
                        )
                    )
                end)

            result =
                tonumber(result)

            if ok == true
            and result ~= nil
            and result >= 0 then

                value =
                    result

                break
            end
        end
    end

    if value == nil then

        local sellValueData =
            type(runtime.SellValueData) == "table"
            and runtime.SellValueData
            or {}

        local baseValue =
            tonumber(
                sellValueData[row.Name]
            )
            or tonumber(
                sellValueData[
                    HolyVisualStripBracketText(
                        row.Name
                    )
                ]
            )
            or 0

        local sizeMultiplier =
            tonumber(row.SizeMultiplier)
            or 1

        sizeMultiplier =
            math.max(
                0.01,
                sizeMultiplier
            )

        value =
            baseValue
            * (
                sizeMultiplier ^ 2.5
            )
    end

    value =
        value
        * HolyVisualMutationMultiplier(
            row.RawMutation
        )

    return math.max(
        0,
        math.floor(value + 0.5)
    )
end

function HolyVisualReadFruitTool(tool, index)

    if HolySellLooksLikeFruitTool(tool) ~= true then
        return nil
    end

    local attrs =
        HolySellGetToolAttributes(
            tool
        )

    local fruitName =
        HolySellGetToolFruitName(
            tool
        )

    if fruitName == "" then

        fruitName =
            HolyVisualStripBracketText(
                tool.Name
            )
    end

    fruitName =
        HolyCleanText(
            fruitName
        )

    if fruitName == "" then
        return nil
    end

    local rawMutation =
        HolySellGetRawToolMutation(
            tool
        )

    if rawMutation == "" then

        rawMutation =
            HolyVisualParseBracketMutation(
                tool.Name
            )
    end

    local weight =
        HolySellGetToolWeight(
            tool
        )

    if weight <= 0 then

        weight =
            HolyVisualParseKg(
                tool.Name
            )
    end

    local sizeMultiplier =
        tonumber(
            attrs.SizeMultiplier
            or attrs.SizeMulti
            or attrs.ScaleMultiplier
            or attrs.ScaleMulti
            or attrs.Scale
            or attrs.SizeScale
        )

    if sizeMultiplier == nil
    or sizeMultiplier <= 0 then

        sizeMultiplier =
            math.max(
                0.01,
                weight
            )
    end

    local row = {
        Tool =
            tool,

        Name =
            fruitName,

        NameKey =
            HolyVisualNameKey(
                fruitName
            ),

        RawName =
            tostring(tool.Name or ""),

        RawNameKey =
            HolyVisualNameKey(
                tool.Name
            ),

        RawMutation =
            rawMutation,

        Weight =
            HolyVisualRoundKg(
                weight
            ),

        WeightKey =
            tostring(
                HolyVisualRoundKg(
                    weight
                )
            ),

        SizeMultiplier =
            tonumber(sizeMultiplier)
            or 1,

        Index =
            tonumber(index)
            or 0,
    }

    row.Value =
        HolyVisualCalculateFruitValue(
            tool,
            row
        )

    row.ValueText =
        HolyVisualFormatFruitValue(
            row.Value
        )

    return row
end

function HolyVisualAddFruitRowToMap(map, row)

    if type(row) ~= "table" then
        return false
    end

    local keys = {
        row.NameKey
            .. "|"
            .. row.WeightKey,

        row.RawNameKey
            .. "|"
            .. row.WeightKey,

        row.NameKey,
        row.RawNameKey,
    }

    for _, key in ipairs(keys) do

        key =
            HolyCleanText(
                key
            )

        if key ~= "" then

            map[key] =
                map[key]
                or {}

            table.insert(
                map[key],
                row
            )
        end
    end

    return true
end

function HolyVisualBuildFruitMaps()

    local map =
        {}

    local index =
        0

    for _, tool in ipairs(HolySellGetFruitTools()) do

        index =
            index + 1

        local row =
            HolyVisualReadFruitTool(
                tool,
                index
            )

        if row then

            HolyVisualAddFruitRowToMap(
                map,
                row
            )
        end
    end

    return map
end

function HolyVisualTakeFruitRow(map, key, used)

    key =
        HolyCleanText(
            key
        )

    if key == "" then
        return nil
    end

    local rows =
        map[key]

    if type(rows) ~= "table" then
        return nil
    end

    for _, row in ipairs(rows) do

        if used[row] ~= true then

            used[row] =
                true

            return row
        end
    end

    return nil
end

function HolyVisualGetText(instance)

    if typeof(instance) ~= "Instance" then
        return ""
    end

    if instance:IsA("TextLabel")
    or instance:IsA("TextButton")
    or instance:IsA("TextBox") then

        return HolyCleanText(
            instance.Text
        )
    end

    return ""
end

function HolyVisualFindText(root, matcher)

    if typeof(root) ~= "Instance" then
        return ""
    end

    for _, descendant in ipairs(root:GetDescendants()) do

        local text =
            HolyVisualGetText(
                descendant
            )

        if text ~= ""
        and matcher(text) == true then

            return text
        end
    end

    return ""
end

function HolyVisualSlotLooksLikeInventoryItem(slot)

    if typeof(slot) ~= "Instance"
    or slot:IsA("GuiObject") ~= true then

        return false
    end

    if slot.Visible ~= true then
        return false
    end

    local blockedNames = {
        Backpack = true,
        Inventory = true,
        ScrollingFrame = true,
        UIGridFrame = true,
        Hotbar = true,
        Search = true,
        Tabs = true,
    }

    if blockedNames[tostring(slot.Name)] == true then
        return false
    end

    local size =
        slot.AbsoluteSize

    if typeof(size) == "Vector2" then

        if size.X < 32
        or size.Y < 32 then

            return false
        end

        -- Real inventory cards are small. Big containers should never get labels.
        if size.X > 180
        or size.Y > 180 then

            return false
        end
    end

    return true
end

function HolyVisualReadSlotInfo(slot)

    if HolyVisualSlotLooksLikeInventoryItem(slot) ~= true then
        return nil
    end

    local nameText =
        HolyVisualFindText(
            slot,
            function(text)

                local lower =
                    text:lower()

                if lower:find("kg", 1, true) then
                    return false
                end

                if text:match("^x%d") then
                    return false
                end

                if text:match("^%$") then
                    return false
                end

                if text == "" then
                    return false
                end

                return true
            end
        )

    local kgText =
        HolyVisualFindText(
            slot,
            function(text)

                return text:lower():find(
                    "kg",
                    1,
                    true
                ) ~= nil
            end
        )

    local weight =
        HolyVisualRoundKg(
            HolyVisualParseKg(
                kgText
            )
        )

    if nameText == ""
    or weight <= 0 then

        return nil
    end

    local cleanName =
        HolyVisualStripBracketText(
            nameText
        )

    if cleanName == "" then
        return nil
    end

    return {
        Name =
            cleanName,

        NameKey =
            HolyVisualNameKey(
                cleanName
            ),

        RawName =
            nameText,

        RawNameKey =
            HolyVisualNameKey(
                nameText
            ),

        Weight =
            weight,

        WeightKey =
            tostring(weight),
    }
end

function HolyVisualMatchSlotToFruit(slot, map, used)

    local slotInfo =
        HolyVisualReadSlotInfo(
            slot
        )

    if type(slotInfo) ~= "table" then
        return nil
    end

    local keys =
        {}

    if slotInfo.Weight > 0 then

        table.insert(
            keys,
            slotInfo.NameKey
                .. "|"
                .. slotInfo.WeightKey
        )

        table.insert(
            keys,
            slotInfo.RawNameKey
                .. "|"
                .. slotInfo.WeightKey
        )
    end

    table.insert(
        keys,
        slotInfo.NameKey
    )

    table.insert(
        keys,
        slotInfo.RawNameKey
    )

    for _, key in ipairs(keys) do

        local row =
            HolyVisualTakeFruitRow(
                map,
                key,
                used
            )

        if row then
            return row
        end
    end

    return nil
end

function HolyVisualClearOldSlotOverlays(slot)

    if typeof(slot) ~= "Instance" then
        return false
    end

    for _, child in ipairs(slot:GetChildren()) do

        if child.Name == "HolyFruitValueSlotText"
        or child.Name == "HolyFruitValueOverlay"
        or child.Name == "HolyFruitValueTextOverlay" then

            pcall(function()

                child:Destroy()
            end)
        end
    end

    return true
end

function HolyVisualEnsureSlotLabel(slot)

    if typeof(slot) ~= "Instance"
    or slot:IsA("GuiObject") ~= true then

        return nil
    end

    local label =
        slot:FindFirstChild(
            "HolyFruitValueSlotText"
        )

    if typeof(label) == "Instance"
    and label:IsA("TextLabel") then

        return label
    end

    HolyVisualClearOldSlotOverlays(
        slot
    )

    label =
        Instance.new(
            "TextLabel"
        )

    label.Name =
        "HolyFruitValueSlotText"

    label.BackgroundTransparency =
        1

    label.AnchorPoint =
        Vector2.new(
            0.5,
            0
        )

    label.Position =
        UDim2.new(
            0.5,
            0,
            0,
            1
        )

    label.Size =
        UDim2.new(
            1,
            -4,
            0,
            18
        )

    label.Font =
        Enum.Font.GothamBlack

    label.TextSize =
        14

    label.TextColor3 =
        Color3.fromRGB(
            57,
            255,
            20
        )

    label.TextStrokeColor3 =
        Color3.fromRGB(
            0,
            0,
            0
        )

    label.TextStrokeTransparency =
        0

    label.TextXAlignment =
        Enum.TextXAlignment.Center

    label.TextYAlignment =
        Enum.TextYAlignment.Center

    label.TextWrapped =
        false

    label.TextTruncate =
        Enum.TextTruncate.AtEnd

    label.ZIndex =
        (
            tonumber(slot.ZIndex)
            or 1
        )
        + 60

    label.Parent =
        slot

    return label
end

function HolyVisualRemoveSlotLabel(slot)

    local runtime =
        HolyVisualGetRuntime()

    if typeof(slot) == "Instance" then

        local label =
            runtime.Labels[slot]

        if typeof(label) == "Instance" then

            pcall(function()

                label:Destroy()
            end)
        end

        runtime.Labels[slot] =
            nil

        HolyVisualClearOldSlotOverlays(
            slot
        )
    end

    return true
end

function HolyVisualVisibleChain(instance)

    if typeof(instance) ~= "Instance" then
        return false
    end

    local current =
        instance

    while current
    and current ~= game do

        if current:IsA("GuiObject") then

            if current.Visible ~= true then
                return false
            end
        end

        if current:IsA("LayerCollector") then

            if current.Enabled ~= true then
                return false
            end
        end

        current =
            current.Parent
    end

    return true
end

function HolyVisualGetSlotRoots(includeHidden)

    local playerGui =
        HolyVisualGetPlayerGui()

    if typeof(playerGui) ~= "Instance" then
        return {}
    end

    local roots =
        {}

    local function addRoot(root)

        if typeof(root) ~= "Instance"
        or root:IsA("GuiObject") ~= true then

            return
        end

        if includeHidden ~= true
        and HolyVisualVisibleChain(root) ~= true then

            return
        end

        table.insert(
            roots,
            root
        )
    end

    local backpackGui =
        playerGui:FindFirstChild(
            "BackpackGui"
        )

    local backpack =
        backpackGui
        and backpackGui:FindFirstChild(
            "Backpack"
        )
        or nil

    local inventory =
        backpack
        and backpack:FindFirstChild(
            "Inventory"
        )
        or nil

    local scrollingFrame =
        inventory
        and inventory:FindFirstChild(
            "ScrollingFrame"
        )
        or nil

    addRoot(
        scrollingFrame
        and scrollingFrame:FindFirstChild(
            "UIGridFrame"
        )
        or nil
    )

    addRoot(
        backpack
        and backpack:FindFirstChild(
            "Hotbar"
        )
        or nil
    )

    -- Fallback, but still only slot containers. Never add Inventory itself.
    if #roots <= 0
    and backpackGui then

        addRoot(
            backpackGui:FindFirstChild(
                "UIGridFrame",
                true
            )
        )

        addRoot(
            backpackGui:FindFirstChild(
                "Hotbar",
                true
            )
        )
    end

    return roots
end

function HolyVisualClearAllFruitValueLabels()

    local runtime =
        HolyVisualGetRuntime()

    for slot, label in pairs(runtime.Labels) do

        if typeof(label) == "Instance" then

            pcall(function()

                label:Destroy()
            end)
        end

        runtime.Labels[slot] =
            nil
    end

    local playerGui =
        HolyVisualGetPlayerGui()

    local backpackGui =
        typeof(playerGui) == "Instance"
        and playerGui:FindFirstChild(
            "BackpackGui"
        )
        or nil

    if typeof(backpackGui) == "Instance" then

        for _, descendant in ipairs(backpackGui:GetDescendants()) do

            if descendant.Name == "HolyFruitValueSlotText"
            or descendant.Name == "HolyFruitValueOverlay"
            or descendant.Name == "HolyFruitValueTextOverlay" then

                pcall(function()

                    descendant:Destroy()
                end)
            end
        end
    end

    return true
end

function HolyVisualCalculateTotalFruitValue()

    local count =
        0

    local total =
        0

    local index =
        0

    for _, tool in ipairs(HolySellGetFruitTools()) do

        index =
            index + 1

        local row =
            HolyVisualReadFruitTool(
                tool,
                index
            )

        if type(row) == "table" then

            count =
                count + 1

            total =
                total
                + (
                    tonumber(row.Value)
                    or 0
                )
        end
    end

    return count,
        total
end

function HolyVisualFormatTotalFruitValue(value)

    local number =
        math.max(
            0,
            tonumber(value)
            or 0
        )

    local function trimUnit(text, unit)

        text =
            tostring(text)

        text =
            text:gsub(
                "0+"
                    .. unit
                    .. "$",
                unit
            )

        text =
            text:gsub(
                "%."
                    .. unit
                    .. "$",
                unit
            )

        return text
    end

    if number >= 1000000000 then

        return "$"
            .. trimUnit(
                string.format(
                    "%.3fB",
                    number / 1000000000
                ),
                "B"
            )
    end

    if number >= 1000000 then

        return "$"
            .. trimUnit(
                string.format(
                    "%.3fM",
                    number / 1000000
                ),
                "M"
            )
    end

    if number >= 1000 then

        local text =
            tostring(
                math.floor(number + 0.5)
            )

        while true do

            local newText =
                text:gsub(
                    "^(-?%d+)(%d%d%d)",
                    "%1.%2"
                )

            if newText == text then
                break
            end

            text =
                newText
        end

        return "$"
            .. text
    end

    return "$"
        .. tostring(
            math.floor(number + 0.5)
        )
end

function HolyVisualGetBackpackInventory()

    local playerGui =
        HolyVisualGetPlayerGui()

    if typeof(playerGui) ~= "Instance" then
        return nil
    end

    local backpackGui =
        playerGui:FindFirstChild(
            "BackpackGui"
        )

    local backpack =
        backpackGui
        and backpackGui:FindFirstChild(
            "Backpack"
        )
        or nil

    local inventory =
        backpack
        and backpack:FindFirstChild(
            "Inventory"
        )
        or nil

    return inventory
end

function HolyVisualGetInventoryTitleLabel()

    local inventory =
        HolyVisualGetBackpackInventory()

    if typeof(inventory) ~= "Instance" then
        return nil
    end

    local direct =
        inventory:FindFirstChild(
            "FruitInventory"
        )

    if typeof(direct) == "Instance"
    and direct:IsA("TextLabel") then

        return direct
    end

    for _, descendant in ipairs(inventory:GetDescendants()) do

        if descendant:IsA("TextLabel") then

            local text =
                HolyCleanText(
                    descendant.Text
                )

            local lower =
                text:lower()

            if lower == "inventory"
            or lower:find("fruit", 1, true)
            or text:match("%d+%s*/%s*%d+") then

                return descendant
            end
        end
    end

    return nil
end

function HolyVisualTitleAllowsTotalValue(title)

    if typeof(title) ~= "Instance"
    or title:IsA("TextLabel") ~= true then

        return false
    end

    local text =
        HolyCleanText(
            title.Text
        )

    local lower =
        text:lower()

    if lower == "inventory" then
        return true
    end

    if lower:find("fruit", 1, true) then
        return true
    end

    if text:match("%d+%s*/%s*%d+%s*[Ff]ruits") then
        return true
    end

    return false
end

function HolyVisualClearTotalValueLabel()

    local runtime =
        HolyVisualGetRuntime()

    if typeof(runtime.TotalValueLabel) == "Instance" then

        pcall(function()

            runtime.TotalValueLabel:Destroy()
        end)
    end

    runtime.TotalValueLabel =
        nil

    local inventory =
        HolyVisualGetBackpackInventory()

    if typeof(inventory) == "Instance" then

        for _, descendant in ipairs(inventory:GetDescendants()) do

            if descendant.Name == "HolyFruitTotalValueText"
            or descendant.Name == "HolyFruitTotalValueTestText" then

                pcall(function()

                    descendant:Destroy()
                end)
            end
        end
    end

    return true
end

function HolyVisualEnsureTotalValueLabel(title)

    local runtime =
        HolyVisualGetRuntime()

    local parent =
        typeof(title) == "Instance"
        and title.Parent
        or HolyVisualGetBackpackInventory()

    if typeof(parent) ~= "Instance" then
        return nil
    end

    local label =
        parent:FindFirstChild(
            "HolyFruitTotalValueText"
        )

    if typeof(label) ~= "Instance"
    or label:IsA("TextLabel") ~= true then

        HolyVisualClearTotalValueLabel()

        label =
            Instance.new(
                "TextLabel"
            )

        label.Name =
            "HolyFruitTotalValueText"

        label.BackgroundTransparency =
            1

        label.BorderSizePixel =
            0

        label.RichText =
            true

        label.Text =
            '<font color="#EAEAEA">|</font> <font color="#39FF14">$0</font>'

        label.TextStrokeColor3 =
            Color3.fromRGB(
                0,
                0,
                0
            )

        label.TextStrokeTransparency =
            0

        label.Font =
            Enum.Font.GothamBlack

        label.TextSize =
            32

        label.TextXAlignment =
            Enum.TextXAlignment.Left

        label.TextYAlignment =
            Enum.TextYAlignment.Center

        label.ZIndex =
            (
                tonumber(title and title.ZIndex)
                or 1
            )
            + 80

        label.Parent =
            parent
    end

    label.RichText =
        true

    runtime.TotalValueLabel =
        label

    return label
end

function HolyVisualPositionTotalValueLabel(label, title)

    if typeof(label) ~= "Instance"
    or label:IsA("GuiObject") ~= true
    or typeof(title) ~= "Instance"
    or title:IsA("GuiObject") ~= true then

        return false
    end

    local parent =
        label.Parent

    if typeof(parent) ~= "Instance"
    or parent:IsA("GuiObject") ~= true then

        return false
    end

    local titlePosition =
        title.AbsolutePosition

    local parentPosition =
        parent.AbsolutePosition

    local titleSize =
        title.AbsoluteSize

    local textBounds =
        title.TextBounds

    local x =
        titlePosition.X
        - parentPosition.X
        + math.min(
            titleSize.X - 140,
            textBounds.X + 14
        )

    local y =
        titlePosition.Y
        - parentPosition.Y
        + 1

    label.Position =
        UDim2.fromOffset(
            math.floor(x + 0.5),
            math.floor(y + 0.5)
        )

    label.Size =
        UDim2.fromOffset(
            330,
            math.max(
                36,
                math.floor(titleSize.Y + 0.5)
            )
        )

    label.TextSize =
        math.clamp(
            tonumber(title.TextSize)
            or 32,
            26,
            36
        )

    label.ZIndex =
        (
            tonumber(title.ZIndex)
            or 1
        )
        + 80

    return true
end

function HolyVisualRefreshTotalValueLabel()

    HolyVisualEnsureState()

    if HOLY_VISUAL_STATE.FruitTotalValue ~= true then

        HolyVisualClearTotalValueLabel()

        return false
    end

    local title =
        HolyVisualGetInventoryTitleLabel()

    if typeof(title) ~= "Instance"
    or HolyVisualTitleAllowsTotalValue(title) ~= true then

        local runtime =
            HolyVisualGetRuntime()

        if typeof(runtime.TotalValueLabel) == "Instance" then

            runtime.TotalValueLabel.Visible =
                false
        end

        return false
    end

    local _count,
        total =
        HolyVisualCalculateTotalFruitValue()

    local label =
        HolyVisualEnsureTotalValueLabel(
            title
        )

    if not label then
        return false
    end

    label.Text =
        '<font color="#EAEAEA">|</font> <font color="#39FF14">'
        .. HolyVisualFormatTotalFruitValue(
            total
        )
        .. '</font>'

    label.Visible =
        true

    HolyVisualPositionTotalValueLabel(
        label,
        title
    )

    return true
end

function HolyVisualRefreshFruitValueOverlay()

    HolyVisualEnsureState()

    if HOLY_VISUAL_STATE.FruitValueOverlay ~= true then

        HolyVisualClearAllFruitValueLabels()

        return false
    end

    local runtime =
        HolyVisualGetRuntime()

    local fruitMap =
        HolyVisualBuildFruitMaps()

    local touched =
        {}

    for _, root in ipairs(HolyVisualGetSlotRoots(false)) do

        local used =
            {}

        local slots =
            root:GetChildren()

        for _, slot in ipairs(slots) do

            if typeof(slot) == "Instance"
            and slot:IsA("GuiObject") then

                local row =
                    HolyVisualMatchSlotToFruit(
                        slot,
                        fruitMap,
                        used
                    )

                if row then

                    local label =
                        HolyVisualEnsureSlotLabel(
                            slot
                        )

                    if label then

                        label.Text =
                            tostring(row.ValueText)

                        label.Visible =
                            true

                        runtime.Labels[slot] =
                            label

                        touched[slot] =
                            true
                    end

                else

                    if runtime.Labels[slot] ~= nil
                    or slot:FindFirstChild("HolyFruitValueSlotText") then

                        HolyVisualRemoveSlotLabel(
                            slot
                        )
                    end
                end
            end
        end
    end

    for slot, label in pairs(runtime.Labels) do

        if touched[slot] ~= true
        or typeof(slot) ~= "Instance"
        or slot.Parent == nil
        or typeof(label) ~= "Instance"
        or label.Parent == nil then

            HolyVisualRemoveSlotLabel(
                slot
            )
        end
    end

    return true
end

function HolyVisualAnyInventoryOverlayEnabled()

    HolyVisualEnsureState()

    return HOLY_VISUAL_STATE.FruitValueOverlay == true
        or HOLY_VISUAL_STATE.FruitTotalValue == true
end

function HolyVisualStartInventoryOverlayWorker(reason)

    HolyVisualEnsureState()

    local runtime =
        HolyVisualGetRuntime()

    HolyVisualLoadValueCaches(
        false
    )

    if runtime.Running == true then

        if HOLY_VISUAL_STATE.FruitValueOverlay == true then

            HolyVisualRefreshFruitValueOverlay()
        end

        if HOLY_VISUAL_STATE.FruitTotalValue == true then

            HolyVisualRefreshTotalValueLabel()
        end

        return true
    end

    local token =
        {}

    runtime.Token =
        token

    runtime.Running =
        true

    task.spawn(function()

        while runtime.Token == token
        and HolyVisualAnyInventoryOverlayEnabled() == true do

            if HOLY_VISUAL_STATE.FruitValueOverlay == true then

                pcall(function()

                    HolyVisualRefreshFruitValueOverlay()
                end)
            end

            if HOLY_VISUAL_STATE.FruitTotalValue == true then

                pcall(function()

                    HolyVisualRefreshTotalValueLabel()
                end)
            end

            task.wait(
                runtime.UpdateDelay
            )
        end

        if runtime.Token == token then

            runtime.Running =
                false
        end

        if HOLY_VISUAL_STATE.FruitValueOverlay ~= true then

            HolyVisualClearAllFruitValueLabels()
        end

        if HOLY_VISUAL_STATE.FruitTotalValue ~= true then

            HolyVisualClearTotalValueLabel()
        end
    end)

    return true
end

function HolyVisualStopInventoryOverlayWorkerIfIdle()

    if HolyVisualAnyInventoryOverlayEnabled() == true then
        return false
    end

    local runtime =
        HolyVisualGetRuntime()

    runtime.Token =
        nil

    runtime.Running =
        false

    return true
end

function HolyVisualStartFruitValueOverlay(reason, skipSave)

    HolyVisualEnsureState()

    HOLY_VISUAL_STATE.FruitValueOverlay =
        true

    if skipSave ~= true then

        HolySaveVisualSettings()
    end

    HolyVisualClearAllFruitValueLabels()

    HolyVisualLoadValueCaches(
        true
    )

    HolyVisualStartInventoryOverlayWorker(
        reason or "fruit value overlay"
    )

    HolyVisualRefreshFruitValueOverlay()

    return true
end

function HolyVisualStopFruitValueOverlay(reason, skipSave)

    HolyVisualEnsureState()

    HOLY_VISUAL_STATE.FruitValueOverlay =
        false

    if skipSave ~= true then

        HolySaveVisualSettings()
    end

    HolyVisualClearAllFruitValueLabels()

    HolyVisualStopInventoryOverlayWorkerIfIdle()

    return true
end

function HolyVisualSetFruitValueOverlay(value)

    if value == true then

        return HolyVisualStartFruitValueOverlay(
            "toggle on",
            false
        )
    end

    return HolyVisualStopFruitValueOverlay(
        "toggle off",
        false
    )
end

function HolyVisualStartFruitTotalValue(reason, skipSave)

    HolyVisualEnsureState()

    HOLY_VISUAL_STATE.FruitTotalValue =
        true

    if skipSave ~= true then

        HolySaveVisualSettings()
    end

    HolyVisualClearTotalValueLabel()

    HolyVisualLoadValueCaches(
        true
    )

    HolyVisualStartInventoryOverlayWorker(
        reason or "fruit total value"
    )

    HolyVisualRefreshTotalValueLabel()

    return true
end

function HolyVisualStopFruitTotalValue(reason, skipSave)

    HolyVisualEnsureState()

    HOLY_VISUAL_STATE.FruitTotalValue =
        false

    if skipSave ~= true then

        HolySaveVisualSettings()
    end

    HolyVisualClearTotalValueLabel()

    HolyVisualStopInventoryOverlayWorkerIfIdle()

    return true
end

function HolyVisualSetFruitTotalValue(value)

    if value == true then

        return HolyVisualStartFruitTotalValue(
            "toggle on",
            false
        )
    end

    return HolyVisualStopFruitTotalValue(
        "toggle off",
        false
    )
end

function HolyVisualGardenRichEscape(value)

    local text =
        tostring(value or "")

    text =
        text:gsub("&", "&amp;")
            :gsub("<", "&lt;")
            :gsub(">", "&gt;")
            :gsub('"', "&quot;")
            :gsub("'", "&apos;")

    return text
end

function HolyVisualGardenCleanInstanceName(instance)

    local name =
        tostring(
            instance
            and instance.Name
            or ""
        )

    name =
        name:gsub(
            "^%d+_",
            ""
        )

    name =
        name:gsub(
            "_[%w]+%-%w+%-%w+%-%w+%-%w+$",
            ""
        )

    name =
        name:gsub(
            "[_%s]*Fruit$",
            ""
        )

    return HolyCleanText(
        name
    )
end

function HolyVisualGardenReadFruitName(plant, fruit)

    local name =
        ""

    if type(HolyFarmReadAttribute) == "function" then

        name =
            HolyFarmReadAttribute(
                fruit,
                {
                    "CorePartName",
                    "FruitName",
                    "SeedName",
                    "PlantName",
                    "CropName",
                    "DisplayName",
                    "ItemName",
                    "Name",
                }
            )
    end

    if name == ""
    and type(HolyFarmReadAttribute) == "function" then

        name =
            HolyFarmReadAttribute(
                plant,
                {
                    "SeedName",
                    "PlantName",
                    "CropName",
                    "FruitName",
                    "DisplayName",
                    "ItemName",
                    "Name",
                }
            )
    end

    if name == ""
    and type(HolyFarmReadPlantName) == "function" then

        name =
            HolyFarmReadPlantName(
                plant,
                fruit
            )
    end

    if name == ""
    or name == "Unknown" then

        name =
            HolyVisualGardenCleanInstanceName(
                fruit
            )
    end

    if name == ""
    or name == "Unknown" then

        name =
            HolyVisualGardenCleanInstanceName(
                plant
            )
    end

    return HolyCleanText(
        name
    )
end

function HolyVisualGardenReadNumberAttribute(instance, names)

    if type(HolyFarmReadNumberAttribute) == "function" then

        return HolyFarmReadNumberAttribute(
            instance,
            names
        )
    end

    if typeof(instance) ~= "Instance" then
        return nil
    end

    for _, name in ipairs(names or {}) do

        local ok,
            value =
            pcall(function()

                return instance:GetAttribute(
                    name
                )
            end)

        local number =
            tonumber(
                ok == true
                and value
                or nil
            )

        if number ~= nil then
            return number
        end
    end

    return nil
end

function HolyVisualGardenReadSizeMultiplier(plant, fruit, kind)

    local target =
        kind == "PlantHarvest"
        and plant
        or fruit

    local size =
        HolyVisualGardenReadNumberAttribute(
            target,
            {
                "SizeMultiplier",
                "SizeMulti",
                "ScaleMultiplier",
                "ScaleMulti",
                "Scale",
                "SizeScale",
            }
        )

    if size ~= nil
    and size > 0 then

        return size
    end

    if typeof(target) == "Instance"
    and target:IsA("Model") then

        local ok,
            result =
            pcall(function()

                return target:GetScale()
            end)

        result =
            tonumber(result)

        if ok == true
        and result ~= nil
        and result > 0 then

            return result
        end
    end

    return 1
end

function HolyVisualGardenReadWeightKg(plant, fruit, fruitName, sizeMultiplier, kind)

    local target =
        kind == "PlantHarvest"
        and plant
        or fruit

    local direct =
        HolyVisualGardenReadNumberAttribute(
            target,
            {
                "WeightKg",
                "WeightKG",
                "KG",
                "Kg",
                "Weight",
                "Mass",
            }
        )

    if direct ~= nil
    and direct > 0 then

        return direct
    end

    local plantDirect =
        HolyVisualGardenReadNumberAttribute(
            plant,
            {
                "WeightKg",
                "WeightKG",
                "KG",
                "Kg",
                "Weight",
                "Mass",
            }
        )

    if kind == "PlantHarvest"
    and plantDirect ~= nil
    and plantDirect > 0 then

        return plantDirect
    end

    local baseKg =
        nil

    if type(HolyFarmGetBaseKg) == "function" then

        baseKg =
            HolyFarmGetBaseKg(
                fruitName,
                kind
            )
    end

    baseKg =
        tonumber(baseKg)
        or 1

    return baseKg
        * (
            tonumber(sizeMultiplier)
            or 1
        )
end

function HolyVisualGardenSplitMutationText(value)

    local output =
        {}

    local text =
        HolyCleanText(
            value
        )

    if text == "" then
        return output
    end

    text =
        text:gsub("^%[", "")
            :gsub("%]$", "")
            :gsub("^%{", "")
            :gsub("%}$", "")

    for part in text:gmatch("[^,%|/;]+") do

        part =
            HolyCleanText(
                part
            )

        if part ~= "" then

            table.insert(
                output,
                part
            )
        end
    end

    if #output <= 0 then

        table.insert(
            output,
            text
        )
    end

    return output
end

function HolyVisualGardenReadRawAttribute(instance, names)

    if type(HolyFarmReadAttribute) == "function" then

        return HolyFarmReadAttribute(
            instance,
            names
        )
    end

    if typeof(instance) ~= "Instance" then
        return ""
    end

    for _, name in ipairs(names or {}) do

        local ok,
            value =
            pcall(function()

                return instance:GetAttribute(
                    name
                )
            end)

        value =
            HolyCleanText(
                ok == true
                and value
                or ""
            )

        if value ~= "" then
            return value
        end
    end

    return ""
end

function HolyVisualGardenReadInstanceMutations(instance)

    local output =
        {}

    local seen =
        {}

    if typeof(instance) ~= "Instance" then
        return output
    end

    for _, attributeName in ipairs({
        "Mutation",
        "Mutations",
        "Variant",
        "FruitVariant",
        "Type",
    }) do

        local raw =
            HolyVisualGardenReadRawAttribute(
                instance,
                {
                    attributeName,
                }
            )

        for _, part in ipairs(HolyVisualGardenSplitMutationText(raw)) do

            local mutation =
                ""

            if type(HolyFarmNormalizeMutationName) == "function" then

                mutation =
                    HolyFarmNormalizeMutationName(
                        part
                    )

            else

                mutation =
                    HolyCleanText(
                        part
                    )
            end

            if mutation ~= ""
            and seen[mutation] ~= true then

                seen[mutation] =
                    true

                table.insert(
                    output,
                    mutation
                )
            end
        end
    end

    table.sort(output, function(a, b)

        return tostring(a):lower()
            < tostring(b):lower()
    end)

    return output
end

function HolyVisualGardenReadMutations(plant, fruit, kind)

    if kind == "PlantHarvest" then

        return HolyVisualGardenReadInstanceMutations(
            plant
        )
    end

    -- Important: fruit ESP should not inherit plant mutations.
    return HolyVisualGardenReadInstanceMutations(
        fruit
    )
end

function HolyVisualGardenFindAdornee(instance)

    if typeof(instance) ~= "Instance" then
        return nil
    end

    if instance:IsA("BasePart") then
        return instance
    end

    local harvestPart =
        instance:FindFirstChild(
            "HarvestPart",
            true
        )

    if typeof(harvestPart) == "Instance" then

        if harvestPart:IsA("BasePart") then
            return harvestPart
        end

        local nested =
            harvestPart:FindFirstChildWhichIsA(
                "BasePart",
                true
            )

        if nested then
            return nested
        end
    end

    if instance:IsA("Model") then

        if instance.PrimaryPart then
            return instance.PrimaryPart
        end

        local rootPart =
            instance:FindFirstChild(
                "RootPart",
                true
            )

        if rootPart
        and rootPart:IsA("BasePart") then

            return rootPart
        end
    end

    return instance:FindFirstChildWhichIsA(
        "BasePart",
        true
    )
end

function HolyVisualGardenGetRootPart()

    local character =
        LocalPlayer
        and LocalPlayer.Character
        or nil

    if typeof(character) ~= "Instance" then
        return nil
    end

    return character:FindFirstChild(
        "HumanoidRootPart"
    )
    or character:FindFirstChild(
        "RootPart"
    )
    or character.PrimaryPart
end

function HolyVisualGardenGetDistance(adornee)

    if typeof(adornee) ~= "Instance"
    or adornee:IsA("BasePart") ~= true then

        return 0
    end

    local root =
        HolyVisualGardenGetRootPart()

    if typeof(root) ~= "Instance"
    or root:IsA("BasePart") ~= true then

        return 0
    end

    return (
        root.Position
        - adornee.Position
    ).Magnitude
end

function HolyVisualGardenSelectedFruitMap()

    HolyVisualEnsureState()

    local map =
        {}

    for _, fruitName in ipairs(HOLY_VISUAL_STATE.GardenFruitSelectedFruits or {}) do

        local normalized =
            ""

        if type(HolyFarmNormalizePlantName) == "function" then

            normalized =
                HolyFarmNormalizePlantName(
                    fruitName
                )

        else

            normalized =
                HolyCleanText(
                    fruitName
                )
        end

        if normalized ~= "" then

            map[normalized] =
                true
        end
    end

    return map
end

function HolyVisualGardenFruitAllows(fruitName)

    HolyVisualEnsureState()

    local mode =
        HolyVisualNormalizeGardenFruitMode(
            HOLY_VISUAL_STATE.GardenFruitMode
            or "All"
        )

    if mode == "All" then
        return true
    end

    fruitName =
        HolyCleanText(
            fruitName
        )

    local normalized =
        fruitName

    if type(HolyFarmNormalizePlantName) == "function" then

        normalized =
            HolyFarmNormalizePlantName(
                fruitName
            )
    end

    local selectedMap =
        HolyVisualGardenSelectedFruitMap()

    local hasSelected =
        false

    for _ in pairs(selectedMap) do

        hasSelected =
            true

        break
    end

    if mode == "Only Selected" then

        if hasSelected ~= true then
            return false
        end

        return selectedMap[normalized] == true
            or selectedMap[fruitName] == true
    end

    if mode == "Skip Selected" then

        if hasSelected ~= true then
            return true
        end

        return selectedMap[normalized] ~= true
            and selectedMap[fruitName] ~= true
    end

    return true
end

function HolyVisualGardenSelectedMutationMap()

    HolyVisualEnsureState()

    local map =
        {}

    for _, mutationName in ipairs(HOLY_VISUAL_STATE.GardenFruitSelectedMutations or {}) do

        local normalized =
            ""

        if type(HolyFarmNormalizeMutationName) == "function" then

            normalized =
                HolyFarmNormalizeMutationName(
                    mutationName
                )

        else

            normalized =
                HolyCleanText(
                    mutationName
                )
        end

        if normalized ~= "" then

            map[normalized] =
                true
        end
    end

    return map
end

function HolyVisualGardenMutationAllows(mutations)

    HolyVisualEnsureState()

    local mode =
        HolyVisualNormalizeGardenMutationMode(
            HOLY_VISUAL_STATE.GardenFruitMutationMode
            or "All"
        )

    local hasMutation =
        type(mutations) == "table"
        and #mutations > 0

    if mode == "All" then
        return true
    end

    if mode == "Only Mutated" then
        return hasMutation == true
    end

    local selectedMap =
        HolyVisualGardenSelectedMutationMap()

    local hasSelected =
        false

    for _ in pairs(selectedMap) do

        hasSelected =
            true

        break
    end

    if mode == "Only Selected" then

        if hasSelected ~= true then
            return false
        end

        for _, mutationName in ipairs(mutations or {}) do

            if selectedMap[mutationName] == true then
                return true
            end
        end

        return false
    end

    if mode == "Skip Selected" then

        if hasSelected ~= true then
            return true
        end

        for _, mutationName in ipairs(mutations or {}) do

            if selectedMap[mutationName] == true then
                return false
            end
        end

        return true
    end

    return true
end

function HolyVisualGardenWeightAllows(weight)

    HolyVisualEnsureState()

    local mode =
        "Off"

    if type(HolyFarmNormalizeWeightMode) == "function" then

        mode =
            HolyFarmNormalizeWeightMode(
                HOLY_VISUAL_STATE.GardenFruitWeightMode
                or "Off"
            )
    end

    if mode == "Off" then
        return true
    end

    local threshold =
        0

    if type(HolyFarmReadWeightThresholdKg) == "function" then

        threshold =
            HolyFarmReadWeightThresholdKg(
                HOLY_VISUAL_STATE.GardenFruitWeightThresholdKg
            )

    else

        threshold =
            tonumber(
                HOLY_VISUAL_STATE.GardenFruitWeightThresholdKg
            )
            or 0
    end

    if threshold <= 0 then
        return true
    end

    weight =
        tonumber(weight)
        or 0

    if mode == "Above" then
        return weight >= threshold
    end

    if mode == "Below" then
        return weight <= threshold
    end

    return true
end

function HolyVisualGardenValueAllows(value)

    HolyVisualEnsureState()

    local minValue =
        tonumber(
            HOLY_VISUAL_STATE.GardenFruitMinValue
        )
        or 0

    if minValue <= 0 then
        return true
    end

    return (
        tonumber(value)
        or 0
    ) >= minValue
end

function HolyVisualGardenCalculateValue(row)

    row =
        type(row) == "table"
        and row
        or {}

    row.RawMutation =
        table.concat(
            row.Mutations
            or {},
            ","
        )

    local value =
        HolyVisualCalculateFruitValue(
            row.Fruit,
            row
        )

    return math.max(
        0,
        tonumber(value)
        or 0
    )
end

function HolyVisualGardenFormatMoney(value)

    local number =
        math.max(
            0,
            tonumber(value)
            or 0
        )

    local suffix =
        ""

    if number >= 1000000000 then

        number =
            number / 1000000000

        suffix =
            "B"

    elseif number >= 1000000 then

        number =
            number / 1000000

        suffix =
            "M"

    elseif number >= 1000 then

        number =
            number / 1000

        suffix =
            "K"
    end

    if suffix ~= "" then

        local text =
            string.format(
                "%.3f",
                number
            )

        text =
            text:gsub("0+$", "")
                :gsub("%.$", "")

        return "$"
            .. text
            .. suffix
    end

    return "$"
        .. tostring(
            math.floor(number + 0.5)
        )
end

function HolyVisualGardenFormatKg(value)

    return string.format(
        "%.2fkg",
        tonumber(value)
        or 0
    )
end

function HolyVisualGardenKgColor(weight)

    weight =
        tonumber(weight)
        or 0

    if weight >= 100 then
        return "#FF2D2D"
    end

    if weight >= 50 then
        return "#FFD84A"
    end

    return "#D8D8D8"
end

function HolyVisualGardenMutationColor(mutationName)

    local key =
        HolyVisualNameKey(
            mutationName
        )

    local colors = {
        gold = "#FFD84A",
        rainbow = "#FF4DFF",
        electric = "#00E5FF",
        frozen = "#9CEBFF",
        bloodlit = "#FF3D3D",
        starstruck = "#FFF06A",
        aurora = "#B56CFF",
        solarflare = "#FF8A00",
        ignited = "#FF4B1F",
        chained = "#B8B8B8",
        pizza = "#FFB347",
    }

    return colors[key]
        or "#FFFFFF"
end

function HolyVisualGardenMutationEmoji(mutationName)

    local key =
        HolyVisualNameKey(
            mutationName
        )

    local emojis = {
        gold = "🥇",
        rainbow = "🌈",
        electric = "⚡",
        frozen = "❄️",
        bloodlit = "🩸",
        starstruck = "✨",
        aurora = "🟣",
        solarflare = "☀️",
        ignited = "🔥",
        chained = "⛓️",
        pizza = "🍕",
    }

    return emojis[key]
        or ""
end

function HolyVisualGardenBuildRichText(row)

    local lineOneParts =
        {}

    table.insert(
        lineOneParts,
        '<font color="#FFFFFF">'
            .. HolyVisualGardenRichEscape(row.Name)
            .. '</font>'
    )

    table.insert(
        lineOneParts,
        '<font color="'
            .. HolyVisualGardenKgColor(row.Weight)
            .. '">'
            .. HolyVisualGardenRichEscape(
                HolyVisualGardenFormatKg(
                    row.Weight
                )
            )
            .. '</font>'
    )

    if HOLY_VISUAL_STATE.GardenFruitShowValue == true then

        table.insert(
            lineOneParts,
            '<font color="#39FF14">['
                .. HolyVisualGardenRichEscape(
                    HolyVisualGardenFormatMoney(
                        row.Value
                    )
                )
                .. ']</font>'
        )
    end

    local lineOne =
        table.concat(
            lineOneParts,
            " "
        )

    local badges =
        {}

    for _, mutationName in ipairs(row.Mutations or {}) do

        local emoji =
            HolyVisualGardenMutationEmoji(
                mutationName
            )

        local prefix =
            emoji ~= ""
            and (
                emoji
                .. " "
            )
            or ""

        table.insert(
            badges,
            '<font color="'
                .. HolyVisualGardenMutationColor(mutationName)
                .. '">'
                .. HolyVisualGardenRichEscape(prefix .. mutationName)
                .. '</font>'
        )
    end

    if #badges > 0 then

        return lineOne
            .. "\n"
            .. table.concat(
                badges,
                "  "
            )
    end

    return lineOne
end

function HolyVisualGardenReadRow(plant, fruit, kind)

    if typeof(plant) ~= "Instance"
    or typeof(fruit) ~= "Instance"
    or fruit.Parent == nil then

        return nil
    end

    local adornee =
        HolyVisualGardenFindAdornee(
            fruit
        )

    if typeof(adornee) ~= "Instance"
    or adornee:IsA("BasePart") ~= true then

        return nil
    end

    local maxDistance =
        tonumber(
            HOLY_VISUAL_STATE.GardenFruitMaxDistance
        )
        or 150

    local distance =
        HolyVisualGardenGetDistance(
            adornee
        )

    if maxDistance > 0
    and distance > maxDistance then

        return nil
    end

    local fruitName =
        HolyVisualGardenReadFruitName(
            plant,
            fruit
        )

    if fruitName == ""
    or fruitName == "Unknown" then

        return nil
    end

    if HolyVisualGardenFruitAllows(
        fruitName
    ) ~= true then

        return nil
    end

    local sizeMultiplier =
        HolyVisualGardenReadSizeMultiplier(
            plant,
            fruit,
            kind
        )

    local weight =
        HolyVisualGardenReadWeightKg(
            plant,
            fruit,
            fruitName,
            sizeMultiplier,
            kind
        )

    if HolyVisualGardenWeightAllows(weight) ~= true then
        return nil
    end

    local mutations =
        HolyVisualGardenReadMutations(
            plant,
            fruit,
            kind
        )

    if HolyVisualGardenMutationAllows(mutations) ~= true then
        return nil
    end

    local row = {
        Key =
            fruit,

        Plant =
            plant,

        Fruit =
            fruit,

        Kind =
            kind,

        Adornee =
            adornee,

        Name =
            fruitName,

        RawMutation =
            table.concat(
                mutations,
                ","
            ),

        Mutations =
            mutations,

        Weight =
            tonumber(weight)
            or 0,

        SizeMultiplier =
            tonumber(sizeMultiplier)
            or 1,

        Distance =
            tonumber(distance)
            or 0,
    }

    row.Value =
        HolyVisualGardenCalculateValue(
            row
        )

    if HolyVisualGardenValueAllows(row.Value) ~= true then
        return nil
    end

    row.Score =
        (
            tonumber(row.Value)
            or 0
        )
        + (
            #mutations
            * 100000000
        )
        + (
            tonumber(row.Weight)
            or 0
        )
        * 250
        - (
            tonumber(row.Distance)
            or 0
        )

    return row
end

function HolyVisualGardenBuildRows()

    HolyVisualEnsureState()

    local rows =
        {}

    local plot =
        nil

    if type(HolyFarmResolveOwnPlot) == "function" then

        plot =
            HolyFarmResolveOwnPlot(
                false
            )
    end

    if typeof(plot) ~= "Instance" then
        return rows
    end

    local plantsFolder =
        plot:FindFirstChild(
            "Plants"
        )

    if typeof(plantsFolder) ~= "Instance" then
        return rows
    end

    for _, plant in ipairs(plantsFolder:GetChildren()) do

        if typeof(plant) == "Instance" then

            local fruitsFolder =
                plant:FindFirstChild(
                    "Fruits"
                )

            if typeof(fruitsFolder) == "Instance" then

                for _, fruit in ipairs(fruitsFolder:GetChildren()) do

                    local row =
                        HolyVisualGardenReadRow(
                            plant,
                            fruit,
                            "FruitHarvest"
                        )

                    if row then

                        table.insert(
                            rows,
                            row
                        )
                    end
                end

            elseif plant:FindFirstChild("HarvestPart", true) then

                local row =
                    HolyVisualGardenReadRow(
                        plant,
                        plant,
                        "PlantHarvest"
                    )

                if row then

                    table.insert(
                        rows,
                        row
                    )
                end
            end
        end
    end

    table.sort(rows, function(a, b)

        return tonumber(a.Score or 0)
            > tonumber(b.Score or 0)
    end)

    return rows
end

function HolyVisualGardenGetGui()

    local runtime =
        HolyVisualGetRuntime()

    if typeof(runtime.GardenFruitGui) == "Instance"
    and runtime.GardenFruitGui.Parent ~= nil then

        return runtime.GardenFruitGui
    end

    local playerGui =
        HolyVisualGetPlayerGui()

    if typeof(playerGui) ~= "Instance" then
        return nil
    end

    local oldGui =
        playerGui:FindFirstChild(
            "HolyGardenFruitESPGui"
        )

    if typeof(oldGui) == "Instance" then

        pcall(function()

            oldGui:Destroy()
        end)
    end

    local gui =
        Instance.new(
            "ScreenGui"
        )

    gui.Name =
        "HolyGardenFruitESPGui"

    gui.ResetOnSpawn =
        false

    gui.IgnoreGuiInset =
        true

    gui.DisplayOrder =
        999999

    gui.ZIndexBehavior =
        Enum.ZIndexBehavior.Global

    gui.Parent =
        playerGui

    runtime.GardenFruitGui =
        gui

    return gui
end

function HolyVisualGardenEnsureLabel(row)

    local runtime =
        HolyVisualGetRuntime()

    local gui =
        HolyVisualGardenGetGui()

    if typeof(gui) ~= "Instance" then
        return nil
    end

    local label =
        runtime.GardenFruitLabels[row.Key]

    if typeof(label) == "Instance"
    and label.Parent == gui then

        return label
    end

    label =
        Instance.new(
            "BillboardGui"
        )

    label.Name =
        "HolyGardenFruitESPLabel"

    label.AlwaysOnTop =
        true

    label.LightInfluence =
        0

    label.MaxDistance =
        tonumber(
            HOLY_VISUAL_STATE.GardenFruitMaxDistance
        )
        or 150

    label.Size =
        UDim2.fromOffset(
            285,
            44
        )

    label.StudsOffset =
        Vector3.new(
            0,
            2.2,
            0
        )

    label.Adornee =
        row.Adornee

    label.Parent =
        gui

    local text =
        Instance.new(
            "TextLabel"
        )

    text.Name =
        "Text"

    text.BackgroundTransparency =
        1

    text.Size =
        UDim2.fromScale(
            1,
            1
        )

    text.RichText =
        true

    text.Text =
        ""

    text.TextColor3 =
        Color3.fromRGB(
            255,
            255,
            255
        )

    text.TextStrokeColor3 =
        Color3.fromRGB(
            0,
            0,
            0
        )

    text.TextStrokeTransparency =
        0

    text.TextSize =
        12

    text.Font =
        Enum.Font.GothamBold

    text.TextXAlignment =
        Enum.TextXAlignment.Center

    text.TextYAlignment =
        Enum.TextYAlignment.Center

    text.ZIndex =
        10

    text.Parent =
        label

    runtime.GardenFruitLabels[row.Key] =
        label

    return label
end

function HolyVisualGardenRemoveLabel(key)

    local runtime =
        HolyVisualGetRuntime()

    local label =
        runtime.GardenFruitLabels[key]

    if typeof(label) == "Instance" then

        pcall(function()

            label:Destroy()
        end)
    end

    runtime.GardenFruitLabels[key] =
        nil
end

function HolyVisualClearGardenFruitESP()

    local runtime =
        HolyVisualGetRuntime()

    for key, label in pairs(runtime.GardenFruitLabels or {}) do

        if typeof(label) == "Instance" then

            pcall(function()

                label:Destroy()
            end)
        end

        runtime.GardenFruitLabels[key] =
            nil
    end

    if typeof(runtime.GardenFruitGui) == "Instance" then

        pcall(function()

            runtime.GardenFruitGui:Destroy()
        end)
    end

    runtime.GardenFruitGui =
        nil

    return true
end

function HolyVisualRefreshGardenFruitESP()

    HolyVisualEnsureState()

    if HOLY_VISUAL_STATE.GardenFruitESP ~= true then

        HolyVisualClearGardenFruitESP()

        return false
    end

    local runtime =
        HolyVisualGetRuntime()

    HolyVisualLoadValueCaches(
        false
    )

    if type(HolyFarmPrimeStaticCaches) == "function" then

        pcall(function()

            HolyFarmPrimeStaticCaches(
                false
            )
        end)
    end

    local rows =
        HolyVisualGardenBuildRows()

    local maxLabels =
        math.clamp(
            math.floor(
                tonumber(runtime.GardenFruitMaxLabels)
                or 160
            ),
            20,
            250
        )

    local touched =
        {}

    local shown =
        0

    for _, row in ipairs(rows) do

        if shown >= maxLabels then
            break
        end

        local label =
            HolyVisualGardenEnsureLabel(
                row
            )

        if label then

            label.Adornee =
                row.Adornee

            label.MaxDistance =
                tonumber(
                    HOLY_VISUAL_STATE.GardenFruitMaxDistance
                )
                or 150

            label.Size =
                UDim2.fromOffset(
                    285,
                    #row.Mutations > 0
                    and 44
                    or 28
                )

            local text =
                label:FindFirstChild(
                    "Text"
                )

            if typeof(text) == "Instance"
            and text:IsA("TextLabel") then

                text.Text =
                    HolyVisualGardenBuildRichText(
                        row
                    )

                text.TextSize =
                    12

                text.Font =
                    Enum.Font.GothamBold
            end

            label.Enabled =
                true

            touched[row.Key] =
                true

            shown =
                shown + 1
        end
    end

    local stale =
        {}

    for key in pairs(runtime.GardenFruitLabels or {}) do

        if touched[key] ~= true then

            table.insert(
                stale,
                key
            )
        end
    end

    for _, key in ipairs(stale) do

        HolyVisualGardenRemoveLabel(
            key
        )
    end

    return true
end

function HolyVisualStartGardenFruitESP(reason, skipSave)

    HolyVisualEnsureState()

    HOLY_VISUAL_STATE.GardenFruitESP =
        true

    if skipSave ~= true then

        HolySaveVisualSettings()
    end

    local runtime =
        HolyVisualGetRuntime()

    HolyVisualLoadValueCaches(
        true
    )

    if runtime.GardenFruitRunning == true then

        HolyVisualRefreshGardenFruitESP()

        return true
    end

    local token =
        {}

    runtime.GardenFruitToken =
        token

    runtime.GardenFruitRunning =
        true

    task.spawn(function()

        while runtime.GardenFruitToken == token
        and HOLY_VISUAL_STATE.GardenFruitESP == true do

            pcall(function()

                HolyVisualRefreshGardenFruitESP()
            end)

            task.wait(
                runtime.GardenFruitUpdateDelay
            )
        end

        if runtime.GardenFruitToken == token then

            runtime.GardenFruitRunning =
                false
        end

        if HOLY_VISUAL_STATE.GardenFruitESP ~= true then

            HolyVisualClearGardenFruitESP()
        end
    end)

    HolyVisualRefreshGardenFruitESP()

    return true
end

function HolyVisualStopGardenFruitESP(reason, skipSave)

    HolyVisualEnsureState()

    HOLY_VISUAL_STATE.GardenFruitESP =
        false

    if skipSave ~= true then

        HolySaveVisualSettings()
    end

    local runtime =
        HolyVisualGetRuntime()

    runtime.GardenFruitToken =
        nil

    runtime.GardenFruitRunning =
        false

    HolyVisualClearGardenFruitESP()

    return true
end

function HolyVisualSetGardenFruitESP(value)

    if value == true then

        return HolyVisualStartGardenFruitESP(
            "toggle on",
            false
