function HolyVisualSprinklerColorToHex(color)

    return string.format(
        "#%02X%02X%02X",
        math.floor(
            color.R * 255
        ),
        math.floor(
            color.G * 255
        ),
        math.floor(
            color.B * 255
        )
    )
end

function HolyVisualSprinklerFormatTime(seconds)

    seconds =
        math.max(
            0,
            math.floor(
                tonumber(seconds)
                or 0
            )
        )

    local yearSeconds =
        365 * 24 * 60 * 60

    local daySeconds =
        24 * 60 * 60

    local hourSeconds =
        60 * 60

    local years =
        math.floor(
            seconds / yearSeconds
        )

    seconds =
        seconds % yearSeconds

    local days =
        math.floor(
            seconds / daySeconds
        )

    seconds =
        seconds % daySeconds

    local hours =
        math.floor(
            seconds / hourSeconds
        )

    seconds =
        seconds % hourSeconds

    local minutes =
        math.floor(
            seconds / 60
        )

    local remainingSeconds =
        seconds % 60

    if years > 0 then

        return string.format(
            "%dy %dd · %02dh %02dm %02ds",
            years,
            days,
            hours,
            minutes,
            remainingSeconds
        )
    end

    if days > 0 then

        return string.format(
            "%dd · %02dh %02dm %02ds",
            days,
            hours,
            minutes,
            remainingSeconds
        )
    end

    if hours > 0 then

        return string.format(
            "%dh · %02dm %02ds",
            hours,
            minutes,
            remainingSeconds
        )
    end

    if minutes > 0 then

        return string.format(
            "%dm %02ds",
            minutes,
            remainingSeconds
        )
    end

    return string.format(
        "%ds",
        remainingSeconds
    )
end

function HolyVisualSprinklerGetFunctionUpvalues(func)

    local getter =
        type(debug) == "table"
        and debug.getupvalues
        or getupvalues

    if type(getter) ~= "function" then
        return {}
    end

    local success,
        result =
        pcall(function()

            return getter(
                func
            )
        end)

    return success
        and result
        or {}
end

function HolyVisualSprinklerIsTimerData(tbl)

    if type(tbl) ~= "table" then
        return false
    end

    local checked =
        0

    for key, value in pairs(tbl) do

        checked =
            checked + 1

        if type(key) == "string"
        and type(value) == "table"
        and type(value.PlacedAt) == "number"
        and type(value.Lifetime) == "number" then

            return true
        end

        if checked >= 100 then
            break
        end
    end

    return false
end

function HolyVisualSprinklerResolveTimerData()

    local runtime =
        HolyVisualGetRuntime()

    if HolyVisualSprinklerIsTimerData(
        runtime.SprinklerTimerData
    ) then

        return runtime.SprinklerTimerData
    end

    local playerScripts =
        LocalPlayer
        and LocalPlayer:FindFirstChild(
            "PlayerScripts"
        )

    local controllers =
        playerScripts
        and playerScripts:FindFirstChild(
            "Controllers"
        )

    local controllerModule =
        controllers
        and controllers:FindFirstChild(
            "SprinklerVisualizerController"
        )

    if typeof(controllerModule) ~= "Instance"
    or not controllerModule:IsA("ModuleScript") then

        return nil
    end

    local success,
        controller =
        pcall(function()

            return require(
                controllerModule
            )
        end)

    if success ~= true
    or type(controller) ~= "table" then

        return nil
    end

    local updateFunction =
        controller.UpdateSprinklerTimers

    if type(updateFunction) ~= "function" then
        return nil
    end

    for _, upvalue in pairs(
        HolyVisualSprinklerGetFunctionUpvalues(
            updateFunction
        )
    ) do

        if HolyVisualSprinklerIsTimerData(
            upvalue
        ) then

            runtime.SprinklerTimerData =
                upvalue

            return runtime.SprinklerTimerData
        end
    end

    return nil
end

function HolyVisualSprinklerGetOwnGarden()

    local gardens =
        Workspace:FindFirstChild(
            "Gardens"
        )

    if typeof(gardens) ~= "Instance" then
        return nil
    end

    for _, garden in ipairs(
        gardens:GetChildren()
    ) do

        if garden:GetAttribute(
            "OwnerUserId"
        ) == LocalPlayer.UserId then

            return garden
        end
    end

    return nil
end

function HolyVisualSprinklerGetAdornee(model)

    if typeof(model) ~= "Instance" then
        return nil
    end

    local root =
        model:FindFirstChild(
            "Root"
        )

    if typeof(root) == "Instance"
    and root:IsA("BasePart") then

        return root
    end

    if model:IsA("Model")
    and typeof(model.PrimaryPart) == "Instance" then

        return model.PrimaryPart
    end

    return model:FindFirstChildWhichIsA(
        "BasePart",
        true
    )
end

function HolyVisualSprinklerHideDefaultTimer(model)

    local runtime =
        HolyVisualGetRuntime()

    local timerGui =
        model
        and model:FindFirstChild(
            "SprinklerTimerUI"
        )

    if typeof(timerGui) == "Instance"
    and timerGui:IsA("BillboardGui") then

        if runtime.SprinklerTimerOriginalStates[
            timerGui
        ] == nil then

            runtime.SprinklerTimerOriginalStates[
                timerGui
            ] =
                timerGui.Enabled
        end

        timerGui.Enabled =
            false
    end
end

function HolyVisualSprinklerRestoreDefaultTimers()

    local runtime =
        HolyVisualGetRuntime()

    for timerGui, originalState in pairs(
        runtime.SprinklerTimerOriginalStates
        or {}
    ) do

        if typeof(timerGui) == "Instance"
        and timerGui.Parent then

            pcall(function()

                timerGui.Enabled =
                    originalState
            end)
        end

        runtime.SprinklerTimerOriginalStates[
            timerGui
        ] =
            nil
    end

    return true
end

