function HolyVisualClearSprinklerTimerESP()

    local runtime =
        HolyVisualGetRuntime()

    local models =
        {}

    for model in pairs(
        runtime.SprinklerTimerLabels
        or {}
    ) do

        table.insert(
            models,
            model
        )
    end

    for _, model in ipairs(models) do

        HolyVisualSprinklerRemoveLabel(
            model
        )
    end

    HolyVisualSprinklerRestoreDefaultTimers()

    return true
end

function HolyVisualSprinklerApplyESPScale(billboard)

    if typeof(billboard) ~= "Instance"
    or billboard:IsA("BillboardGui") ~= true then

        return false
    end

    local percent =
        HolyVisualReadSprinklerESPScale(
            HOLY_VISUAL_STATE.SprinklerTimerESPScale
            or "80"
        )

    local scale =
        percent / 100

    billboard.Size =
        UDim2.fromOffset(
            205 * scale,
            46 * scale
        )

    local background =
        billboard:FindFirstChild(
            "Background"
        )

    if typeof(background) ~= "Instance" then
        return true
    end

    local corner =
        background:FindFirstChildOfClass(
            "UICorner"
        )

    if typeof(corner) == "Instance" then

        corner.CornerRadius =
            UDim.new(
                0,
                6 * scale
            )
    end

    local stroke =
        background:FindFirstChild(
            "Stroke"
        )

    if typeof(stroke) == "Instance"
    and stroke:IsA("UIStroke") then

        stroke.Thickness =
            scale
    end

    local text =
        background:FindFirstChild(
            "Text"
        )

    if typeof(text) == "Instance"
    and text:IsA("TextLabel") then

        text.Size =
            UDim2.new(
                1,
                -8 * scale,
                1,
                -4 * scale
            )

        text.Position =
            UDim2.fromOffset(
                4 * scale,
                2 * scale
            )

        text.TextSize =
            14 * scale
    end

    return true
end

