    billboard.Parent =
        model

    local background =
        Instance.new(
            "Frame"
        )

    background.Name =
        "Background"

    background.Size =
        UDim2.fromScale(
            1,
            1
        )

    background.BackgroundColor3 =
        Color3.fromRGB(
            8,
            8,
            11
        )

    background.BackgroundTransparency =
        0.42

    background.BorderSizePixel =
        0

    background.Parent =
        billboard

    local corner =
        Instance.new(
            "UICorner"
        )

    corner.CornerRadius =
        UDim.new(
            0,
            6
        )

    corner.Parent =
        background

    local stroke =
        Instance.new(
            "UIStroke"
        )

    stroke.Name =
        "Stroke"

    stroke.Color =
        style.Color

    stroke.Transparency =
        0.5

    stroke.Thickness =
        1

    stroke.Parent =
        background

    local text =
        Instance.new(
            "TextLabel"
        )

    text.Name =
        "Text"

    text.Size =
        UDim2.new(
            1,
            -8,
            1,
            -4
        )

    text.Position =
        UDim2.fromOffset(
            4,
            2
        )

    text.BackgroundTransparency =
        1

    text.RichText =
        true

    text.Text =
        "Loading..."

    text.TextColor3 =
        Color3.fromRGB(
            255,
            255,
            255
        )

    text.TextSize =
        14

    text.TextScaled =
        false

    text.TextWrapped =
        false

    text.TextStrokeColor3 =
        Color3.fromRGB(
            0,
            0,
            0
        )

    text.TextStrokeTransparency =
        0.38

    text.Font =
        Enum.Font.GothamBold

    text.TextXAlignment =
        Enum.TextXAlignment.Center

    text.TextYAlignment =
        Enum.TextYAlignment.Center

    text.Parent =
        background

    HolyVisualSprinklerApplyESPScale(
        billboard
    )

    runtime.SprinklerTimerLabels[
        model
    ] =
