    return true
end

--==================================================
-- ROLLBACK SYSTEM
--==================================================

function HolyRollbackResolvePacket()

    local runtime =
        HOLY_ROLLBACK_RUNTIME

    if type(runtime.Packet) == "table"
    and type(runtime.Packet.Fire) == "function" then

        return runtime.Packet
    end

    local networking =
        nil

    if type(HolyShopRequireModule) == "function" then

        networking =
            HolyShopRequireModule(
                "SharedModules.Networking"
            )
    end

    if type(networking) ~= "table" then

        local sharedModules =
            ReplicatedStorage:FindFirstChild(
                "SharedModules"
            )

        local networkingModule =
            sharedModules
            and sharedModules:FindFirstChild(
                "Networking"
            )

        if typeof(networkingModule) == "Instance"
        and networkingModule:IsA("ModuleScript") then

            local success,
                result =
                pcall(function()

                    return require(
                        networkingModule
                    )
                end)

            if success == true
            and type(result) == "table" then

                networking =
                    result
            end
        end
    end

    local packet =
        type(networking) == "table"
        and type(networking.SignTool) == "table"
        and networking.SignTool.SetSignImage
        or nil

    if type(packet) ~= "table"
    or type(packet.Fire) ~= "function" then

        warn(
            "[HOLY Rollback] SetSignImage packet is missing."
        )

        return nil
    end

    runtime.Packet =
        packet

    return packet
end

function HolyRollbackFire(payload)

    local packet =
        HolyRollbackResolvePacket()

    if packet == nil then
        return false
    end

    local success,
        errorMessage =
        pcall(function()

            packet:Fire(
                payload
            )
        end)

    if success ~= true then

        warn(
            "[HOLY Rollback] "
            .. tostring(errorMessage)
        )
    end

    return success == true
end

function HolyRollbackHasAnyOwner()

    local runtime =
        HOLY_ROLLBACK_RUNTIME

    return runtime.ManualRequested == true
        or runtime.WateringRequested == true
        or runtime.PersistenceRequested == true
end

function HolyRollbackRefreshWorker()

    local state =
        HOLY_ROLLBACK_STATE

    local runtime =
        HOLY_ROLLBACK_RUNTIME

    if HolyRollbackHasAnyOwner() ~= true then

        runtime.Running =
            false

        runtime.Generation +=
            1

        HolyRollbackFire(
            ""
        )

        return true
    end

    local packet =
        HolyRollbackResolvePacket()

    if packet == nil then

        runtime.Running =
            false

        return false
    end

    if runtime.Running == true then

        return true
    end

    runtime.Running =
        true

    runtime.Generation +=
        1

    local generation =
        runtime.Generation

    task.spawn(function()

        while runtime.Running == true
        and runtime.Generation == generation
        and HolyRollbackHasAnyOwner() == true do

            local success =
                HolyRollbackFire(
                    string.char(255)
                )

            if success ~= true then

                runtime.Running =
                    false

                runtime.Generation +=
                    1

                break
            end

            local delay =
                10

            if runtime.ManualRequested == true then

                delay =
                    math.min(
                        delay,
                        math.clamp(
                            tonumber(
                                state.FireDelay
                            )
                            or 0.1,
                            0,
                            10
                        )
                    )
            end

            if runtime.WateringRequested == true then

                delay =
                    math.min(
                        delay,
                        math.clamp(
                            tonumber(
                                runtime.WateringFireDelay
                            )
                            or 0.1,
                            0,
                            10
                        )
                    )
            end

            if runtime.PersistenceRequested == true then

                delay =
                    math.min(
                        delay,
                        0.1
                    )
            end

            task.wait(
                delay
            )
        end

        if runtime.Generation == generation then

            runtime.Running =
                false
        end
    end)

    return true
end

function HolyRollbackSetOwner(
    owner,
    value
)

    local state =
        HOLY_ROLLBACK_STATE

    local runtime =
        HOLY_ROLLBACK_RUNTIME

    value =
        value == true

    if owner == "Manual" then

        runtime.ManualRequested =
            value

        state.Enabled =
            value

    elseif owner == "Watering" then

        runtime.WateringRequested =
            value

    elseif owner == "Persistence" then

        runtime.PersistenceRequested =
            value

    else

        return false
    end

    if HolyRollbackHasAnyOwner() == true then

        return HolyRollbackRefreshWorker()
    end

    runtime.Running =
        false

    runtime.Generation +=
        1

    HolyRollbackFire(
        ""
    )

    return true
end

function HolyRollbackStop(reason)

    return HolyRollbackSetOwner(
        "Manual",
        false
    )
end

function HolyRollbackStart(reason)

    return HolyRollbackSetOwner(
        "Manual",
        true
    )
end

function HolyRollbackSetEnabled(value)

    return HolyRollbackSetOwner(
        "Manual",
        value == true
    )
end

function HolyRollbackStopAll(reason)

    local state =
        HOLY_ROLLBACK_STATE

    local runtime =
        HOLY_ROLLBACK_RUNTIME

    state.Enabled =
        false

    runtime.ManualRequested =
        false

    runtime.WateringRequested =
        false

    runtime.PersistenceRequested =
        false

    runtime.Running =
        false

    runtime.Generation +=
        1

    HolyRollbackFire(
        ""
    )

    return true
end

function HolyRollbackSetFireDelay(value)

    HOLY_ROLLBACK_STATE.FireDelay =
        math.clamp(
            tonumber(value)
            or 0.1,
            0,
            10
        )

    return HOLY_ROLLBACK_STATE.FireDelay
end

HOLY_ROLLBACK_RUNTIME.Stop =
    HolyRollbackStopAll

--==================================================
-- WATERING REJOIN SYSTEM
--==================================================

function HolyWateringRejoinNormalizeState()

    local state =
        HOLY_WATERING_REJOIN_STATE

    state.Enabled =
        state.Enabled == true

    if state.WateringCan ~= "Common Watering Can"
    and state.WateringCan ~= "Super Watering Can" then

        state.WateringCan =
            "Super Watering Can"
    end

    if state.UseMode ~= "All Available"
    and state.UseMode ~= "Custom Amount" then

        state.UseMode =
            "All Available"
    end

    local useAmount =
        tonumber(
            state.UseAmount
        )

    if not useAmount
    or useAmount ~= useAmount
    or useAmount == math.huge
    or useAmount == -math.huge then

        useAmount =
            1
    end

    state.UseAmount =
        math.max(
            1,
            math.floor(
                useAmount
            )
        )

    if state.WateringMode ~= "Delay"
    and state.WateringMode ~= "Decay" then

        state.WateringMode =
            "Delay"
    end

    state.WateringDelay =
        math.clamp(
            tonumber(
                state.WateringDelay
            )
            or 3,
            0.1,
            10
        )

    state.RejoinDelay =
        math.clamp(
            tonumber(
                state.RejoinDelay
            )
            or 5,
            1,
            60
        )

    if state.MovementMode ~= "Walk"
    and state.MovementMode ~= "Tween" then

        state.MovementMode =
            "Tween"
    end

    state.TweenSpeed =
        math.clamp(
            tonumber(
                state.TweenSpeed
            )
            or 30,
            5,
            100
        )

    state.HidePlants =
        state.HidePlants ~= false

    if state.AvoidPlantAttacksMode ~= "Off"
    and state.AvoidPlantAttacksMode ~= "Night Only"
    and state.AvoidPlantAttacksMode ~= "Always" then

        state.AvoidPlantAttacksMode =
            "Night Only"
    end

    state.RetreatDistance =
        math.clamp(
            tonumber(
                state.RetreatDistance
            )
            or 30,
            15,
            80
        )

    state.TargetUsername =
        tostring(
            state.TargetUsername
            or ""
        )

    state.TargetOwnerUserId =
        tonumber(
            state.TargetOwnerUserId
        )

    if type(state.StandOffset) ~= "table" then

        state.StandOffset =
            nil
    end

    if type(state.AimOffset) ~= "table" then

        state.AimOffset =
            nil
    end

    return state
end

function HolyWateringRejoinHasSetup()

    local state =
        HolyWateringRejoinNormalizeState()

    return tonumber(
        state.TargetOwnerUserId
    ) ~= nil
        and type(state.StandOffset) == "table"
        and #state.StandOffset == 12
        and type(state.AimOffset) == "table"
end

function HolyWateringRejoinSaveSettings()

    if HolyCanUseFiles() ~= true then
        return false
    end

    HolyEnsureFolder()

    local state =
        HolyWateringRejoinNormalizeState()

    local payload = {
        Version = 5,

        Enabled =
            state.Enabled == true,

        WateringCan =
            state.WateringCan,

        ToolName =
            state.WateringCan,

        UseMode =
            state.UseMode,

        UseAmount =
            state.UseAmount,

        WateringMode =
            state.WateringMode,

        WateringDelay =
            state.WateringDelay,

        RejoinDelay =
            state.RejoinDelay,

        MovementMode =
            state.MovementMode,

        TweenSpeed =
            state.TweenSpeed,

        HidePlants =
            state.HidePlants == true,

        AvoidPlantAttacksMode =
            state.AvoidPlantAttacksMode,

        RetreatDistance =
            state.RetreatDistance,

        TargetUsername =
            state.TargetUsername,

        TargetOwnerUserId =
            state.TargetOwnerUserId,

        StandOffset =
            state.StandOffset,

        AimOffset =
            state.AimOffset,
    }

    local encodeSuccess,
        encoded =
        pcall(function()

            return HttpService:JSONEncode(
                payload
            )
        end)

    if encodeSuccess ~= true
    or type(encoded) ~= "string" then

        return false
    end

    local writeSuccess =
        pcall(function()

            writefile(
                WATERING_REJOIN_SETTINGS_FILE,
                encoded
            )
        end)

    return writeSuccess == true
end

function HolyWateringRejoinLoadSettings()

    if HolyCanUseFiles() ~= true then
        return false
    end

    local selectedFile =
        nil

    pcall(function()

        if isfile(
            WATERING_REJOIN_SETTINGS_FILE
        ) then

            selectedFile =
                WATERING_REJOIN_SETTINGS_FILE
        elseif isfile(
            WATERING_REJOIN_LEGACY_FILE
        ) then

            selectedFile =
                WATERING_REJOIN_LEGACY_FILE
        end
    end)

    if not selectedFile then
        return false
    end

    local readSuccess,
        raw =
        pcall(function()

            return readfile(
                selectedFile
            )
        end)

    if readSuccess ~= true
    or type(raw) ~= "string" then

        return false
    end

    local decodeSuccess,
        data =
        pcall(function()

            return HttpService:JSONDecode(
                raw
            )
        end)

    if decodeSuccess ~= true
    or type(data) ~= "table" then

        return false
    end

    local state =
        HOLY_WATERING_REJOIN_STATE

    state.Enabled =
        data.Enabled == true

    state.WateringCan =
        tostring(
            data.WateringCan
            or data.ToolName
            or state.WateringCan
        )

    state.UseMode =
        tostring(
            data.UseMode
            or state.UseMode
            or "All Available"
        )

    state.UseAmount =
        tonumber(
            data.UseAmount
        )
        or state.UseAmount
        or 1

    state.WateringMode =
        tostring(
            data.WateringMode
            or state.WateringMode
        )

    state.WateringDelay =
        tonumber(
            data.WateringDelay
        )
        or state.WateringDelay

    state.RejoinDelay =
        tonumber(
            data.RejoinDelay
        )
        or state.RejoinDelay

    state.MovementMode =
        tostring(
            data.MovementMode
            or state.MovementMode
            or "Tween"
        )

    state.TweenSpeed =
        tonumber(
            data.TweenSpeed
        )
        or state.TweenSpeed
        or 30

    if data.HidePlants ~= nil then

        state.HidePlants =
            data.HidePlants == true
    end

    if data.AvoidPlantAttacksMode ~= nil then

        state.AvoidPlantAttacksMode =
            tostring(
                data.AvoidPlantAttacksMode
            )

    elseif data.AvoidPlantAttacks ~= nil then

        state.AvoidPlantAttacksMode =
            data.AvoidPlantAttacks == true
            and "Night Only"
            or "Off"
    end

    state.RetreatDistance =
        tonumber(
            data.RetreatDistance
        )
        or state.RetreatDistance
        or 30

    state.TargetUsername =
        tostring(
            data.TargetUsername
            or state.TargetUsername
            or ""
        )

    state.TargetOwnerUserId =
        tonumber(
            data.TargetOwnerUserId
        )

    state.StandOffset =
        type(data.StandOffset) == "table"
        and data.StandOffset
        or nil

    state.AimOffset =
        type(data.AimOffset) == "table"
        and data.AimOffset
        or nil

    HolyWateringRejoinNormalizeState()

    if HolyWateringRejoinHasSetup() ~= true then

        state.Enabled =
            false
    end

    if selectedFile == WATERING_REJOIN_LEGACY_FILE then

        HolyWateringRejoinSaveSettings()
    end

    return true
end

function HolyWateringRejoinCFrameToData(value)

    if typeof(value) ~= "CFrame" then
        return nil
    end

    return {
        value:GetComponents()
    }
end

function HolyWateringRejoinDataToCFrame(value)

    if type(value) ~= "table"
    or #value ~= 12 then

        return nil
    end

    return CFrame.new(
        table.unpack(
            value
        )
    )
end

function HolyWateringRejoinVectorToData(value)

    if typeof(value) ~= "Vector3" then
        return nil
    end

    return {
        X = value.X,
        Y = value.Y,
        Z = value.Z,
    }
end

function HolyWateringRejoinDataToVector(value)

    if type(value) ~= "table" then
        return nil
    end

    local x =
        tonumber(value.X)

    local y =
        tonumber(value.Y)

    local z =
        tonumber(value.Z)

    if not x
    or not y
    or not z then

        return nil
    end

    return Vector3.new(
        x,
        y,
        z
    )
end

function HolyWateringRejoinGetCharacter()

    local character =
        LocalPlayer.Character

    if typeof(character) ~= "Instance" then
        return nil
    end

    local humanoid =
        character:FindFirstChildOfClass(
            "Humanoid"
        )

    local root =
        character:FindFirstChild(
            "HumanoidRootPart"
        )

    return character,
        humanoid,
        root
end

function HolyWateringRejoinFindTool(toolName)

    toolName =
        tostring(
            toolName
            or HOLY_WATERING_REJOIN_STATE.WateringCan
        )

    local character =
        LocalPlayer.Character

    local backpack =
        LocalPlayer:FindFirstChildOfClass(
            "Backpack"
        )

    return (
        character
        and character:FindFirstChild(
            toolName
        )
    )
        or (
            backpack
            and backpack:FindFirstChild(
                toolName
            )
        )
end

function HolyWateringRejoinFindUsableTool(toolName)

    toolName =
        tostring(
            toolName
            or HOLY_WATERING_REJOIN_STATE.WateringCan
        )

    local function scanContainer(container)

        if typeof(container) ~= "Instance" then

            return nil,
                0
        end

        for _, object in ipairs(
            container:GetChildren()
        ) do

            if object.Name == toolName
            and object:IsA("Tool") then

                local count =
                    tonumber(
                        object:GetAttribute(
                            "Count"
                        )
                    )
                    or 0

                if count > 0 then

                    return object,
                        count
                end
            end
        end

        return nil,
            0
    end

    local characterTool,
        characterCount =
        scanContainer(
            LocalPlayer.Character
        )

    if characterTool then

        return characterTool,
            characterCount
    end

    local backpack =
        LocalPlayer:FindFirstChildOfClass(
            "Backpack"
        )

    return scanContainer(
        backpack
    )
end

function HolyWateringRejoinEquipTool(tool)

    local character,
        humanoid =
        HolyWateringRejoinGetCharacter()

    if typeof(character) ~= "Instance"
    or typeof(humanoid) ~= "Instance"
    or typeof(tool) ~= "Instance"
    or tool:IsA("Tool") ~= true then

        return false
    end

    if tool.Parent ~= character then

        humanoid:EquipTool(
            tool
        )

        task.wait(
            0.25
        )
    end

    return tool.Parent == character
end

function HolyWateringRejoinResolvePacket()

    local runtime =
        HOLY_WATERING_REJOIN_RUNTIME

    if type(runtime.Packet) == "table"
    and type(runtime.Packet.Fire) == "function" then

        return runtime.Packet
    end

    local networking =
        nil

    if type(HolyShopRequireModule) == "function" then

        networking =
            HolyShopRequireModule(
                "SharedModules.Networking"
            )
    end

    if type(networking) ~= "table" then

        local sharedModules =
            ReplicatedStorage:FindFirstChild(
                "SharedModules"
            )

        local networkingModule =
            sharedModules
            and sharedModules:FindFirstChild(
                "Networking"
            )

        if typeof(networkingModule) == "Instance"
        and networkingModule:IsA("ModuleScript") then

            local success,
                result =
                pcall(function()

                    return require(
                        networkingModule
                    )
                end)

            if success == true
            and type(result) == "table" then

                networking =
                    result
            end
        end
    end

    local packet =
        type(networking) == "table"
        and type(networking.WateringCan) == "table"
        and networking.WateringCan.UseWateringCan
        or nil

    if type(packet) ~= "table"
    or type(packet.Fire) ~= "function" then

        warn(
            "[HOLY Watering Rejoin] UseWateringCan packet is missing."
        )

        return nil
    end

    runtime.Packet =
        packet

    return packet
end

function HolyWateringRejoinGetGardenAnchor(garden)

    if typeof(garden) ~= "Instance" then
        return nil
    end

    local visual =
        garden:FindFirstChild(
            "Visual"
        )

    local anchor =
        visual
        and visual:FindFirstChild(
            "GardenZonePart"
        )

    if not anchor then

        anchor =
            garden:FindFirstChild(
                "GardenZonePart",
                true
            )
    end

    if typeof(anchor) == "Instance"
    and anchor:IsA("BasePart") then

        return anchor.CFrame,
            anchor
    end

    return nil
end

function HolyWateringRejoinGetGardenOwner(garden)

    if typeof(garden) ~= "Instance" then
        return nil
    end

    local ownerUserId =
        tonumber(
            garden:GetAttribute(
                "OwnerUserId"
            )
        )

    local ownerName =
        tostring(
            garden:GetAttribute(
                "Owner"
            )
            or ""
        )

    if not ownerUserId
    and ownerName ~= "" then

        local ownerPlayer =
            Players:FindFirstChild(
                ownerName
            )

        if ownerPlayer then

            ownerUserId =
                ownerPlayer.UserId
        else

            pcall(function()

                ownerUserId =
                    Players:GetUserIdFromNameAsync(
                        ownerName
                    )
            end)
        end
    end

    if ownerUserId
    and ownerName == "" then

        local ownerPlayer =
            Players:GetPlayerByUserId(
                ownerUserId
            )

        if ownerPlayer then

            ownerName =
                ownerPlayer.Name
        end
    end

    return ownerUserId,
        ownerName
end

function HolyWateringRejoinFindGardenByOwner(
    ownerUserId,
    ownerName
)

    local gardens =
        workspace:FindFirstChild(
            "Gardens"
        )

    if not gardens then
        return nil
    end

    for _, garden in ipairs(
        gardens:GetChildren()
    ) do

        local gardenOwnerUserId =
            tonumber(
                garden:GetAttribute(
                    "OwnerUserId"
                )
            )

        local gardenOwnerName =
            tostring(
                garden:GetAttribute(
                    "Owner"
                )
                or ""
            )

        if ownerUserId
        and gardenOwnerUserId == tonumber(ownerUserId) then

            return garden
        end

        if tostring(ownerName or "") ~= ""
        and gardenOwnerName == tostring(ownerName) then

            return garden
        end
    end

    return nil
end

function HolyWateringRejoinFindGardenAtPosition(position)

    if typeof(position) ~= "Vector3" then
        return nil
    end

    local gardens =
        workspace:FindFirstChild(
            "Gardens"
        )

    if not gardens then
        return nil
    end

    local bestGarden =
        nil

    local bestScore =
        math.huge

    for _, garden in ipairs(
        gardens:GetChildren()
    ) do

        local anchorCFrame,
            anchor =
            HolyWateringRejoinGetGardenAnchor(
                garden
            )

        if anchorCFrame
        and anchor then

            local localPosition =
                anchorCFrame:PointToObjectSpace(
                    position
                )

            local overflowX =
                math.max(
                    0,
                    math.abs(localPosition.X)
                    - (
                        anchor.Size.X / 2
                    )
                )

            local overflowZ =
                math.max(
                    0,
                    math.abs(localPosition.Z)
                    - (
                        anchor.Size.Z / 2
                    )
                )

            local score =
                overflowX
                + overflowZ

            if score < bestScore then

                bestScore =
                    score

                bestGarden =
                    garden
            end
        end
    end

    if bestScore <= 12 then

        return bestGarden
    end

    return nil
end

function HolyWateringRejoinResolveSavedPositions()

    local state =
        HOLY_WATERING_REJOIN_STATE

    local garden =
        HolyWateringRejoinFindGardenByOwner(
            state.TargetOwnerUserId,
            state.TargetUsername
        )

    local anchorCFrame,
        anchor =
        HolyWateringRejoinGetGardenAnchor(
            garden
        )

    local standOffset =
        HolyWateringRejoinDataToCFrame(
            state.StandOffset
        )

    local aimOffset =
        HolyWateringRejoinDataToVector(
            state.AimOffset
        )

    if not garden
    or not anchorCFrame
    or not standOffset
    or not aimOffset then

        return nil
    end

    return garden,
        anchor,
        anchorCFrame * standOffset,
        anchorCFrame:PointToWorldSpace(
            aimOffset
        )
end

function HolyWateringRejoinSyncToggle(value)

    local runtime =
        HOLY_WATERING_REJOIN_RUNTIME

    if runtime.ToggleSyncing == true then
        return false
    end

    local toggle =
        HOLY_WATERING_REJOIN_UI
        and HOLY_WATERING_REJOIN_UI.Toggle
        or nil

    if type(toggle) ~= "table"
    or type(toggle.SetValue) ~= "function" then

        return false
    end

    runtime.ToggleSyncing =
        true

    task.defer(function()

        pcall(function()

            toggle:SetValue(
                value == true
            )
        end)

        runtime.ToggleSyncing =
            false
    end)

    return true
end

function HolyWateringRejoinSyncRollbackToggle()

    local library =
        HOLY_DEV_LIBRARY

    local toggles =
        type(library) == "table"
        and library.Toggles
        or nil

    local toggle =
        type(toggles) == "table"
        and toggles.HolyRollbackEnabled
        or nil

    if type(toggle) == "table"
    and type(toggle.SetValue) == "function" then

        task.defer(function()

            pcall(function()

                toggle:SetValue(
                    true
                )
            end)
        end)
    end
end

function HolyWateringRejoinEnsureRollback()

    if HOLY_WATERING_REJOIN_STATE.Enabled ~= true then

        return false
    end

    HOLY_ROLLBACK_RUNTIME.WateringFireDelay =
        0.1

    return HolyRollbackSetOwner(
        "Watering",
        true
    )
end

function HolyWateringRejoinRestorePlantCollision()

    local runtime =
        HOLY_WATERING_REJOIN_RUNTIME

    for _, connection in ipairs(
        runtime.PlantConnections
        or {}
    ) do

        pcall(function()

            connection:Disconnect()
        end)
    end

    runtime.PlantConnections =
        {}

    for object, original in pairs(
        runtime.PlantCollisionOriginal
        or {}
    ) do

        if typeof(object) == "Instance"
        and object:IsA("BasePart")
        and type(original) == "table" then

            pcall(function()

                object.CanCollide =
                    original.CanCollide == true

                object.LocalTransparencyModifier =
                    tonumber(
                        original.LocalTransparencyModifier
                    )
                    or 0
            end)
        end
    end

    runtime.PlantCollisionOriginal =
        {}
end

function HolyWateringRejoinApplyPlantCollision(garden)

    HolyWateringRejoinRestorePlantCollision()

    local state =
        HOLY_WATERING_REJOIN_STATE

    local runtime =
        HOLY_WATERING_REJOIN_RUNTIME

    local gardensRoot =
        workspace:FindFirstChild(
            "Gardens"
        )

    local scanRoot =
        gardensRoot
        or garden

    if typeof(scanRoot) ~= "Instance" then

        return false
    end

    local function isInsidePlants(object)

        local current =
            object.Parent

        while current do

            if current.Name == "Plants" then

                return true
            end

            if current == scanRoot then
                break
            end

            current =
                current.Parent
        end

        return false
    end

    local function apply(object)

        if typeof(object) ~= "Instance"
        or object:IsA("BasePart") ~= true
        or isInsidePlants(object) ~= true then

            return
        end

        if runtime.PlantCollisionOriginal[object] == nil then

            runtime.PlantCollisionOriginal[object] = {
                CanCollide =
                    object.CanCollide == true,

                LocalTransparencyModifier =
                    object.LocalTransparencyModifier,
            }
        end

        pcall(function()

            object.CanCollide =
                false

            if state.HidePlants == true then

                object.LocalTransparencyModifier =
                    1
            end
        end)
    end

    for _, object in ipairs(
        scanRoot:GetDescendants()
    ) do

        apply(
            object
        )
    end

    table.insert(
        runtime.PlantConnections,
        scanRoot.DescendantAdded:Connect(function(object)

            task.defer(function()

                if state.Enabled == true then

                    apply(
                        object
                    )
                end
            end)
        end)
    )

    return true
end

function HolyWateringRejoinDistanceTo(
    root,
    destination
)

    if typeof(root) ~= "Instance"
    or root:IsA("BasePart") ~= true
    or typeof(destination) ~= "Vector3" then

        return math.huge
    end

    return (
        root.Position
        - destination
    ).Magnitude
end

function HolyWateringRejoinHorizontalDistanceTo(
    root,
    destination
)

    if typeof(root) ~= "Instance"
    or root:IsA("BasePart") ~= true
    or typeof(destination) ~= "Vector3" then

        return math.huge
    end

    local difference =
        root.Position
        - destination

    return Vector3.new(
        difference.X,
        0,
        difference.Z
    ).Magnitude
end

function HolyWateringRejoinBuildRoute(
    root,
    destination
)

    local route =
        {}

    local path =
        PathfindingService:CreatePath({
            AgentRadius = 1,
            AgentHeight = 4,
            AgentCanJump = true,
            AgentCanClimb = true,
            WaypointSpacing = 6,
        })

    local success =
        pcall(function()

            path:ComputeAsync(
                root.Position,
                destination
            )
        end)

    if success == true
    and path.Status == Enum.PathStatus.Success then

        local waypoints =
            path:GetWaypoints()

        for index = 2, #waypoints do

            table.insert(
                route,
                waypoints[index]
            )
        end
    end

    if #route == 0 then

        table.insert(
            route,
            {
                Position =
                    destination,

                Action =
                    Enum.PathWaypointAction.Walk,
            }
        )
    end

    return route
end

function HolyWateringRejoinWalkTo(
    destinationCFrame,
    generation
)

    if typeof(destinationCFrame) ~= "CFrame" then

        return false,
            math.huge
    end

    local character,
        humanoid,
        root =
        HolyWateringRejoinGetCharacter()

    if typeof(character) ~= "Instance"
    or typeof(humanoid) ~= "Instance"
    or typeof(root) ~= "Instance"
    or root:IsA("BasePart") ~= true
    or humanoid.Health <= 0 then

        return false,
            math.huge
    end

    local runtime =
        HOLY_WATERING_REJOIN_RUNTIME

    local destination =
        destinationCFrame.Position

    local arrivalDistance =
        4

    local startedAt =
        os.clock()

    local maximumDuration =
        90

    local lastMoveCommandAt =
        0

    local lastProgressPosition =
        root.Position

    local lastProgressAt =
        os.clock()

    local lastJumpAt =
        0

    local function isActive()

        return HOLY_WATERING_REJOIN_STATE.Enabled == true
            and runtime.Running == true
            and runtime.Generation == generation
            and runtime.RespawnPending ~= true
            and LocalPlayer.Character == character
            and character.Parent ~= nil
            and humanoid.Parent ~= nil
            and humanoid.Health > 0
            and root.Parent ~= nil
            and os.clock() - startedAt < maximumDuration
    end

    local function faceSavedDirection()

        local lookVector =
            destinationCFrame.LookVector

        local flatLook =
            Vector3.new(
                lookVector.X,
                0,
                lookVector.Z
            )

        if flatLook.Magnitude <= 0.01 then
            return
        end

        pcall(function()

            root.CFrame =
                CFrame.lookAt(
                    root.Position,
                    root.Position
                    + flatLook.Unit
                )
        end)
    end

    local function stopAtDestination()

        pcall(function()

            humanoid:MoveTo(
                root.Position
            )

            humanoid:Move(
                Vector3.zero,
                false
            )

            humanoid.AutoRotate =
                true
        end)

        faceSavedDirection()
    end

    pcall(function()

        humanoid:UnequipTools()

        humanoid.Sit =
            false

        humanoid.PlatformStand =
            false

        humanoid.AutoRotate =
            true
    end)

    while isActive() do

        local currentDistance =
            HolyWateringRejoinHorizontalDistanceTo(
                root,
                destination
            )

        if currentDistance <= arrivalDistance then

            stopAtDestination()

            return true,
                currentDistance
        end

        local now =
            os.clock()

        local progressDelta =
            root.Position
            - lastProgressPosition

        local horizontalProgress =
            Vector3.new(
                progressDelta.X,
                0,
                progressDelta.Z
            ).Magnitude

        if horizontalProgress >= 0.35 then

            lastProgressPosition =
                root.Position

            lastProgressAt =
                now

        elseif now - lastProgressAt >= 1.25
        and now - lastJumpAt >= 1 then

            lastJumpAt =
                now

            lastProgressAt =
                now

            lastProgressPosition =
                root.Position

            pcall(function()

                humanoid.Sit =
                    false

                humanoid.PlatformStand =
                    false

                humanoid.Jump =
                    true
            end)
        end

        if now - lastMoveCommandAt >= 0.12 then

            lastMoveCommandAt =
                now

            pcall(function()

                humanoid.Sit =
                    false

                humanoid.PlatformStand =
                    false

                humanoid.AutoRotate =
                    true

                humanoid:MoveTo(
                    destination
                )
            end)
        end

        task.wait(
            0.04
        )
    end

    local finalDistance =
        HolyWateringRejoinHorizontalDistanceTo(
            root,
            destination
        )

    if finalDistance <= arrivalDistance then

        stopAtDestination()

        return true,
            finalDistance
    end

    -- Do not issue MoveTo(root.Position) here.
    -- Keeping the existing destination prevents a visible pause
    -- while recovery prepares the next movement worker.

    return false,
        finalDistance
end

function HolyWateringRejoinCancelTween()

    local runtime =
        HOLY_WATERING_REJOIN_RUNTIME

    local tween =
        runtime.ActiveTween

    runtime.ActiveTween =
        nil

    if tween then

        pcall(function()

            tween:Cancel()
        end)
    end
end

function HolyWateringRejoinTweenTo(
    destinationCFrame,
    generation
)

    if typeof(destinationCFrame) ~= "CFrame" then

        return false,
            math.huge
    end

    local character,
        humanoid,
        root =
        HolyWateringRejoinGetCharacter()

    if not character
    or not humanoid
    or not root then

        return false,
            math.huge
    end

    local state =
        HOLY_WATERING_REJOIN_STATE

    local runtime =
        HOLY_WATERING_REJOIN_RUNTIME

    local destination =
        destinationCFrame.Position

    local startingDistance =
        HolyWateringRejoinHorizontalDistanceTo(
            root,
            destination
        )

    if startingDistance <= 4 then

        pcall(function()

            root.CFrame =
                destinationCFrame
        end)

        return true,
            startingDistance
    end

    pcall(function()

        humanoid:UnequipTools()

        humanoid.Sit =
            false

        humanoid.PlatformStand =
            false

        humanoid.AutoRotate =
            false
    end)

    local speed =
        math.clamp(
            tonumber(
                state.TweenSpeed
            )
            or 30,
            5,
            100
        )

    local duration =
        math.max(
            0.1,
            (
                root.Position
                - destination
            ).Magnitude
            / speed
        )

    local TweenService =
        game:GetService(
            "TweenService"
        )

    local tween =
        TweenService:Create(
            root,
            TweenInfo.new(
                duration,
                Enum.EasingStyle.Linear,
                Enum.EasingDirection.Out
            ),
            {
                CFrame =
                    destinationCFrame,
            }
        )

    runtime.ActiveTween =
        tween

    local completed =
        false

    local completedConnection =
        tween.Completed:Connect(function()

            completed =
                true
        end)

    tween:Play()

    local deadline =
        os.clock()
        + duration
        + 3

    while state.Enabled == true
    and runtime.Running == true
    and runtime.Generation == generation
    and runtime.RespawnPending ~= true
    and completed ~= true
    and os.clock() < deadline do

        task.wait(
            0.05
        )
    end

    pcall(function()

        completedConnection:Disconnect()
    end)

    if runtime.ActiveTween == tween then

        runtime.ActiveTween =
            nil
    end

    if state.Enabled ~= true
    or runtime.Running ~= true
    or runtime.Generation ~= generation
    or runtime.RespawnPending == true then

        pcall(function()

            tween:Cancel()
        end)

        return false,
            HolyWateringRejoinHorizontalDistanceTo(
                root,
                destination
            )
    end

    pcall(function()

        humanoid.AutoRotate =
            true
    end)

    local finalDistance =
        HolyWateringRejoinHorizontalDistanceTo(
            root,
            destination
        )

    return finalDistance <= 4,
        finalDistance
end

function HolyWateringRejoinMoveTo(
    destinationCFrame,
    generation
)

    if HOLY_WATERING_REJOIN_STATE.MovementMode
        == "Tween" then

        return HolyWateringRejoinTweenTo(
            destinationCFrame,
            generation
        )
    end

    return HolyWateringRejoinWalkTo(
        destinationCFrame,
        generation
    )
end

function HolyWateringRejoinBuildSafeCFrame(
    savedStandCFrame,
    savedAimPosition
)

    if typeof(savedStandCFrame) ~= "CFrame"
    or typeof(savedAimPosition) ~= "Vector3" then

        return nil
    end

    local standPosition =
        savedStandCFrame.Position

    local awayDirection =
        Vector3.new(
            standPosition.X - savedAimPosition.X,
            0,
            standPosition.Z - savedAimPosition.Z
        )

    if awayDirection.Magnitude <= 0.01 then

        local lookVector =
            savedStandCFrame.LookVector

        awayDirection =
            Vector3.new(
                -lookVector.X,
                0,
                -lookVector.Z
            )
    end

    if awayDirection.Magnitude <= 0.01 then

        return nil
    end

    local retreatDistance =
        math.clamp(
            tonumber(
                HOLY_WATERING_REJOIN_STATE.RetreatDistance
            )
            or 30,
            15,
            80
        )

    local safePosition =
        standPosition
        + awayDirection.Unit
        * retreatDistance

    local flatAim =
        Vector3.new(
            savedAimPosition.X,
            safePosition.Y,
            savedAimPosition.Z
        )

    if (
        flatAim
        - safePosition
    ).Magnitude <= 0.01 then

        return CFrame.new(
            safePosition
        )
    end

    return CFrame.lookAt(
        safePosition,
        flatAim
    )
end

function HolyWateringRejoinIsNight()

    return workspace:GetAttribute(
        "ActivePhase"
    ) == "Night"
end

function HolyWateringRejoinShouldAvoidPlantAttacks()

    local mode =
        tostring(
            HOLY_WATERING_REJOIN_STATE.AvoidPlantAttacksMode
            or "Night Only"
        )

    if mode == "Always" then

        return true
    end

    if mode == "Night Only" then

        return HolyWateringRejoinIsNight()
    end

    return false
end

function HolyWateringRejoinRetreatToSafety(
    savedStandCFrame,
    savedAimPosition,
    generation
)

    local safeCFrame =
        HolyWateringRejoinBuildSafeCFrame(
            savedStandCFrame,
            savedAimPosition
        )

    if typeof(safeCFrame) ~= "CFrame" then

        return false
    end

    local arrived =
        HolyWateringRejoinMoveTo(
            safeCFrame,
            generation
        )

    return arrived == true
end

function HolyWateringRejoinRestoreSetupHook()

    local runtime =
        HOLY_WATERING_REJOIN_RUNTIME

    if type(runtime.SetupHookRestore) == "function" then

        pcall(
            runtime.SetupHookRestore
        )
    end

    runtime.SetupHookRestore =
        nil

    runtime.SetupArmed =
        false
end

function HolyWateringRejoinFinishSetupCapture(
    aimPosition,
    canName,
    tool,
    standCFrame,
    startingCount,
    setupGeneration
)

    local runtime =
        HOLY_WATERING_REJOIN_RUNTIME

    local deadline =
        os.clock()
        + 5

    local finalCount =
        startingCount

    while runtime.SetupGeneration == setupGeneration
    and os.clock() < deadline do

        finalCount =
            tonumber(
                tool:GetAttribute(
                    "Count"
                )
            )
            or startingCount

        if finalCount < startingCount then
            break
        end

        task.wait(
            0.02
        )
    end

    HolyWateringRejoinRestoreSetupHook()

    pcall(function()

        tool:Deactivate()
    end)

    if finalCount >= startingCount then

        HolyNotify(
            "Watering Rejoin",
            "Position was not saved because watering was not confirmed.",
            5
        )

        return false
    end

    local garden =
        HolyWateringRejoinFindGardenAtPosition(
            aimPosition
        )

    local anchorCFrame =
        HolyWateringRejoinGetGardenAnchor(
            garden
        )

    local ownerUserId,
        ownerName =
        HolyWateringRejoinGetGardenOwner(
            garden
        )

    if not garden
    or not anchorCFrame
    or not ownerUserId then

        HolyNotify(
            "Watering Rejoin",
            "Could not detect the target garden owner.",
            5
        )

        return false
    end

    local state =
        HOLY_WATERING_REJOIN_STATE

    state.TargetOwnerUserId =
        ownerUserId

    state.TargetUsername =
        ownerName

    state.WateringCan =
        canName

    state.StandOffset =
        HolyWateringRejoinCFrameToData(
            anchorCFrame:ToObjectSpace(
                standCFrame
            )
        )

    state.AimOffset =
        HolyWateringRejoinVectorToData(
            anchorCFrame:PointToObjectSpace(
                aimPosition
            )
        )

    HolyWateringRejoinSaveSettings()

    HolyNotify(
        "Watering Rejoin",
        "Target position saved for "
        .. tostring(
            ownerName ~= ""
            and ownerName
            or ownerUserId
        )
        .. ".",
        5
    )

    return true
end

function HolyWateringRejoinInstallSetupHook()

    if type(hookfunction) ~= "function" then

        HolyNotify(
            "Watering Rejoin",
            "Position capture is unavailable.",
            5
        )

        return false
    end

    HolyWateringRejoinRestoreSetupHook()

    local runtime =
        HOLY_WATERING_REJOIN_RUNTIME

    local packet =
        HolyWateringRejoinResolvePacket()

    if not packet then
        return false
    end

    local hookTarget =
        packet.Fire

    local originalFunction =
        nil

    local wrapper =
        function(self, ...)

            local arguments =
                table.pack(...)

            local shouldCapture =
                runtime.SetupArmed == true
                and self == packet
                and typeof(arguments[1]) == "Vector3"
                and type(arguments[2]) == "string"
                and typeof(arguments[3]) == "Instance"
                and arguments[2] == HOLY_WATERING_REJOIN_STATE.WateringCan

            local aimPosition =
                nil

            local canName =
                nil

            local tool =
                nil

            local standCFrame =
                nil

            local startingCount =
                nil

            local setupGeneration =
                nil

            if shouldCapture then

                local _,
                    _,
                    root =
                    HolyWateringRejoinGetCharacter()

                if root then

                    aimPosition =
                        arguments[1]

                    canName =
                        arguments[2]

                    tool =
                        arguments[3]

                    standCFrame =
                        root.CFrame

                    startingCount =
                        tonumber(
                            tool:GetAttribute(
                                "Count"
                            )
                        )

                    if startingCount then

                        runtime.SetupArmed =
                            false

                        runtime.SetupGeneration +=
                            1

                        setupGeneration =
                            runtime.SetupGeneration
                    else

                        shouldCapture =
                            false
                    end
                else

                    shouldCapture =
                        false
                end
            end

            local returnValues =
                table.pack(
                    originalFunction(
                        self,
                        table.unpack(
                            arguments,
                            1,
                            arguments.n
                        )
                    )
                )

            if shouldCapture then

                task.defer(function()

                    pcall(function()

                        tool:Deactivate()
                    end)
                end)

                task.spawn(
                    HolyWateringRejoinFinishSetupCapture,
                    aimPosition,
                    canName,
                    tool,
                    standCFrame,
                    startingCount,
                    setupGeneration
                )
            end

            return table.unpack(
                returnValues,
                1,
                returnValues.n
            )
        end

    if type(newcclosure) == "function" then

        wrapper =
            newcclosure(
                wrapper
            )
    end

    local success,
        result =
        pcall(
            hookfunction,
            hookTarget,
            wrapper
        )

    if success ~= true
    or type(result) ~= "function" then

        HolyNotify(
            "Watering Rejoin",
            "Could not install position capture.",
            5
        )

        return false
    end

    originalFunction =
        result

    runtime.SetupHookRestore =
        function()

            hookfunction(
                hookTarget,
                originalFunction
            )
        end

    return true
end

function HolyWateringRejoinArmSetup()

    local state =
        HOLY_WATERING_REJOIN_STATE

    local runtime =
        HOLY_WATERING_REJOIN_RUNTIME

    if state.Enabled == true
    or runtime.Running == true then

        HolyNotify(
            "Watering Rejoin",
            "Disable Auto Watering Rejoin before setting a position.",
            5
        )

        return false
    end

    local tool =
        HolyWateringRejoinFindTool(
            state.WateringCan
        )

    if not tool then

        HolyNotify(
            "Watering Rejoin",
            state.WateringCan
            .. " was not found.",
            5
        )

        return false
    end

    if HolyWateringRejoinEquipTool(
        tool
    ) ~= true then

        HolyNotify(
            "Watering Rejoin",
            "Could not equip "
            .. state.WateringCan
            .. ".",
            5
        )

        return false
    end

    pcall(function()

        tool:Deactivate()
    end)

    if HolyWateringRejoinInstallSetupHook() ~= true then
        return false
    end

    runtime.SetupArmed =
        true

    runtime.SetupGeneration +=
        1

    local generation =
        runtime.SetupGeneration

    HolyNotify(
        "Watering Rejoin",
        "Manually water the target spot once to save it.",
        6
    )

    task.delay(
        15,
        function()

            if runtime.SetupArmed == true
            and runtime.SetupGeneration == generation then

                HolyWateringRejoinRestoreSetupHook()

                HolyNotify(
                    "Watering Rejoin",
                    "Position capture timed out.",
                    4
                )
            end
        end
    )

    return true
end

function HolyWateringRejoinConfirmUse(
    packet,
    aimPosition,
    toolName,
    tool,
    generation
)

    local runtime =
        HOLY_WATERING_REJOIN_RUNTIME

    local startingCount =
        tonumber(
            tool:GetAttribute(
                "Count"
            )
        )

    if not startingCount
    or startingCount <= 0 then

        return false,
            startingCount or 0,
            false
    end

    local fireSuccess,
        fireError =
        pcall(function()

            packet:Fire(
                aimPosition,
                toolName,
                tool
            )
        end)

    if fireSuccess ~= true then

        warn(
            "[HOLY Watering Rejoin] "
            .. tostring(fireError)
        )

        return false,
            startingCount,
            false
    end

    local deadline =
        os.clock()
        + 5

    local finalCount =
        startingCount

    local missingSince =
        nil

    while HOLY_WATERING_REJOIN_STATE.Enabled == true
    and runtime.Running == true
    and runtime.Generation == generation
    and os.clock() < deadline do

        local observedCount =
            tonumber(
                tool:GetAttribute(
                    "Count"
                )
            )

        if observedCount then

            finalCount =
                observedCount
        end

        if finalCount < startingCount then

            return true,
                finalCount,
                true
        end

        local usableTool =
            HolyWateringRejoinFindUsableTool(
                toolName
            )

        if not usableTool then

            missingSince =
                missingSince
                or os.clock()

            if os.clock() - missingSince >= 0.25 then

                return true,
                    0,
                    true
            end

        else

            missingSince =
                nil
        end

        task.wait(
            0.02
        )
    end

    return false,
        finalCount,
        true
end

function HolyWateringRejoinOfflineAnimationActive()

    local playerGui =
        LocalPlayer
        and LocalPlayer:FindFirstChild(
            "PlayerGui"
        )

    local offlineAnimation =
        playerGui
        and playerGui:FindFirstChild(
            "OfflineAnimation"
        )

    if typeof(offlineAnimation) ~= "Instance" then

        return false
    end

    if offlineAnimation:IsA("ScreenGui")
    and offlineAnimation.Enabled ~= true then

        return false
    end

    local holdLabel =
        offlineAnimation:FindFirstChild(
            "HTSLabel",
            true
        )

    if typeof(holdLabel) == "Instance"
    and holdLabel:IsA("GuiObject") then

        return holdLabel.Visible == true
    end

    return true
end

function HolyWateringRejoinScheduleRecovery(
    reason,
    delay
)

    local state =
        HOLY_WATERING_REJOIN_STATE

    local runtime =
        HOLY_WATERING_REJOIN_RUNTIME

    if state.Enabled ~= true
    or runtime.Teleporting == true then

        return false
    end

    if runtime.RecoveryScheduled == true then

        return true
    end

    runtime.RecoveryScheduled =
        true

    runtime.Running =
        false

    runtime.Busy =
        false

    runtime.Generation +=
        1

    local recoveryGeneration =
        runtime.Generation

    HolyWateringRejoinCancelTween()
    HolyWateringRejoinEnsureRollback()

    task.spawn(function()

        task.wait(
            math.clamp(
                tonumber(delay)
                or 1,
                0.25,
                10
            )
        )

        local readyDeadline =
            os.clock()
            + 30

        while state.Enabled == true
        and runtime.Teleporting ~= true
        and runtime.Generation == recoveryGeneration
        and os.clock() < readyDeadline do

            local character,
                humanoid,
                root =
                HolyWateringRejoinGetCharacter()

            if character
            and humanoid
            and root
            and humanoid.Health > 0
            and HolyWateringRejoinOfflineAnimationActive() ~= true then

                runtime.RecoveryScheduled =
                    false

                runtime.RespawnPending =
                    false

                HolyWateringRejoinStart(
                    "recovery"
                )

                return
            end

            task.wait(
                0.25
            )
        end

        if runtime.Generation == recoveryGeneration then

            runtime.RecoveryScheduled =
                false
        end
    end)

    return true
end

function HolyWateringRejoinAbort(message)

    if type(HolyNotify) == "function" then

        HolyNotify(
            "Watering Rejoin",
            tostring(message),
            5
        )
    end

    if type(HOLY_WATERING_REJOIN_RUNTIME.Stop) == "function" then

        HOLY_WATERING_REJOIN_RUNTIME.Stop(
            "abort",
            false
        )
    end

    return false
end

function HolyWateringRejoinFinishRejoin(generation)

    local state =
        HOLY_WATERING_REJOIN_STATE

    local runtime =
        HOLY_WATERING_REJOIN_RUNTIME

    if runtime.RejoinAt == nil then

        runtime.RejoinAt =
            os.clock()
            + math.clamp(
                tonumber(
                    state.RejoinDelay
                )
                or 5,
                1,
                60
            )
    end

    HolyWateringRejoinEnsureRollback()

    while state.Enabled == true
    and runtime.Running == true
    and runtime.Generation == generation
    and os.clock() < runtime.RejoinAt do

        task.wait(
            0.05
        )
    end

    if state.Enabled ~= true
    or runtime.Running ~= true
    or runtime.Generation ~= generation then

        return false
    end

    HolyWateringRejoinEnsureRollback()
    HolyWateringRejoinSaveSettings()

    runtime.Teleporting =
        true

    local teleportSuccess,
        teleportError =
        pcall(function()

            TeleportService:Teleport(
                game.PlaceId,
                LocalPlayer
            )
        end)

    if teleportSuccess ~= true then

        runtime.Teleporting =
            false

        warn(
            "[HOLY Watering Rejoin] Rejoin failed: "
            .. tostring(teleportError)
        )

        HolyWateringRejoinAbort(
            "Rejoin failed."
        )

        return false
    end

    return true
end

function HolyWateringRejoinRunCycle(generation)

    local state =
        HOLY_WATERING_REJOIN_STATE

    local runtime =
        HOLY_WATERING_REJOIN_RUNTIME

    local packet =
        HolyWateringRejoinResolvePacket()

    if not packet then

        HolyWateringRejoinAbort(
            "Watering packet is unavailable."
        )

        return
    end

    if HolyWateringRejoinEnsureRollback() ~= true then

        HolyWateringRejoinAbort(
            "Rollback could not be started."
        )

        return
    end

    if runtime.WateringFinished == true then

        HolyWateringRejoinFinishRejoin(
            generation
        )

        return
    end

    local garden,
        anchor,
        savedStandCFrame,
        savedAimPosition =
        nil,
        nil,
        nil,
        nil

    local tool =
        nil

    local loadDeadline =
        os.clock()
        + 30

    while state.Enabled == true
    and runtime.Running == true
    and runtime.Generation == generation
    and os.clock() < loadDeadline do

        garden,
            anchor,
            savedStandCFrame,
            savedAimPosition =
            HolyWateringRejoinResolveSavedPositions()

        tool =
            HolyWateringRejoinFindTool(
                state.WateringCan
            )

        local _,
            humanoid,
            root =
            HolyWateringRejoinGetCharacter()

        if garden
        and anchor
        and savedStandCFrame
        and savedAimPosition
        and tool
        and humanoid
        and root then

            break
        end

        task.wait(
            0.5
        )
    end

    if state.Enabled ~= true
    or runtime.Running ~= true
    or runtime.Generation ~= generation then

        return
    end

    if not garden
    or not savedStandCFrame
    or not savedAimPosition then

        HolyWateringRejoinAbort(
            "The saved target garden is unavailable."
        )

        return
    end

    if not tool then

        HolyWateringRejoinScheduleRecovery(
            state.WateringCan
            .. " is not ready yet.",
            1
        )

        return
    end

    HolyWateringRejoinApplyPlantCollision(
        garden
    )

    local arrived,
        finalDistance =
        HolyWateringRejoinMoveTo(
            savedStandCFrame,
            generation
        )

    if arrived ~= true then

        if state.Enabled == true
        and (
            runtime.Generation ~= generation
            or runtime.RespawnPending == true
        ) then

            return
        end

        HolyWateringRejoinScheduleRecovery(
            "Movement to the saved position was interrupted.",
            1
        )

        return
    end

    if state.Enabled ~= true
    or runtime.Running ~= true
    or runtime.Generation ~= generation then

        return
    end

    HolyWateringRejoinEnsureRollback()

    tool =
        HolyWateringRejoinFindTool(
            state.WateringCan
        )

    if not tool
    or HolyWateringRejoinEquipTool(tool) ~= true then

        HolyWateringRejoinScheduleRecovery(
            "Could not equip "
            .. state.WateringCan
            .. ".",
            1
        )

        return
    end

    local useLimit =
        math.huge

    if state.UseMode == "Custom Amount" then

        useLimit =
            math.max(
                1,
                math.floor(
                    tonumber(
                        state.UseAmount
                    )
                    or 1
                )
            )
    end

    local attemptedUses =
        math.max(
            0,
            math.floor(
                tonumber(
                    runtime.CompletedUses
                )
                or 0
            )
        )

    local confirmedUses =
        0

    local depleted =
        false

    local wateringFailure =
        nil

    while state.Enabled == true
    and runtime.Running == true
    and runtime.Generation == generation
    and attemptedUses < useLimit do

        HolyWateringRejoinEnsureRollback()

        local usableCount

        tool,
            usableCount =
            HolyWateringRejoinFindUsableTool(
                state.WateringCan
            )

        if not tool
        or usableCount <= 0 then

            depleted =
                true

            break
        end

        if HolyWateringRejoinEquipTool(tool) ~= true then

            wateringFailure =
                "Could not equip "
                .. state.WateringCan
                .. " while watering."

            break
        end

        local sentAt =
            os.clock()

        local confirmed,
            remainingCount,
            packetSent =
            HolyWateringRejoinConfirmUse(
                packet,
                savedAimPosition,
                state.WateringCan,
                tool,
                generation
            )

        if state.Enabled ~= true
        or runtime.Running ~= true
        or runtime.Generation ~= generation then

            return
        end

        if packetSent ~= true then

            wateringFailure =
                "The watering packet could not be fired."

            break
        end

        attemptedUses +=
            1

        runtime.CompletedUses =
            attemptedUses

        if confirmed == true then

            confirmedUses +=
                1
        end

        local remainingTool,
            detectedRemainingCount =
            HolyWateringRejoinFindUsableTool(
                state.WateringCan
            )

        remainingCount =
            tonumber(
                remainingCount
            )
            or detectedRemainingCount
            or 0

        if not remainingTool
        or detectedRemainingCount <= 0
        or remainingCount <= 0 then

            depleted =
                true
        end

        local shouldContinue =
            attemptedUses < useLimit
            and depleted ~= true
            and not (
                confirmed ~= true
                and state.UseMode == "All Available"
            )

        local retreatedForPlantAttacks =
            false

        local function retreatFromPlantAttacks()

            if retreatedForPlantAttacks == true then

                return true
            end

            local retreated =
                HolyWateringRejoinRetreatToSafety(
                    savedStandCFrame,
                    savedAimPosition,
                    generation
                )

            if retreated ~= true then

                if state.Enabled == true
                and runtime.Generation == generation
                and runtime.RespawnPending ~= true then

                    HolyWateringRejoinScheduleRecovery(
                        "Could not retreat from the plants.",
                        1
                    )
                end

                return false
            end

            retreatedForPlantAttacks =
                true

            return true
        end

        local function returnToWateringPosition()

            if retreatedForPlantAttacks ~= true then

                return true
            end

            local returnedToTarget =
                HolyWateringRejoinMoveTo(
                    savedStandCFrame,
                    generation
                )

            if returnedToTarget ~= true then

                if state.Enabled == true
                and runtime.Generation == generation
                and runtime.RespawnPending ~= true then

                    HolyWateringRejoinScheduleRecovery(
                        "Could not return to the watering position.",
                        1
                    )
                end

                return false
            end

            retreatedForPlantAttacks =
                false

            return true
        end

        if HolyWateringRejoinShouldAvoidPlantAttacks() == true then

            if retreatFromPlantAttacks() ~= true then

                return
            end
        end

        if shouldContinue ~= true then

            break
        end

        local interval

        if state.WateringMode == "Decay" then

            interval =
                state.WateringCan == "Super Watering Can"
                and 15
                or 10
        else

            interval =
                math.clamp(
                    tonumber(
                        state.WateringDelay
                    )
                    or 1,
                    0.1,
                    10
                )
        end

        local nextUseAt =
            sentAt
            + interval

        while state.Enabled == true
        and runtime.Running == true
        and runtime.Generation == generation
        and os.clock() < nextUseAt do

            local shouldAvoidNow =
                HolyWateringRejoinShouldAvoidPlantAttacks()

            if shouldAvoidNow == true
            and retreatedForPlantAttacks ~= true then

                if retreatFromPlantAttacks() ~= true then

                    return
                end

            elseif shouldAvoidNow ~= true
            and retreatedForPlantAttacks == true then

                if returnToWateringPosition() ~= true then

                    return
                end
            end

            task.wait(
                0.05
            )
        end

        if state.Enabled ~= true
        or runtime.Running ~= true
        or runtime.Generation ~= generation then

            return
        end

        if retreatedForPlantAttacks == true then

            if returnToWateringPosition() ~= true then

                return
            end
        end
    end

    if wateringFailure then

        HolyWateringRejoinScheduleRecovery(
            wateringFailure,
            1
        )

        return
    end

    local requestedAmountReached =
        attemptedUses >= useLimit

    local wateringCompleted =
        requestedAmountReached == true
        or depleted == true
        or attemptedUses > 0
        or confirmedUses > 0

    if wateringCompleted ~= true then

        HolyWateringRejoinAbort(
            "No watering attempt was completed. Rejoin cancelled."
        )

        return
    end
    if state.Enabled ~= true
    or runtime.Running ~= true
    or runtime.Generation ~= generation then

        return
    end

    runtime.WateringFinished =
        true

    if runtime.RejoinAt == nil then

        runtime.RejoinAt =
            os.clock()
            + math.clamp(
                tonumber(
                    state.RejoinDelay
                )
                or 5,
                1,
                60
            )
    end

    HolyWateringRejoinFinishRejoin(
        generation
    )
end

function HolyWateringRejoinDisconnectCharacterWatcher()

    local runtime =
        HOLY_WATERING_REJOIN_RUNTIME

    if runtime.CharacterConnection then

        pcall(function()

            runtime.CharacterConnection:Disconnect()
        end)

        runtime.CharacterConnection =
            nil
    end

    if runtime.DiedConnection then

        pcall(function()

            runtime.DiedConnection:Disconnect()
        end)

        runtime.DiedConnection =
            nil
    end
end

function HolyWateringRejoinHandleDeath()

    local state =
        HOLY_WATERING_REJOIN_STATE

    local runtime =
        HOLY_WATERING_REJOIN_RUNTIME

    if state.Enabled ~= true
    or runtime.Teleporting == true then

        return
    end

    runtime.RespawnPending =
        true

    runtime.RecoveryScheduled =
        false

    runtime.Running =
        false

    runtime.Busy =
        false

    runtime.Generation +=
        1

    HolyWateringRejoinCancelTween()
    HolyWateringRejoinEnsureRollback()
end

function HolyWateringRejoinBindCharacter(character)

    local runtime =
        HOLY_WATERING_REJOIN_RUNTIME

    if runtime.DiedConnection then

        pcall(function()

            runtime.DiedConnection:Disconnect()
        end)

        runtime.DiedConnection =
            nil
    end

    if typeof(character) ~= "Instance" then

        return false
    end

    local humanoid =
        character:FindFirstChildOfClass(
            "Humanoid"
        )
        or character:WaitForChild(
            "Humanoid",
            10
        )

    if typeof(humanoid) ~= "Instance" then

        return false
    end

    runtime.DiedConnection =
        humanoid.Died:Connect(function()

            HolyWateringRejoinHandleDeath()
        end)

    return true
end

function HolyWateringRejoinConnectCharacterWatcher()

    local runtime =
        HOLY_WATERING_REJOIN_RUNTIME

    if runtime.CharacterConnection then

        return true
    end

    HolyWateringRejoinBindCharacter(
        LocalPlayer.Character
    )

    runtime.CharacterConnection =
        LocalPlayer.CharacterAdded:Connect(function(character)

            task.spawn(function()

                runtime.RespawnPending =
                    true

                runtime.RecoveryScheduled =
                    false

                runtime.Running =
                    false

                runtime.Busy =
                    false

                runtime.Generation +=
                    1

                local respawnGeneration =
                    runtime.Generation

                HolyWateringRejoinCancelTween()
                HolyWateringRejoinEnsureRollback()

                HolyWateringRejoinBindCharacter(
                    character
                )

                local humanoid =
                    character:WaitForChild(
                        "Humanoid",
                        15
                    )

                local root =
                    character:WaitForChild(
                        "HumanoidRootPart",
                        15
                    )

                if LocalPlayer.Character ~= character
                or typeof(humanoid) ~= "Instance"
                or typeof(root) ~= "Instance"
                or humanoid.Health <= 0 then

                    return
                end

                local readyDeadline =
                    os.clock()
                    + 15

                while HOLY_WATERING_REJOIN_STATE.Enabled == true
                and runtime.Teleporting ~= true
                and runtime.Generation == respawnGeneration
                and LocalPlayer.Character == character
                and humanoid.Health > 0
                and HolyWateringRejoinOfflineAnimationActive() == true
                and os.clock() < readyDeadline do

                    task.wait(
                        0.25
                    )
                end

                if HOLY_WATERING_REJOIN_STATE.Enabled == true
                and runtime.Teleporting ~= true
                and runtime.Generation == respawnGeneration
                and LocalPlayer.Character == character
                and humanoid.Health > 0 then

                    runtime.RespawnPending =
                        false

                    HolyWateringRejoinStart(
                        "respawn"
                    )
                end
            end)
        end)

    return true
end

function HolyWateringRejoinStart(reason)

    local state =
        HOLY_WATERING_REJOIN_STATE

    local runtime =
        HOLY_WATERING_REJOIN_RUNTIME

    if HolyWateringRejoinHasSetup() ~= true then

        state.Enabled =
            false

        HolyWateringRejoinSaveSettings()

        HolyWateringRejoinSyncToggle(
            false
        )

        HolyNotify(
            "Watering Rejoin",
            "Set a target position before enabling.",
            5
        )

        return false
    end

    if runtime.Running == true
    and state.Enabled == true then

        HolyWateringRejoinEnsureRollback()

        return true
    end

    if tostring(reason) ~= "recovery"
    and tostring(reason) ~= "respawn"
    and type(HolyFarmMiddlePauseForWatering)
        == "function" then

        HolyFarmMiddlePauseForWatering(
            "watering rejoin started"
        )
    end

    state.Enabled =
        true

    if tostring(reason) ~= "respawn"
    and tostring(reason) ~= "recovery" then

        runtime.CompletedUses =
            0

        runtime.WateringFinished =
            false

        runtime.RejoinAt =
            nil
    end

    runtime.RespawnPending =
        false

    runtime.RecoveryScheduled =
        false

    runtime.Running =
        true

    runtime.Busy =
        true

    runtime.Teleporting =
        false

    runtime.Generation +=
        1

    local generation =
        runtime.Generation

    HolyWateringRejoinConnectCharacterWatcher()
    HolyWateringRejoinSaveSettings()

    HolyWateringRejoinSyncToggle(
        true
    )

    HolyWateringRejoinEnsureRollback()

    task.spawn(function()

        HolyWateringRejoinRunCycle(
            generation
        )

        if runtime.Generation == generation
        and runtime.Teleporting ~= true then

            runtime.Running =
                false

            runtime.Busy =
                false
        end
    end)

    return true
end

function HolyWateringRejoinStop(
    reason,
    preserveEnabled
)

    local state =
        HOLY_WATERING_REJOIN_STATE

    local runtime =
        HOLY_WATERING_REJOIN_RUNTIME

    runtime.Running =
        false

    runtime.Busy =
        false

    runtime.Teleporting =
        false

    runtime.RespawnPending =
        false

    runtime.RecoveryScheduled =
        false

    runtime.Generation +=
        1

    runtime.CompletedUses =
        0

    runtime.WateringFinished =
        false

    runtime.RejoinAt =
        nil

    HolyWateringRejoinCancelTween()
    HolyWateringRejoinDisconnectCharacterWatcher()
    HolyWateringRejoinRestoreSetupHook()
    HolyWateringRejoinRestorePlantCollision()

    if type(HolyRollbackSetOwner) == "function" then

        HolyRollbackSetOwner(
            "Watering",
            false
        )
    end

    local _,
        humanoid,
        root =
        HolyWateringRejoinGetCharacter()

    if humanoid
    and root then

        pcall(function()

            humanoid:MoveTo(
                root.Position
            )

            humanoid.AutoRotate =
                true
        end)
    end

    if preserveEnabled ~= true then

        state.Enabled =
            false

        HolyWateringRejoinSaveSettings()

        HolyWateringRejoinSyncToggle(
            false
        )

        if type(HolyFarmMiddleResumeAfterWatering)
            == "function" then

            task.defer(function()

                task.wait(
                    0.1
                )

                HolyFarmMiddleResumeAfterWatering()
            end)
        end
    end

    return true
end

function HolyWateringRejoinSetEnabled(value)

    if HOLY_WATERING_REJOIN_RUNTIME.ToggleSyncing == true then
        return false
    end

    if value == true then

        return HolyWateringRejoinStart(
            "toggle"
        )
    end

    return HolyWateringRejoinStop(
        "toggle",
        false
    )
end

function HolyWateringRejoinSetMovementMode(value)

    value =
        tostring(value)

    if value ~= "Walk"
    and value ~= "Tween" then

        value =
            "Tween"
    end

    HOLY_WATERING_REJOIN_STATE.MovementMode =
        value

    HolyWateringRejoinSaveSettings()

    return value
end

function HolyWateringRejoinSetTweenSpeed(value)

    HOLY_WATERING_REJOIN_STATE.TweenSpeed =
        math.clamp(
            tonumber(value)
            or 30,
            5,
            100
        )

    HolyWateringRejoinSaveSettings()

    return HOLY_WATERING_REJOIN_STATE.TweenSpeed
end

function HolyWateringRejoinSetHidePlants(value)

    HOLY_WATERING_REJOIN_STATE.HidePlants =
        value == true

    HolyWateringRejoinSaveSettings()

    if HOLY_WATERING_REJOIN_STATE.Enabled == true then

        HolyWateringRejoinApplyPlantCollision(
            nil
        )
    else

        HolyWateringRejoinRestorePlantCollision()
    end

    return HOLY_WATERING_REJOIN_STATE.HidePlants
end

function HolyWateringRejoinSetAvoidPlantAttacksMode(value)

    value =
        tostring(value)

    if value ~= "Off"
    and value ~= "Night Only"
    and value ~= "Always" then

        value =
            "Night Only"
    end

    HOLY_WATERING_REJOIN_STATE.AvoidPlantAttacksMode =
        value

    HolyWateringRejoinSaveSettings()

    return value
end

function HolyWateringRejoinSetCan(value)

    value =
        tostring(value)

    if value ~= "Common Watering Can"
    and value ~= "Super Watering Can" then

        value =
            "Super Watering Can"
    end

    HOLY_WATERING_REJOIN_STATE.WateringCan =
        value

    HolyWateringRejoinSaveSettings()

    return value
end

function HolyWateringRejoinSetUseMode(value)

    value =
        tostring(value)

    if value ~= "All Available"
    and value ~= "Custom Amount" then

        value =
            "All Available"
    end

    HOLY_WATERING_REJOIN_STATE.UseMode =
        value

    HolyWateringRejoinSaveSettings()

    return value
end

function HolyWateringRejoinSetUseAmount(value)

    local amount =
        tonumber(value)

    if not amount
    or amount ~= amount
    or amount == math.huge
    or amount == -math.huge then

        amount =
            1
    end

    amount =
        math.max(
            1,
            math.floor(
                amount
            )
        )

    HOLY_WATERING_REJOIN_STATE.UseAmount =
        amount

    HolyWateringRejoinSaveSettings()

    return amount
end

function HolyWateringRejoinSetMode(value)

    value =
        tostring(value)

    if value ~= "Delay"
    and value ~= "Decay" then

        value =
            "Delay"
    end

    HOLY_WATERING_REJOIN_STATE.WateringMode =
        value

    HolyWateringRejoinSaveSettings()

    return value
end

function HolyWateringRejoinSetWateringDelay(value)

    HOLY_WATERING_REJOIN_STATE.WateringDelay =
        math.clamp(
            tonumber(value)
            or 1,
            0.1,
            10
        )

    HolyWateringRejoinSaveSettings()

    return HOLY_WATERING_REJOIN_STATE.WateringDelay
end

function HolyWateringRejoinSetRejoinDelay(value)

    HOLY_WATERING_REJOIN_STATE.RejoinDelay =
        math.clamp(
            tonumber(value)
            or 5,
            1,
            60
        )

    HolyWateringRejoinSaveSettings()

    return HOLY_WATERING_REJOIN_STATE.RejoinDelay
end

HOLY_WATERING_REJOIN_RUNTIME.Stop =
    HolyWateringRejoinStop

