local HOLY_THEME_STATE = {
    Version =
        "HOLY_THEME_MANAGER_V1",

    BuiltInOrder = {},
    BuiltInSet = {},
    BuiltInData = {},

    CustomThemes = {},
    RegisteredCustom = {},

    FontByName = {},
    FontLabelByName = {},
    FontNameByLabel = {},
    FontLabels = {},

    StatusDefaults = {},
    UI = {},

    ActiveName =
        "HOLY Red",

    Draft =
        nil,

    Dirty =
        false,

    SyncingEditor =
        false,
}

local HOLY_THEME_COLOR_FIELDS = {
    "Background",
    "Surface",
    "Accent",
    "Border",
    "Text",
}

local HOLY_THEME_STATUS_FIELDS = {
    "SuccessColor",
    "WarningColor",
    "MutedColor",
    "RedColor",
    "DestructiveColor",
    "DarkColor",
    "WhiteColor",
}

local function HolyThemeCloneData(data)

    if type(data) ~= "table" then
        return nil
    end

    return {
        Background =
            data.Background,

        Surface =
            data.Surface,

        Accent =
            data.Accent,

        Border =
            data.Border,

        Text =
            data.Text,

        Font =
            tostring(
                data.Font
                or "GothamMedium"
            ),
    }
end

local function HolyThemeFindFont(enumName)

    for _, fontItem in ipairs(
        Enum.Font:GetEnumItems()
    ) do

        if fontItem.Name == enumName then

            return fontItem
        end
    end

    return nil
end

local function HolyThemeRegisterFont(
    label,
    enumName
)

    local fontItem =
        HolyThemeFindFont(
            enumName
        )

    if typeof(fontItem) ~= "EnumItem" then
        return
    end

    local success,
        fontFace =
        pcall(function()

            return Font.fromEnum(
                fontItem
            )
        end)

    if success ~= true
    or typeof(fontFace) ~= "Font" then

        return
    end

    HOLY_THEME_STATE.FontByName[
        enumName
    ] =
        fontFace

    HOLY_THEME_STATE.FontLabelByName[
        enumName
    ] =
        label

    HOLY_THEME_STATE.FontNameByLabel[
        label
    ] =
        enumName

    table.insert(
        HOLY_THEME_STATE.FontLabels,
        label
    )
end

