function HolyDevQuickSnapshotTimeWeather()

    local serverNow =
        nil

    pcall(function()

        serverNow =
            workspace:GetServerTimeNow()
    end)

    local function readModule(path)

        local ok,
            result =
            pcall(function()

                return HolyShopRequireModule(
                    path
                )
            end)

        if ok == true
        and type(result) == "table" then

            return result,
                nil
        end

        return nil,
            tostring(
                result
                or "module unavailable"
            )
    end

    local timeCycleData,
        timeCycleError =
        readModule(
            "SharedModules.TimeCycleData"
        )

    local weatherData,
        weatherError =
        readModule(
            "SharedModules.WeatherData"
        )

    local predictor =
        type(HOLY_MOON_PREDICTOR_STATE)
            == "table"
        and HOLY_MOON_PREDICTOR_STATE
        or {}

    return {
        ClientClock = os.clock(),
        ClientUnix = os.time(),
        ServerNow = serverNow,

        WorkspaceAttributes =
            workspace:GetAttributes(),

        Current = {
            ActiveWeather =
                workspace:GetAttribute(
                    "ActiveWeather"
                ),

            Phase =
                workspace:GetAttribute(
                    "Phase"
                ),

            PhaseDuration =
                workspace:GetAttribute(
                    "PhaseDuration"
                ),
        },

        Predictor = {
            CycleInfo =
                predictor.CycleInfo,

            MoonTypes =
                predictor.MoonTypes,

            WeatherRecords =
                predictor.WeatherRecords,

            LastBuildCycle =
                predictor.LastBuildCycle,

            Predictions =
                predictor.Predictions,
        },

        Modules = {
            TimeCycleData =
                timeCycleData,

            WeatherData =
                weatherData,
        },

        ModuleErrors = {
            TimeCycleData =
                timeCycleError,

            WeatherData =
                weatherError,
        },
    }
end

function HolyDevQuickSnapshotCapture(copyReport)

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    local scope =
        HolyDevQuickSnapshotScope(
            HOLY_DEV_SUITE_STATE.SnapshotScope
        )

    HOLY_DEV_SUITE_STATE.SnapshotScope =
        scope

    HolyDevSetStatus(
        "SnapshotStatusLabel",
        "Capturing "
            .. scope
            .. "..."
    )

    local placeVersion =
        nil

    pcall(function()

        placeVersion =
            game.PlaceVersion
    end)

    local report = {
        Version = "HOLY_DEV_QUICK_SNAPSHOT_V1",
        Scope = scope,
        PlaceId = game.PlaceId,
        PlaceVersion = placeVersion,
        JobId = game.JobId,
        CapturedAt = os.time(),

        Player = {
            Name = LocalPlayer.Name,
            UserId = LocalPlayer.UserId,
        },

        Capabilities = {},
        Errors = {},
        Data = {},
    }

    local function capture(
        section,
        callback
    )

        if HolyDevQuickSnapshotWants(
            scope,
            section
        ) ~= true then

            return
        end

        local ok,
            value =
            pcall(callback)

        report.Capabilities[section] =
            ok == true

        if ok == true then

            report.Data[section] =
                value

        else

            report.Errors[section] =
                tostring(value)
        end
    end

    capture(
        "Auction",
        HolyDevRecorderAuctionSnapshot
    )

    capture(
        "HOLY Runtime",
        HolyDevQuickSnapshotRuntime
    )

    capture(
        "Player Tools",
        function()

            return {
                PlayerAttributes =
                    LocalPlayer:GetAttributes(),

                Tools =
                    HolyDevSnapshotToolRows(),
            }
        end
    )

    capture(
        "Own Garden",
        function()

            local plot =
                HolyDevFindOwnPlot()

            if typeof(plot) ~= "Instance" then

                return {
                    Found = false,
                }
            end

            return {
                Found = true,
                Name = plot.Name,
                FullName = HolyDevGetFullName(plot),
                Attributes = plot:GetAttributes(),

                AttributedObjects =
                    HolyDevSnapshotAttributedRoot(
                        plot,
                        {}
                    ),
            }
        end
    )

    capture(
        "Wild Pets",
        function()

            local map =
                workspace:FindFirstChild(
                    "Map"
                )

            local root =
                map
                and map:FindFirstChild(
                    "WildPetRef"
                )

            if typeof(root) ~= "Instance" then

                return {
                    Found = false,
                }
            end

            return {
                Found = true,
                Count = #root:GetChildren(),
                Attributes = root:GetAttributes(),

                AttributedObjects =
                    HolyDevSnapshotAttributedRoot(
                        root,
                        {}
                    ),
            }
        end
    )

    capture(
        "Time & Weather",
        HolyDevQuickSnapshotTimeWeather
    )

    runtime.LastQuickSnapshot =
        report

    local saved =
        HolyDevWriteJson(
            DEV_QUICK_SNAPSHOT_FILE,
            report
        )

    local copied =
        copyReport == true
        and HolyDevCopyReport(report)
        or false

    local sectionCount =
        0

    for _ in pairs(
        report.Data
    ) do

        sectionCount +=
            1
    end

    local status =
        scope
        .. " · "
        .. tostring(sectionCount)
        .. (
            sectionCount == 1
            and " section"
            or " sections"
        )

    if copied == true then

        status =
            status
            .. " · copied"
    end

    if saved == true then

        status =
            status
            .. " · saved"
    end

    HolyDevSetStatus(
        "SnapshotStatusLabel",
        status
    )

    HolyNotify(
        "HOLY Dev",
        status,
        4
    )

    return report
end

