function HolyDevFlatten(
    value,
    prefix,
    output,
    depth,
    seen
)

    output =
        type(output) == "table"
        and output
        or {}

    prefix =
        tostring(prefix or "Root")

    depth =
        tonumber(depth)
        or 0

    seen =
        type(seen) == "table"
        and seen
        or {}

    local valueType =
        typeof(value)

    if valueType ~= "table"
    or depth >= 6 then

        local encoded =
            HolyDevEncode(value)

        output[prefix] =
            encoded
            or tostring(value)

        return output
    end

    if seen[value] == true then

        output[prefix] =
            "<cycle>"

        return output
    end

    seen[value] =
        true

    local found =
        false

    for key, child in pairs(value) do

        found =
            true

        HolyDevFlatten(
            child,
            prefix
                .. "."
                .. tostring(key),
            output,
            depth + 1,
            seen
        )
    end

    if found ~= true then

        output[prefix] =
            "{}"
    end

    seen[value] =
        nil

    return output
end

function HolyDevDiffMaps(beforeMap, afterMap)

    beforeMap =
        type(beforeMap) == "table"
        and beforeMap
        or {}

    afterMap =
        type(afterMap) == "table"
        and afterMap
        or {}

    local report = {
        Added = {},
        Removed = {},
        Changed = {},
    }

    for key, afterValue in pairs(afterMap) do

        local beforeValue =
            beforeMap[key]

        if beforeValue == nil then

            report.Added[#report.Added + 1] = {
                Path = key,
                Value = afterValue,
            }

        elseif beforeValue ~= afterValue then

            report.Changed[#report.Changed + 1] = {
                Path = key,
                Before = beforeValue,
                After = afterValue,
            }
        end
    end

    for key, beforeValue in pairs(beforeMap) do

        if afterMap[key] == nil then

            report.Removed[#report.Removed + 1] = {
                Path = key,
                Value = beforeValue,
            }
        end
    end

    local function sortRows(rows)

        table.sort(rows, function(a, b)

            return tostring(a.Path):lower()
                < tostring(b.Path):lower()
        end)
    end

    sortRows(report.Added)
    sortRows(report.Removed)
    sortRows(report.Changed)

    report.AddedCount =
        #report.Added

    report.RemovedCount =
        #report.Removed

    report.ChangedCount =
        #report.Changed

    return report
end

function HolyDevBeginActionCapture()

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    runtime.ActionBefore =
        HolyDevCaptureActionScope(
            HOLY_DEV_SUITE_STATE.ActionScope
        )

    HolyDevSetStatus(
        "ActionStatusLabel",
        "Capturing — perform one action."
    )

    HolyNotify(
        "HOLY Dev",
        "Action capture started.",
        4
    )

    return true
end

function HolyDevEndActionCapture()

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    if type(runtime.ActionBefore) ~= "table" then

        HolyNotify(
            "HOLY Dev",
            "Press Begin Capture first.",
            4
        )

        return false
    end

    local after =
        HolyDevCaptureActionScope(
            runtime.ActionBefore.Scope
        )

    local beforeFlat =
        HolyDevFlatten(
            runtime.ActionBefore.Values,
            "Action",
            {}
        )

    local afterFlat =
        HolyDevFlatten(
            after.Values,
            "Action",
            {}
        )

    local diff =
        HolyDevDiffMaps(
            beforeFlat,
            afterFlat
        )

    local report = {
        Version =
            "HOLY_DEV_ACTION_CAPTURE_V1",

        Scope =
            runtime.ActionBefore.Scope,

        StartedAt =
            runtime.ActionBefore.Time,

        FinishedAt =
            os.time(),

        JobId =
            game.JobId,

        Diff =
            diff,

        Before =
            runtime.ActionBefore,

        After =
            after,
    }

    runtime.LastActionReport =
        report

    runtime.ActionBefore =
        nil

    HolyDevCopyReport(
        report
    )

    HolyDevSetStatus(
        "ActionStatusLabel",
        "+"
            .. tostring(diff.AddedCount)
            .. "  -"
            .. tostring(diff.RemovedCount)
            .. "  ~"
            .. tostring(diff.ChangedCount)
            .. " — copied"
    )

    return true
end

function HolyDevSnapshotUpdateState()

    local snapshot = {
        PlaceId = game.PlaceId,
        PlaceVersion = nil,
        CapturedAt = os.time(),
        Values = {},
    }

    pcall(function()

        snapshot.PlaceVersion =
            game.PlaceVersion
    end)

    local values =
        snapshot.Values

    local function captureTree(root, prefix)

        if typeof(root) ~= "Instance" then
            return
        end

        values[prefix] =
            root.ClassName

        for _, object in ipairs(
            root:GetDescendants()
        ) do

            values[
                "Instance."
                    .. HolyDevGetFullName(object)
            ] =
                object.ClassName
        end
    end

    local sharedModules =
        ReplicatedStorage:FindFirstChild(
            "SharedModules"
        )

    local clientModules =
        ReplicatedStorage:FindFirstChild(
            "ClientModules"
        )

    captureTree(
        sharedModules,
        "Root.SharedModules"
    )

    captureTree(
        clientModules,
        "Root.ClientModules"
    )

    local dataModules = {
        "ItemCatalog",
        "GearShopData",
        "WateringcanData",
        "SprinklerData",
        "Networking",
    }

    for _, moduleName in ipairs(dataModules) do

        local module =
            sharedModules
            and sharedModules:FindFirstChild(
                moduleName
            )

        if module
        and module:IsA("ModuleScript") then

            local success,
                result =
                pcall(
                    require,
                    module
                )

            if success == true then

                HolyDevFlatten(
                    result,
                    "Module." .. moduleName,
                    values,
                    0,
                    {}
                )

            else

                values[
                    "Module."
                        .. moduleName
                        .. ".RequireError"
                ] =
                    tostring(result)
            end
        end
    end

    local gearImages =
        sharedModules
        and sharedModules:FindFirstChild(
            "GearImages"
        )

    if gearImages then

        for _, child in ipairs(
            gearImages:GetChildren()
        ) do

            values[
                "GearCatalog."
                    .. child.Name
            ] =
                child.ClassName
        end
    end

    return snapshot
end

function HolyDevSaveUpdateBaseline()

    local snapshot =
        HolyDevSnapshotUpdateState()

    local success =
        HolyDevWriteJson(
            DEV_UPDATE_BASELINE_FILE,
            snapshot
        )

    if success == true then

        HolyDevSetStatus(
            "UpdateStatusLabel",
            "Baseline saved • v"
                .. tostring(
                    snapshot.PlaceVersion
                    or "?"
                )
        )

        HolyNotify(
            "HOLY Dev",
            "Update baseline saved.",
            4
        )

    else

        HolyDevSetStatus(
            "UpdateStatusLabel",
            "Could not save baseline."
        )
    end

    return success
end

function HolyDevScanUpdateChanges(copyResult)

    local baseline =
        HolyDevReadJson(
            DEV_UPDATE_BASELINE_FILE
        )

    if type(baseline) ~= "table"
    or type(baseline.Values) ~= "table" then

        HolyDevSetStatus(
            "UpdateStatusLabel",
            "No baseline — save one first."
        )

        return false
    end

    local current =
        HolyDevSnapshotUpdateState()

    local diff =
        HolyDevDiffMaps(
            baseline.Values,
            current.Values
        )

    local report = {
        Version =
            "HOLY_DEV_UPDATE_DIFF_V1",

        PlaceId =
            game.PlaceId,

        BaselinePlaceVersion =
            baseline.PlaceVersion,

        CurrentPlaceVersion =
            current.PlaceVersion,

        ScannedAt =
            os.time(),

        Diff =
            diff,
    }

    HOLY_DEV_SUITE_RUNTIME.LastUpdateDiff =
        report

    HolyDevSetStatus(
        "UpdateStatusLabel",
        "v"
            .. tostring(
                baseline.PlaceVersion
                or "?"
            )
            .. " → v"
            .. tostring(
                current.PlaceVersion
                or "?"
            )
            .. "  +"
            .. tostring(diff.AddedCount)
            .. " -"
            .. tostring(diff.RemovedCount)
            .. " ~"
            .. tostring(diff.ChangedCount)
    )

    if copyResult == true then

        HolyDevCopyReport(
            report
        )
    end

    return true
end

function HolyDevStartPersistenceTest()

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    if type(runtime.PersistenceSession) == "table" then

        HolyNotify(
            "HOLY Dev",
            "A persistence test is already running.",
            4
        )

        return false
    end

    local target =
        tostring(
            HOLY_DEV_SUITE_STATE.PersistenceTarget
            or ""
        )

    local count,
        found =
        HolyDevGetToolCount(
            target
        )

    if target == ""
    or found ~= true then

        HolyNotify(
            "HOLY Dev",
            "Select an owned usable tool first.",
            5
        )

        return false
    end

    runtime.PersistenceSession = {
        Target = target,
        BeforeCount = count,
        StartedAt = os.time(),
        JobId = game.JobId,
    }

    HolyRollbackSetOwner(
        "Persistence",
        true
    )

    HolyDevSetStatus(
        "PersistenceStatusLabel",
        target
            .. ": "
            .. tostring(count)
            .. " • use it once"
    )

    HolyNotify(
        "HOLY Dev",
        "Test running. Use "
            .. target
            .. " once, then press Finish + Save.",
        7
    )

    return true
end

function HolyDevFinishPersistenceTest()

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    local session =
        runtime.PersistenceSession

    if type(session) ~= "table" then

        HolyNotify(
            "HOLY Dev",
            "Press Begin Test first.",
            4
        )

        return false
    end

    HolyRollbackSetOwner(
        "Persistence",
        false
    )

    task.wait(
        0.75
    )

    local afterCount,
        found =
        HolyDevGetToolCount(
            session.Target
        )

    local payload = {
        Version =
            "HOLY_DEV_PERSISTENCE_V1",

        Phase =
            "AwaitingRejoin",

        PlaceId =
            game.PlaceId,

        JobId =
            game.JobId,

        Player = {
            Name = LocalPlayer.Name,
            UserId = LocalPlayer.UserId,
        },

        Target =
            session.Target,

        BeforeCount =
            session.BeforeCount,

        AfterUseCount =
            found == true
            and afterCount
            or nil,

        StartedAt =
            session.StartedAt,

        SavedAt =
            os.time(),
    }

    local saved =
        HolyDevWriteJson(
            DEV_PERSISTENCE_FILE,
            payload
        )

    HolyDevCopyReport(
        payload
    )

    runtime.PersistenceSession =
        nil

    HolyDevSetStatus(
        "PersistenceStatusLabel",
        saved == true
        and "Saved • rejoin, then execute again."
        or "Could not save test state."
    )

    return saved
end

function HolyDevCheckPersistenceRejoin()

    local payload =
        HolyDevReadJson(
            DEV_PERSISTENCE_FILE
        )

    if type(payload) ~= "table"
    or payload.Phase ~= "AwaitingRejoin" then

        return false
    end

    if tostring(payload.JobId)
    == tostring(game.JobId) then

        HolyDevSetStatus(
            "PersistenceStatusLabel",
            "Saved • rejoin to complete."
        )

        return false
    end

    task.wait(
        3
    )

    local afterRejoin,
        found =
        HolyDevGetToolCount(
            payload.Target
        )

    local verdict =
        "INCONCLUSIVE"

    if found == true then

        if tonumber(afterRejoin)
        == tonumber(payload.AfterUseCount) then

            verdict =
                "PERSISTED"

        elseif tonumber(afterRejoin)
        == tonumber(payload.BeforeCount) then

            verdict =
                "ROLLED BACK"

        else

            verdict =
                "CHANGED"
        end
    end

    local finalReport = {
        Version =
            "HOLY_DEV_PERSISTENCE_V1",

        Phase =
            "Complete",

        PlaceId =
            game.PlaceId,

        PreviousJobId =
            payload.JobId,

        CurrentJobId =
            game.JobId,

        Target =
            payload.Target,

        BeforeCount =
            payload.BeforeCount,

        AfterUseCount =
            payload.AfterUseCount,

        AfterRejoinCount =
            found == true
            and afterRejoin
            or nil,

        Verdict =
            verdict,

        FinishedAt =
            os.time(),
    }

    HolyDevWriteJson(
        DEV_PERSISTENCE_FILE,
        finalReport
    )

    HolyDevCopyReport(
        finalReport
    )

    HOLY_DEV_SUITE_RUNTIME.LastPersistenceReport =
        finalReport

    HolyDevSetStatus(
        "PersistenceStatusLabel",
        tostring(payload.BeforeCount)
            .. " → "
            .. tostring(payload.AfterUseCount)
            .. " → "
            .. tostring(
                found == true
                and afterRejoin
                or "?"
            )
            .. " • "
            .. verdict
            .. " • copied"
    )

    HolyNotify(
        "HOLY Dev",
        payload.Target
            .. ": "
            .. verdict
            .. ". Report copied.",
        8
    )

    return true
end

function HolyDevRefreshModuleDropdown()

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    local sharedModules =
        ReplicatedStorage:FindFirstChild(
            "SharedModules"
        )

    local values =
        {}

    local moduleMap =
        {}

    if sharedModules then

        for _, object in ipairs(
            sharedModules:GetDescendants()
        ) do

            if object:IsA("ModuleScript") then

                local fullName =
                    HolyDevGetFullName(object)

                local display =
                    fullName:gsub(
                        "^ReplicatedStorage%.SharedModules%.",
                        ""
                    )

                values[#values + 1] =
                    display

                moduleMap[display] =
                    object
            end
        end
    end

    table.sort(values, function(a, b)

        return a:lower()
            < b:lower()
    end)

    if #values == 0 then

        values[1] =
            "No modules found"
    end

    runtime.ModuleMap =
        moduleMap

    local selected =
        tostring(
            HOLY_DEV_SUITE_STATE.DataModule
            or ""
        )

    if moduleMap[selected] == nil then

        selected =
            moduleMap["ItemCatalog"]
            and "ItemCatalog"
            or values[1]

        HOLY_DEV_SUITE_STATE.DataModule =
            selected
    end

    local dropdown =
        runtime.UI.DataDropdown

    if type(dropdown) == "table" then

        pcall(function()

            if type(dropdown.SetValues) == "function" then

                dropdown:SetValues(
                    values
                )
            end

            if type(dropdown.SetValue) == "function" then

                dropdown:SetValue(
                    selected
                )
            end
        end)
    end

    return true
end

function HolyDevInspectSelectedModule()

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    local selected =
        tostring(
            HOLY_DEV_SUITE_STATE.DataModule
            or ""
        )

    local module =
        runtime.ModuleMap
        and runtime.ModuleMap[selected]

    if typeof(module) ~= "Instance"
    or module:IsA("ModuleScript") ~= true then

        HolyDevSetStatus(
            "DataStatusLabel",
            "Select a module first."
        )

        return false
    end

    local success,
        result =
        pcall(
            require,
            module
        )

    local report = {
        Version =
            "HOLY_DEV_DATA_INSPECTOR_V1",

        Module =
            selected,

        FullName =
            HolyDevGetFullName(module),

        Success =
            success,

        CapturedAt =
            os.time(),

        Data =
            success == true
            and HolyDevSafeValue(result)
            or nil,

        Error =
            success ~= true
            and tostring(result)
            or nil,
    }

    runtime.LastDataReport =
        report

    HolyDevCopyReport(
        report
    )

    HolyDevSetStatus(
        "DataStatusLabel",
        success == true
        and selected
            .. " copied."
        or selected
            .. " require failed."
    )

    return success == true
end

function HolyDevRefreshErrorStatus()

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    local uniqueCount =
        #runtime.ErrorOrder

    local totalCount =
        0

    local latest =
        nil

    for _, key in ipairs(
        runtime.ErrorOrder
    ) do

        local row =
            runtime.Errors[key]

        if row then

            totalCount +=
                tonumber(row.Count)
                or 0

            latest =
                row
        end
    end

    local text =
        "Capturing • 0 errors"

    if totalCount > 0 then

        text =
            tostring(totalCount)
            .. " errors • "
            .. tostring(uniqueCount)
            .. " unique"

        if latest then

            local preview =
                tostring(
                    latest.Message
                    or ""
                )

            if #preview > 42 then

                preview =
                    preview:sub(1, 42)
                    .. "..."
            end

            text =
                text
                .. " • "
                .. preview
        end
    end

    HolyDevSetStatus(
        "ErrorStatusLabel",
        text
    )
end

function HolyDevStartErrorMonitor()

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    if runtime.ErrorConnection then
        return true
    end

    local ScriptContext =
        game:GetService(
            "ScriptContext"
        )

    local success,
        connection =
        pcall(function()

            return ScriptContext.Error:Connect(function(
                message,
                stackTrace,
                source
            )

                local key =
                    tostring(message)
                    .. "\n"
                    .. tostring(stackTrace)

                local row =
                    runtime.Errors[key]

                if row == nil then

                    row = {
                        Message = tostring(message),
                        StackTrace = tostring(stackTrace),
                        Source = HolyDevSafeValue(source),
                        Count = 0,
                        FirstAt = os.time(),
                    }

                    runtime.Errors[key] =
                        row

                    runtime.ErrorOrder[
                        #runtime.ErrorOrder + 1
                    ] =
                        key
                end

                row.Count +=
                    1

                row.LastAt =
                    os.time()

                if type(HolyDevTrace)
                == "function" then

                    pcall(
                        HolyDevTrace,
                        "Errors",
                        "ScriptError",
                        {
                            Message =
                                tostring(message),

                            StackTrace =
                                tostring(stackTrace),

                            Source =
                                HolyDevSafeValue(
                                    source
                                ),
                        },
                        "Error"
                    )
                end

                HolyDevRefreshErrorStatus()
            end)
        end)

    if success == true then

        runtime.ErrorConnection =
            connection

        HolyDevRefreshErrorStatus()

        return true
    end

    HolyDevSetStatus(
        "ErrorStatusLabel",
        "Error capture unavailable."
    )

    return false
end

function HolyDevCopyErrors()

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    local rows =
        {}

    for _, key in ipairs(
        runtime.ErrorOrder
    ) do

        if runtime.Errors[key] then

            rows[#rows + 1] =
                runtime.Errors[key]
        end
    end

    return HolyDevCopyReport({
        Version = "HOLY_DEV_ERRORS_V1",
        PlaceId = game.PlaceId,
        JobId = game.JobId,
        CapturedAt = os.time(),
        Errors = rows,
    })
end

function HolyDevClearErrors()

    HOLY_DEV_SUITE_RUNTIME.Errors =
        {}

    HOLY_DEV_SUITE_RUNTIME.ErrorOrder =
        {}

    HolyDevRefreshErrorStatus()

    return true
end

function HolyDevPacketLimit(value)

    return math.clamp(
        math.floor(
            tonumber(value)
            or 300
        ),
        10,
        10000
    )
end

function HolyDevPacketDirection(value)

    value =
        tostring(
            value
            or "Both"
        )

    if value == "Sent"
    or value == "Received" then

        return value
    end

    return "Both"
end

function HolyDevPacketId(packet)

    for _, key in ipairs({
        "PacketId",
        "PacketID",
        "Id",
        "ID",
        "id",
    }) do

        local ok,
            value =
            pcall(function()

                return packet[key]
            end)

        value =
            ok == true
            and tonumber(value)
            or nil

        if value
        and value >= 0
        and value <= 65535
        and value % 1 == 0 then

            return value
        end
    end

    return nil
end

function HolyDevPacketSafeValue(value)

    return HolyDevSafeValue(
        value,
        0,
        {},
        {
            MaxDepth = 8,
            MaxMapEntries = 500,
            MaxArrayEntries = 2000,
            MaxStringLength = 2000,
        }
    )
end

function HolyDevPacketArguments(...)

    local packed =
        table.pack(...)

    local output =
        {}

    for index = 1, packed.n do

        output[index] =
            HolyDevPacketSafeValue(
                packed[index]
            )
    end

    return output
end

function HolyDevPacketMatches(direction, entry)

    local wantedDirection =
        HolyDevPacketDirection(
            HOLY_DEV_SUITE_STATE.PacketDirection
        )

    if wantedDirection ~= "Both"
    and wantedDirection ~= direction then

        return false
    end

    local filter =
        tostring(
            HOLY_DEV_SUITE_STATE.PacketFilter
            or ""
        ):lower()

    if filter == "" then
        return true
    end

    local searchable =
        (
            tostring(
                entry.Path
                or ""
            )
            .. " "
            .. tostring(
                entry.PacketId
                or ""
            )
        ):lower()

    return searchable:find(
        filter,
        1,
        true
    ) ~= nil
end

function HolyDevPacketRefreshStatus(force)

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    local now =
        os.clock()

    if force ~= true
    and now - (
        runtime.PacketStatusClock
        or 0
    ) < 0.15 then

        return
    end

    runtime.PacketStatusClock =
        now

    local count =
        #(
            runtime.PacketEvents
            or {}
        )

    local limit =
        HolyDevPacketLimit(
            HOLY_DEV_SUITE_STATE.PacketMaxEvents
        )

    local text =
        runtime.PacketActive == true
        and "Capturing"
        or "Ready"

    text =
        text
        .. " · "
        .. tostring(count)
        .. "/"
        .. tostring(limit)

    if (
        runtime.PacketSkipped
        or 0
    ) > 0 then

        text =
            text
            .. " · "
            .. tostring(
                runtime.PacketSkipped
            )
            .. " skipped"
    end

    if tostring(
        runtime.PacketLastName
        or ""
    ) ~= "" then

        text =
            text
            .. " · "
            .. tostring(
                runtime.PacketLastName
            )
    end

    HolyDevSetStatus(
        "PacketStatusLabel",
        text
    )
end

function HolyDevPacketRecord(direction, entry, ...)

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    if runtime.PacketActive ~= true then
        return
    end

    runtime.PacketObserved[direction] =
        (
            runtime.PacketObserved[direction]
            or 0
        )
        + 1

    if type(HolyDevRecorderRecordPacket)
        == "function" then

        pcall(
            HolyDevRecorderRecordPacket,
            direction,
            entry,
            ...
        )
    end

    if HolyDevPacketMatches(
        direction,
        entry
    ) ~= true then

        runtime.PacketFiltered +=
            1

        return
    end

    runtime.PacketCounts[direction] =
        (
            runtime.PacketCounts[direction]
            or 0
        )
        + 1

    runtime.PacketLastName =
        entry.Path

    local limit =
        HolyDevPacketLimit(
            HOLY_DEV_SUITE_STATE.PacketMaxEvents
        )

    if #runtime.PacketEvents >= limit then

        runtime.PacketSkipped +=
            1

        HolyDevPacketRefreshStatus(
            false
        )

        return
    end

    runtime.PacketEvents[
        #runtime.PacketEvents + 1
    ] = {
        Index =
            #runtime.PacketEvents + 1,

        Time =
            os.clock()
            - runtime.PacketStartedClock,

        Direction =
            direction,

        Packet =
            entry.Path,

        PacketId =
            entry.PacketId,

        Arguments =
            HolyDevPacketArguments(...),
    }

    HolyDevPacketRefreshStatus(
        false
    )
end

function HolyDevPacketCleanup()

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    for _, connection in ipairs(
        runtime.PacketConnections
        or {}
    ) do

        pcall(function()

            connection:Disconnect()
        end)
    end

    runtime.PacketConnections =
        {}

    for index = #(
        runtime.PacketWrappers
        or {}
    ), 1, -1 do

        local row =
            runtime.PacketWrappers[index]

        pcall(function()

            if row.Packet[row.Method]
            == row.Wrapper then

                row.Packet[row.Method] =
                    row.Original
            end
        end)
    end

    runtime.PacketWrappers =
        {}
end

function HolyDevPacketNetworking()

    if type(HolyShopRequireModule)
    == "function" then

        local result =
            HolyShopRequireModule(
                "SharedModules.Networking"
            )

        if type(result) == "table" then
            return result
        end
    end

    local sharedModules =
        ReplicatedStorage:FindFirstChild(
            "SharedModules"
        )

    local module =
        sharedModules
        and sharedModules:FindFirstChild(
            "Networking"
        )

    if typeof(module) ~= "Instance"
    or module:IsA("ModuleScript") ~= true then

        return nil
    end

    local ok,
        result =
        pcall(
            require,
            module
        )

    if ok == true
    and type(result) == "table" then

        return result
    end

    return nil
end

function HolyDevPacketStart()

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    if runtime.PacketActive == true then

        HolyNotify(
            "HOLY Dev",
            "Packet capture is already running.",
            3
        )

        return false
    end

    HolyDevPacketCleanup()

    local networking =
        HolyDevPacketNetworking()

    if type(networking) ~= "table" then

        HolyDevSetStatus(
            "PacketStatusLabel",
            "Networking module unavailable."
        )

        HolyNotify(
            "HOLY Dev",
            "Networking module unavailable.",
            5
        )

        return false
    end

    HOLY_DEV_SUITE_STATE.PacketMaxEvents =
        HolyDevPacketLimit(
            HOLY_DEV_SUITE_STATE.PacketMaxEvents
        )

    runtime.PacketActive =
        true

    runtime.PacketStartedAt =
        os.time()

    runtime.PacketStartedClock =
        os.clock()

    runtime.PacketEvents =
        {}

    runtime.PacketConnections =
        {}

    runtime.PacketWrappers =
        {}

    runtime.PacketRegistry =
        {}

    runtime.PacketCounts = {
        Sent = 0,
        Received = 0,
    }

    runtime.PacketObserved = {
        Sent = 0,
        Received = 0,
    }

    runtime.PacketFiltered =
        0

    runtime.PacketSkipped =
        0

    runtime.PacketLastName =
        ""

    runtime.PacketStatusClock =
        0

    local direction =
        HolyDevPacketDirection(
            HOLY_DEV_SUITE_STATE.PacketDirection
        )

    local seen =
        {}

    local packetSeen =
        {}

    local nodes =
        0

    local coverage = {
        PacketTables = 0,
        SentHooks = 0,
        ReceivedHooks = 0,
        FailedSentHooks = 0,
        FailedReceivedHooks = 0,
        NodesScanned = 0,
        Truncated = false,
    }

    local function installSent(entry, methodName)

        local packet =
            entry.Packet

        local original =
            packet[methodName]

        if type(original) ~= "function" then
            return false
        end

        local wrapper

        wrapper =
            function(self, ...)

                HolyDevPacketRecord(
                    "Sent",
                    entry,
                    ...
                )

                return original(
                    self,
                    ...
                )
            end

        local ok =
            pcall(function()

                packet[methodName] =
                    wrapper
            end)

        if ok ~= true
        or packet[methodName] ~= wrapper then

            return false
        end

        runtime.PacketWrappers[
            #runtime.PacketWrappers + 1
        ] = {
            Packet = packet,
            Method = methodName,
            Original = original,
            Wrapper = wrapper,
        }

        entry.SentMethods[
            #entry.SentMethods + 1
        ] =
            methodName

        return true
    end

    local function installReceived(entry)

        local signal

        pcall(function()

            signal =
                entry.Packet.OnClientEvent
        end)

        if signal == nil then
            return false
        end

        local ok,
            connection =
            pcall(function()

                return signal:Connect(function(...)

                    HolyDevPacketRecord(
                        "Received",
                        entry,
                        ...
                    )
                end)
            end)

        if ok ~= true
        or connection == nil then

            return false
        end

        runtime.PacketConnections[
            #runtime.PacketConnections + 1
        ] =
            connection

        entry.Received =
            true

        return true
    end

    local function scan(node, path, depth)

        if type(node) ~= "table"
        or seen[node] == true
        or depth > 12 then

            return
        end

        if nodes >= 30000 then

            coverage.Truncated =
                true

            return
        end

        seen[node] =
            true

        nodes +=
            1

        local hasSent =
            type(node.Fire) == "function"
            or type(node.Invoke) == "function"

        local hasReceived =
            false

        pcall(function()

            hasReceived =
                node.OnClientEvent ~= nil
        end)

        if hasSent == true
        or hasReceived == true then

            if packetSeen[node] ~= true then

                packetSeen[node] =
                    true

                local entry = {
                    Packet = node,

                    Path =
                        path ~= ""
                        and path
                        or "<root>",

                    PacketId =
                        HolyDevPacketId(node),

                    SentMethods = {},
                    Received = false,
                }

                runtime.PacketRegistry[
                    #runtime.PacketRegistry + 1
                ] =
                    entry

                coverage.PacketTables +=
                    1

                if direction == "Both"
                or direction == "Sent" then

                    for _, methodName in ipairs({
                        "Fire",
                        "Invoke",
                    }) do

                        if type(node[methodName])
                        == "function" then

                            if installSent(
                                entry,
                                methodName
                            ) then

                                coverage.SentHooks +=
                                    1

                            else

                                coverage.FailedSentHooks +=
                                    1
                            end
                        end
                    end
                end

                if hasReceived == true
                and (
                    direction == "Both"
                    or direction == "Received"
                ) then

                    if installReceived(entry) then

                        coverage.ReceivedHooks +=
                            1

                    else

                        coverage.FailedReceivedHooks +=
                            1
                    end
                end
            end

            return
        end

        local children =
            {}

        pcall(function()

            for key, child in pairs(node) do

                if type(child) == "table" then

                    children[
                        #children + 1
                    ] = {
                        Key = key,
                        Value = child,
                    }
                end
            end
        end)

        table.sort(
            children,
            function(left, right)

                return tostring(left.Key)
                    < tostring(right.Key)
            end
        )

        for _, child in ipairs(children) do

            local childPath =
                path == ""
                and tostring(child.Key)
                or path
                    .. "."
                    .. tostring(child.Key)

            scan(
                child.Value,
                childPath,
                depth + 1
            )
        end
    end

    scan(
        networking,
        "",
        0
    )

    coverage.NodesScanned =
        nodes

    runtime.PacketCoverage =
        coverage

    if coverage.PacketTables <= 0 then

        runtime.PacketActive =
            false

        HolyDevPacketCleanup()

        HolyDevSetStatus(
            "PacketStatusLabel",
            "No packet tables found."
        )

        HolyNotify(
            "HOLY Dev",
            "No packet tables were found.",
            5
        )

        return false
    end

    HolyDevPacketRefreshStatus(
        true
    )

    HolyNotify(
        "HOLY Dev",
        "Packet capture started.",
        3
    )

    return true
end

function HolyDevPacketBuildReport(reason)

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    local registry =
        {}

    local placeVersion

    pcall(function()

        placeVersion =
            game.PlaceVersion
    end)

    for _, entry in ipairs(
        runtime.PacketRegistry
        or {}
    ) do

        registry[
            #registry + 1
        ] = {
            Path = entry.Path,
            PacketId = entry.PacketId,
            SentMethods = entry.SentMethods,
            Received = entry.Received,
        }
    end

    return {
        Version =
            "HOLY_PACKET_WATCHER_V1",

        PlaceId =
            game.PlaceId,

        PlaceVersion =
            placeVersion,

        JobId =
            game.JobId,

        StartedAt =
            runtime.PacketStartedAt,

        FinishedAt =
            os.time(),

        Runtime =
            os.clock()
            - (
                runtime.PacketStartedClock
                or os.clock()
            ),

        FinishReason =
            tostring(
                reason
                or "manual stop"
            ),

        Config = {
            Direction =
                HolyDevPacketDirection(
                    HOLY_DEV_SUITE_STATE.PacketDirection
                ),

            Filter =
                tostring(
                    HOLY_DEV_SUITE_STATE.PacketFilter
                    or ""
                ),

            MaxEvents =
                HolyDevPacketLimit(
                    HOLY_DEV_SUITE_STATE.PacketMaxEvents
                ),
        },

        Counts =
            runtime.PacketCounts,

        ObservedCounts =
            runtime.PacketObserved,

        FilteredEvents =
            runtime.PacketFiltered,

        StoredEvents =
            #runtime.PacketEvents,

        SkippedAtLimit =
            runtime.PacketSkipped,

        Coverage =
            runtime.PacketCoverage,

        Registry =
            registry,

        Events =
            runtime.PacketEvents,

        Safety = {
            Passive = true,
            PacketsFiredByWatcher = 0,
        },
    }
end

function HolyDevPacketStop(copyResult, reason)

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    if runtime.PacketActive ~= true then

        HolyNotify(
            "HOLY Dev",
            "Packet capture is not running.",
            3
        )

        return false
    end

    runtime.PacketActive =
        false

    local report =
        HolyDevPacketBuildReport(
            reason
        )

    HolyDevPacketCleanup()

    runtime.LastPacketReport =
        report

    local saved =
        HolyDevWriteJson(
            DEV_PACKET_WATCHER_FILE,
            report
        )

    local copied =
        copyResult == true
        and HolyDevCopyReport(
            report
        )
        or false

    local status =
        "Stopped · "
        .. tostring(
            report.StoredEvents
        )
        .. " events"

    if report.SkippedAtLimit > 0 then

        status =
            status
            .. " · "
            .. tostring(
                report.SkippedAtLimit
            )
            .. " skipped"
    end

    if copied == true then

        status =
            status
            .. " · copied"
    end

    if saved == true then

        status =
            status
            .. " · saved"
    end

    HolyDevSetStatus(
        "PacketStatusLabel",
        status
    )

    HolyNotify(
        "HOLY Dev",
        status,
        5
    )

    return true
end

function HolyDevPacketCopyLast()

    local report =
        HOLY_DEV_SUITE_RUNTIME.LastPacketReport
        or HolyDevReadJson(
            DEV_PACKET_WATCHER_FILE
        )

    if type(report) ~= "table" then

        HolyNotify(
            "HOLY Dev",
            "No packet report is available yet.",
            4
        )

        return false
    end

    local copied =
        HolyDevCopyReport(
            report
        )

    if copied == true then

        HolyNotify(
            "HOLY Dev",
            "Packet report copied.",
            4
        )
    end

    return copied
end

function HolyDevPacketClear()

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    runtime.PacketEvents =
        {}

    runtime.PacketCounts = {
        Sent = 0,
        Received = 0,
    }

    runtime.PacketObserved = {
        Sent = 0,
        Received = 0,
    }

    runtime.PacketFiltered =
        0

    runtime.PacketSkipped =
        0

    runtime.PacketLastName =
        ""

    runtime.LastPacketReport =
        nil

    if runtime.PacketActive == true then

        runtime.PacketStartedAt =
            os.time()

        runtime.PacketStartedClock =
            os.clock()
    end

    if HolyCanUseFiles() == true
    and type(delfile) == "function" then

        pcall(function()

            if isfile(
                DEV_PACKET_WATCHER_FILE
            ) then

                delfile(
                    DEV_PACKET_WATCHER_FILE
                )
            end
        end)
    end

    HolyDevPacketRefreshStatus(
        true
    )

    return true
end

function HolyDevAutoCheckUpdate()

    local baseline =
        HolyDevReadJson(
            DEV_UPDATE_BASELINE_FILE
        )

    if type(baseline) ~= "table" then

        HolyDevSetStatus(
            "UpdateStatusLabel",
            "No baseline saved."
        )

        return false
    end

    local currentVersion =
        nil

    pcall(function()

        currentVersion =
            game.PlaceVersion
    end)

    if tostring(currentVersion)
    ~= tostring(baseline.PlaceVersion) then

        return HolyDevScanUpdateChanges(
            false
        )
    end

    HolyDevSetStatus(
        "UpdateStatusLabel",
        "No version change • v"
            .. tostring(
                currentVersion
                or "?"
            )
    )

    return true
end

HOLY_DEV_SUITE_RUNTIME.Stop =
    function(reason)

        local runtime =
            HOLY_DEV_SUITE_RUNTIME

        runtime.RecorderActive =
            false

        runtime.RecorderTriggerGeneration =
            (
                runtime.RecorderTriggerGeneration
                or 0
            )
            + 1

        if type(HolyDevRecorderCleanupSources)
        == "function" then

            pcall(
                HolyDevRecorderCleanupSources
            )
        end

        runtime.Active =
            false

        runtime.RefreshGeneration +=
            1

        if runtime.ErrorConnection then

            pcall(function()

                runtime.ErrorConnection:Disconnect()
            end)

            runtime.ErrorConnection =
                nil
        end

        runtime.PacketActive =
            false

        HolyDevPacketCleanup()

        if type(HolyRollbackSetOwner) == "function" then

            pcall(function()

                HolyRollbackSetOwner(
                    "Persistence",
                    false
                )
            end)
        end

        return true
    end

