function HolyMoonExtractPickWeather()

    if type(debug) ~= "table"
    or type(debug.getupvalues) ~= "function" then

        return nil
    end

    local playerScripts =
        LocalPlayer
        and LocalPlayer:FindFirstChild(
            "PlayerScripts"
        )

    local controllers =
        playerScripts
        and playerScripts:FindFirstChild(
            "Controllers"
        )

    local module =
        controllers
        and controllers:FindFirstChild(
            "TimeCycleController"
        )

    if typeof(module) ~= "Instance"
    or module:IsA("ModuleScript") ~= true then

        return nil
    end

    local requireOk,
        controller =
        pcall(function()

            return require(
                module
            )
        end)

    if requireOk ~= true
    or type(controller) ~= "table"
    or type(controller.Start) ~= "function" then

        return nil
    end

    local upvalueOk,
        upvalues =
        pcall(function()

            return debug.getupvalues(
                controller.Start
            )
        end)

    if upvalueOk ~= true
    or type(upvalues) ~= "table" then

        return nil
    end

    local cycleInfo =
        HOLY_MOON_PREDICTOR_STATE.CycleInfo

    local function isPicker(candidate)

        if type(candidate) ~= "function"
        or type(cycleInfo) ~= "table"
        or type(cycleInfo.NightRecord) ~= "table" then

            return false
        end

        local ok,
            moonName =
            pcall(function()

                return candidate(
                    cycleInfo.NightRecord,
                    Random.new(123456)
                )
            end)

        return ok == true
            and type(moonName) == "string"
            and cycleInfo.NightRecord.Weathers[
                moonName
            ] ~= nil
    end

    if isPicker(upvalues[2]) == true then
        return upvalues[2]
    end

    for _, candidate in pairs(upvalues) do

        if isPicker(candidate) == true then
            return candidate
        end
    end

    return nil
end

function HolyMoonFallbackPickWeather(
    phaseRecord,
    rng
)

    if type(phaseRecord) ~= "table"
    or type(phaseRecord.Weathers) ~= "table" then

        return "?"
    end

    local rows =
        {}

    local total =
        0

    for weatherName, weatherData in pairs(
        phaseRecord.Weathers
    ) do

        local chance =
            tonumber(
                type(weatherData) == "table"
                and weatherData.Chance
                or 0
            )
            or 0

        table.insert(rows, {
            Name =
                tostring(weatherName),

            Chance =
                chance,
        })

        total +=
            chance
    end

    table.sort(rows, function(a, b)

        return tostring(a.Name)
            < tostring(b.Name)
    end)

    if total <= 0 then

        return rows[1]
            and rows[1].Name
            or "?"
    end

    local roll =
        rng:NextNumber()
        * total

    local cumulative =
        0

    for _, row in ipairs(rows) do

        cumulative +=
            tonumber(row.Chance)
            or 0

        if roll <= cumulative then
            return row.Name
        end
    end

    return rows[#rows]
        and rows[#rows].Name
        or "?"
end

function HolyMoonEnsureReady()

    local state =
        HOLY_MOON_PREDICTOR_STATE

    if type(state.CycleInfo) ~= "table" then

        state.CycleInfo =
            HolyMoonBuildCycleInfo()

        HolyMoonBuildTypes()
    end

    if type(state.PickWeather) ~= "function" then

        state.PickWeather =
            HolyMoonExtractPickWeather()
    end

    return type(state.CycleInfo) == "table"
end

function HolyMoonPredict(cycleIndex)

    local state =
        HOLY_MOON_PREDICTOR_STATE

    if HolyMoonEnsureReady() ~= true then
        return "?"
    end

    cycleIndex =
        math.floor(
            tonumber(cycleIndex)
            or 0
        )

    local cached =
        state.PredictionCache[cycleIndex]

    if type(cached) == "string" then
        return cached
    end

    local seed =
        cycleIndex
        * 1000
        + tonumber(
            state.CycleInfo.NightIndex
        )

    local moonName =
        nil

    if type(state.PickWeather) == "function" then

        local ok,
            result =
            pcall(function()

                return state.PickWeather(
                    state.CycleInfo.NightRecord,
                    Random.new(seed)
                )
            end)

        if ok == true
        and type(result) == "string" then

            moonName =
                result
        end
    end

    if type(moonName) ~= "string" then

        moonName =
            HolyMoonFallbackPickWeather(
                state.CycleInfo.NightRecord,
                Random.new(seed)
            )
    end

    state.PredictionCache[cycleIndex] =
        moonName

    return moonName
end

function HolyMoonSelectedChance()

    local selectedChance =
        0

    local totalChance =
        0

    for _, row in ipairs(
        HOLY_MOON_PREDICTOR_STATE.MoonTypes
    ) do

        local chance =
            math.max(
                0,
                tonumber(row.Chance)
                or 0
            )

        totalChance +=
            chance

        if HOLY_MOON_PREDICTOR_STATE.SelectedMoons[
            row.Raw
        ] == true then

            selectedChance +=
                chance
        end
    end

    return selectedChance,
        totalChance
end

function HolyMoonCalculateScanLimit()

    local amount =
        HolyMoonReadAmount(
            HOLY_MOON_PREDICTOR_STATE.Amount
        )

    local selectedChance,
        totalChance =
        HolyMoonSelectedChance()

    if selectedChance <= 0
    or totalChance <= 0 then

        return 0
    end

    local expected =
        amount
        * totalChance
        / selectedChance

    return math.clamp(
        math.ceil(
            math.max(
                2000,
                expected * 8
            )
        ),
        2000,
        250000
    )
end

function HolyMoonRequestBuild(reason)

    if HolyMoonEnsureReady() ~= true then
        return false
    end

    local state =
        HOLY_MOON_PREDICTOR_STATE

    state.ScanGeneration +=
        1

    local generation =
        state.ScanGeneration

    state.Predictions =
        {}

    state.Scanning =
        true

    state.ScanChecked =
        0

    state.ScanLimit =
        HolyMoonCalculateScanLimit()

    if state.ScanLimit <= 0 then

        state.Scanning =
            false

        HolyMoonRender()

        return false
    end

    local now =
        HolyMoonGetNow()

    local cycleInfo =
        state.CycleInfo

    local currentCycle =
        math.floor(
            now
            / cycleInfo.FullCycle
        )

    state.LastBuildCycle =
        currentCycle

    local wanted =
        HolyMoonReadAmount(
            state.Amount
        )

    HolyMoonRender()

    task.spawn(function()

        for offset = 0, state.ScanLimit do

            if state.ScanGeneration
            ~= generation then

                return
            end

            local cycleIndex =
                currentCycle
                + offset

            local nightStart =
                cycleIndex
                * cycleInfo.FullCycle
                + cycleInfo.SecondsBeforeNight

            if nightStart > now then

                local moonName =
                    HolyMoonPredict(
                        cycleIndex
                    )

                if state.SelectedMoons[
                    moonName
                ] == true then

                    table.insert(
                        state.Predictions,
                        {
                            Moon =
                                moonName,

                            StartsAt =
                                nightStart,

                            CycleIndex =
                                cycleIndex,
                        }
                    )

                    if #state.Predictions
                    >= wanted then

                        break
                    end
                end
            end

            state.ScanChecked =
                offset + 1

            if offset % 75 == 0 then

                HolyMoonRender()

                task.wait()
            end
        end

        if state.ScanGeneration
        ~= generation then

            return
        end

        state.Scanning =
            false

        HolyMoonRender()
    end)

    return true
end

function HolyMoonFindWeatherRecord(value)

    local state =
        HOLY_MOON_PREDICTOR_STATE

    local direct =
        state.WeatherRecords[
            tostring(value or "")
        ]

    if type(direct) == "table" then
        return direct
    end

    local wantedKey =
        HolyMoonKey(
            value
        )

    for rawName, record in pairs(
        state.WeatherRecords
    ) do

        if HolyMoonKey(rawName)
        == wantedKey then

            return record
        end
    end

    return nil
end

function HolyMoonUpdateCurrentUI()

    local ui =
        HOLY_MOON_PREDICTOR_UI

    if typeof(ui.CurrentLabel) ~= "Instance" then
        return false
    end

    local activeWeather =
        HolyCleanText(
            workspace:GetAttribute(
                "ActiveWeather"
            )
        )

    if activeWeather == "" then
        activeWeather = "Unknown"
    end

    local now =
        HolyMoonGetNow()

    local phaseEnd =
        tonumber(
            workspace:GetAttribute(
                "PhaseDuration"
            )
        )
        or now

    local remaining =
        math.max(
            0,
            phaseEnd - now
        )

    local record =
        HolyMoonFindWeatherRecord(
            activeWeather
        )

    local weatherData =
        type(record) == "table"
        and record.Data
        or {}

    local displayName =
        HolyMoonDisplayName(
            activeWeather
        )

    local color =
        HolyMoonColor(
            activeWeather,
            weatherData
        )

    ui.CurrentLabel.Text =
        '<font color="rgb(226,232,240)"><b>Current:</b></font> '
        .. '<font color="'
        .. HolyMoonRichColor(color)
        .. '"><b>'
        .. HolyMoonEscape(displayName)
        .. '</b></font> '
        .. '<font color="rgb(148,163,184)">· '
        .. HolyMoonFormatSeconds(remaining)
        .. ' left</font>'

    if typeof(ui.CurrentIcon) == "Instance" then

        local image =
            type(weatherData) == "table"
            and tostring(
                weatherData.Image
                or ""
            )
            or ""

        ui.CurrentIcon.Image =
            image

        ui.CurrentIcon.Visible =
            image ~= ""
    end

    return true
end

function HolyMoonRender()

    local state =
        HOLY_MOON_PREDICTOR_STATE

    local ui =
        HOLY_MOON_PREDICTOR_UI

    if typeof(ui.Surface) ~= "Instance" then
        return false
    end

    HolyMoonUpdateCurrentUI()

    local rowsPerPage =
        math.max(
            1,
            math.floor(
                tonumber(state.RowsPerPage)
                or 6
            )
        )

    local resultCount =
        #state.Predictions

    local maxPage =
        math.max(
            1,
            math.ceil(
                resultCount
                / rowsPerPage
            )
        )

    state.Page =
        math.clamp(
            math.floor(
                tonumber(state.Page)
                or 1
            ),
            1,
            maxPage
        )

    local wanted =
        HolyMoonReadAmount(
            state.Amount
        )

    if typeof(ui.HeaderLabel) == "Instance" then

        if state.Scanning == true then

            ui.HeaderLabel.Text =
                "Moon  •  Finding "
                .. tostring(resultCount)
                .. "/"
                .. tostring(wanted)

        else

            ui.HeaderLabel.Text =
                "Moon  •  "
                .. tostring(resultCount)
                .. " results"
        end
    end

    if typeof(ui.PageLabel) == "Instance" then

        ui.PageLabel.Text =
            "Page "
            .. tostring(state.Page)
            .. " / "
            .. tostring(maxPage)
    end

    local canPrevious =
        state.Page > 1

    local canNext =
        state.Page < maxPage

    if typeof(ui.PreviousButton) == "Instance" then

        ui.PreviousButton.TextTransparency =
            canPrevious
            and 0
            or 0.55
    end

    if typeof(ui.NextButton) == "Instance" then

        ui.NextButton.TextTransparency =
            canNext
            and 0
            or 0.55
    end

    local firstIndex =
        (state.Page - 1)
        * rowsPerPage
        + 1

    local now =
        HolyMoonGetNow()

    for rowIndex = 1, rowsPerPage do

        local rowUI =
            ui.Rows[rowIndex]

        local prediction =
            state.Predictions[
                firstIndex
                + rowIndex
                - 1
            ]

        if type(rowUI) == "table"
        and typeof(rowUI.Frame) == "Instance" then

            if type(prediction) == "table" then

                local record =
                    HolyMoonFindWeatherRecord(
                        prediction.Moon
                    )

                local weatherData =
                    type(record) == "table"
                    and record.Data
                    or {}

                rowUI.Frame.Visible =
                    true

                rowUI.Name.Text =
                    HolyMoonDisplayName(
                        prediction.Moon
                    )

                rowUI.Name.TextColor3 =
                    HolyMoonColor(
                        prediction.Moon,
                        weatherData
                    )

                rowUI.Timer.Text =
                    HolyMoonFormatSeconds(
                        tonumber(
                            prediction.StartsAt
                        )
                        - now
                    )

                local image =
                    type(weatherData) == "table"
                    and tostring(
                        weatherData.Image
                        or ""
                    )
                    or ""

                rowUI.Icon.Image =
                    image

                rowUI.Icon.Visible =
                    image ~= ""

            else

                rowUI.Frame.Visible =
                    false
            end
        end
    end

    if typeof(ui.EmptyLabel) == "Instance" then

        local hasSelection =
            next(state.SelectedMoons)
            ~= nil

        ui.EmptyLabel.Visible =
            resultCount <= 0

        if hasSelection ~= true then

            ui.EmptyLabel.Text =
                "Select at least one moon."

        elseif state.Scanning == true then

            ui.EmptyLabel.Text =
                "Finding moons..."

        else

            ui.EmptyLabel.Text =
                "No matching moons found."
        end
    end

    return true
end

function HolyMoonSetPage(value)

    local state =
        HOLY_MOON_PREDICTOR_STATE

    local maxPage =
        math.max(
            1,
            math.ceil(
                #state.Predictions
                / math.max(
                    1,
                    tonumber(state.RowsPerPage)
                    or 6
                )
            )
        )

    state.Page =
        math.clamp(
            math.floor(
                tonumber(value)
                or 1
            ),
            1,
            maxPage
        )

    HolyMoonRender()

    return state.Page
end

function HolyMoonSetFilters(value)

    local state =
        HOLY_MOON_PREDICTOR_STATE

    local selected =
        {}

    for _, displayName in ipairs(
        HolyShopSelectionArray(
            value
        )
    ) do

        local rawName =
            state.RawByDisplay[
                displayName
            ]

        if rawName ~= nil then

            selected[rawName] =
                true
        end
    end

    state.SelectedMoons =
        selected

    state.HasSavedSelection =
        true

    state.Page =
        1

    HolyMoonSaveSettings()

    HolyMoonRequestBuild(
        "filters changed"
    )

    return true
end

function HolyMoonSetAmount(value)

    local amount =
        HolyMoonReadAmount(
            value
        )

    HOLY_MOON_PREDICTOR_STATE.Amount =
        amount

    HOLY_MOON_PREDICTOR_STATE.Page =
        1

    HolyMoonSaveSettings()

    local input =
        HOLY_MOON_PREDICTOR_UI.AmountInput

    if type(input) == "table"
    and type(input.SetValue) == "function"
    and tostring(value) ~= tostring(amount) then

        task.defer(function()

            pcall(function()

                input:SetValue(
                    tostring(amount)
                )
            end)
        end)
    end

    HolyMoonRequestBuild(
        "amount changed"
    )

    return amount
end

function HolyMoonCreateTextLabel(
    parent,
    name,
    position,
    size,
    textSize,
    align
)

    local label =
        Instance.new(
            "TextLabel"
        )

    label.Name =
        name

    label.BackgroundTransparency =
        1

    label.Position =
        position

    label.Size =
        size

    label.FontFace =
        Library.Scheme.Font

    label.Text =
        ""

    label.TextColor3 =
        Library.Scheme.FontColor

    label.TextSize =
        textSize
        or 11

    label.TextXAlignment =
        align
        or Enum.TextXAlignment.Left

    label.TextYAlignment =
        Enum.TextYAlignment.Center

    label.Parent =
        parent

    return label
end

