function HolyMoonHudAddConnection(connection)

    local runtime =
        HOLY_MOON_PREDICTOR_RUNTIME

    runtime.HudConnections =
        type(runtime.HudConnections) == "table"
        and runtime.HudConnections
        or {}

    if connection ~= nil then

        table.insert(
            runtime.HudConnections,
            connection
        )
    end

    return connection
end

function HolyMoonHudDestroy()

    local runtime =
        HOLY_MOON_PREDICTOR_RUNTIME

    runtime.HudToken =
        nil

    runtime.HudScanGeneration =
        (tonumber(runtime.HudScanGeneration) or 0)
        + 1

    runtime.HudScanning =
        false

    if type(runtime.HudConnections) == "table" then

        for _, connection in ipairs(
            runtime.HudConnections
        ) do

            pcall(function()

                connection:Disconnect()
            end)
        end
    end

    runtime.HudConnections =
        {}

    if typeof(runtime.HudScreenGui) == "Instance" then

        pcall(function()

            runtime.HudScreenGui:Destroy()
        end)
    end

    runtime.HudScreenGui =
        nil

    runtime.HudHolder =
        nil

    runtime.HudHeader =
        nil

    runtime.HudCurrentIcon =
        nil

    runtime.HudCurrentLabel =
        nil

    runtime.HudEmptyLabel =
        nil

    runtime.HudCards =
        {}

    runtime.HudPredictions =
        {}

    return true
end

function HolyMoonHudGetParent()

    if type(gethui) == "function" then

        local ok,
            result =
            pcall(function()

                return gethui()
            end)

        if ok == true
        and typeof(result) == "Instance" then

            return result
        end
    end

    return CoreGui
end

function HolyMoonHudGetViewport()

    local viewport =
        Vector2.new(
            1920,
            1080
        )

    pcall(function()

        local camera =
            workspace.CurrentCamera

        if camera then

            viewport =
                camera.ViewportSize
        end
    end)

    return viewport
end

function HolyMoonHudReadPosition()

    local saved =
        HOLY_MOON_PREDICTOR_STATE.HudPosition

    if type(saved) == "table" then

        local x =
            tonumber(
                saved.X
                or saved.x
                or saved[1]
            )

        local y =
            tonumber(
                saved.Y
                or saved.y
                or saved[2]
            )

        if x ~= nil
        and y ~= nil then

            return UDim2.fromOffset(
                math.floor(x + 0.5),
                math.floor(y + 0.5)
            )
        end
    end

    local viewport =
        HolyMoonHudGetViewport()

    return UDim2.fromOffset(
        math.max(
            12,
            viewport.X - 432
        ),
        math.max(
            12,
            viewport.Y - 190
        )
    )
end

function HolyMoonHudClampHolder()

    local holder =
        HOLY_MOON_PREDICTOR_RUNTIME.HudHolder

    if typeof(holder) ~= "Instance" then
        return false
    end

    local viewport =
        HolyMoonHudGetViewport()

    local width =
        holder.AbsoluteSize.X

    local height =
        holder.AbsoluteSize.Y

    if width <= 0 then
        width = 420
    end

    if height <= 0 then
        height = 112
    end

    local x =
        math.clamp(
            holder.Position.X.Offset,
            0,
            math.max(
                0,
                viewport.X - width
            )
        )

    local y =
        math.clamp(
            holder.Position.Y.Offset,
            0,
            math.max(
                0,
                viewport.Y - height
            )
        )

    holder.Position =
        UDim2.fromOffset(
            x,
            y
        )

    return true
end

function HolyMoonHudSavePosition()

    local holder =
        HOLY_MOON_PREDICTOR_RUNTIME.HudHolder

    if typeof(holder) ~= "Instance" then
        return false
    end

    HOLY_MOON_PREDICTOR_STATE.HudPosition = {
        X =
            math.floor(
                holder.Position.X.Offset
                + 0.5
            ),

        Y =
            math.floor(
                holder.Position.Y.Offset
                + 0.5
            ),
    }

    HolyMoonSaveSettings()

    return true
end

function HolyMoonHudMakeDraggable(holder, handle)

    if typeof(holder) ~= "Instance"
    or typeof(handle) ~= "Instance" then

        return false
    end

    local dragging =
        false

    local dragInput =
        nil

    local dragStart =
        nil

    local startPosition =
        nil

    handle.Active =
        true

    HolyMoonHudAddConnection(
        handle.InputBegan:Connect(function(input)

            local inputType =
                input.UserInputType

            if inputType ~= Enum.UserInputType.MouseButton1
            and inputType ~= Enum.UserInputType.Touch then

                return
            end

            dragging =
                true

            dragInput =
                input

            dragStart =
                input.Position

            startPosition =
                holder.Position
        end)
    )

    HolyMoonHudAddConnection(
        UserInputService.InputChanged:Connect(function(input)

            if dragging ~= true
            or dragStart == nil
            or startPosition == nil then

                return
            end

            local inputType =
                input.UserInputType

            if inputType ~= Enum.UserInputType.MouseMovement
            and inputType ~= Enum.UserInputType.Touch then

                return
            end

            if dragInput
            and dragInput.UserInputType == Enum.UserInputType.Touch
            and input ~= dragInput then

                return
            end

            local delta =
                input.Position
                - dragStart

            holder.Position =
                UDim2.fromOffset(
                    startPosition.X.Offset
                    + delta.X,
                    startPosition.Y.Offset
                    + delta.Y
                )

            HolyMoonHudClampHolder()
        end)
    )

    HolyMoonHudAddConnection(
        UserInputService.InputEnded:Connect(function(input)

            if dragging ~= true then
                return
            end

            local inputType =
                input.UserInputType

            if inputType == Enum.UserInputType.MouseButton1
            or (
                inputType == Enum.UserInputType.Touch
                and input == dragInput
            ) then

                dragging =
                    false

                dragInput =
                    nil

                dragStart =
                    nil

                startPosition =
                    nil

                HolyMoonHudClampHolder()

                HolyMoonHudSavePosition()
            end
        end)
    )

    return true
end

function HolyMoonHudRequestBuild(reason)

    local state =
        HOLY_MOON_PREDICTOR_STATE

    local runtime =
        HOLY_MOON_PREDICTOR_RUNTIME

    if state.HudEnabled ~= true
    or HolyMoonEnsureReady() ~= true then

        return false
    end

    runtime.HudScanGeneration =
        (tonumber(runtime.HudScanGeneration) or 0)
        + 1

    local generation =
        runtime.HudScanGeneration

    runtime.HudPredictions =
        {}

    runtime.HudScanning =
        true

    local now =
        HolyMoonGetNow()

    local cycleInfo =
        state.CycleInfo

    local currentCycle =
        math.floor(
            now
            / cycleInfo.FullCycle
        )

    runtime.HudLastCycle =
        currentCycle

    HolyMoonHudRender()

    task.spawn(function()

        for offset = 0, 5000 do

            if runtime.HudScanGeneration
            ~= generation
            or state.HudEnabled ~= true then

                return
            end

            local cycleIndex =
                currentCycle
                + offset

            local nightStart =
                cycleIndex
                * cycleInfo.FullCycle
                + cycleInfo.SecondsBeforeNight

            if nightStart > now then

                local moonName =
                    HolyMoonPredict(
                        cycleIndex
                    )

                local record =
                    HolyMoonFindWeatherRecord(
                        moonName
                    )

                if HolyMoonKey(moonName) ~= "moon"
                and type(record) == "table" then

                    table.insert(
                        runtime.HudPredictions,
                        {
                            Moon =
                                moonName,

                            StartsAt =
                                nightStart,

                            CycleIndex =
                                cycleIndex,
                        }
                    )

                    if #runtime.HudPredictions >= 5 then
                        break
                    end
                end
            end

            if offset % 75 == 0 then

                HolyMoonHudRender()

                task.wait()
            end
        end

        if runtime.HudScanGeneration
        ~= generation then

            return
        end

        runtime.HudScanning =
            false

        HolyMoonHudRender()
    end)

    return true
end

function HolyMoonHudRender()

    local state =
        HOLY_MOON_PREDICTOR_STATE

    local runtime =
        HOLY_MOON_PREDICTOR_RUNTIME

    local holder =
        runtime.HudHolder

    if state.HudEnabled ~= true
    or typeof(holder) ~= "Instance" then

        return false
    end

    local activeWeather =
        HolyCleanText(
            workspace:GetAttribute(
                "ActiveWeather"
            )
        )

    if activeWeather == "" then
        activeWeather = "Unknown"
    end

    local now =
        HolyMoonGetNow()

    local phaseEnd =
        tonumber(
            workspace:GetAttribute(
                "PhaseDuration"
            )
        )
        or now

    local currentRecord =
        HolyMoonFindWeatherRecord(
            activeWeather
        )

    local currentData =
        type(currentRecord) == "table"
        and currentRecord.Data
        or {}

    local currentColor =
        HolyMoonColor(
            activeWeather,
            currentData
        )

    if typeof(runtime.HudCurrentLabel) == "Instance" then

        runtime.HudCurrentLabel.Text =
            '<font color="rgb(226,232,240)"><b>Current:</b></font> '
            .. '<font color="'
            .. HolyMoonRichColor(currentColor)
            .. '"><b>'
            .. HolyMoonEscape(
                HolyMoonDisplayName(
                    activeWeather
                )
            )
            .. '</b></font> '
            .. '<font color="rgb(148,163,184)">· '
            .. HolyMoonFormatSeconds(
                math.max(
                    0,
                    phaseEnd - now
                )
            )
            .. ' left</font>'
    end

    if typeof(runtime.HudCurrentIcon) == "Instance" then

        local currentImage =
            type(currentData) == "table"
            and tostring(currentData.Image or "")
            or ""

        runtime.HudCurrentIcon.Image =
            currentImage

        runtime.HudCurrentIcon.Visible =
            currentImage ~= ""
    end

    local predictions =
        type(runtime.HudPredictions) == "table"
        and runtime.HudPredictions
        or {}

    for index = 1, 5 do

        local card =
            runtime.HudCards[index]

        local prediction =
            predictions[index]

        if type(card) == "table"
        and typeof(card.Frame) == "Instance" then

            if type(prediction) == "table" then

                local record =
                    HolyMoonFindWeatherRecord(
                        prediction.Moon
                    )

                local weatherData =
                    type(record) == "table"
                    and record.Data
                    or {}

                card.Frame.Visible =
                    true

                card.Name.Text =
                    HolyMoonDisplayName(
                        prediction.Moon
                    )

                card.Name.TextColor3 =
                    HolyMoonColor(
                        prediction.Moon,
                        weatherData
                    )

                card.Timer.Text =
                    HolyMoonFormatSeconds(
                        tonumber(prediction.StartsAt)
                        - now
                    )

                local image =
                    type(weatherData) == "table"
                    and tostring(weatherData.Image or "")
                    or ""

                card.Icon.Image =
                    image

                card.Icon.Visible =
                    image ~= ""

            else

                card.Frame.Visible =
                    false
            end
        end
    end

    if typeof(runtime.HudEmptyLabel) == "Instance" then

        runtime.HudEmptyLabel.Visible =
            #predictions <= 0

        runtime.HudEmptyLabel.Text =
            runtime.HudScanning == true
            and "Finding upcoming moons..."
            or "No upcoming moons found."
    end

    HolyMoonHudClampHolder()

    return true
end

