                Default =
                    HOLY_MOON_PREDICTOR_STATE.HudEnabled == true,

                Tooltip =
                    "Shows a draggable HUD with the next five non-normal moons.",
            }
        )

    HOLY_MOON_PREDICTOR_UI.HudToggle =
        hudToggle

    hudToggle:OnChanged(function(value)

        HolyMoonHudSetEnabled(
            value
        )
    end)

    local filterDropdown =
        groupbox:AddDropdown(
            "HolyMainMoonFilters",
            {
                Text =
                    "Moons to Show",

                Values =
                    HolyMoonGetFilterValues(),

                Default =
                    HolyMoonGetSelectedDisplays(),

                Multi =
                    true,

                Searchable =
                    false,

                MaxVisibleDropdownItems =
                    8,

                Tooltip =
                    "Choose which upcoming moon types appear in the predictor.",
            }
        )

    HOLY_MOON_PREDICTOR_UI.FilterDropdown =
        filterDropdown

    filterDropdown:OnChanged(function(value)

        HolyMoonSetFilters(
