                Finished =
                    true,

                ClearTextOnFocus =
                    false,

                Tooltip =
                    "Total matching upcoming moons to generate. Range: 1 to 500.",
            }
        )

    HOLY_MOON_PREDICTOR_UI.AmountInput =
