            {
                Instance =
                    surface,

                Height =
                    240,

                Visible =
                    true,
            }
        )

    HolyMoonRender()

    return true
end

function HolyMoonStart()

    local runtime =
        HOLY_MOON_PREDICTOR_RUNTIME

    if runtime.Running == true then
        return false
    end

    runtime.Running =
        true

    local token =
        {}

    runtime.Token =
        token

    HolyMoonRequestBuild(
        "startup"
    )

    if HOLY_MOON_PREDICTOR_STATE.HudEnabled == true then

        HolyMoonHudStart()
    end

    task.spawn(function()

        while runtime.Token == token do

            HolyMoonRender()

            local state =
                HOLY_MOON_PREDICTOR_STATE

            local now =
                HolyMoonGetNow()

            local cycleInfo =
                state.CycleInfo

            if type(cycleInfo) == "table" then

                local currentCycle =
                    math.floor(
                        now
                        / cycleInfo.FullCycle
                    )

                local first =
                    state.Predictions[1]

                local expired =
                    type(first) == "table"
                    and tonumber(first.StartsAt)
                    and tonumber(first.StartsAt) <= now

                if state.Scanning ~= true
                and (
                    currentCycle
                    ~= state.LastBuildCycle
                    or expired == true
                ) then

                    HolyMoonRequestBuild(
                        "cycle advanced"
                    )
                end
            end

            task.wait(
                1
            )
        end

        if runtime.Token == token then

            runtime.Running =
                false
        end
    end)

    return true
end

function HolyMoonStop(reason)

    local runtime =
        HOLY_MOON_PREDICTOR_RUNTIME

    runtime.Token =
        nil

    runtime.Running =
        false

    HOLY_MOON_PREDICTOR_STATE.ScanGeneration +=
        1

    HOLY_MOON_PREDICTOR_STATE.Scanning =
        false

    HolyMoonHudDestroy()

    return true
end

HOLY_MOON_PREDICTOR_RUNTIME.Stop =
    HolyMoonStop

