function HolyServerFinderNormalizeAutoJoinMode(value)

    local text =
        HolyCleanText(
            value
        )
        :lower()

    if text:find("notify", 1, true) then
        return "Notify"
    end

    if text:find("join", 1, true)
    or text:find("best", 1, true) then
        return "Join Best"
    end

    return "Off"
end

function HolyServerFinderNextAutoJoinMode(value)

    value =
        HolyServerFinderNormalizeAutoJoinMode(
            value
        )

    if value == "Off" then
        return "Notify"
    end

    if value == "Notify" then
        return "Join Best"
    end

    return "Off"
end

function HolyServerFinderNormalizeAutoJoinMatchMode(value)

    local text =
        HolyCleanText(
            value
        )
        :lower()

    if text:find("all", 1, true)
    or text == "and" then

        return "All Selected"
    end

    return "Any Selected"
end

function HolyServerFinderNormalizeAutoJoinPetScope(value)

    local text =
        HolyCleanText(
            value
        )
        :lower()

    if text:find("any", 1, true) then
        return "Any Pet"
    end

    return "Selected Pets"
end

function HolyServerFinderSplitCommaList(value)

    local output =
        {}

    if type(value) == "table" then

        for key, enabled in pairs(value) do

            local text =
                ""

            if type(key) == "number" then

                text =
                    HolyCleanText(
                        enabled
                    )

            elseif enabled == true then

                text =
                    HolyCleanText(
                        key
                    )
            end

            if text ~= "" then

                table.insert(
                    output,
                    text
                )
            end
        end

    else

        value =
            HolyCleanText(
                value
            )

        value =
            value:gsub("/", ",")
                :gsub("%+", ",")
                :gsub(";", ",")

        for part in value:gmatch("[^,]+") do

            local text =
                HolyCleanText(
                    part
                )

            if text ~= "" then

                table.insert(
                    output,
                    text
                )
            end
        end
    end

    return output
end

function HolyServerFinderAutoJoinListHasAny(list)

    if type(list) ~= "table"
    or #list <= 0 then

        return true
    end

    for _, value in ipairs(list) do

        local text =
            HolyCleanText(
                value
            )
            :lower()

        if text == ""
        or text == "any"
        or text == "any pet"
        or text == "all" then

            return true
        end
    end

    return false
end

function HolyServerFinderAutoJoinUniqueList(list, normalizer, fallback)

    local output =
        {}

    local seen =
        {}

    fallback =
        fallback
        or "Any"

    for _, value in ipairs(HolyServerFinderSplitCommaList(list)) do

        local text =
            HolyCleanText(
                value
            )

        local lower =
            text:lower()

        if lower == ""
        or lower == "any"
        or lower == "all"
        or lower == "any pet" then

            return {
                "Any",
            }
        end

        if type(normalizer) == "function" then

            text =
                normalizer(
                    text
                )
        end

        text =
            HolyCleanText(
                text
            )

        if text ~= "" then

            local key =
                text:lower()

            if seen[key] ~= true then

                seen[key] =
                    true

                table.insert(
                    output,
                    text
                )
            end
        end
    end

    if #output <= 0 then
        return {
            fallback,
        }
    end

    return output
end

function HolyServerFinderNormalizeAutoJoinPetName(value)

    local text =
        HolyCleanText(
            value
        )

    if text == "" then
        return ""
    end

    return HolySniperResolvePetDisplay(
        text
    )
end

function HolyServerFinderNormalizeAutoJoinSizeName(value)

    local text =
        HolySniperNormalizeSizeName(
            value
        )

    if text == "Normal"
    or text == "Big"
    or text == "Huge" then

        return text
    end

    return ""
end

function HolyServerFinderNormalizeAutoJoinVariantName(value)

    local text =
        HolyCleanText(
            value
        )

    local lower =
        text:lower()

    if lower == "regular"
    or lower == "normal" then

        return "Regular"
    end

    text =
        HolySniperNormalizeVariantName(
            text
        )

    if text == "Normal" then
        return "Regular"
    end

    if text == "Rainbow" then
        return "Rainbow"
    end

    return text
end

function HolyServerFinderNormalizeAutoJoinRarityName(value)

    local text =
        HolyCleanText(
            value
        )

    if text == "" then
        return ""
    end

    return text
end

function HolyServerFinderNormalizeAutoJoinPriority(value)

    local text =
        HolyCleanText(
            value
        )
        :lower()

    if text:find(
        "high",
        1,
        true
    ) then

        return "High"
    end

    if text:find(
        "low",
        1,
        true
    ) then

        return "Low"
    end

    return "Medium"
end

function HolyServerFinderAutoJoinPriorityRank(value)

    value =
        HolyServerFinderNormalizeAutoJoinPriority(
            value
        )

    if value == "High" then
        return 1
    end

    if value == "Low" then
        return 3
    end

    return 2
end

function HolyServerFinderNormalizeAutoJoinRule(rule)

    rule =
        type(rule) == "table"
        and rule
        or {}

    local petScope =
        HolyServerFinderNormalizeAutoJoinPetScope(
            rule.PetScope
            or rule.Scope
            or "Selected Pets"
        )

    local pets =
        HolyServerFinderAutoJoinUniqueList(
            rule.Pets
            or rule.Pet
            or rule.SelectedPets,
            HolyServerFinderNormalizeAutoJoinPetName,
            "Any"
        )

    if petScope == "Any Pet" then

        pets =
            {
                "Any",
            }
    end

    if petScope ~= "Any Pet"
    and HolyServerFinderAutoJoinListHasAny(pets) == true then

        pets =
            {
                "Bunny",
            }
    end

    local sizes =
        HolyServerFinderAutoJoinUniqueList(
            rule.Sizes
            or rule.Size,
            HolyServerFinderNormalizeAutoJoinSizeName,
            "Any"
        )

    local variants =
        HolyServerFinderAutoJoinUniqueList(
            rule.Variants
            or rule.Variant
            or rule.Mutations
            or rule.Mutation,
            HolyServerFinderNormalizeAutoJoinVariantName,
            "Any"
        )

    local rarities =
        HolyServerFinderAutoJoinUniqueList(
            rule.Rarities
            or rule.Rarity,
            HolyServerFinderNormalizeAutoJoinRarityName,
            "Any"
        )

    return {
        PetScope =
            petScope,

        Pets =
            pets,

        Sizes =
            sizes,

        Variants =
            variants,

        Rarities =
            rarities,

        MatchMode =
            "All Selected",

        Priority =
            HolyServerFinderNormalizeAutoJoinPriority(
                rule.Priority
                or "Medium"
            ),
    }
end

function HolyServerFinderNormalizeAutoJoinRules(rules)

    local output =
        {}

    local suppliedList =
        type(rules) == "table"

    if suppliedList then

        for _, target in ipairs(rules) do

            if type(target) == "table" then

                table.insert(
                    output,
                    HolyServerFinderNormalizeAutoJoinRule(
                        target
                    )
                )
            end
        end
    end

    if suppliedList ~= true then

        for _, target in ipairs(
            HolyServerFinderGetDefaultAutoJoinRules()
        ) do

            table.insert(
                output,
                HolyServerFinderNormalizeAutoJoinRule(
                    target
                )
            )
        end
    end

    return output
end

function HolyServerFinderNormalizeAutoJoinHold(hold)

    if type(hold) ~= "table"
    or hold.Active ~= true then

        return nil
    end

    local jobId =
        HolyCleanText(
            hold.JobId
            or hold.TargetJobId
            or hold.ServerId
        )

    if jobId == "" then
        return nil
    end

    local expiresAt =
        tonumber(
            hold.ExpiresAt
            or hold.expiresAt
        )
        or 0

    if expiresAt > 0
    and expiresAt <= os.time() - 8 then

        return nil
    end

    local size =
        HolyCleanText(
            hold.Size
            or "Any"
        )

    if size == ""
    or size:lower() == "any" then

        size =
            "Any"

    else

        size =
            HolySniperNormalizeSizeName(
                size
            )
    end

    local variant =
        HolyCleanText(
            hold.Variant
            or hold.Mutation
            or "Any"
        )

    if variant == ""
    or variant:lower() == "any" then

        variant =
            "Any"

    else

        variant =
            HolyServerFinderNormalizeAutoJoinVariantName(
                variant
            )
    end

    local rarity =
        HolyCleanText(
            hold.Rarity
            or "Any"
        )

    if rarity == "" then
        rarity =
            "Any"
    end

    return {
        Active =
            true,

        JobId =
            jobId,

        PlaceId =
            tonumber(
                hold.PlaceId
                or hold.placeId
                or game.PlaceId
            )
            or game.PlaceId,

        Pet =
            HolyCleanText(
                hold.Pet
                or hold.BasePet
                or hold.BestPet
            ),

        Size =
            size,

        Variant =
            variant,

        Rarity =
            rarity,

        DisplayName =
            HolyCleanText(
                hold.DisplayName
                or hold.Name
                or hold.Pet
            ),

        RuleIndex =
            tonumber(
                hold.RuleIndex
            )
            or 0,

        ExpiresAt =
            expiresAt,

        CreatedAt =
            tonumber(
                hold.CreatedAt
            )
            or os.time(),

        Source =
            HolyCleanText(
                hold.Source
                or "Auto Join"
            ),
    }
end

function HolyServerFinderEnsureAutoJoinState()

    HOLY_SERVER_FINDER_STATE =
        type(HOLY_SERVER_FINDER_STATE) == "table"
        and HOLY_SERVER_FINDER_STATE
        or {}

    HOLY_SERVER_FINDER_STATE.AutoJoinMode =
        HolyServerFinderNormalizeAutoJoinMode(
            HOLY_SERVER_FINDER_STATE.AutoJoinMode
            or "Off"
        )

    HOLY_SERVER_FINDER_STATE.AutoJoinMinLife =
        math.clamp(
            tonumber(
                HOLY_SERVER_FINDER_STATE.AutoJoinMinLife
            )
            or 30,
            0,
            420
        )

    HOLY_SERVER_FINDER_STATE.AutoJoinCooldown =
        math.clamp(
            tonumber(
                HOLY_SERVER_FINDER_STATE.AutoJoinCooldown
            )
            or 10,
            1,
            120
        )

    HOLY_SERVER_FINDER_STATE.AutoJoinHoldLoadGrace =
        math.clamp(
            tonumber(
                HOLY_SERVER_FINDER_STATE.AutoJoinHoldLoadGrace
            )
            or 22,
            5,
            90
        )

    HOLY_SERVER_FINDER_STATE.AutoJoinRules =
        HolyServerFinderNormalizeAutoJoinRules(
            HOLY_SERVER_FINDER_STATE.AutoJoinRules
        )

    HOLY_SERVER_FINDER_STATE.AutoJoinSelectedRuleIndex =
        math.clamp(
            math.floor(
                tonumber(
                    HOLY_SERVER_FINDER_STATE.AutoJoinSelectedRuleIndex
                )
                or 1
            ),
            1,
            math.max(
                1,
                #HOLY_SERVER_FINDER_STATE.AutoJoinRules
            )
        )

    HOLY_SERVER_FINDER_STATE.AutoJoinHold =
        HolyServerFinderNormalizeAutoJoinHold(
            HOLY_SERVER_FINDER_STATE.AutoJoinHold
        )

    return HOLY_SERVER_FINDER_STATE
end

function HolyServerFinderSetAutoJoinMode(value)

    HolyServerFinderEnsureAutoJoinState()

    local wantedMode =
        HolyServerFinderNormalizeAutoJoinMode(
            value
        )

    if wantedMode ~= "Off"
    and HolyAuthRequireServerSniper(
        "Auto Join",
        true
    ) ~= true then

        HOLY_SERVER_FINDER_STATE.AutoJoinMode =
            "Off"

        if type(HOLY_SERVER_FINDER_HUD) == "table"
        and type(HOLY_SERVER_FINDER_HUD.SetAutoJoinMode) == "function" then

            pcall(function()

                HOLY_SERVER_FINDER_HUD:SetAutoJoinMode(
                    "Off"
                )
            end)
        end

        HolyQueueSaveServerFinderSettings()

        if type(HolyServerFinderRefreshAutoJoinRulesPopup) == "function" then

            HolyServerFinderRefreshAutoJoinRulesPopup()
        end

        return "Off"
    end

    HOLY_SERVER_FINDER_STATE.AutoJoinMode =
        wantedMode

    if type(HOLY_SERVER_FINDER_HUD) == "table"
    and type(HOLY_SERVER_FINDER_HUD.SetAutoJoinMode) == "function" then

        pcall(function()

            HOLY_SERVER_FINDER_HUD:SetAutoJoinMode(
                HOLY_SERVER_FINDER_STATE.AutoJoinMode
            )
        end)
    end

    HolyQueueSaveServerFinderSettings()

    HolyServerFinderRefreshAutoJoinRulesPopup()

    return HOLY_SERVER_FINDER_STATE.AutoJoinMode
end

function HolyServerFinderRowKey(row)

    if type(row) ~= "table" then
        return ""
    end

    return HolyCleanText(
        row.Key
        or row.Id
        or row.JobId
        or row.jobId
        or ""
    )
end

function HolyServerFinderRowJobId(row)

    if type(row) ~= "table" then
        return ""
    end

    return HolyCleanText(
        row.JobId
        or row.jobId
        or row.ServerId
        or row.id
        or row.Id
        or row.Key
    )
end

function HolyServerFinderRowTimeLeft(row)

    if type(row) ~= "table" then
        return 0
    end

    local expiresAt =
        tonumber(
            row.ExpiresAt
            or row.expiresAt
        )
        or 0

    if expiresAt > 0 then

        return math.max(
            0,
            expiresAt - os.time()
        )
    end

    local timeLeft =
        tonumber(
            row.TimeLeft
            or row.timeLeft
        )
        or 0

    local reportedAt =
        tonumber(
            row.ReportedAt
            or row.reportedAt
        )
        or 0

    if reportedAt > 0 then

        timeLeft =
            timeLeft
            - math.max(
                0,
                os.time() - reportedAt
            )
    end

    return math.max(
        0,
        timeLeft
    )
end

function HolyServerFinderRowIsFull(row)

    if type(row) ~= "table" then
        return true
    end

    local playing =
        tonumber(
            row.Playing
            or row.playing
        )
        or 0

    local maxPlayers =
        tonumber(
            row.MaxPlayers
            or row.maxPlayers
        )
        or 8

    return maxPlayers > 0
        and playing >= maxPlayers
end

function HolyServerFinderRowIsCurrent(row)

    local jobId =
        HolyServerFinderRowJobId(
            row
        )

    return jobId ~= ""
        and jobId == tostring(game.JobId)
end

function HolyServerFinderRowReportAge(row)

    if type(row) ~= "table" then
        return 999999
    end

    local reportedAt =
        tonumber(
            row.ReportedAt
            or row.reportedAt
        )
        or 0

    if reportedAt <= 0 then
        return 0
    end

    return math.max(
        0,
        os.time() - reportedAt
    )
end

function HolyServerFinderRowIsHiddenByAge(row)

    if type(row) ~= "table" then
        return true
    end

    if row.HideFromFinder == true
    or row.Expired == true then

        return true
    end

    local expiresAt =
        tonumber(
            row.ExpiresAt
            or row.expiresAt
        )
        or 0

    if expiresAt > 0
    and expiresAt <= os.time() then

        return true
    end

    local reportedAt =
        tonumber(
            row.ReportedAt
            or row.reportedAt
        )
        or 0

    if reportedAt <= 0 then
        return false
    end

    local maxAge =
        tonumber(
            row.MaxReportAge
            or row.maxReportAge
        )
        or tonumber(SERVER_FINDER_ROW_HIDE_AFTER_SECONDS)
        or 45

    return HolyServerFinderRowReportAge(row) > maxAge
end

function HolyServerFinderRowIsStale(row)

    local maxAge =
        tonumber(
            row
            and (
                row.ManualJoinMaxAge
                or row.manualJoinMaxAge
            )
        )
        or tonumber(SERVER_FINDER_MANUAL_JOIN_FRESH_SECONDS)
        or 20

    return HolyServerFinderRowReportAge(row) > maxAge
end

function HolyServerFinderRowIsTooLate(row, minLife)

    if type(row) ~= "table" then
        return true
    end

    local expiresAt =
        tonumber(
            row.ExpiresAt
            or row.expiresAt
        )
        or 0

    local rawTimeLeft =
        tonumber(
            row.TimeLeft
            or row.timeLeft
        )

    if expiresAt <= 0
    and rawTimeLeft == nil then

        return false
    end

    local timeLeft =
        HolyServerFinderRowTimeLeft(
            row
        )

    if timeLeft <= 0 then
        return true
    end

    minLife =
        tonumber(minLife)
        or tonumber(SERVER_FINDER_TOO_LATE_SECONDS)
        or 15

    return timeLeft < minLife
end

function HolyServerFinderRowManualJoinAllowed(row)

    if type(row) ~= "table" then
        return false
    end

    if HolyServerFinderRowIsCurrent(row) == true then
        return false
    end

    if HolyServerFinderRowIsFull(row) == true then
        return false
    end

    if HolyServerFinderRowIsHiddenByAge(row) == true then
        return false
    end

    return true
end

function HolyServerFinderRowAutoJoinFresh(row, minLife)

    return HolyServerFinderRowManualJoinAllowed(
        row
    ) == true
end

function HolyServerFinderAnnotateJoinState(row)

    if type(row) ~= "table" then
        return nil
    end

    row.MaxReportAge =
        tonumber(SERVER_FINDER_ROW_HIDE_AFTER_SECONDS)
        or 45

    row.ManualJoinMaxAge =
        tonumber(SERVER_FINDER_MANUAL_JOIN_FRESH_SECONDS)
        or 20

    row.AutoJoinMaxAge =
        tonumber(SERVER_FINDER_AUTO_JOIN_FRESH_SECONDS)
        or 12

    row.ManualMinLife =
        tonumber(SERVER_FINDER_TOO_LATE_SECONDS)
        or 15

    row.ReportAge =
        HolyServerFinderRowReportAge(
            row
        )

    row.JoinEnabled =
        true

    row.JoinDisabled =
        false

    row.JoinText =
        "Join"

    row.JoinState =
        "fresh"

    row.Freshness =
        "Fresh"

    if HolyServerFinderRowIsHiddenByAge(row) == true then

        row.Expired =
            true

        row.HideFromFinder =
            true

        row.JoinEnabled =
            false

        row.JoinDisabled =
            true

        row.JoinText =
            "Gone"

        row.JoinState =
            "gone"

        row.Freshness =
            "Gone"

        return row
    end

    if HolyServerFinderRowIsCurrent(row) == true then

        row.JoinEnabled =
            false

        row.JoinDisabled =
            true

        row.JoinText =
            "Current"

        row.JoinState =
            "current"

        row.Freshness =
            "Current"

        return row
    end

    if HolyServerFinderRowIsFull(row) == true then

        row.JoinEnabled =
            false

        row.JoinDisabled =
            true

        row.JoinText =
            "Full"

        row.JoinState =
            "full"

        row.Freshness =
            "Full"

        return row
    end

    if HolyServerFinderRowIsTooLate(
        row,
        SERVER_FINDER_TOO_LATE_SECONDS
    ) == true then

        row.JoinEnabled =
            true

        row.JoinDisabled =
            false

        row.JoinText =
            "Join"

        row.JoinState =
            "late"

        row.Freshness =
            "Late"

        return row
    end

    if HolyServerFinderRowIsStale(row) == true then

        row.JoinEnabled =
            true

        row.JoinDisabled =
            false

        row.JoinText =
            "Join"

        row.JoinState =
            "stale"

        row.Freshness =
            "Stale"

        return row
    end

    if HolyServerFinderRowReportAge(row)
    > (
        tonumber(SERVER_FINDER_AUTO_JOIN_FRESH_SECONDS)
        or 12
    ) then

        row.JoinState =
            "aging"

        row.Freshness =
            "Aging"

    else

        row.JoinState =
            "fresh"

        row.Freshness =
            "Fresh"
    end

    return row
end

function HolyServerFinderAnnotateDisplayRows(rows)

    local output =
        {}

    rows =
        type(rows) == "table"
        and rows
        or {}

    for _, row in ipairs(rows) do

        row =
            HolyServerFinderAnnotateJoinState(
                row
            )

        if type(row) == "table"
        and row.HideFromFinder ~= true then

            table.insert(
                output,
                row
            )
        end
    end

    return output
end

function HolyServerFinderSelectionMatchesText(selection, text)

    if HolyServerFinderAutoJoinListHasAny(selection) == true then
        return true
    end

    local haystack =
        HolySniperPetAliasKey(
            text
        )

    for _, value in ipairs(selection or {}) do

        local needle =
            HolySniperPetAliasKey(
                value
            )

        if needle ~= ""
        and haystack == needle then

            return true
        end
    end

    return false
end

function HolyServerFinderAutoJoinRowSize(row)

    return HolySniperNormalizeSizeName(
        row.Size
        or row.size
        or "Normal"
    )
end

function HolyServerFinderAutoJoinRowVariant(row)

    local variant =
        HolySniperNormalizeVariantName(
            row.Variant
            or row.variant
            or row.Mutation
            or row.mutation
            or "Normal"
        )

    if variant == "Normal" then
        return "Regular"
    end

    return variant
end

function HolyServerFinderSelectionContainsValue(selection, value, normalizer)

    if HolyServerFinderAutoJoinListHasAny(selection) == true then
        return true
    end

    if type(normalizer) == "function" then

        value =
            normalizer(
                value
            )
    end

    value =
        HolyCleanText(
            value
        )
        :lower()

    for _, wanted in ipairs(selection or {}) do

        wanted =
            type(normalizer) == "function"
            and normalizer(wanted)
            or wanted

        wanted =
            HolyCleanText(
                wanted
            )
            :lower()

        if wanted == value then
            return true
        end
    end

    return false
end

function HolyServerFinderRaritySelectionMatches(selection, value)

    if HolyServerFinderAutoJoinListHasAny(selection) == true then
        return true
    end

    local rarity =
        HolyCleanText(
            value
        )
        :lower()

    for _, wanted in ipairs(selection or {}) do

        if rarity == HolyCleanText(wanted):lower() then
            return true
        end
    end

    return false
end

function HolyServerFinderAutoJoinRuleMatchesRow(rule, row)

    if type(rule) ~= "table"
    or type(row) ~= "table" then

        return false
    end

    rule =
        HolyServerFinderNormalizeAutoJoinRule(
            rule
        )

    if rule.PetScope ~= "Any Pet" then

        local basePet =
            HolyCleanText(
                row.BasePet
                or row.BestPet
                or row.PetName
                or row.Pet
                or row.DisplayName
                or row.Name
            )

        if HolyServerFinderSelectionMatchesText(
            rule.Pets,
            basePet
        ) ~= true then

            return false
        end
    end

    if HolyServerFinderRaritySelectionMatches(
        rule.Rarities,
        row.Rarity
        or row.rarity
    ) ~= true then

        return false
    end

    local sizeAny =
        HolyServerFinderAutoJoinListHasAny(
            rule.Sizes
        )

    local variantAny =
        HolyServerFinderAutoJoinListHasAny(
            rule.Variants
        )

    if sizeAny == true
    and variantAny == true then

        return true
    end

    local sizeMatch =
        HolyServerFinderSelectionContainsValue(
            rule.Sizes,
            HolyServerFinderAutoJoinRowSize(row),
            HolyServerFinderNormalizeAutoJoinSizeName
        )

    local variantMatch =
        HolyServerFinderSelectionContainsValue(
            rule.Variants,
            HolyServerFinderAutoJoinRowVariant(row),
            HolyServerFinderNormalizeAutoJoinVariantName
        )

    local matchMode =
        HolyServerFinderNormalizeAutoJoinMatchMode(
            rule.MatchMode
        )

    if matchMode == "All Selected" then

        if sizeAny ~= true
        and sizeMatch ~= true then
            return false
        end

        if variantAny ~= true
        and variantMatch ~= true then
            return false
        end

        return true
    end

    if sizeAny ~= true
    and sizeMatch == true then
        return true
    end

    if variantAny ~= true
    and variantMatch == true then
        return true
    end

    return false
end

function HolyServerFinderAutoJoinScoreRow(row)

    if type(row) ~= "table" then
        return 0
    end

    local score =
        0

    score =
        score
        + (
            tonumber(row.RarityRank)
            or HolyServerFinderRarityRank(
                row.Rarity
            )
        ) * 100000

    local freshness =
        HolyCleanText(
            row.Freshness
            or row.JoinState
            or ""
        )
        :lower()

    if HolyServerFinderRowIsTooLate(
        row,
        SERVER_FINDER_TOO_LATE_SECONDS
    ) == true then

        freshness =
            "late"

    elseif HolyServerFinderRowIsStale(row) == true then

        freshness =
            "stale"

    elseif HolyServerFinderRowReportAge(row)
    > (
        tonumber(SERVER_FINDER_AUTO_JOIN_FRESH_SECONDS)
        or 12
    ) then

        freshness =
            "aging"

    elseif freshness == "" then

        freshness =
            "fresh"
    end

    if freshness == "fresh" then

        score =
            score + 4500

    elseif freshness == "aging" then

        score =
            score + 3000

    elseif freshness == "stale" then

        score =
            score + 1500
    end

    local variant =
        HolyServerFinderAutoJoinRowVariant(
            row
        )

    local size =
        HolyServerFinderAutoJoinRowSize(
            row
        )

    if variant == "Rainbow" then
        score =
            score + 10000
    end

    if size == "Huge" then
        score =
            score + 5000

    elseif size == "Big" then

        score =
            score + 2500
    end

    score =
        score
        + math.min(
            999,
            math.floor(
                HolyServerFinderRowTimeLeft(row)
            )
        )

    local playing =
        tonumber(row.Playing)
        or 0

    local maxPlayers =
        tonumber(row.MaxPlayers)
        or 8

    score =
        score
        + math.max(
            0,
            maxPlayers - playing
        ) * 10

    return score
end

function HolyServerFinderFindAutoJoinTarget(rows)

    HolyServerFinderEnsureAutoJoinState()

    rows =
        type(rows) == "table"
        and rows
        or {}

    local minLife =
        tonumber(
            HOLY_SERVER_FINDER_STATE.AutoJoinMinLife
        )
        or 30

    local orderedFilters =
        {}

    for sourceIndex, filter in ipairs(
        HOLY_SERVER_FINDER_STATE.AutoJoinRules
        or {}
    ) do

        table.insert(
            orderedFilters,
            {
                SourceIndex =
                    sourceIndex,

                Filter =
                    HolyServerFinderNormalizeAutoJoinRule(
                        filter
                    ),
            }
        )
    end

    table.sort(orderedFilters, function(a, b)

        local rankA =
            HolyServerFinderAutoJoinPriorityRank(
                a.Filter.Priority
            )

        local rankB =
            HolyServerFinderAutoJoinPriorityRank(
                b.Filter.Priority
            )

        if rankA ~= rankB then
            return rankA < rankB
        end

        return a.SourceIndex
            < b.SourceIndex
    end)

    for _, entry in ipairs(orderedFilters) do

        local candidates =
            {}

        for _, row in ipairs(rows) do

            if type(row) == "table"
            and HolyServerFinderRowAutoJoinFresh(
                row,
                minLife
            ) == true
            and HolyServerFinderAutoJoinRuleMatchesRow(
                entry.Filter,
                row
            ) == true then

                table.insert(
                    candidates,
                    {
                        RuleIndex =
                            entry.SourceIndex,

                        Rule =
                            entry.Filter,

                        Row =
                            row,

                        Score =
                            HolyServerFinderAutoJoinScoreRow(
                                row
                            ),
                    }
                )
            end
        end

        if #candidates > 0 then

            table.sort(candidates, function(a, b)

                if a.Score ~= b.Score then
                    return a.Score > b.Score
                end

                return tostring(
                    a.Row.DisplayName
                    or ""
                ) < tostring(
                    b.Row.DisplayName
                    or ""
                )
            end)

            return candidates[1]
        end
    end

    return nil
end

function HolyServerFinderRowAlive(row)

    if type(row) ~= "table" then
        return false
    end

    local expiresAt =
        tonumber(
            row.ExpiresAt
            or row.expiresAt
        )
        or 0

    if expiresAt <= 0 then
        return true
    end

    return expiresAt > os.time() - 2
        and HolyServerFinderRowTimeLeft(row) > 0
end

function HolyServerFinderRowBasePet(row)

    if type(row) ~= "table" then
        return ""
    end

    return HolyCleanText(
        row.BasePet
        or row.BestPet
        or row.Pet
        or row.PetName
        or row.DisplayName
        or row.Name
    )
end

function HolyServerFinderAutoJoinValueIsAny(value)

    local text =
        HolyCleanText(
            value
        )
        :lower()

    return text == ""
        or text == "any"
        or text == "any pet"
        or text == "all"
end

function HolyServerFinderHoldMatchesRow(hold, row)

    hold =
        HolyServerFinderNormalizeAutoJoinHold(
            hold
        )

    if type(hold) ~= "table"
    or type(row) ~= "table" then
        return false
    end

    if HolyServerFinderRowAlive(row) ~= true then
        return false
    end

    if HolyServerFinderAutoJoinValueIsAny(hold.Pet) ~= true then

        local holdPet =
            HolySniperPetAliasKey(
                hold.Pet
            )

        local rowPet =
            HolySniperPetAliasKey(
                HolyServerFinderRowBasePet(
                    row
                )
            )

        if holdPet == ""
        or rowPet ~= holdPet then
            return false
        end
    end

    if HolyServerFinderAutoJoinValueIsAny(hold.Size) ~= true then

        if HolySniperNormalizeSizeName(
            row.Size
            or row.size
            or "Normal"
        ) ~= HolySniperNormalizeSizeName(
            hold.Size
        ) then

            return false
        end
    end

    if HolyServerFinderAutoJoinValueIsAny(hold.Variant) ~= true then

        if HolyServerFinderAutoJoinRowVariant(
            row
        ) ~= HolyServerFinderNormalizeAutoJoinVariantName(
            hold.Variant
        ) then

            return false
        end
    end

    if HolyServerFinderAutoJoinValueIsAny(hold.Rarity) ~= true then

        if HolyCleanText(
            row.Rarity
            or row.rarity
        ):lower() ~= HolyCleanText(
            hold.Rarity
        ):lower() then

            return false
        end
    end

    return true
end

function HolyServerFinderFindHoldTargetInCurrentRows(rows, hold)

    rows =
        type(rows) == "table"
        and rows
        or {}

    for _, row in ipairs(rows) do

        if type(row) == "table"
        and HolyServerFinderRowIsCurrent(row) == true
        and HolyServerFinderHoldMatchesRow(
            hold,
            row
        ) == true then

            return row
        end
    end

    return nil
end

function HolyServerFinderFindCurrentAutoJoinTarget(rows)

    HolyServerFinderEnsureAutoJoinState()

    rows =
        type(rows) == "table"
        and rows
        or {}

    for ruleIndex, rule in ipairs(HOLY_SERVER_FINDER_STATE.AutoJoinRules or {}) do

        for _, row in ipairs(rows) do

            if type(row) == "table"
            and HolyServerFinderRowIsCurrent(row) == true
            and HolyServerFinderRowAlive(row) == true
            and HolyServerFinderAutoJoinRuleMatchesRow(
                rule,
                row
            ) == true then

                return {
                    RuleIndex =
                        ruleIndex,

                    Rule =
                        rule,

                    Row =
                        row,
                }
            end
        end
    end

    return nil
end

function HolyServerFinderClearAutoJoinHold(reason)

    HOLY_SERVER_FINDER_STATE =
        type(HOLY_SERVER_FINDER_STATE) == "table"
        and HOLY_SERVER_FINDER_STATE
        or {}

    HOLY_SERVER_FINDER_STATE.AutoJoinHold =
        nil

    if type(HOLY_SERVER_FINDER_AUTO_JOIN_RUNTIME) == "table" then

        HOLY_SERVER_FINDER_AUTO_JOIN_RUNTIME.HoldArrivedJobId =
            ""

        HOLY_SERVER_FINDER_AUTO_JOIN_RUNTIME.HoldArrivedAt =
            0

        HOLY_SERVER_FINDER_AUTO_JOIN_RUNTIME.LastHoldStatus =
            tostring(reason or "")
    end

    HolyQueueSaveServerFinderSettings()

    return true
end

function HolyServerFinderArmAutoJoinHold(row, source, targetInfo)

    if type(row) ~= "table" then
        return false
    end

    local jobId =
        HolyServerFinderRowJobId(
            row
        )

    if jobId == "" then
        return false
    end

    local displayName =
        HolyCleanText(
            row.DisplayName
            or row.Pet
            or row.PetName
            or "target pet"
        )

    local hold = {
        Active =
            true,

        JobId =
            jobId,

        PlaceId =
            tonumber(
                row.PlaceId
                or row.placeId
                or game.PlaceId
            )
            or game.PlaceId,

        Pet =
            HolyServerFinderRowBasePet(
                row
            ),

        Size =
            HolyServerFinderAutoJoinRowSize(
                row
            ),

        Variant =
            HolyServerFinderAutoJoinRowVariant(
                row
            ),

        Rarity =
            HolyCleanText(
                row.Rarity
                or row.rarity
                or "Any"
            ),

        DisplayName =
            displayName,

        RuleIndex =
            type(targetInfo) == "table"
            and tonumber(targetInfo.RuleIndex)
            or 0,

        ExpiresAt =
            tonumber(
                row.ExpiresAt
                or row.expiresAt
            )
            or 0,

        CreatedAt =
            os.time(),

        Source =
            tostring(
                source
                or "Auto Join"
            ),
    }

    HOLY_SERVER_FINDER_STATE.AutoJoinHold =
        HolyServerFinderNormalizeAutoJoinHold(
            hold
        )

    HOLY_SERVER_FINDER_AUTO_JOIN_RUNTIME.HoldArrivedJobId =
        ""

    HOLY_SERVER_FINDER_AUTO_JOIN_RUNTIME.HoldArrivedAt =
        0

    HOLY_SERVER_FINDER_AUTO_JOIN_RUNTIME.LastHoldStatus =
        "Armed "
        .. displayName

    HolySaveServerFinderSettings()

    return true
end

function HolyServerFinderAutoJoinHoldBlocks(rows)

    HolyServerFinderEnsureAutoJoinState()

    rows =
        type(rows) == "table"
        and rows
        or {}

    local hold =
        HOLY_SERVER_FINDER_STATE.AutoJoinHold

    if type(hold) == "table"
    and hold.Active == true then

        if hold.JobId == tostring(game.JobId) then

            if HOLY_SERVER_FINDER_AUTO_JOIN_RUNTIME.HoldArrivedJobId ~= tostring(game.JobId) then

                HOLY_SERVER_FINDER_AUTO_JOIN_RUNTIME.HoldArrivedJobId =
                    tostring(game.JobId)

                HOLY_SERVER_FINDER_AUTO_JOIN_RUNTIME.HoldArrivedAt =
                    os.clock()
            end

            local targetRow =
                HolyServerFinderFindHoldTargetInCurrentRows(
                    rows,
                    hold
                )

            if targetRow then

                HOLY_SERVER_FINDER_AUTO_JOIN_RUNTIME.LastHoldStatus =
                    "Holding "
                    .. tostring(
                        targetRow.DisplayName
                        or hold.DisplayName
                        or "target"
                    )

                return true,
                    "hold target present"
            end

            local arrivedAt =
                tonumber(
                    HOLY_SERVER_FINDER_AUTO_JOIN_RUNTIME.HoldArrivedAt
                )
                or os.clock()

            local grace =
                tonumber(
                    HOLY_SERVER_FINDER_STATE.AutoJoinHoldLoadGrace
                )
                or 22

            if os.clock() - arrivedAt < grace then

                HOLY_SERVER_FINDER_AUTO_JOIN_RUNTIME.LastHoldStatus =
                    "Waiting for target data"

                return true,
                    "waiting for target data"
            end

            HolyServerFinderClearAutoJoinHold(
                "hold target gone"
            )

        elseif os.time() - (
            tonumber(hold.CreatedAt)
            or os.time()
        ) > 120 then

            HolyServerFinderClearAutoJoinHold(
                "stale hold"
            )
        end
    end

    local currentTarget =
        HolyServerFinderFindCurrentAutoJoinTarget(
            rows
        )

    if type(currentTarget) == "table"
    and type(currentTarget.Row) == "table" then

        HOLY_SERVER_FINDER_AUTO_JOIN_RUNTIME.LastHoldStatus =
            "Current match "
            .. tostring(
                currentTarget.Row.DisplayName
                or currentTarget.Row.Pet
                or "pet"
            )

        return true,
            "current server has matching pet"
    end

    return false,
        "clear"
end

function HolyServerFinderJoinRow(row, source, targetInfo)

    if HolyAuthRequireServerSniper(
        tostring(source or "Server Finder Join"),
        true
    ) ~= true then

        return false
    end

    if type(row) ~= "table" then
        return false
    end

    local jobId =
        HolyServerFinderRowJobId(
            row
        )

    local placeId =
        tonumber(
            row.PlaceId
            or row.placeId
            or game.PlaceId
        )
        or game.PlaceId

    if jobId == "" then
        return false
    end

    if jobId == tostring(game.JobId) then

        if type(HolyNotify) == "function" then

            HolyNotify(
                "HOLY Server Finder",
                "Already in this server.",
                3
            )
        end

        return false
    end

    if HolySniperServerSwitchBlocked(
        "Server Finder",
        true
    ) == true then

        return false
    end

    if HolyServerFinderRowManualJoinAllowed(row) ~= true then

        local reason =
            tostring(
                row.JoinText
                or row.Freshness
                or "not fresh"
            )

        if type(HolyNotify) == "function" then

            HolyNotify(
                "HOLY Server Finder",
                "Join blocked: "
                .. reason
                .. ". Refresh or wait for a fresh report.",
                4
            )
        end

        return false
    end

    HolyServerFinderArmAutoJoinHold(
        row,
        source,
        targetInfo
    )

    HOLY_SERVER_FINDER_AUTO_JOIN_RUNTIME.Teleporting =
        true

    HOLY_SERVER_FINDER_AUTO_JOIN_RUNTIME.LastTargetKey =
        HolyServerFinderRowKey(
            row
        )

    if type(HolyNotify) == "function" then

        HolyNotify(
            "HOLY Server Finder",
            tostring(source or "Joining")
            .. ": "
            .. tostring(row.DisplayName or row.Pet or "server"),
            3
        )
    end

    local startedJobId =
        tostring(game.JobId)

    local ok,
        err =
        pcall(function()

            TeleportService:TeleportToPlaceInstance(
                placeId,
                jobId,
                LocalPlayer
            )
        end)

    if ok ~= true then

        HOLY_SERVER_FINDER_AUTO_JOIN_RUNTIME.Teleporting =
            false

        HolyServerFinderClearAutoJoinHold(
            "teleport failed"
        )

        if type(HolyNotify) == "function" then

            HolyNotify(
                "HOLY Server Finder",
                "Teleport failed: "
                .. tostring(err),
                4
            )
        end

        return false
    end

    task.delay(12, function()

        if tostring(game.JobId) == startedJobId
        and type(HOLY_SERVER_FINDER_AUTO_JOIN_RUNTIME) == "table" then

            HOLY_SERVER_FINDER_AUTO_JOIN_RUNTIME.Teleporting =
                false
        end
    end)

    return true
end

function HolyServerFinderEvaluateAutoJoin(hud)

    HolyServerFinderEnsureAutoJoinState()

    local mode =
        HolyServerFinderNormalizeAutoJoinMode(
            HOLY_SERVER_FINDER_STATE.AutoJoinMode
        )

    if mode == "Off" then
        return false
    end

    if HolyAuthRequireServerSniper(
        "Auto Join",
        false
    ) ~= true then

        HOLY_SERVER_FINDER_STATE.AutoJoinMode =
            "Off"

        if type(hud) == "table"
        and type(hud.SetAutoJoinMode) == "function" then

            pcall(function()

                hud:SetAutoJoinMode(
                    "Off"
                )
            end)
        end

        HolyQueueSaveServerFinderSettings()

        return false
    end

    if HolySniperServerSwitchBlocked(
        "Auto Join",
        false
    ) == true then

        return false
    end

    if HOLY_SERVER_FINDER_AUTO_JOIN_RUNTIME.Teleporting == true then
        return false
    end

    local rows =
        type(hud) == "table"
        and type(hud.Rows) == "table"
        and hud.Rows
        or {}

    local holdBlocked =
        HolyServerFinderAutoJoinHoldBlocks(
            rows
        )

    if holdBlocked == true then
        return false
    end

    local now =
        os.clock()

    local cooldown =
        tonumber(
            HOLY_SERVER_FINDER_STATE.AutoJoinCooldown
        )
        or 10

    if now - (
        tonumber(
            HOLY_SERVER_FINDER_AUTO_JOIN_RUNTIME.LastAttemptAt
        )
        or 0
    ) < cooldown then

        return false
    end

    local target =
        HolyServerFinderFindAutoJoinTarget(
            rows
        )

    if type(target) ~= "table"
    or type(target.Row) ~= "table" then

        return false
    end

    local row =
        target.Row

    HOLY_SERVER_FINDER_AUTO_JOIN_RUNTIME.LastAttemptAt =
        now

    if mode == "Notify" then

        if type(HolyNotify) == "function" then

            HolyNotify(
                "HOLY Auto Join",
                "Matched target #"
                .. tostring(target.RuleIndex)
                .. ": "
                .. tostring(row.DisplayName or row.Pet or "server"),
                5
            )
        end

        return true
    end

    return HolyServerFinderJoinRow(
        row,
        "Auto Join",
        target
    )
end

function HolyServerFinderAutoJoinJoinList(list, fallback)

    if HolyServerFinderAutoJoinListHasAny(list) == true then
        return fallback or "Any"
    end

    return table.concat(
        list,
        "/"
    )
end

function HolyServerFinderAutoJoinRulePetText(rule)

    rule =
        HolyServerFinderNormalizeAutoJoinRule(
            rule
        )

    if rule.PetScope == "Any Pet" then
        return "Any Pet"
    end

    return HolyServerFinderAutoJoinJoinList(
        rule.Pets,
        "Any Pet"
    )
end

function HolyServerFinderAutoJoinRuleDetailText(rule)

    rule =
        HolyServerFinderNormalizeAutoJoinRule(
            rule
        )

    local parts =
        {}

    if HolyServerFinderAutoJoinListHasAny(rule.Sizes) ~= true then

        table.insert(
            parts,
            HolyServerFinderAutoJoinJoinList(
                rule.Sizes,
                ""
            )
        )
    end

    if HolyServerFinderAutoJoinListHasAny(rule.Variants) ~= true then

        table.insert(
            parts,
            HolyServerFinderAutoJoinJoinList(
                rule.Variants,
                ""
            )
        )
    end

    if HolyServerFinderAutoJoinListHasAny(rule.Rarities) ~= true then

        table.insert(
            parts,
            HolyServerFinderAutoJoinJoinList(
                rule.Rarities,
                ""
            )
        )
    end

    if #parts <= 0 then
        return "Any"
    end

    local text =
        table.concat(
            parts,
            "/"
        )

    if rule.MatchMode == "All Selected"
    and #parts > 1 then

        text =
            text
            .. " · All"
    end

    return text
end

HOLY_SERVER_FINDER_MAIN_UI = {
    Lock = false,

    SelectedIndex =
        tonumber(
            HOLY_SERVER_FINDER_STATE.AutoJoinSelectedRuleIndex
        ),

    EditingIndex =
        nil,

    SearchText =
        "",

    WatchlistPage =
        1,

    WatchlistPageSize =
        7,

    BuilderPet =
        "Any Pet",

    BuilderSizes = {
        "Any",
    },

    BuilderVariants = {
        "Any",
    },

    BuilderRarities = {
        "Any",
    },

    BuilderPriority =
        "Medium",
}

function HolyServerFinderReadSingleValue(value)

    if type(value) ~= "table" then

        return HolyCleanText(
            value
        )
    end

    for key, enabled in pairs(value) do

        if enabled == true then

            return HolyCleanText(
                key
            )
        end
    end

    return HolyCleanText(
        value[1]
    )
end

function HolyServerFinderTargetSelectionList(value, anyLabel)

    local values =
        {}

    if type(value) == "table" then

        values =
            HolyServerFinderSelectionValues(
                value
            )

    else

        local text =
            HolyCleanText(
                value
            )

        if text ~= "" then

            values[1] =
                text
        end
    end

    anyLabel =
        HolyCleanText(
            anyLabel
        )

    for _, item in ipairs(values) do

        local lower =
            HolyCleanText(
                item
            )
            :lower()

        if lower == "any"
        or lower == "all"
        or lower == anyLabel:lower() then

            return {
                "Any",
            }
        end
    end

    local output =
        {}

    local seen =
        {}

    for _, item in ipairs(values) do

        local text =
            HolyCleanText(
                item
            )

        local key =
            text:lower()

        if text ~= ""
        and seen[key] ~= true then

            seen[key] =
                true

            table.insert(
                output,
                text
            )
        end
    end

    if #output == 0 then

        return {
            "Any",
        }
    end

    table.sort(output, function(a, b)

        return tostring(a):lower()
            < tostring(b):lower()
    end)

    return output
end

function HolyServerFinderBuildPetOptions()

    local values = {
        "Any Pet",
    }

    local seen = {
        ["any pet"] = true,
    }

    local options =
        HolyServerFinderBuildFilterOptions()

    for _, petName in ipairs(
        options.Pets
        or {}
    ) do

        local text =
            HolyCleanText(
                petName
            )

        local key =
            text:lower()

        if text ~= ""
        and seen[key] ~= true then

            seen[key] =
                true

            table.insert(
                values,
                text
            )
        end
    end

    return values
end

function HolyServerFinderShortFilterList(values, fallback)

    if HolyServerFinderAutoJoinListHasAny(
        values
    ) == true then

        return fallback
            or "Any"
    end

    local shortNames = {
        Normal = "Norm",
        Regular = "Reg",
        Rainbow = "Rb",
        Common = "Com",
        Uncommon = "Unc",
        Legendary = "Leg",
        Mythic = "Myth",
    }

    local output =
        {}

    for _, value in ipairs(values or {}) do

        local text =
            HolyCleanText(
                value
            )

        table.insert(
            output,
            shortNames[text]
            or text
        )
    end

    return #output > 0
        and table.concat(
            output,
            "+"
        )
        or (
            fallback
            or "Any"
        )
end

function HolyServerFinderFilterKey(filter)

    filter =
        HolyServerFinderNormalizeAutoJoinRule(
            filter
        )

    local function sortedText(values)

        local copy =
            table.clone(
                values
                or {}
            )

        table.sort(copy, function(a, b)

            return tostring(a):lower()
                < tostring(b):lower()
        end)

        return table.concat(
            copy,
            "+"
        )
        :lower()
    end

    return table.concat({
        tostring(
            filter.PetScope
        ):lower(),

        sortedText(
            filter.Pets
        ),

        sortedText(
            filter.Sizes
        ),

        sortedText(
            filter.Variants
        ),

        sortedText(
            filter.Rarities
        ),
    }, "|")
end

function HolyServerFinderBuildAllWatchlistRows()

    HolyServerFinderEnsureAutoJoinState()

    local rows =
        {}

    local searchText =
        HolyCleanText(
            HOLY_SERVER_FINDER_MAIN_UI.SearchText
            or ""
        )
        :lower()

    for sourceIndex, sourceFilter in ipairs(
        HOLY_SERVER_FINDER_STATE.AutoJoinRules
        or {}
    ) do

        local filter =
            HolyServerFinderNormalizeAutoJoinRule(
                sourceFilter
            )

        local petText =
            filter.PetScope == "Any Pet"
            and "Any Pet"
            or table.concat(
                filter.Pets,
                "+"
            )

        local row = {
            SourceIndex =
                sourceIndex,

            Pet =
                petText,

            Size =
                HolyServerFinderShortFilterList(
                    filter.Sizes,
                    "Any"
                ),

            Variant =
                HolyServerFinderShortFilterList(
                    filter.Variants,
                    "Any"
                ),

            Rarity =
                HolyServerFinderShortFilterList(
                    filter.Rarities,
                    "Any"
                ),

            Priority =
                HolyServerFinderNormalizeAutoJoinPriority(
                    filter.Priority
                ),

            Filter =
                filter,
        }

        local haystack =
            table.concat({
                row.Pet,
                row.Size,
                row.Variant,
                row.Rarity,
                row.Priority,
            }, " ")
            :lower()

        if searchText == ""
        or haystack:find(
            searchText,
            1,
            true
        ) then

            table.insert(
                rows,
                row
            )
        end
    end

    table.sort(rows, function(a, b)

        local rankA =
            HolyServerFinderAutoJoinPriorityRank(
                a.Priority
            )

        local rankB =
            HolyServerFinderAutoJoinPriorityRank(
                b.Priority
            )

        if rankA ~= rankB then
            return rankA < rankB
        end

        return a.SourceIndex
            < b.SourceIndex
    end)

    return rows
end

function HolyServerFinderBuildWatchlistPage()

    local allRows =
        HolyServerFinderBuildAllWatchlistRows()

    local pageSize =
        math.clamp(
            tonumber(
                HOLY_SERVER_FINDER_MAIN_UI.WatchlistPageSize
            )
            or 7,
            1,
            16
        )

    local pageCount =
        math.max(
            1,
            math.ceil(
                #allRows
                / pageSize
            )
        )

    HOLY_SERVER_FINDER_MAIN_UI.WatchlistPage =
        math.clamp(
            tonumber(
                HOLY_SERVER_FINDER_MAIN_UI.WatchlistPage
            )
            or 1,
            1,
            pageCount
        )

    local firstIndex =
        (
            (
                HOLY_SERVER_FINDER_MAIN_UI.WatchlistPage
                - 1
            )
            * pageSize
        )
        + 1

    local lastIndex =
        math.min(
            #allRows,
            firstIndex
            + pageSize
            - 1
        )

    local pageRows =
        {}

    for index = firstIndex, lastIndex do

        if type(allRows[index]) == "table" then

            table.insert(
                pageRows,
                allRows[index]
            )
        end
    end

    return pageRows,
        HOLY_SERVER_FINDER_MAIN_UI.WatchlistPage,
        pageCount
end

function HolyServerFinderSetWatchlistPage(page)

    HOLY_SERVER_FINDER_MAIN_UI.WatchlistPage =
        tonumber(page)
        or 1

    HOLY_SERVER_FINDER_MAIN_UI.SelectedIndex =
