function HolySniperNormalizePageMode(value)

    local text =
        HolyCleanText(
            value
        )
        :lower()

    if text:find("server", 1, true) then
        return "Server Sniper"
    end

    return "Sniper Setup"
end

function HolySniperSetPageMode(value)

    HOLY_SNIPER_PAGE_STATE =
        type(HOLY_SNIPER_PAGE_STATE) == "table"
        and HOLY_SNIPER_PAGE_STATE
        or {
            Mode = "Sniper Setup",
        }

    HOLY_SNIPER_PAGE_STATE.Mode =
        HolySniperNormalizePageMode(
            value
        )

    local setupVisible =
        HOLY_SNIPER_PAGE_STATE.Mode == "Sniper Setup"

    local serverVisible =
        setupVisible ~= true

    if serverVisible == true
    and HolyAuthHasServerSniperSlot() ~= true then

        HolyServerSniperForceLockedOff(
            "Server Sniper page",
            false
        )
    end

    HolySetGroupboxVisible(
        SniperEngineBox,
        setupVisible
    )

    HolySetGroupboxVisible(
        SniperDefenseBox,
        setupVisible
    )

    HolySetGroupboxVisible(
        SniperExecutionBox,
        setupVisible
    )

    HolySetGroupboxVisible(
        SniperFilterBox,
        setupVisible
    )

    HolySetGroupboxVisible(
        SniperWatchlistBox,
        setupVisible
    )

    HolySetGroupboxVisible(
        ServerSniperBox,
        serverVisible
    )

    HolySetGroupboxVisible(
        ServerAutoJoinBox,
        serverVisible
    )

    HolySetGroupboxVisible(
        ServerAutoJoinFilterBox,
        serverVisible
    )

    HolySetGroupboxVisible(
        ServerAutoJoinWatchlistBox,
        serverVisible
    )
end

