    )
end

function HolyShopSetMode(mode)

    mode =
        tostring(mode or "Buy")

    if mode ~= "Sell" then

        mode =
            "Buy"
    end

    HOLY_SHOP_STATE.Mode =
        mode

    HolySaveShopSettings()

    if ShopModeControl
    and type(ShopModeControl.SetValue) == "function" then

        ShopModeControl:SetValue(
            mode,
            true
        )
    end

    HolyShopRefreshMode()
end

