HOLY_AUCTION_WATCHLIST_UI =
    type(HOLY_AUCTION_WATCHLIST_UI) == "table"
    and HOLY_AUCTION_WATCHLIST_UI
    or {}

function HolyAuctionWatchlistLiveRow(itemName)

    local wantedKey =
        HolyAuctionItemKey(
            itemName
        )

    for _, row in ipairs(
        HOLY_SHOP_STATE.AuctionLastLots
        or {}
    ) do

        if HolyAuctionItemKey(row.Name) == wantedKey then

            return row
        end
    end

    return nil
end

function HolyAuctionWatchlistState(entry)

    local row =
        HolyAuctionWatchlistLiveRow(
            entry.Name
        )

    if type(row) ~= "table" then

        return "WAIT",
            Color3.fromRGB(245, 199, 100)
    end

    if row.Expired == true then

        return "ENDED",
            Color3.fromRGB(135, 141, 153)
    end

    if row.StockKnown == true
    and (
        tonumber(row.Stock)
        or 0
    ) <= 0 then

        return "SOLD OUT",
            Color3.fromRGB(135, 141, 153)
    end

    if row.Active == true
    and row.NetworkReady == true
    and HolyAuctionPriceAllows(row) == true then

        return "READY",
            Color3.fromRGB(105, 229, 160)
    end

    return "WAIT",
        Color3.fromRGB(245, 199, 100)
end

function HolyAuctionWatchlistAvailableItems()

    local values = {}

    for _, row in ipairs(
        HolyAuctionBuildItemRows(
            true
        )
    ) do

        if HolyAuctionGetWatchEntry(row.Name) == nil then

            values[#values + 1] =
                tostring(
                    row.Name
                )
        end
    end

    return values
end

function HolyAuctionWatchlistReadSingleValue(value)

    if type(value) ~= "table" then

        return HolyCleanText(
            value
        )
    end

    for key, enabled in pairs(value) do

        if enabled == true then

            return HolyCleanText(
                key
            )
        end
    end

    return HolyCleanText(
        value[1]
    )
end

function HolyAuctionOpenAddWatchDialog()

    local available =
        HolyAuctionWatchlistAvailableItems()

    if #available <= 0 then

        HolyNotify(
            "Auction Watchlist",
            "No new auction items are currently available.",
            4
        )

        return
    end

    table.sort(
        available,
        function(a, b)

            return tostring(a):lower()
                < tostring(b):lower()
        end
    )

    local selectedItem =
        available[1]

    local enteredPrice =
        "0"

    local dialog

    local function updateValidation()

        if dialog == nil then
            return
        end

        local parsedPrice =
            HolyAuctionReadMoney(
                enteredPrice
            )

        dialog:SetDescription(
            parsedPrice > 0
            and (
                "Maximum price: "
                .. HolyAuctionFormatMoney(
                    parsedPrice
                )
            )
            or "Choose an item and enter the most you are willing to pay."
        )

        dialog:SetButtonDisabled(
            "Add",
            selectedItem == ""
                or parsedPrice <= 0
        )
    end

    dialog =
        Window:AddDialog(
            "HolyAuctionAddWatchItem",
            {
                Title =
                    "Add Auction Item",

                Description =
                    "Choose an item and enter the most you are willing to pay.",

                AutoDismiss =
                    false,

                OutsideClickDismiss =
                    true,

                FooterButtons = {
                    Cancel = {
                        Title =
                            "Cancel",

                        Variant =
                            "Ghost",

                        Order =
                            1,

                        Callback =
                            function()

                                dialog:Dismiss()
                            end,
                    },

                    Add = {
                        Title =
                            "Add Item",

                        Variant =
                            "Primary",

                        Order =
                            2,

                        Callback =
                            function()

                                local success,
                                    reason =
                                    HolyAuctionUpsertWatchItem(
                                        selectedItem,
                                        enteredPrice
                                    )

                                if success == true then

                                    dialog:Dismiss()

                                else

                                    dialog:SetDescription(
                                        tostring(
                                            reason
                                        )
                                    )
                                end
                            end,
                    },
                },
            }
        )

    dialog:AddDropdown(
        "HolyAuctionAddWatchItemDropdown",
        {
            Text =
                "Item",

            Values =
                available,

            Default =
                1,

            Multi =
                false,

            AllowNull =
                false,

            Searchable =
                true,

            MaxVisibleDropdownItems =
                8,
        }
    ):OnChanged(function(value)

        selectedItem =
            HolyAuctionWatchlistReadSingleValue(
                value
            )

        updateValidation()
    end)

    dialog:AddInput(
        "HolyAuctionAddWatchItemPrice",
        {
            Text =
                "Maximum Price",

            Default =
                "0",

            Placeholder =
                "Example: 50M",

            Numeric =
                false,

            Finished =
                false,

            ClearTextOnFocus =
                false,
        }
    ):OnChanged(function(value)

        enteredPrice =
            tostring(
                value
                or "0"
            )

        updateValidation()
    end)

    updateValidation()
end

function HolyAuctionOpenEditWatchDialog()

    local entry =
        HolyAuctionGetSelectedWatchEntry()

    if type(entry) ~= "table" then

        HolyNotify(
            "Auction Watchlist",
            "Select an item first.",
            3
        )

        return
    end

    local itemName =
        tostring(
            entry.Name
        )

    local enteredPrice =
        tostring(
            entry.MaxPrice
            or "0"
        )

    local liveRow =
        HolyAuctionWatchlistLiveRow(
            itemName
        )

    local currentText =
        type(liveRow) == "table"
        and tostring(
            liveRow.PriceText
            or HolyAuctionFormatMoney(
                liveRow.Price
            )
        )
        or "Unavailable"

    local dialog

    local function updateValidation()

        local parsedPrice =
            HolyAuctionReadMoney(
                enteredPrice
            )

        dialog:SetDescription(
            "Current price: "
            .. currentText
            .. "\nMaximum price: "
            .. (
                parsedPrice > 0
                and HolyAuctionFormatMoney(
                    parsedPrice
                )
                or "Invalid"
            )
        )

        dialog:SetButtonDisabled(
            "Save",
            parsedPrice <= 0
        )
    end

    dialog =
        Window:AddDialog(
            "HolyAuctionEditWatchItem",
            {
                Title =
                    "Edit "
                    .. itemName,

                Description =
                    "Current price: "
                    .. currentText,

                AutoDismiss = false,
                OutsideClickDismiss = true,

                FooterButtons = {
                    Remove = {
                        Title = "Remove",
                        Variant = "Destructive",
                        WaitTime = 1,
                        Order = 1,

                        Callback = function()

                            HolyAuctionRemoveWatchItem(
                                itemName
                            )

                            dialog:Dismiss()
                        end,
                    },

                    Cancel = {
                        Title = "Cancel",
                        Variant = "Ghost",
                        Order = 2,

                        Callback = function()

                            dialog:Dismiss()
                        end,
                    },

                    Save = {
                        Title = "Save",
                        Variant = "Primary",
                        Order = 3,

                        Callback = function()

                            local success,
                                reason =
                                HolyAuctionUpsertWatchItem(
                                    itemName,
                                    enteredPrice
                                )

                            if success == true then

                                dialog:Dismiss()

                            else

                                dialog:SetDescription(
                                    tostring(
                                        reason
                                    )
                                )
                            end
                        end,
                    },
                },
            }
        )

    dialog:AddInput(
        "HolyAuctionEditWatchItemPrice",
        {
            Text = "Maximum Price",
            Default = enteredPrice,
            Placeholder = "Example: 50M",
            Numeric = false,
            Finished = false,
            ClearTextOnFocus = false,
        }
    ):OnChanged(function(value)

        enteredPrice =
            tostring(
                value
                or "0"
            )

        updateValidation()
    end)

    updateValidation()
end

