local function createHeaderLabel(text, position, size, alignment)

    local label =
        Instance.new(
            "TextLabel"
        )

    label.BackgroundTransparency =
        1

    label.Position =
        position

    label.Size =
        size

    label.Text =
        text

    label.TextColor3 =
        Library.Scheme.FontColor

    label.TextTransparency =
        0.50

    label.TextSize =
        10

    label.TextXAlignment =
        alignment

    label.FontFace =
        Library.Scheme.Font

    label.Parent =
        AuctionWatchlistHeader

    return label
end

