function HolySettingsRefreshDashboard()

    local dashboard =
        tostring(
            HOLY_DEV_UI_STATE.SettingsDashboard
            or "Interface"
        )

    local showInterface =
        dashboard == "Interface"

    local showThemes =
        dashboard == "Themes"

    local showSession =
        dashboard == "Session"

    local showPerformance =
        dashboard == "Performance"

    HolySetGroupboxVisible(
        SettingsUIBox,
        showInterface
    )

    HolySetGroupboxVisible(
        SettingsLayoutBox,
        showInterface
    )

    HolySetGroupboxVisible(
        SettingsThemeEditorBox,
        showThemes
    )

    HolySetGroupboxVisible(
        SettingsThemeLibraryBox,
        showThemes
    )

    HolySetGroupboxVisible(
        SettingsSessionBox,
        showSession
    )

    HolySetGroupboxVisible(
        SettingsPerformanceBox,
        showPerformance
    )
end

function HolySettingsSetDashboard(value)

    value =
        tostring(
            value
            or "Interface"
        )

    if value ~= "Themes"
    and value ~= "Session"
    and value ~= "Performance" then

        value =
            "Interface"
    end

    HOLY_DEV_UI_STATE.SettingsDashboard =
        value

    HolySaveUISettings()

    if SettingsModeControl
    and type(SettingsModeControl.SetValue) == "function" then

        SettingsModeControl:SetValue(
            value,
            true
        )
    end

    HolySettingsRefreshDashboard()
end

