if type(HolyRareAlertStart) == "function" then

    task.defer(function()

        HolyRareAlertStart(
            "startup"
        )
    end)
end

if SHOW_PATCHED_VULN_TOOLS == true
and HOLY_WATERING_REJOIN_STATE.Enabled == true then

    task.defer(function()

        task.wait(
            1
        )

        HolyWateringRejoinStart(
            "saved startup"
        )
    end)
end

HolyStartupLoadingStep(
    4,
    "Ready",
    "HOLY PRO has finished loading."
)

if type(HolyStartupLoading) == "table" then

    local loadingElapsed =
        os.clock()
        - HolyStartupLoadingStartedAt

    if loadingElapsed < 0.6 then

        task.wait(
            0.6 - loadingElapsed
        )
    end

    pcall(function()

        HolyStartupLoading:Continue()
    end)

    pcall(function()

        Window:Toggle(
            HOLY_DEV_UI_STATE.ShowUIOnLoad
            == true
        )
    end)
end

HolyNotify(
    "HOLY Premium",
    "Loaded. Toggle UI with LeftAlt.",
    4
)

